@dataclass(frozen=True)
class Issue:
    kind: str
    location: str
    message: str


def load_json(path: Path) -> dict:
    return json.loads(path.read_text())


def build_registry() -> Registry:
    resources = []
    for schema_path in sorted(SCHEMA_DIR.glob("*.schema.json")):
        schema = load_json(schema_path)
        resource = Resource.from_contents(schema)
        schema_uri = schema.get("$id", f"https://taxat.dev/schemas/{schema_path.name}")
        resources.extend(
            (
                (schema_uri, resource),
                (schema_path.name, resource),
                (f"./{schema_path.name}", resource),
            )
        )
    return Registry().with_resources(resources)


def infer_schema_name(sample_path: Path) -> str:
    return sample_path.name.replace("sample_", "").replace(".json", ".schema.json")


def infer_kind_from_name(path: Path) -> str:
    return path.name.replace("sample_", "").replace(".json", "").replace(".schema", "")


def duplicate_values(values: list[str]) -> list[str]:
    seen: set[str] = set()
    duplicates: list[str] = []
    for value in values:
        if value in seen and value not in duplicates:
            duplicates.append(value)
        seen.add(value)
    return duplicates


def matches_regex(value: object, pattern: re.Pattern[str]) -> bool:
    return isinstance(value, str) and bool(pattern.fullmatch(value))


