def parse_exact_decimal(value: object) -> Decimal | None:
    if not isinstance(value, str) or not EXACT_DECIMAL_PATTERN.fullmatch(value):
        return None
    try:
        parsed = Decimal(value)
    except InvalidOperation:
        return None
    if not parsed.is_finite():
        return None
    return parsed


def decimal_scale(value: str) -> int:
    if "." not in value:
        return 0
    return len(value.split(".", 1)[1])


def zero_money_literal(scale: int) -> str:
    return "0" if scale == 0 else f"0.{('0' * scale)}"


def validate_money_profile(
    payload: dict,
    location: str,
    field_name: str = "money_profile",
) -> tuple[list["Issue"], int | None]:
    issues: list[Issue] = []
    money_profile = payload.get(field_name)
    if not isinstance(money_profile, dict):
        issues.append(Issue("custom", location, f"`{field_name}` must be present as an object."))
        return issues, None

    scale = money_profile.get("scale")
    if not isinstance(scale, int) or isinstance(scale, bool):
        issues.append(Issue("custom", location, f"`{field_name}.scale` must be an integer."))
        return issues, None
    if scale < 0:
        issues.append(Issue("custom", location, f"`{field_name}.scale` must be >= 0."))
        return issues, None

    return issues, scale


def validate_money_value(
    value: object,
    scale: int | None,
    issues: list["Issue"],
    location: str,
    label: str,
    *,
    allow_negative: bool = True,
) -> Decimal | None:
    parsed = parse_exact_decimal(value)
    if parsed is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} must be a canonical decimal string with no exponent or locale formatting.",
            )
        )
        return None

    if isinstance(value, str) and value.startswith("-") and parsed == 0:
        issues.append(Issue("custom", location, f"{label} must not serialize negative zero."))
    if scale is not None and decimal_scale(value) != scale:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} must use exactly {scale} fractional digits from `money_profile.scale`.",
            )
        )
    if not allow_negative and parsed < 0:
        issues.append(Issue("custom", location, f"{label} must not be negative."))
    return parsed


def validate_money_tree(
    node: object,
    scale: int | None,
    issues: list["Issue"],
    location: str,
    label: str,
) -> None:
    if isinstance(node, str):
        validate_money_value(node, scale, issues, location, label)
        return
    if isinstance(node, dict):
        for key, value in node.items():
            validate_money_tree(value, scale, issues, location, f"{label}.{key}")
        return
    issues.append(Issue("custom", location, f"{label} must be a canonical money value or nested object map."))


