def extract_numbered_markdown_items(text: str) -> list[int]:
    return [int(match.group(1)) for match in re.finditer(r"(?m)^(\d+)\. ", text)]


def parse_markdown_table_after_heading(
    text: str, heading: str
) -> tuple[list[str] | None, list[list[str]] | None]:
    start = text.find(heading)
    if start == -1:
        return None, None

    table_lines: list[str] = []
    for line in text[start + len(heading) :].splitlines():
        stripped = line.strip()
        if not stripped:
            if table_lines:
                break
            continue
        if stripped.startswith("## "):
            break
        if stripped.startswith("|"):
            table_lines.append(stripped)
            continue
        if table_lines:
            break

    if len(table_lines) < 2:
        return None, None

    header = [cell.strip() for cell in table_lines[0].strip("|").split("|")]
    rows = [[cell.strip() for cell in line.strip("|").split("|")] for line in table_lines[2:]]
    return header, rows


def markdown_code_tokens(cell: str) -> list[str]:
    return re.findall(r"`([^`]+)`", cell)


def format_traceability_location(path: str, root: Path | None) -> str:
    return str(root / path) if root is not None else path


def build_constraint_traceability_doc_cache(
    register: dict[str, Any],
    *,
    root: Path | None,
    preload: dict[str, str] | None = None,
) -> dict[str, str | None]:
    cache: dict[str, str | None] = {}
    if preload:
        cache.update(preload)
    for entry in register.get("entries", []):
        if not isinstance(entry, dict):
            continue
        for group_name in TRACEABILITY_REF_GROUPS:
            for ref in entry.get(group_name, []):
                if not isinstance(ref, dict):
                    continue
                path = ref.get("path")
                if not isinstance(path, str) or path in cache:
                    continue
                if root is None:
                    cache[path] = None
                    continue
                target = root / path
                cache[path] = target.read_text() if target.exists() else None
    return cache


def validate_live_constraint_traceability_register(
    register: dict[str, Any],
    *,
    schema: dict[str, Any] | None,
    coverage_index_text: str,
    doc_text_by_path: dict[str, str | None],
    register_location: str,
    coverage_location: str,
    root: Path | None,
) -> list[Issue]:
    issues: list[Issue] = []

    if schema is not None:
        validator = Draft202012Validator(
            schema,
            format_checker=Draft202012Validator.FORMAT_CHECKER,
        )
        for error in sorted(validator.iter_errors(register), key=lambda err: list(err.absolute_path)):
            absolute_path = "/".join(map(str, error.absolute_path)) or "<root>"
            issues.append(Issue("repo-coherence", f"{register_location}:{absolute_path}", error.message))

    entries = register.get("entries")
    if not isinstance(entries, list):
        issues.append(
            Issue(
                "repo-coherence",
                register_location,
                "constraint_traceability_register.json must contain an `entries[]` array.",
            )
        )
        return issues

    entry_ids: list[str] = []
    entry_by_id: dict[str, dict[str, Any]] = {}
    for entry in entries:
        if not isinstance(entry, dict):
            issues.append(
                Issue(
                    "repo-coherence",
                    register_location,
                    "constraint_traceability_register.json entries must be objects.",
                )
            )
            continue
        constraint_id = entry.get("constraint_id")
        if not isinstance(constraint_id, str):
            issues.append(
                Issue(
                    "repo-coherence",
                    register_location,
                    "Every constraint-traceability entry must keep a string `constraint_id`.",
                )
            )
            continue
        if constraint_id in entry_by_id:
            issues.append(
                Issue(
                    "repo-coherence",
                    register_location,
                    f"constraint_traceability_register.json duplicates `{constraint_id}`.",
                )
            )
            continue

        entry_ids.append(constraint_id)
        entry_by_id[constraint_id] = entry

        for group_name in TRACEABILITY_REF_GROUPS:
            refs = entry.get(group_name, [])
            if not isinstance(refs, list):
                issues.append(
                    Issue(
                        "repo-coherence",
                        register_location,
                        f"{constraint_id} must keep `{group_name}` as an array.",
                    )
                )
                continue

            for ref in refs:
                if not isinstance(ref, dict):
                    issues.append(
                        Issue(
                            "repo-coherence",
                            register_location,
                            f"{constraint_id} `{group_name}` refs must be objects.",
                        )
                    )
                    continue

                path = ref.get("path")
                kind = ref.get("kind")
                required_terms = ref.get("required_terms")
                if not isinstance(path, str):
                    issues.append(
                        Issue(
                            "repo-coherence",
                            register_location,
                            f"{constraint_id} `{group_name}` refs must keep a string `path`.",
                        )
                    )
                    continue

                allowed_kinds = TRACEABILITY_ALLOWED_KINDS_BY_GROUP[group_name]
                if kind not in allowed_kinds:
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} `{group_name}` uses unsupported kind `{kind}`.",
                        )
                    )

                if kind == "FORENSIC_HISTORY" and group_name not in TRACEABILITY_ALLOWED_HISTORY_GROUPS:
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} must keep `FORENSIC_HISTORY` refs out of `{group_name}`.",
                        )
                    )
                if kind == "FORENSIC_HISTORY" and path not in CONSTRAINT_TRACEABILITY_ALLOWED_HISTORICAL_PATHS:
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} must keep `FORENSIC_HISTORY` refs limited to {sorted(CONSTRAINT_TRACEABILITY_ALLOWED_HISTORICAL_PATHS)}.",
                        )
                    )

                if not isinstance(required_terms, list):
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} `{group_name}` ref `{path}` must keep `required_terms[]`.",
                        )
                    )
                    continue

                text = doc_text_by_path.get(path)
                if text is None:
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} references missing traceability path `{path}`.",
                        )
                    )
                    continue

                lowered = text.lower()
                missing_terms = [
                    term for term in required_terms if not isinstance(term, str) or term.lower() not in lowered
                ]
                if missing_terms:
                    issues.append(
                        Issue(
                            "repo-coherence",
                            format_traceability_location(path, root),
                            f"{constraint_id} `{group_name}` ref `{path}` is missing required traceability terms {missing_terms}.",
                        )
                    )

        enforcement_refs = entry.get("enforcement_refs", [])
        if isinstance(enforcement_refs, list):
            has_validator = any(
                isinstance(ref, dict)
                and ref.get("kind") == "VALIDATOR"
                and ref.get("path") == "scripts/validate_contracts.py"
                for ref in enforcement_refs
            )
            has_guard = any(
                isinstance(ref, dict)
                and ref.get("kind") == "FORENSIC_GUARD"
                and ref.get("path") == "tools/forensic_contract_guard.py"
                for ref in enforcement_refs
            )
            if not has_validator or not has_guard:
                issues.append(
                    Issue(
                        "repo-coherence",
                        register_location,
                        f"{constraint_id} must bind one validator ref at `scripts/validate_contracts.py` and one forensic-guard ref at `tools/forensic_contract_guard.py`.",
                    )
                )

    if entry_ids != sorted(entry_ids):
        issues.append(
            Issue(
                "repo-coherence",
                register_location,
                "constraint_traceability_register.json entries must stay ordered by `constraint_id`.",
            )
        )

    header, rows = parse_markdown_table_after_heading(
        coverage_index_text, CONSTRAINT_TRACEABILITY_REGISTER_HEADING
    )
    if header is None or rows is None:
        issues.append(
            Issue(
                "repo-coherence",
                coverage_location,
                f"constraint_coverage_index.md must publish a `{CONSTRAINT_TRACEABILITY_REGISTER_HEADING}` table.",
            )
        )
        return issues

    if tuple(header) != CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS:
        issues.append(
            Issue(
                "repo-coherence",
                coverage_location,
                f"constraint_coverage_index.md must keep the active named constraint register header exactly {CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS}.",
            )
        )
        return issues

    row_by_id: dict[str, dict[str, str]] = {}
    for row in rows:
        if len(row) != len(CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS):
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"constraint_coverage_index.md has a malformed active named constraint row: {row}.",
                )
            )
            continue
        row_map = dict(zip(CONSTRAINT_TRACEABILITY_REGISTER_COLUMNS, row))
        id_tokens = markdown_code_tokens(row_map["ID"])
        constraint_id = id_tokens[0] if id_tokens else row_map["ID"].strip()
        if constraint_id in row_by_id:
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"constraint_coverage_index.md duplicates `{constraint_id}` in the active named constraint register.",
                )
            )
            continue
        row_by_id[constraint_id] = row_map

    if list(row_by_id) != entry_ids:
        issues.append(
            Issue(
                "repo-coherence",
                coverage_location,
                "constraint_coverage_index.md must list the same active constraint ids in the same order as constraint_traceability_register.json.",
            )
        )

    for constraint_id in entry_ids:
        entry = entry_by_id.get(constraint_id)
        row = row_by_id.get(constraint_id)
        if entry is None or row is None:
            continue
        if row["Active constraint"] != entry.get("constraint_name"):
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"{constraint_id} name drift: constraint_coverage_index.md must mirror constraint_traceability_register.json exactly.",
                )
            )
        if not row["Architectural rationale"].strip():
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"{constraint_id} must keep a non-empty architectural rationale in constraint_coverage_index.md.",
                )
            )

        expected_authoritative = [ref["path"] for ref in entry.get("authoritative_refs", []) if isinstance(ref, dict)]
        expected_enforcement = [ref["path"] for ref in entry.get("enforcement_refs", []) if isinstance(ref, dict)]
        expected_downstream_and_examples = [
            *[ref["path"] for ref in entry.get("downstream_refs", []) if isinstance(ref, dict)],
            *[ref["path"] for ref in entry.get("example_refs", []) if isinstance(ref, dict)],
        ]

        actual_authoritative = markdown_code_tokens(row["Authoritative boundary"])
        actual_enforcement = markdown_code_tokens(row["Machine enforcement"])
        actual_downstream_and_examples = markdown_code_tokens(row["Downstream and example propagation"])

        if actual_authoritative != expected_authoritative:
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"{constraint_id} authoritative-boundary paths must mirror constraint_traceability_register.json exactly.",
                )
            )
        if actual_enforcement != expected_enforcement:
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"{constraint_id} machine-enforcement paths must mirror constraint_traceability_register.json exactly.",
                )
            )
        if actual_downstream_and_examples != expected_downstream_and_examples:
            issues.append(
                Issue(
                    "repo-coherence",
                    coverage_location,
                    f"{constraint_id} downstream/example paths must mirror constraint_traceability_register.json exactly.",
                )
            )

    return issues


def parse_datetime(value: str | None) -> datetime | None:
    if value is None:
        return None
    try:
        return datetime.fromisoformat(value.replace("Z", "+00:00"))
    except ValueError:
        return None


def is_clear_portal_due_label(value: object) -> bool:
    if not isinstance(value, str):
        return False
    if value == "No deadline yet":
        return True
    if value.startswith("Due ") or value.startswith("Overdue "):
        return any(character.isdigit() for character in value)
    return False


def validate_portal_language_contract(
    contract: object,
    location: str,
    label: str,
) -> list[Issue]:
    if contract != PORTAL_LANGUAGE_CONTRACT:
        return [
            Issue(
                "custom",
                location,
                f"{label} must retain the shared portal language contract for client-safe task wording, single-dominant-task posture, role-filtered copy publication, jargon bans, and bounded first-view copy.",
            )
        ]
    return []


def validate_portal_visible_copy(
    value: object,
    location: str,
    field_name: str,
    budget_key: str,
    *,
    due_label: bool = False,
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(value, str) or not value.strip():
        return issues
    budget = PORTAL_LANGUAGE_CONTRACT["copy_budget"][budget_key]
    if len(value) > budget:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} exceeds the governed portal copy budget of {budget} characters.",
            )
        )
    leaked_markers = sorted(set(portal_language_leak_markers(value)))
    if leaked_markers:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must stay in client-safe portal language and must not leak {leaked_markers}.",
            )
        )
    if due_label and not is_clear_portal_due_label(value):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must use explicit `Due ...`/`Overdue ...` wording with a date or `No deadline yet`.",
            )
        )
    return issues


def portal_visible_copy_text(value: object) -> str | None:
    if not isinstance(value, str):
        return None
    normalized = " ".join(value.split()).strip()
    if not normalized:
        return None
    return normalized


def portal_copy_budget_total(*values: object) -> int:
    total = 0
    for value in values:
        text = portal_visible_copy_text(value)
        if text is not None:
            total += len(text)
    return total


def normalized_portal_copy(value: object) -> str | None:
    text = portal_visible_copy_text(value)
    if text is None:
        return None
    return " ".join(text.casefold().split())


def validate_portal_first_view_budget(
    location: str,
    route_label: str,
    budget_key: str,
    *values: object,
) -> list[Issue]:
    budget = PORTAL_LANGUAGE_CONTRACT["copy_budget"][budget_key]
    total = portal_copy_budget_total(*values)
    if total <= budget:
        return []
    return [
        Issue(
            "custom",
            location,
            f"{route_label} exceeds the governed first-view portal copy budget of {budget} characters.",
        )
    ]


def validate_portal_duplicate_support_copy(
    location: str,
    fragments: list[tuple[str, object]],
) -> list[Issue]:
    repeated_labels: dict[str, list[str]] = {}
    for field_name, value in fragments:
        normalized = normalized_portal_copy(value)
        if normalized is None or len(normalized) < 24:
            continue
        repeated_labels.setdefault(normalized, []).append(field_name)
    duplicates = [
        labels
        for labels in repeated_labels.values()
        if len(labels) > 1
    ]
    if not duplicates:
        return []
    duplicate_description = ", ".join(
        " / ".join(labels) for labels in duplicates
    )
    return [
        Issue(
            "custom",
            location,
            f"Portal routes must not repeat the same limitation or recovery narrative across multiple visible regions; duplicate copy found in {duplicate_description}.",
        )
    ]


def ensure_datetime_order(
    start: datetime | None,
    end: datetime | None,
    issues: list["Issue"],
    location: str,
    message: str,
) -> None:
    if start is not None and end is not None and end < start:
        issues.append(Issue("custom", location, message))


def validate_manifest_branch_decision(
    decision: dict | None,
    location: str,
    path: str,
) -> tuple[list[Issue], dict | None]:
    issues: list[Issue] = []
    if not isinstance(decision, dict):
        return issues, None

    issues.extend(validate_scope_sequence(decision.get("requested_scope"), location, f"{path}.requested_scope[]"))
    issues.extend(validate_scope_sequence(decision.get("effective_scope"), location, f"{path}.effective_scope[]"))

    branch_action = decision.get("branch_action")
    branch_reason_code = decision.get("branch_reason_code")
    run_kind = decision.get("run_kind")
    replay_class = decision.get("replay_class_or_null")
    nightly_window_key = decision.get("nightly_window_key_or_null")
    request_identity_hash = decision.get("request_identity_hash")
    prior_manifest_id = decision.get("prior_manifest_id_or_null")
    prior_manifest_hash = decision.get("prior_manifest_hash_at_decision_or_null")
    prior_manifest_lifecycle_state = decision.get("prior_manifest_lifecycle_state_or_null")
    selected_manifest_id = decision.get("selected_manifest_id")
    selected_manifest_continuation_basis = decision.get("selected_manifest_continuation_basis")
    root_manifest_id = decision.get("root_manifest_id")
    parent_manifest_id = decision.get("parent_manifest_id_or_null")
    continuation_of_manifest_id = decision.get("continuation_of_manifest_id_or_null")
    replay_of_manifest_id = decision.get("replay_of_manifest_id_or_null")
    supersedes_manifest_id = decision.get("supersedes_manifest_id_or_null")
    selected_manifest_generation = decision.get("selected_manifest_generation")
    requested_scope = decision.get("requested_scope")
    effective_scope = decision.get("effective_scope")
    config_inheritance_mode = decision.get("config_inheritance_mode_or_null")
    input_inheritance_mode = decision.get("input_inheritance_mode_or_null")
    returned_decision_bundle_hash = decision.get("returned_decision_bundle_hash_or_null")

    if branch_action not in MANIFEST_BRANCH_ACTIONS:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.branch_action` must be one of {sorted(MANIFEST_BRANCH_ACTIONS)}.",
            )
        )

    if branch_reason_code not in MANIFEST_BRANCH_REASON_CODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.branch_reason_code` must be one of {sorted(MANIFEST_BRANCH_REASON_CODES)}.",
            )
        )

    if not isinstance(request_identity_hash, str) or not request_identity_hash:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.request_identity_hash` must retain the frozen request-comparison digest.",
            )
        )

    if isinstance(requested_scope, list) and isinstance(effective_scope, list):
        widened_scope_tokens = [token for token in effective_scope if token not in requested_scope]
        if widened_scope_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.effective_scope[]` must stay within `requested_scope[]`; missing {widened_scope_tokens}.",
                )
            )

    expected_reason_code = expected_manifest_branch_reason_code(branch_action, run_kind)
    if expected_reason_code is not None and branch_reason_code != expected_reason_code:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.branch_reason_code` must equal `{expected_reason_code}` when `branch_action = {branch_action}`.",
            )
        )

    if run_kind == "NIGHTLY" and not isinstance(nightly_window_key, str):
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.nightly_window_key_or_null` must be present for `run_kind = NIGHTLY`.",
            )
        )
    if run_kind != "NIGHTLY" and nightly_window_key is not None:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.nightly_window_key_or_null` must stay null outside `run_kind = NIGHTLY`.",
            )
        )

    if run_kind == "REPLAY" and replay_class not in REPLAY_CLASSES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.replay_class_or_null` must be present for replay requests.",
            )
        )
    if run_kind != "REPLAY" and replay_class is not None:
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.replay_class_or_null` must stay null outside `run_kind = REPLAY`.",
            )
        )

    if (prior_manifest_id is None) != (prior_manifest_hash is None) or (prior_manifest_id is None) != (
        prior_manifest_lifecycle_state is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}` must pair prior-manifest id, hash, and lifecycle state together.",
            )
        )

    if selected_manifest_continuation_basis == "NEW_MANIFEST":
        if selected_manifest_generation != 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.selected_manifest_generation` must stay `0` for `selected_manifest_continuation_basis = NEW_MANIFEST`.",
                )
            )
        if root_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.root_manifest_id` must mirror `selected_manifest_id` for root manifests.",
                )
            )
        unexpected_root_lineage = [
            field
            for field, value in (
                ("parent_manifest_id_or_null", parent_manifest_id),
                ("continuation_of_manifest_id_or_null", continuation_of_manifest_id),
                ("replay_of_manifest_id_or_null", replay_of_manifest_id),
                ("supersedes_manifest_id_or_null", supersedes_manifest_id),
            )
            if value is not None
        ]
        if unexpected_root_lineage:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must clear child lineage refs for selected root manifests; found {unexpected_root_lineage}.",
                )
            )
    elif selected_manifest_continuation_basis in CHILD_CONTINUATION_BASES:
        if not isinstance(selected_manifest_generation, int) or selected_manifest_generation < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.selected_manifest_generation` must stay `>= 1` for child manifests.",
                )
            )
        if not isinstance(parent_manifest_id, str) or not parent_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.parent_manifest_id_or_null` must retain the selected child parent.",
                )
            )
        if selected_manifest_continuation_basis == "REPLAY_CHILD" and parent_manifest_id != replay_of_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` replay-child lineage must keep `parent_manifest_id_or_null = replay_of_manifest_id_or_null`.",
                )
            )

    if returned_decision_bundle_hash is not None and branch_action != "RETURN_EXISTING_BUNDLE":
        issues.append(
            Issue(
                "custom",
                location,
                f"`{path}.returned_decision_bundle_hash_or_null` must stay null unless `branch_action = RETURN_EXISTING_BUNDLE`.",
            )
        )

    if branch_action == "NEW_MANIFEST":
        if selected_manifest_continuation_basis != "NEW_MANIFEST":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.selected_manifest_continuation_basis` must stay `NEW_MANIFEST` when `branch_action = NEW_MANIFEST`.",
                )
            )
        if prior_manifest_id is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must not retain prior-manifest refs for `branch_action = NEW_MANIFEST`.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must keep inheritance modes null for `branch_action = NEW_MANIFEST`.",
                )
            )
    elif branch_action == "RETURN_EXISTING_BUNDLE":
        if prior_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must keep `prior_manifest_id_or_null = selected_manifest_id` when returning an existing bundle.",
                )
            )
        if prior_manifest_lifecycle_state not in TERMINAL_MANIFEST_LIFECYCLE_STATES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.prior_manifest_lifecycle_state_or_null` must be terminal when returning an existing bundle.",
                )
            )
        if returned_decision_bundle_hash is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.returned_decision_bundle_hash_or_null` must be present when `branch_action = RETURN_EXISTING_BUNDLE`.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must keep inheritance modes null for bundle-return reuse paths.",
                )
            )
    elif branch_action == "REUSE_SEALED_MANIFEST":
        if prior_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must keep `prior_manifest_id_or_null = selected_manifest_id` when reusing a sealed manifest.",
                )
            )
        if prior_manifest_lifecycle_state != "SEALED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.prior_manifest_lifecycle_state_or_null` must stay `SEALED` for same-manifest pre-start reuse.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` must keep inheritance modes null for same-manifest pre-start reuse.",
                )
            )
    elif branch_action in CHILD_CONTINUATION_BASES:
        if selected_manifest_continuation_basis != branch_action:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.selected_manifest_continuation_basis` must equal `{branch_action}` when `branch_action = {branch_action}`.",
                )
            )
        if prior_manifest_id != parent_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}.prior_manifest_id_or_null` must mirror `parent_manifest_id_or_null` for child allocation actions.",
                )
            )
        if selected_manifest_id == prior_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{path}` child allocation actions must not reuse the same manifest id as the parent anchor.",
                )
            )

        if branch_action == "REPLAY_CHILD":
            if replay_of_manifest_id != prior_manifest_id:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{path}.replay_of_manifest_id_or_null` must mirror `prior_manifest_id_or_null` for replay children.",
                    )
                )
            if config_inheritance_mode != "REPLAY_EXACT" or input_inheritance_mode != "REPLAY_EXACT":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{path}` replay children must keep exact replay config and input inheritance modes.",
                    )
                )
        elif branch_action == "RECOVERY_CHILD":
            if config_inheritance_mode != "RECOVERY_EXACT" or input_inheritance_mode != "RECOVERY_EXACT":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{path}` recovery children must keep exact recovery config and input inheritance modes.",
                    )
                )
        elif branch_action in {"CONTINUATION_CHILD", "NEW_REQUEST_CHILD"}:
            if config_inheritance_mode not in {"FRESH_CHILD_RESOLUTION", "HISTORICAL_EXPLICIT"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{path}.config_inheritance_mode_or_null` must stay fresh or historical-explicit for ordinary continuation children.",
                    )
                )
            if input_inheritance_mode not in {"FRESH_CHILD_COLLECTION", "HISTORICAL_EXPLICIT"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{path}.input_inheritance_mode_or_null` must stay fresh or historical-explicit for ordinary continuation children.",
                    )
                )

    return issues, decision


def validate_manifest_lineage_trace_payload(payload: object, location: str) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace` must remain a structured object.",
            )
        )
        return issues

    issues.extend(validate_scope_sequence(payload.get("requested_scope"), location, "`requested_scope[]`"))
    issues.extend(validate_scope_sequence(payload.get("effective_scope"), location, "`effective_scope[]`"))

    selected_branch_action = payload.get("selected_branch_action")
    selected_branch_reason_code = payload.get("selected_branch_reason_code")
    run_kind = payload.get("run_kind")
    replay_class = payload.get("replay_class_or_null")
    nightly_window_key = payload.get("nightly_window_key_or_null")
    requested_scope = payload.get("requested_scope")
    effective_scope = payload.get("effective_scope")
    request_identity_hash = payload.get("request_identity_hash")
    access_binding_hash = payload.get("access_binding_hash")
    selected_manifest_id = payload.get("selected_manifest_id")
    selected_manifest_continuation_basis = payload.get("selected_manifest_continuation_basis")
    selected_manifest_generation = payload.get("selected_manifest_generation")
    root_manifest_id = payload.get("root_manifest_id")
    parent_manifest_id = payload.get("parent_manifest_id_or_null")
    continuation_of_manifest_id = payload.get("continuation_of_manifest_id_or_null")
    replay_of_manifest_id = payload.get("replay_of_manifest_id_or_null")
    supersedes_manifest_id = payload.get("supersedes_manifest_id_or_null")
    prior_manifest_id = payload.get("prior_manifest_id_or_null")
    prior_manifest_hash = payload.get("prior_manifest_hash_at_decision_or_null")
    prior_manifest_lifecycle_state = payload.get("prior_manifest_lifecycle_state_or_null")
    config_inheritance_mode = payload.get("config_inheritance_mode_or_null")
    input_inheritance_mode = payload.get("input_inheritance_mode_or_null")
    returned_decision_bundle_hash = payload.get("returned_decision_bundle_hash_or_null")
    candidate_evaluations = payload.get("candidate_evaluations")
    mirror_sources = payload.get("mirror_sources")
    nightly_context_reason = payload.get("nightly_context_reason_code_or_null")
    nightly_predecessor_batch_run_ref = payload.get("nightly_predecessor_batch_run_ref_or_null")
    nightly_predecessor_manifest_id = payload.get("nightly_predecessor_manifest_id_or_null")
    nightly_predecessor_manifest_hash = payload.get("nightly_predecessor_manifest_hash_or_null")

    for field_name, value in (
        ("request_identity_hash", request_identity_hash),
        ("access_binding_hash", access_binding_hash),
        ("selected_manifest_id", selected_manifest_id),
    ):
        if not isinstance(value, str) or not value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.{field_name}` must remain a non-empty string.",
                )
            )

    if selected_branch_action not in MANIFEST_BRANCH_ACTIONS:
        issues.append(
            Issue(
                "custom",
                location,
                f"`manifest_lineage_trace.selected_branch_action` must be one of {sorted(MANIFEST_BRANCH_ACTIONS)}.",
            )
        )
    if selected_branch_reason_code not in MANIFEST_BRANCH_REASON_CODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`manifest_lineage_trace.selected_branch_reason_code` must be one of {sorted(MANIFEST_BRANCH_REASON_CODES)}.",
            )
        )

    if isinstance(requested_scope, list) and isinstance(effective_scope, list):
        widened_scope_tokens = [token for token in effective_scope if token not in requested_scope]
        if widened_scope_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.effective_scope[]` must stay within `requested_scope[]`.",
                )
            )

    expected_reason_code = expected_manifest_branch_reason_code(selected_branch_action, run_kind)
    if expected_reason_code is not None and selected_branch_reason_code != expected_reason_code:
        issues.append(
            Issue(
                "custom",
                location,
                f"`manifest_lineage_trace.selected_branch_reason_code` must equal `{expected_reason_code}` when `selected_branch_action = {selected_branch_action}`.",
            )
        )

    if run_kind == "NIGHTLY" and not isinstance(nightly_window_key, str):
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.nightly_window_key_or_null` must remain non-null for nightly traces.",
            )
        )
    if run_kind != "NIGHTLY" and nightly_window_key is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.nightly_window_key_or_null` must stay null outside `run_kind = NIGHTLY`.",
            )
        )
    if run_kind == "REPLAY" and replay_class not in REPLAY_CLASSES:
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.replay_class_or_null` must remain non-null for replay traces.",
            )
        )
    if run_kind != "REPLAY" and replay_class is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.replay_class_or_null` must stay null outside `run_kind = REPLAY`.",
            )
        )

    if (prior_manifest_id is None) != (prior_manifest_hash is None) or (prior_manifest_id is None) != (
        prior_manifest_lifecycle_state is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace` must pair prior manifest id, hash, and lifecycle state together.",
            )
        )

    if selected_branch_action == "NEW_MANIFEST":
        if selected_manifest_continuation_basis != "NEW_MANIFEST":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.selected_manifest_continuation_basis` must stay `NEW_MANIFEST` for `selected_branch_action = NEW_MANIFEST`.",
                )
            )
        if selected_manifest_generation != 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.selected_manifest_generation` must stay `0` for root-manifest traces.",
                )
            )
        if root_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.root_manifest_id` must mirror `selected_manifest_id` for root-manifest traces.",
                )
            )
        if any(
            value is not None
            for value in (
                parent_manifest_id,
                continuation_of_manifest_id,
                replay_of_manifest_id,
                supersedes_manifest_id,
                prior_manifest_id,
            )
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace` must clear child and prior-manifest refs for `selected_branch_action = NEW_MANIFEST`.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace` must keep inheritance modes null for `selected_branch_action = NEW_MANIFEST`.",
                )
            )
    elif selected_branch_action == "RETURN_EXISTING_BUNDLE":
        if prior_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.prior_manifest_id_or_null` must mirror `selected_manifest_id` for bundle-return traces.",
                )
            )
        if prior_manifest_lifecycle_state not in TERMINAL_MANIFEST_LIFECYCLE_STATES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.prior_manifest_lifecycle_state_or_null` must be terminal for bundle-return traces.",
                )
            )
        if returned_decision_bundle_hash is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.returned_decision_bundle_hash_or_null` must remain non-null for bundle-return traces.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace` must keep inheritance modes null for bundle-return traces.",
                )
            )
    elif selected_branch_action == "REUSE_SEALED_MANIFEST":
        if prior_manifest_id != selected_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.prior_manifest_id_or_null` must mirror `selected_manifest_id` for same-manifest sealed reuse.",
                )
            )
        if prior_manifest_lifecycle_state != "SEALED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.prior_manifest_lifecycle_state_or_null` must stay `SEALED` for same-manifest reuse traces.",
                )
            )
        if returned_decision_bundle_hash is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.returned_decision_bundle_hash_or_null` must stay null for same-manifest sealed reuse.",
                )
            )
        if config_inheritance_mode is not None or input_inheritance_mode is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace` must keep inheritance modes null for same-manifest sealed reuse.",
                )
            )
    elif selected_branch_action in CHILD_CONTINUATION_BASES:
        if selected_manifest_continuation_basis != selected_branch_action:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.selected_manifest_continuation_basis` must equal `{selected_branch_action}` for child-allocation traces.",
                )
            )
        if not isinstance(selected_manifest_generation, int) or selected_manifest_generation < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.selected_manifest_generation` must stay `>= 1` for child-allocation traces.",
                )
            )
        if prior_manifest_id != parent_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.prior_manifest_id_or_null` must mirror `parent_manifest_id_or_null` for child-allocation traces.",
                )
            )
        if selected_manifest_id == prior_manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace` child-allocation traces must not reuse the parent manifest id as the selected manifest id.",
                )
            )
        if selected_branch_action == "REPLAY_CHILD":
            if replay_of_manifest_id != prior_manifest_id:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.replay_of_manifest_id_or_null` must mirror `prior_manifest_id_or_null` for replay-child traces.",
                    )
                )
            if config_inheritance_mode != "REPLAY_EXACT" or input_inheritance_mode != "REPLAY_EXACT":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace` replay-child traces must retain exact replay inheritance modes.",
                    )
                )
        elif selected_branch_action == "RECOVERY_CHILD":
            if config_inheritance_mode != "RECOVERY_EXACT" or input_inheritance_mode != "RECOVERY_EXACT":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace` recovery-child traces must retain exact recovery inheritance modes.",
                    )
                )
        elif selected_branch_action in {"CONTINUATION_CHILD", "NEW_REQUEST_CHILD"}:
            if config_inheritance_mode not in {"FRESH_CHILD_RESOLUTION", "HISTORICAL_EXPLICIT"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.config_inheritance_mode_or_null` must stay fresh or historical-explicit for continuation-style children.",
                    )
                )
            if input_inheritance_mode not in {"FRESH_CHILD_COLLECTION", "HISTORICAL_EXPLICIT"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.input_inheritance_mode_or_null` must stay fresh or historical-explicit for continuation-style children.",
                    )
                )

    if not isinstance(candidate_evaluations, list):
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.candidate_evaluations[]` must remain an ordered array.",
            )
        )
    else:
        candidate_actions: list[str] = []
        selected_candidates = 0
        selected_candidate: dict[str, Any] | None = None
        for index, candidate in enumerate(candidate_evaluations):
            candidate_path = f"`manifest_lineage_trace.candidate_evaluations[{index}]`"
            if not isinstance(candidate, dict):
                issues.append(Issue("custom", location, f"{candidate_path} must be an object."))
                continue
            candidate_action = candidate.get("candidate_action")
            evaluation_state = candidate.get("evaluation_state")
            disqualifier_reason_codes = candidate.get("disqualifier_reason_codes")
            if isinstance(candidate_action, str):
                candidate_actions.append(candidate_action)
            if candidate_action not in MANIFEST_BRANCH_ACTIONS:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.candidate_action must be one of {sorted(MANIFEST_BRANCH_ACTIONS)}.",
                    )
                )
            if evaluation_state not in {"SELECTED", "REJECTED"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.evaluation_state must be `SELECTED` or `REJECTED`.",
                    )
                )
            if not isinstance(disqualifier_reason_codes, list):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.disqualifier_reason_codes[]` must remain an array.",
                    )
                )
                continue
            invalid_codes = [code for code in disqualifier_reason_codes if code not in MANIFEST_LINEAGE_TRACE_DISQUALIFIER_CODES]
            if invalid_codes:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.disqualifier_reason_codes[] contains unsupported codes {sorted(invalid_codes)}.",
                    )
                )
            duplicate_codes = duplicate_values(
                [code for code in disqualifier_reason_codes if isinstance(code, str)]
            )
            if duplicate_codes:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.disqualifier_reason_codes[] must stay unique; duplicate {sorted(duplicate_codes)}.",
                    )
                )
            if evaluation_state == "SELECTED":
                selected_candidates += 1
                selected_candidate = candidate
                if candidate_action != selected_branch_action:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"{candidate_path}.candidate_action must mirror `selected_branch_action` for the selected candidate.",
                        )
                    )
                if disqualifier_reason_codes:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"{candidate_path}.disqualifier_reason_codes[] must be empty for the selected candidate.",
                        )
                    )
            elif not disqualifier_reason_codes:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{candidate_path}.disqualifier_reason_codes[] must remain non-empty for rejected candidates.",
                    )
                )

        duplicate_candidate_actions = duplicate_values(candidate_actions)
        if duplicate_candidate_actions:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.candidate_evaluations[]` must not duplicate candidate_action values; duplicate {sorted(duplicate_candidate_actions)}.",
                )
            )
        missing_candidate_actions = sorted(MANIFEST_BRANCH_ACTIONS - set(candidate_actions))
        if missing_candidate_actions:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.candidate_evaluations[]` must cover every canonical branch action; missing {missing_candidate_actions}.",
                )
            )
        if selected_candidates != 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.candidate_evaluations[]` must contain exactly one selected candidate.",
                )
            )
        if isinstance(selected_candidate, dict):
            if selected_branch_action == "NEW_MANIFEST" and selected_candidate.get("compared_manifest_id_or_null") is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "The selected NEW_MANIFEST candidate must keep `compared_manifest_id_or_null = null`.",
                    )
                )
            if selected_branch_action in {"RETURN_EXISTING_BUNDLE", "REUSE_SEALED_MANIFEST"} and selected_candidate.get(
                "compared_manifest_id_or_null"
            ) != selected_manifest_id:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Same-manifest selection traces must keep the selected candidate bound to `selected_manifest_id`.",
                    )
                )
            if selected_branch_action in CHILD_CONTINUATION_BASES and selected_candidate.get("compared_manifest_id_or_null") != prior_manifest_id:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Child-allocation traces must keep the selected candidate bound to `prior_manifest_id_or_null`.",
                    )
                )

    if not isinstance(mirror_sources, list):
        issues.append(
            Issue(
                "custom",
                location,
                "`manifest_lineage_trace.mirror_sources[]` must remain an ordered array.",
            )
        )
    else:
        missing_required_sources = sorted(MANIFEST_LINEAGE_TRACE_REQUIRED_MIRROR_SOURCES - set(mirror_sources))
        duplicate_sources = duplicate_values([source for source in mirror_sources if isinstance(source, str)])
        if missing_required_sources:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.mirror_sources[]` must include {missing_required_sources}.",
                )
            )
        if duplicate_sources:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`manifest_lineage_trace.mirror_sources[]` must stay unique; duplicate {sorted(duplicate_sources)}.",
                )
            )

    if run_kind == "NIGHTLY":
        if nightly_context_reason == "WINDOW_ADVANCE_FROM_PREDECESSOR":
            for field_name, value in (
                ("nightly_predecessor_batch_run_ref_or_null", nightly_predecessor_batch_run_ref),
                ("nightly_predecessor_manifest_id_or_null", nightly_predecessor_manifest_id),
                ("nightly_predecessor_manifest_hash_or_null", nightly_predecessor_manifest_hash),
            ):
                if not isinstance(value, str) or not value:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`manifest_lineage_trace.{field_name}` must remain non-null when `nightly_context_reason_code_or_null = WINDOW_ADVANCE_FROM_PREDECESSOR`.",
                        )
                    )
            if selected_branch_reason_code != "NIGHTLY_WINDOW_ADVANCED":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.selected_branch_reason_code` must stay `NIGHTLY_WINDOW_ADVANCED` when nightly predecessor advancement is declared.",
                    )
                )
        elif nightly_context_reason == "NO_PREDECESSOR_BATCH":
            if any(
                value is not None
                for value in (
                    nightly_predecessor_batch_run_ref,
                    nightly_predecessor_manifest_id,
                    nightly_predecessor_manifest_hash,
                )
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace` must clear nightly predecessor refs when `nightly_context_reason_code_or_null = NO_PREDECESSOR_BATCH`.",
                    )
                )
        elif nightly_context_reason == "SAME_WINDOW_REUSE":
            if selected_branch_action not in {"RETURN_EXISTING_BUNDLE", "REUSE_SEALED_MANIFEST"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.nightly_context_reason_code_or_null = SAME_WINDOW_REUSE` is only legal for same-window reuse paths.",
                    )
                )
            if nightly_predecessor_manifest_id != prior_manifest_id or nightly_predecessor_manifest_hash != prior_manifest_hash:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace` same-window nightly reuse must mirror prior-manifest predecessor refs.",
                    )
                )
            if not isinstance(nightly_predecessor_batch_run_ref, str) or not nightly_predecessor_batch_run_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_lineage_trace.nightly_predecessor_batch_run_ref_or_null` must remain non-null for same-window nightly reuse.",
                    )
                )
        else:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_lineage_trace.nightly_context_reason_code_or_null` must stay inside the governed nightly context vocabulary.",
                )
            )

    return issues


def validate_manifest_lineage_trace(
    trace: object,
    location: str,
    field_name: str,
    *,
    expected_selected_branch_action: object = None,
    expected_selected_manifest_id: object = None,
) -> tuple[list[Issue], dict]:
    issues = validate_manifest_lineage_trace_payload(trace, location)
    if not isinstance(trace, dict):
        return issues, {}

    if expected_selected_branch_action is not None and trace.get("selected_branch_action") != expected_selected_branch_action:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.selected_branch_action must mirror `{expected_selected_branch_action}`.",
            )
        )
    if expected_selected_manifest_id is not None and trace.get("selected_manifest_id") != expected_selected_manifest_id:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.selected_manifest_id must mirror `{expected_selected_manifest_id}`.",
            )
        )

    return issues, trace


def validate_observability_correlation_context(
    correlation_context: dict | None,
    location: str,
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(correlation_context, dict):
        return issues

    nightly_batch_run_ref = correlation_context.get("nightly_batch_run_ref")
    nightly_window_key = correlation_context.get("nightly_window_key")
    selection_disposition = correlation_context.get("selection_disposition")
    run_kind = correlation_context.get("run_kind")
    replay_class = correlation_context.get("replay_class")
    manifest_lineage_trace_ref = correlation_context.get("manifest_lineage_trace_ref")
    manifest_branch_decision = correlation_context.get("manifest_branch_decision")
    manifest_start_claim = correlation_context.get("manifest_start_claim")
    comparison_mode = correlation_context.get("comparison_mode")
    basis_validation_state = correlation_context.get("basis_validation_state")
    expected_execution_basis_hash = correlation_context.get("expected_execution_basis_hash")
    actual_execution_basis_hash = correlation_context.get("actual_execution_basis_hash")
    expected_outcome_hash = correlation_context.get("expected_deterministic_outcome_hash")
    actual_outcome_hash = correlation_context.get("actual_deterministic_outcome_hash")

    manifest_branch_issues, branch_decision = validate_manifest_branch_decision(
        manifest_branch_decision,
        location,
        "`correlation_context.manifest_branch_decision`",
    )
    issues.extend(manifest_branch_issues)
    if isinstance(branch_decision, dict):
        mirror_fields = {
            "manifest_id": "selected_manifest_id",
            "root_manifest_id": "root_manifest_id",
            "parent_manifest_id": "parent_manifest_id_or_null",
            "continuation_of_manifest_id": "continuation_of_manifest_id_or_null",
            "replay_of_manifest_id": "replay_of_manifest_id_or_null",
            "idempotency_key": "idempotency_key",
            "access_binding_hash": "access_binding_hash",
            "continuation_basis": "selected_manifest_continuation_basis",
            "run_kind": "run_kind",
            "mode": "mode",
            "replay_class": "replay_class_or_null",
            "nightly_window_key": "nightly_window_key_or_null",
            "config_inheritance_mode": "config_inheritance_mode_or_null",
            "input_inheritance_mode": "input_inheritance_mode_or_null",
        }
        for correlation_field, decision_field in mirror_fields.items():
            if correlation_context.get(correlation_field) != branch_decision.get(decision_field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`correlation_context.{correlation_field}` must mirror `correlation_context.manifest_branch_decision.{decision_field}`.",
                    )
                )
        if correlation_context.get("manifest_id") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`correlation_context.manifest_id` must be present when `manifest_branch_decision` is carried.",
                )
            )
        if not isinstance(manifest_lineage_trace_ref, str) or not manifest_lineage_trace_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`correlation_context.manifest_lineage_trace_ref` must remain non-null when `manifest_branch_decision` is carried.",
                )
            )
    elif manifest_lineage_trace_ref is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`correlation_context.manifest_lineage_trace_ref` must not appear without `manifest_branch_decision`.",
            )
        )

    manifest_start_claim_issues, start_claim = validate_manifest_start_claim_contract(
        manifest_start_claim,
        location,
        "`correlation_context.manifest_start_claim`",
        require_non_null=False,
    )
    issues.extend(manifest_start_claim_issues)
    if isinstance(start_claim, dict):
        if correlation_context.get("manifest_id") != start_claim.get("manifest_id"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`correlation_context.manifest_id` must mirror `correlation_context.manifest_start_claim.manifest_id`.",
                )
            )
        if correlation_context.get("access_binding_hash") != start_claim.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`correlation_context.access_binding_hash` must mirror `correlation_context.manifest_start_claim.access_binding_hash`.",
                )
            )
        if correlation_context.get("manifest_id") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`correlation_context.manifest_id` must be present when `manifest_start_claim` is carried.",
                )
            )

    if (nightly_batch_run_ref is None) != (nightly_window_key is None):
        issues.append(
            Issue(
                "custom",
                location,
                "`nightly_batch_run_ref` and `nightly_window_key` must appear together in observability correlation.",
            )
        )

    if selection_disposition is not None and selection_disposition not in NIGHTLY_SELECTION_DISPOSITIONS:
        issues.append(
            Issue(
                "custom",
                location,
                f"`selection_disposition` must be one of the frozen nightly dispositions {sorted(NIGHTLY_SELECTION_DISPOSITIONS)}.",
            )
        )

    if selection_disposition is not None and (nightly_batch_run_ref is None or nightly_window_key is None):
        issues.append(
            Issue(
                "custom",
                location,
                "`selection_disposition` requires both nightly batch correlation keys.",
            )
        )

    if nightly_batch_run_ref is not None and run_kind not in {None, "NIGHTLY"}:
        issues.append(
            Issue(
                "custom",
                location,
                "Nightly batch correlation keys must not appear on non-`NIGHTLY` observability contexts.",
            )
        )

    if replay_class is not None and replay_class not in REPLAY_CLASSES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`replay_class` must be one of {sorted(REPLAY_CLASSES)}.",
            )
        )

    if replay_class is not None and run_kind not in {None, "REPLAY"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`replay_class` must not appear on non-`REPLAY` observability contexts.",
            )
        )

    if comparison_mode is not None and comparison_mode not in REPLAY_COMPARISON_MODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`comparison_mode` must be one of {sorted(REPLAY_COMPARISON_MODES)}.",
            )
        )
    if basis_validation_state is not None and basis_validation_state not in REPLAY_BASIS_VALIDATION_STATES:
        issues.append(
            Issue(
                "custom",
                location,
                f"`basis_validation_state` must be one of {sorted(REPLAY_BASIS_VALIDATION_STATES)}.",
            )
        )

    if replay_class is None and any(
        value is not None
        for value in (
            comparison_mode,
            basis_validation_state,
            expected_execution_basis_hash,
            actual_execution_basis_hash,
            expected_outcome_hash,
            actual_outcome_hash,
        )
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Replay comparison keys must not appear without `replay_class`.",
            )
        )

    if (expected_execution_basis_hash is None) != (actual_execution_basis_hash is None):
        issues.append(
            Issue(
                "custom",
                location,
                "`expected_execution_basis_hash` and `actual_execution_basis_hash` must appear together.",
            )
        )

    if (expected_outcome_hash is None) != (actual_outcome_hash is None):
        issues.append(
            Issue(
                "custom",
                location,
                "`expected_deterministic_outcome_hash` and `actual_deterministic_outcome_hash` must appear together.",
            )
        )

    return issues


def validate_compute_result(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    money_profile_issues, scale = validate_money_profile(payload, location)
    issues.extend(money_profile_issues)

    issues.extend(
        validate_sorted_string_sequence(
            payload.get("effective_partition_scope_refs"),
            location,
            "`effective_partition_scope_refs[]`",
            allow_empty=False,
        )
    )

    totals = payload.get("totals")
    if isinstance(totals, dict):
        validate_money_tree(totals, scale, issues, location, "`totals`")

    reporting_scope = payload.get("reporting_scope")
    execution_mode = payload.get("execution_mode")
    quarterly_basis_profile = payload.get("quarterly_basis_profile_or_null")
    basis_profile_ref = payload.get("basis_profile_ref_or_null")
    adjustment_inclusion_policy = payload.get("adjustment_inclusion_policy")
    adjustment_scope_source = payload.get("adjustment_scope_source")

    if reporting_scope is not None and reporting_scope not in REPORTING_SCOPE_TOKENS:
        issues.append(
            Issue(
                "custom",
                location,
                f"`reporting_scope` must be one of {sorted(REPORTING_SCOPE_TOKENS)} and must not reuse action-only tokens such as amendment posture.",
            )
        )

    if reporting_scope == "quarterly_update":
        if quarterly_basis_profile not in {"PERIODIC", "CUMULATIVE"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`quarterly_basis_profile_or_null` must be `PERIODIC` or `CUMULATIVE` for quarterly compute results.",
                )
            )
        if not isinstance(basis_profile_ref, str) or not basis_profile_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`basis_profile_ref_or_null` must be present for quarterly compute results.",
                )
            )
        if adjustment_inclusion_policy != "RECORD_ONLY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Quarterly compute results must keep `adjustment_inclusion_policy = RECORD_ONLY` so year-end adjustments cannot leak into periodic reporting.",
                )
            )
    elif quarterly_basis_profile is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`quarterly_basis_profile_or_null` must stay null outside quarterly reporting scope.",
            )
        )

    if execution_mode == "COMPLIANCE" and adjustment_scope_source != "EXECUTABLE_REPORTING_SCOPE":
        issues.append(
            Issue(
                "custom",
                location,
                "Compliance compute results must derive adjustment scope from the executable reporting scope, not from analysis-only counterfactual posture.",
            )
        )

    if reporting_scope == "quarterly_update" and adjustment_inclusion_policy == "APPLY_SCOPE_FILTERED_ADJUSTMENTS":
        issues.append(
            Issue(
                "custom",
                location,
                "Quarterly compute results must not apply scope-filtered adjustment-layer totals directly.",
            )
        )

    return issues


def validate_forecast_set(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    money_profile_issues, scale = validate_money_profile(payload, location)
    issues.extend(money_profile_issues)

    point_forecasts = payload.get("point_forecasts")
    if isinstance(point_forecasts, list):
        for index, point_forecast in enumerate(point_forecasts):
            if not isinstance(point_forecast, dict):
                continue
            validate_money_value(
                point_forecast.get("point_value"),
                scale,
                issues,
                location,
                f"`point_forecasts[{index}].point_value`",
            )

    scenarios = payload.get("scenarios")
    if isinstance(scenarios, list):
        for scenario_index, scenario in enumerate(scenarios):
            if not isinstance(scenario, dict):
                continue
            values = scenario.get("values")
            if not isinstance(values, list):
                continue
            for value_index, scenario_value in enumerate(values):
                if not isinstance(scenario_value, dict):
                    continue
                validate_money_value(
                    scenario_value.get("simulated_value"),
                    scale,
                    issues,
                    location,
                    f"`scenarios[{scenario_index}].values[{value_index}].simulated_value`",
                )

    return issues


def validate_parity_result(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    money_profile_issues, scale = validate_money_profile(payload, location)
    issues.extend(money_profile_issues)
    temporal_event_issues, _ = validate_temporal_propagation_event_refs(
        payload.get("temporal_propagation_event_refs"),
        location,
        "`temporal_propagation_event_refs`",
    )
    issues.extend(temporal_event_issues)

    def is_number(value: object) -> bool:
        return isinstance(value, (int, float)) and not isinstance(value, bool)

    def close_enough(actual: object, expected: float, *, tolerance: float = 1e-9) -> bool:
        return is_number(actual) and abs(float(actual) - expected) <= tolerance

    deltas = payload.get("deltas")
    if not isinstance(deltas, dict):
        return issues

    comparison_set_state = payload.get("comparison_set_state")
    comparison_requirement = payload.get("comparison_requirement")
    ordered_field_codes = payload.get("ordered_field_codes")
    reason_codes = payload.get("reason_codes")
    dominant_reason_code = payload.get("dominant_reason_code")

    if isinstance(reason_codes, list) and reason_codes:
        if dominant_reason_code != reason_codes[0]:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`dominant_reason_code` must equal the first entry in `reason_codes[]`.",
                )
            )
        elif dominant_reason_code not in reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`dominant_reason_code` must be a member of `reason_codes[]`.",
                )
            )

    expected_order: list[tuple[str, int]] = []
    total_weight = Decimal("0")
    comparable_weight = Decimal("0")
    weighted_pressure_numerator = Decimal("0")
    critical_blocking_count = 0
    critical_material_count = 0
    any_minor_difference = False
    any_high_or_critical_material = False
    blocking_ratio_cap = Decimal("3.0")

    for field_code, delta in deltas.items():
        if not isinstance(delta, dict):
            continue
        label = f"`deltas[{field_code}]`"
        if delta.get("field_code") != field_code:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{label}.field_code must exactly match the containing map key.",
                )
            )

        criticality_class = delta.get("criticality_class")
        criticality_rank = {"CRITICAL": 3, "HIGH": 2, "NORMAL": 1}.get(criticality_class)
        if criticality_rank is not None:
            expected_order.append((field_code, criticality_rank))

        criticality_weight = delta.get("criticality_weight")
        parsed_weight: Decimal | None = None
        if is_number(criticality_weight):
            parsed_weight = Decimal(str(criticality_weight))
            if parsed_weight <= 0:
                issues.append(Issue("custom", location, f"{label}.criticality_weight must be > 0."))
                parsed_weight = None
        elif criticality_weight is not None:
            issues.append(Issue("custom", location, f"{label}.criticality_weight must be numeric."))

        abs_threshold = validate_money_value(
            delta.get("abs_threshold"),
            scale,
            issues,
            location,
            f"{label}.abs_threshold",
            allow_negative=False,
        )
        abs_floor = validate_money_value(
            delta.get("abs_floor"),
            scale,
            issues,
            location,
            f"{label}.abs_floor",
            allow_negative=False,
        )
        effective_abs_floor = validate_money_value(
            delta.get("effective_abs_floor"),
            scale,
            issues,
            location,
            f"{label}.effective_abs_floor",
            allow_negative=False,
        )
        rel_threshold = delta.get("rel_threshold")
        parsed_rel_threshold: Decimal | None = None
        if is_number(rel_threshold):
            parsed_rel_threshold = Decimal(str(rel_threshold))
            if parsed_rel_threshold < 0:
                issues.append(Issue("custom", location, f"{label}.rel_threshold must be >= 0."))
                parsed_rel_threshold = None
        elif rel_threshold is not None:
            issues.append(Issue("custom", location, f"{label}.rel_threshold must be numeric."))

        if abs_floor is not None and abs_floor <= 0:
            issues.append(Issue("custom", location, f"{label}.abs_floor must be > 0."))
        if effective_abs_floor is not None and effective_abs_floor <= 0:
            issues.append(Issue("custom", location, f"{label}.effective_abs_floor must be > 0."))
        if abs_floor is not None and effective_abs_floor is not None and effective_abs_floor < abs_floor:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{label}.effective_abs_floor must be >= abs_floor.",
                )
            )

        internal_value = delta.get("internal_value")
        authority_value = delta.get("authority_value")
        delta_signed = delta.get("delta_signed")
        delta_abs = delta.get("delta_abs")

        parsed_internal = (
            validate_money_value(internal_value, scale, issues, location, f"{label}.internal_value")
            if internal_value is not None
            else None
        )
        parsed_authority = (
            validate_money_value(authority_value, scale, issues, location, f"{label}.authority_value")
            if authority_value is not None
            else None
        )
        parsed_delta_signed = (
            validate_money_value(delta_signed, scale, issues, location, f"{label}.delta_signed")
            if delta_signed is not None
            else None
        )
        parsed_delta_abs = (
            validate_money_value(
                delta_abs,
                scale,
                issues,
                location,
                f"{label}.delta_abs",
                allow_negative=False,
            )
            if delta_abs is not None
            else None
        )

        if delta.get("comparison_input_state") == "COMPARABLE":
            if (
                parsed_internal is not None
                and parsed_authority is not None
                and parsed_delta_signed is not None
                and parsed_delta_abs is not None
            ):
                expected_signed = parsed_internal - parsed_authority
                expected_abs = abs(expected_signed)
                if parsed_delta_signed != expected_signed:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"{label}.delta_signed must equal `internal_value - authority_value` under exact-decimal arithmetic.",
                        )
                    )
                if parsed_delta_abs != expected_abs:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"{label}.delta_abs must equal `abs(delta_signed)` under exact-decimal arithmetic.",
                        )
                    )

                if (
                    abs_threshold is not None
                    and abs_floor is not None
                    and effective_abs_floor is not None
                    and parsed_rel_threshold is not None
                ):
                    denominator = max(abs(parsed_authority), abs(parsed_internal), effective_abs_floor)
                    expected_delta_rel = 0.0 if expected_abs == 0 else float(expected_abs / denominator)
                    expected_breach_abs = (
                        0.0
                        if abs_threshold == 0 and expected_abs == 0
                        else float(blocking_ratio_cap)
                        if abs_threshold == 0
                        else float(expected_abs / abs_threshold)
                    )
                    expected_breach_rel = (
                        0.0
                        if parsed_rel_threshold == 0 and expected_delta_rel == 0
                        else float(blocking_ratio_cap)
                        if parsed_rel_threshold == 0
                        else expected_delta_rel / float(parsed_rel_threshold)
                    )
                    expected_breach_ratio = max(expected_breach_abs, expected_breach_rel)

                    if not close_enough(delta.get("delta_rel"), expected_delta_rel):
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                f"{label}.delta_rel must be recomputed from exact-decimal values and `effective_abs_floor`.",
                            )
                        )
                    if not close_enough(delta.get("breach_ratio"), expected_breach_ratio):
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                f"{label}.breach_ratio must be recomputed from exact-decimal thresholds before rounding.",
                            )
                        )

                    expected_field_class = (
                        "MATCH"
                        if expected_breach_ratio < 0.25
                        else "MINOR_DIFFERENCE"
                        if expected_breach_ratio < 1.0
                        else "MATERIAL_DIFFERENCE"
                        if expected_breach_ratio < 2.5
                        else "BLOCKING_DIFFERENCE"
                    )
                    if delta.get("field_class") != expected_field_class:
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                f"{label}.field_class must follow the frozen breach-ratio thresholds exactly at edge values.",
                            )
                        )

                    if parsed_weight is not None:
                        total_weight += parsed_weight
                        comparable_weight += parsed_weight
                        weighted_pressure_numerator += parsed_weight * min(
                            Decimal(str(expected_breach_ratio)),
                            blocking_ratio_cap,
                        )
                    if criticality_class == "CRITICAL" and expected_field_class == "BLOCKING_DIFFERENCE":
                        critical_blocking_count += 1
                    if criticality_class == "CRITICAL" and expected_field_class == "MATERIAL_DIFFERENCE":
                        critical_material_count += 1
                    if criticality_class in {"CRITICAL", "HIGH"} and expected_field_class == "MATERIAL_DIFFERENCE":
                        any_high_or_critical_material = True
                    if expected_field_class == "MINOR_DIFFERENCE":
                        any_minor_difference = True
        else:
            if parsed_weight is not None:
                total_weight += parsed_weight
            if delta.get("field_class") != "NOT_COMPARABLE":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{label}.field_class must be `NOT_COMPARABLE` whenever `comparison_input_state` is not `COMPARABLE`.",
                    )
                )

    expected_order_codes = [
        field_code for field_code, _ in sorted(expected_order, key=lambda item: (-item[1], item[0]))
    ]
    if comparison_set_state == "VALID":
        if ordered_field_codes != expected_order_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`ordered_field_codes[]` must mirror deterministic `(criticality desc, field_code asc)` ordering.",
                )
            )
    elif comparison_set_state == "INVALID" and ordered_field_codes not in (None, []):
        issues.append(
            Issue(
                "custom",
                location,
                "`ordered_field_codes[]` must be empty when `comparison_set_state = INVALID`.",
            )
        )

    expected_coverage = 0.0 if total_weight == 0 else float(comparable_weight / total_weight)
    expected_pressure = (
        0.0 if comparable_weight == 0 else float(weighted_pressure_numerator / comparable_weight)
    )
    if comparison_set_state == "INVALID":
        expected_classification = "NOT_COMPARABLE"
        expected_score = 0
        if payload.get("parity_score") != 0:
            issues.append(Issue("custom", location, "`comparison_set_state = INVALID` must force `parity_score = 0`."))
        if payload.get("comparison_coverage") != 0:
            issues.append(Issue("custom", location, "`comparison_set_state = INVALID` must force `comparison_coverage = 0`."))
        if payload.get("weighted_parity_pressure") != 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`comparison_set_state = INVALID` must force `weighted_parity_pressure = 0`.",
                )
            )
    else:
        expected_classification = (
            "NOT_COMPARABLE"
            if comparison_requirement in {"MANDATORY", "DESIRABLE"} and expected_coverage < 1.0
            else "BLOCKING_DIFFERENCE"
            if critical_blocking_count > 0
            else "MATERIAL_DIFFERENCE"
            if any_high_or_critical_material or expected_pressure >= 1.0
            else "MINOR_DIFFERENCE"
            if any_minor_difference or expected_pressure >= 0.25
            else "MATCH"
        )
        parity_score_raw = 100.0 * expected_coverage * max(0.0, 1.0 - (expected_pressure / 3.0))
        expected_score = 0 if total_weight == 0 and comparison_requirement == "MANDATORY" else round_score(parity_score_raw)
        if not close_enough(payload.get("comparison_coverage"), expected_coverage):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`comparison_coverage` must be derived from the weighted comparable coverage of the frozen comparison set.",
                )
            )
        if not close_enough(payload.get("weighted_parity_pressure"), expected_pressure):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`weighted_parity_pressure` must be derived from the weighted comparable breach ratios.",
                )
            )
        if payload.get("parity_score") != expected_score:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`parity_score` must be derived from weighted coverage and parity pressure with deterministic rounding.",
                )
            )

    if payload.get("critical_blocking_field_count") != critical_blocking_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`critical_blocking_field_count` must equal the number of critical blocking field deltas.",
            )
        )
    if payload.get("critical_material_field_count") != critical_material_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`critical_material_field_count` must equal the number of critical material field deltas.",
            )
        )
    if payload.get("parity_classification") != expected_classification:
        issues.append(
            Issue(
                "custom",
                location,
                "`parity_classification` must follow the deterministic not-comparable/blocking/material/minor/match precedence ladder.",
            )
        )

    expected_reason = {
        "MATCH": "PARITY_MATCH",
        "MINOR_DIFFERENCE": "PARITY_MINOR_DIFFERENCE",
        "MATERIAL_DIFFERENCE": "PARITY_MATERIAL_DIFFERENCE",
        "BLOCKING_DIFFERENCE": "PARITY_BLOCKING_DIFFERENCE",
        "NOT_COMPARABLE": "PARITY_NOT_COMPARABLE",
    }.get(expected_classification)
    if isinstance(reason_codes, list) and expected_reason is not None and expected_reason not in reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"`reason_codes[]` must include `{expected_reason}` when `parity_classification = {expected_classification}`.",
            )
        )
    if (
        comparison_set_state == "INVALID"
        and isinstance(reason_codes, list)
        and "PARITY_COMPARISON_SET_INVALID" not in reason_codes
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`reason_codes[]` must include `PARITY_COMPARISON_SET_INVALID` when the comparison set is invalid.",
            )
        )
    if (
        comparison_set_state == "VALID"
        and comparison_requirement in {"MANDATORY", "DESIRABLE"}
        and expected_coverage < 1.0
        and isinstance(reason_codes, list)
        and "PARITY_PARTIAL_COVERAGE" not in reason_codes
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`reason_codes[]` must include `PARITY_PARTIAL_COVERAGE` when required comparable coverage is incomplete.",
            )
        )

    return issues


def clamp01(value: float) -> float:
    return max(0.0, min(1.0, value))


def safe_div(numerator: float, denominator: float) -> float:
    if denominator <= 0:
        return 0.0
    return numerator / denominator


def round_score(value: float) -> int:
    return max(0, min(100, int(math.floor(value + 0.5))))


def age_seconds(start: datetime | None, end: datetime | None) -> float:
    if start is None or end is None:
        return float("inf")
    return max(0.0, (end - start).total_seconds())


def remaining_seconds(end: datetime | None, as_of: datetime | None) -> float:
    if end is None or as_of is None:
        return 0.0
    return max(0.0, (end - as_of).total_seconds())


