def expected_governance_impacted_count_class(count: object) -> str | None:
    if not isinstance(count, int) or count < 0:
        return None
    if count == 0:
        return "ZERO"
    if count == 1:
        return "ONE"
    if count <= 5:
        return "SMALL_BATCH"
    if count <= 20:
        return "MEDIUM_BATCH"
    if count <= 100:
        return "LARGE_BATCH"
    return "ESTATE_WIDE"


def governance_score_ratio(value: object) -> float | None:
    if not isinstance(value, int):
        return None
    return clamp01(value / 100.0)


def expected_governance_policy_risk_score(payload: dict[str, Any]) -> int | None:
    d_priv = governance_score_ratio(payload.get("privilege_gain_score"))
    d_scope = governance_score_ratio(payload.get("scope_expansion_score"))
    d_mask = governance_score_ratio(payload.get("masking_relaxation_score"))
    d_tail = governance_score_ratio(payload.get("impact_radius_upper_score"))
    if None in {d_priv, d_scope, d_mask, d_tail}:
        return None
    policy_risk_raw = 1 - (
        ((1 - d_priv) ** 0.40)
        * ((1 - d_scope) ** 0.25)
        * ((1 - d_mask) ** 0.20)
        * ((1 - d_tail) ** 0.15)
    )
    return round_score(100 * policy_risk_raw)


def expected_governance_approval_necessity_score(payload: dict[str, Any]) -> int | None:
    policy_risk_score = governance_score_ratio(payload.get("policy_risk_score"))
    impact_radius_upper_score = governance_score_ratio(payload.get("impact_radius_upper_score"))
    if None in {policy_risk_score, impact_radius_upper_score}:
        return None
    approval_necessity_raw = 1 - (
        ((1 - policy_risk_score) ** 0.70)
        * ((1 - impact_radius_upper_score) ** 0.30)
    )
    return round_score(100 * approval_necessity_raw)


def expected_governance_bounded_safe_mutation(payload: dict[str, Any]) -> int | None:
    checks: tuple[tuple[str, object], ...] = (
        ("privilege_gain_score", payload.get("privilege_gain_score")),
        ("scope_expansion_score", payload.get("scope_expansion_score")),
        ("masking_relaxation_score", payload.get("masking_relaxation_score")),
        ("impact_radius_upper_score", payload.get("impact_radius_upper_score")),
        ("policy_risk_score", payload.get("policy_risk_score")),
        ("simulation_confidence_score", payload.get("simulation_confidence_score")),
        ("predictability_score", payload.get("predictability_score")),
    )
    if any(not isinstance(value, int) for _, value in checks):
        return None
    return int(
        payload["privilege_gain_score"] == 0
        and payload["scope_expansion_score"] == 0
        and payload["masking_relaxation_score"] == 0
        and payload["impact_radius_upper_score"] < 5
        and payload["policy_risk_score"] < 15
        and payload["simulation_confidence_score"] >= 90
        and payload["predictability_score"] >= 85
    )


def expected_governance_approval_requirement(payload: dict[str, Any]) -> str | None:
    approval_necessity_score = payload.get("approval_necessity_score")
    simulation_confidence_score = payload.get("simulation_confidence_score")
    bounded_safe_mutation = payload.get("bounded_safe_mutation")
    if not all(
        isinstance(value, int)
        for value in (
            approval_necessity_score,
            simulation_confidence_score,
            bounded_safe_mutation,
        )
    ):
        return None
    if bounded_safe_mutation == 1:
        return "NOT_REQUIRED"
    if approval_necessity_score >= 80:
        return "CHANGE_ADVISORY_QUORUM"
    if approval_necessity_score >= 55:
        return "SECURITY_REVIEW"
    if approval_necessity_score >= 30:
        return "DUAL_APPROVER"
    if approval_necessity_score >= 10 or simulation_confidence_score < 80:
        return "SINGLE_APPROVER"
    return "SINGLE_APPROVER"


