def expected_governance_commit_authority_posture(
    simulation_confidence_score: object,
    predictability_score: object,
    bounded_safe_mutation: object,
) -> str | None:
    if not isinstance(simulation_confidence_score, int) or not isinstance(predictability_score, int):
        return None
    if simulation_confidence_score < 80 or predictability_score < 75:
        return "PREVIEW_ONLY"
    if bounded_safe_mutation == 1:
        return "BOUNDED_SAFE"
    if bounded_safe_mutation == 0:
        return "APPROVAL_GATED"
    return None


def derive_governance_mutation_hazard_contract_hash(contract: dict[str, Any]) -> str | None:
    required_fields = {
        "contract_version": contract.get("contract_version"),
        "policy_snapshot_hash": contract.get("policy_snapshot_hash"),
        "access_binding_hash": contract.get("access_binding_hash"),
        "dependency_topology_hash": contract.get("dependency_topology_hash"),
        "simulation_basis_hash": contract.get("simulation_basis_hash"),
        "count_class_profile_code": contract.get("count_class_profile_code"),
        "commit_authority_posture": contract.get("commit_authority_posture"),
        "impact_radius_lower_score": contract.get("impact_radius_lower_score"),
        "impact_radius_upper_score": contract.get("impact_radius_upper_score"),
        "impacted_principal_count": contract.get("impacted_principal_count"),
        "impacted_principal_count_class": contract.get("impacted_principal_count_class"),
        "impacted_client_count": contract.get("impacted_client_count"),
        "impacted_client_count_class": contract.get("impacted_client_count_class"),
        "impacted_authority_operation_count": contract.get("impacted_authority_operation_count"),
        "impacted_authority_operation_count_class": contract.get("impacted_authority_operation_count_class"),
        "impacted_workflow_count": contract.get("impacted_workflow_count"),
        "impacted_workflow_count_class": contract.get("impacted_workflow_count_class"),
        "impacted_limitation_count": contract.get("impacted_limitation_count"),
        "impacted_limitation_count_class": contract.get("impacted_limitation_count_class"),
        "privilege_gain_score": contract.get("privilege_gain_score"),
        "scope_expansion_score": contract.get("scope_expansion_score"),
        "masking_relaxation_score": contract.get("masking_relaxation_score"),
        "policy_risk_score": contract.get("policy_risk_score"),
        "approval_necessity_score": contract.get("approval_necessity_score"),
        "approval_requirement": contract.get("approval_requirement"),
        "bounded_safe_mutation": contract.get("bounded_safe_mutation"),
        "required_approvals": contract.get("required_approvals"),
        "simulation_confidence_score": contract.get("simulation_confidence_score"),
        "predictability_score": contract.get("predictability_score"),
        "risk_driver_codes": contract.get("risk_driver_codes"),
        "approval_trigger_codes": contract.get("approval_trigger_codes"),
        "confidence_limiter_codes": contract.get("confidence_limiter_codes"),
        "bounded_safety_blocker_codes": contract.get("bounded_safety_blocker_codes"),
        "reason_codes": contract.get("reason_codes"),
    }
    string_fields = (
        "contract_version",
        "policy_snapshot_hash",
        "access_binding_hash",
        "dependency_topology_hash",
        "simulation_basis_hash",
        "count_class_profile_code",
        "commit_authority_posture",
        "impacted_principal_count_class",
        "impacted_client_count_class",
        "impacted_authority_operation_count_class",
        "impacted_workflow_count_class",
        "impacted_limitation_count_class",
        "approval_requirement",
    )
    for field in string_fields:
        value = required_fields[field]
        if not isinstance(value, str) or not value:
            return None
    int_fields = (
        "impact_radius_lower_score",
        "impact_radius_upper_score",
        "impacted_principal_count",
        "impacted_client_count",
        "impacted_authority_operation_count",
        "impacted_workflow_count",
        "impacted_limitation_count",
        "privilege_gain_score",
        "scope_expansion_score",
        "masking_relaxation_score",
        "policy_risk_score",
        "approval_necessity_score",
        "bounded_safe_mutation",
        "simulation_confidence_score",
        "predictability_score",
    )
    for field in int_fields:
        if not isinstance(required_fields[field], int):
            return None
    list_fields = (
        "required_approvals",
        "risk_driver_codes",
        "approval_trigger_codes",
        "confidence_limiter_codes",
        "bounded_safety_blocker_codes",
        "reason_codes",
    )
    canonical_lists: dict[str, list[str]] = {}
    for field in list_fields:
        values = required_fields[field]
        if not isinstance(values, list):
            return None
        canonical_values = [value for value in values if isinstance(value, str) and value]
        if len(canonical_values) != len(values):
            return None
        canonical_lists[field] = canonical_values

    canonical_payload = dict(required_fields)
    canonical_payload.update(canonical_lists)
    return stable_json_hash(canonical_payload)


def derive_governance_mutation_basis_contract_hash(contract: dict[str, Any]) -> str | None:
    required_fields = {
        "contract_version": contract.get("contract_version"),
        "policy_snapshot_hash": contract.get("policy_snapshot_hash"),
        "access_binding_hash": contract.get("access_binding_hash"),
        "dependency_topology_hash": contract.get("dependency_topology_hash"),
        "simulation_basis_hash": contract.get("simulation_basis_hash"),
        "hazard_contract_hash": contract.get("hazard_contract_hash"),
        "commit_authority_posture": contract.get("commit_authority_posture"),
        "approval_requirement": contract.get("approval_requirement"),
        "bounded_safe_mutation": contract.get("bounded_safe_mutation"),
        "required_approvals": contract.get("required_approvals"),
        "simulation_confidence_score": contract.get("simulation_confidence_score"),
        "predictability_score": contract.get("predictability_score"),
    }
    for field in (
        "contract_version",
        "policy_snapshot_hash",
        "access_binding_hash",
        "dependency_topology_hash",
        "simulation_basis_hash",
        "hazard_contract_hash",
        "commit_authority_posture",
        "approval_requirement",
    ):
        value = required_fields[field]
        if not isinstance(value, str) or not value:
            return None
    if required_fields["bounded_safe_mutation"] not in {0, 1}:
        return None
    if not isinstance(required_fields["required_approvals"], list):
        return None
    if not isinstance(required_fields["simulation_confidence_score"], int) or not isinstance(
        required_fields["predictability_score"], int
    ):
        return None
    canonical_required_approvals = [
        approval for approval in required_fields["required_approvals"] if isinstance(approval, str) and approval
    ]
    if len(canonical_required_approvals) != len(required_fields["required_approvals"]):
        return None
    canonical_payload = {
        "contract_version": required_fields["contract_version"],
        "policy_snapshot_hash": required_fields["policy_snapshot_hash"],
        "access_binding_hash": required_fields["access_binding_hash"],
        "dependency_topology_hash": required_fields["dependency_topology_hash"],
        "simulation_basis_hash": required_fields["simulation_basis_hash"],
        "hazard_contract_hash": required_fields["hazard_contract_hash"],
        "commit_authority_posture": required_fields["commit_authority_posture"],
        "approval_requirement": required_fields["approval_requirement"],
        "bounded_safe_mutation": required_fields["bounded_safe_mutation"],
        "required_approvals": canonical_required_approvals,
        "simulation_confidence_score": required_fields["simulation_confidence_score"],
        "predictability_score": required_fields["predictability_score"],
    }
    return stable_json_hash(canonical_payload)


def derive_twin_comparison_key(payload: dict) -> str | None:
    subject_class = payload.get("subject_class")
    subject_identity_code = payload.get("subject_identity_code")
    if not isinstance(subject_class, str) or not isinstance(subject_identity_code, str):
        return None
    canonical_components = [
        TWIN_COMPARISON_KEY_PROFILE,
        subject_class,
        normalized_optional_identity_value(payload.get("reporting_scope_ref_or_null")),
        normalized_optional_identity_value(payload.get("authority_scope_ref_or_null")),
        normalized_optional_identity_value(payload.get("business_partition_ref_or_null")),
        normalized_optional_identity_value(payload.get("period_ref_or_null")),
        normalized_optional_identity_value(payload.get("basis_type_or_null")),
        subject_identity_code,
        normalized_optional_identity_value(payload.get("lineage_anchor_ref_or_null")),
    ]
    return f"{TWIN_COMPARISON_KEY_PREFIX}{stable_json_hash(canonical_components)}"


def derive_twin_delta_comparability(payload: dict) -> tuple[str, str] | None:
    delta_class = payload.get("delta_class")
    if not isinstance(delta_class, str):
        return None
    contradiction_component_refs = payload.get("contradiction_component_refs", [])
    if not isinstance(contradiction_component_refs, list):
        contradiction_component_refs = []
    if delta_class == "ACK_PENDING":
        return ("WAITING_ON_AUTHORITY", "ACK_PENDING")
    if delta_class == "ACK_PARTIAL":
        return ("PARTIALLY_COMPARABLE", "ACK_PARTIAL")
    if delta_class in {
        "BASELINE_MISSING",
        "STALE_COMPARISON",
        "LIMITED_VISIBILITY",
        "REPLAY_NON_AUTHORITATIVE",
    }:
        return ("NON_COMPARABLE", delta_class)
    if delta_class == "OUT_OF_BAND":
        return ("OUT_OF_BAND", "OUT_OF_BAND")
    if delta_class == "ACK_CONTRADICTORY":
        return ("CONTRADICTORY", "ACK_CONTRADICTORY")
    if contradiction_component_refs:
        return ("CONTRADICTORY", "CONTRADICTION_COMPONENTS")
    return ("COMPARABLE", "NONE")


def twin_mismatch_ordering_key(entry: dict) -> tuple[int, float, str]:
    priority_rank = entry.get("priority_rank")
    if not isinstance(priority_rank, int):
        priority_rank = 0
    last_compared_at = parse_datetime(entry.get("last_compared_at"))
    timestamp = last_compared_at.timestamp() if last_compared_at is not None else float("-inf")
    comparison_key = entry.get("comparison_key")
    if not isinstance(comparison_key, str):
        comparison_key = ""
    return (-priority_rank, -timestamp, comparison_key)


def validate_proof_closure_contract(
    payload: object,
    location: str,
    path: str,
    *,
    support_state: object,
    closure_state: object,
    replayable: object,
    contradiction_refs: object,
    stale_reason_codes: object,
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must be present so proof closure is explicit and deterministic.",
            )
        )
        return issues, None

    if payload.get("closure_profile_code") != PROOF_CLOSURE_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.closure_profile_code must be `{PROOF_CLOSURE_PROFILE}`.",
            )
        )
    if payload.get("path_ranking_profile_code") != PROOF_PATH_SELECTION_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.path_ranking_profile_code must be `{PROOF_PATH_SELECTION_PROFILE}`.",
            )
        )

    failure_reason_codes = payload.get("closure_failure_reason_codes", [])
    if not isinstance(failure_reason_codes, list):
        failure_reason_codes = []

    if closure_state == "CLOSED":
        for field in (
            "support_closed",
            "authority_closed",
            "contradiction_isolated",
            "replay_closed",
            "current_decisive_anchor_present",
        ):
            if payload.get(field) is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field} must be true when `closure_state = CLOSED`.",
                    )
                )
        for field in ("silent_limitation_ambiguity_present", "staleness_invalidated"):
            if payload.get(field) is not False:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field} must be false when `closure_state = CLOSED`.",
                    )
                )
        if failure_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.closure_failure_reason_codes[] must be empty when `closure_state = CLOSED`.",
                )
            )

    if replayable is True and payload.get("replay_closed") is not True:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.replay_closed must be true when the enclosing artifact is replayable.",
            )
        )
    if replayable is False and closure_state == "CLOSED":
        issues.append(
            Issue(
                "custom",
                location,
                "Closed proof posture cannot remain non-replayable.",
            )
        )

    contradiction_ref_list = contradiction_refs if isinstance(contradiction_refs, list) else []
    stale_reason_list = stale_reason_codes if isinstance(stale_reason_codes, list) else []
    if contradiction_ref_list and payload.get("contradiction_isolated") is not False:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.contradiction_isolated must be false when contradiction refs are present.",
            )
        )
    if stale_reason_list and payload.get("staleness_invalidated") is not True:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.staleness_invalidated must be true when stale reason codes are present.",
            )
        )

    if support_state == "SUPPORTED":
        for field in (
            "support_closed",
            "authority_closed",
            "contradiction_isolated",
            "replay_closed",
            "current_decisive_anchor_present",
        ):
            if payload.get(field) is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field} must be true for `support_state = SUPPORTED`.",
                    )
                )
        if payload.get("silent_limitation_ambiguity_present") is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.silent_limitation_ambiguity_present must be false for `support_state = SUPPORTED`.",
                )
            )
    elif support_state == "PARTIALLY_SUPPORTED":
        for field in (
            "support_closed",
            "authority_closed",
            "contradiction_isolated",
            "replay_closed",
            "current_decisive_anchor_present",
        ):
            if payload.get(field) is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field} must be true for `support_state = PARTIALLY_SUPPORTED`.",
                    )
                )
        if payload.get("silent_limitation_ambiguity_present") is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.silent_limitation_ambiguity_present must be false for `support_state = PARTIALLY_SUPPORTED`; limitations may be explicit, not silent.",
                )
            )
    elif support_state == "UNSUPPORTED":
        if all(
            payload.get(field) is True
            for field in (
                "support_closed",
                "authority_closed",
                "contradiction_isolated",
                "replay_closed",
                "current_decisive_anchor_present",
            )
        ) and payload.get("silent_limitation_ambiguity_present") is False and payload.get(
            "staleness_invalidated"
        ) is False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path} must record at least one failed closure factor for `support_state = UNSUPPORTED`.",
                )
            )
    elif support_state == "CONTRADICTED":
        if payload.get("contradiction_isolated") is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.contradiction_isolated must be false for `support_state = CONTRADICTED`.",
                )
            )
    elif support_state == "STALE":
        if payload.get("staleness_invalidated") is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.staleness_invalidated must be true for `support_state = STALE`.",
                )
            )

    return issues, payload


def validate_late_data_temporal_contract(
    payload: object,
    location: str,
    path: str,
    *,
    discovered_at: object,
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must retain a structured late-data temporal contract.",
            )
        )
        return issues, None

    if payload.get("classification_profile_code") != LATE_DATA_TEMPORAL_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.classification_profile_code must be `{LATE_DATA_TEMPORAL_PROFILE}`.",
            )
        )
    if payload.get("replay_lineage_policy") != LATE_DATA_REPLAY_LINEAGE_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.replay_lineage_policy must be `{LATE_DATA_REPLAY_LINEAGE_POLICY}`.",
            )
        )

    reason_codes = payload.get("reason_codes", [])
    if not isinstance(reason_codes, list):
        reason_codes = []

    contract_discovered_at = parse_datetime(payload.get("t_discovered"))
    persisted_discovered_at = parse_datetime(discovered_at)
    if contract_discovered_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_discovered must stay a valid date-time.",
            )
        )
    if (
        contract_discovered_at is not None
        and persisted_discovered_at is not None
        and contract_discovered_at != persisted_discovered_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_discovered must mirror the enclosing persisted discovery timestamp.",
            )
        )

    cutoff_at = parse_datetime(payload.get("t_cutoff"))
    effective_at = parse_datetime(payload.get("t_effective_or_null"))
    visible_at = parse_datetime(payload.get("t_visible_or_null"))
    if cutoff_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_cutoff must stay a valid date-time.",
            )
        )
    if (
        cutoff_at is not None
        and contract_discovered_at is not None
        and contract_discovered_at < cutoff_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_discovered must not precede {path}.t_cutoff.",
            )
        )
    if (
        effective_at is not None
        and contract_discovered_at is not None
        and effective_at > contract_discovered_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_effective_or_null must not be later than {path}.t_discovered.",
            )
        )
    if (
        visible_at is not None
        and contract_discovered_at is not None
        and visible_at > contract_discovered_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_visible_or_null must not be later than {path}.t_discovered.",
            )
        )
    if effective_at is not None and visible_at is not None and visible_at < effective_at:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_visible_or_null must not be earlier than {path}.t_effective_or_null.",
            )
        )

    temporal_classification = payload.get("temporal_classification")
    temporal_certainty_state = payload.get("temporal_certainty_state")
    legal_effect_basis = payload.get("legal_effect_basis")
    baseline_scope_class = payload.get("baseline_scope_class")
    filing_critical_baseline_touch = payload.get("filing_critical_baseline_touch")
    retroactive_impact_required = payload.get("retroactive_impact_required")
    trust_invalidation_required = payload.get("trust_invalidation_required")
    proof_staleness_required = payload.get("proof_staleness_required")
    amendment_reuse_invalidated = payload.get("amendment_reuse_invalidated")

    if temporal_classification == "TEMPORALLY_UNPROVED":
        if temporal_certainty_state != "UNPROVED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.temporal_certainty_state must be `UNPROVED` for temporally unproved late data.",
                )
            )
        if legal_effect_basis != "UNKNOWN":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.legal_effect_basis must be `UNKNOWN` for temporally unproved late data.",
                )
            )
        for field_name, field_value in (
            ("trust_invalidation_required", trust_invalidation_required),
            ("proof_staleness_required", proof_staleness_required),
            ("amendment_reuse_invalidated", amendment_reuse_invalidated),
        ):
            if field_value is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field_name} must be true for temporally unproved late data.",
                    )
                )
        if not reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.reason_codes[] must stay non-empty for temporally unproved late data.",
                )
            )
    else:
        if temporal_certainty_state != "PROVED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.temporal_certainty_state must be `PROVED` for classified late data.",
                )
            )

    if temporal_classification == "AUTHORITY_POSTING_LAG" and legal_effect_basis != "AUTHORITY_PUBLICATION_TIME":
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.legal_effect_basis must be `AUTHORITY_PUBLICATION_TIME` for authority posting lag.",
            )
        )

    if (
        temporal_classification == "TRUE_POST_BASELINE_EVENT"
        and effective_at is not None
        and cutoff_at is not None
        and effective_at <= cutoff_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_effective_or_null must be later than {path}.t_cutoff for `TRUE_POST_BASELINE_EVENT`.",
            )
        )

    if (
        temporal_classification
        in {
            "AUTHORITY_POSTING_LAG",
            "PRE_CUTOFF_PREEXISTING_LATE_ARRIVAL",
            "POST_CUTOFF_DISCOVERY_PRE_BASELINE_FACT",
        }
        and effective_at is not None
        and cutoff_at is not None
        and effective_at > cutoff_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.t_effective_or_null must not be later than {path}.t_cutoff for the persisted pre-baseline classes.",
            )
        )

    if baseline_scope_class == "PRIOR_SUBMISSION_CHAIN" and retroactive_impact_required is not True:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.retroactive_impact_required must be true when prior submission lineage is touched.",
            )
        )
    if retroactive_impact_required is True and baseline_scope_class == "NONE":
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.baseline_scope_class must not be `NONE` when retroactive impact is required.",
            )
        )
    if filing_critical_baseline_touch is True:
        if baseline_scope_class not in {"CURRENT_SCOPE", "PRIOR_SUBMISSION_CHAIN"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.baseline_scope_class must name a touched scope when filing-critical baseline touch is true.",
                )
            )
        for field_name, field_value in (
            ("trust_invalidation_required", trust_invalidation_required),
            ("proof_staleness_required", proof_staleness_required),
            ("amendment_reuse_invalidated", amendment_reuse_invalidated),
        ):
            if field_value is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field_name} must be true when filing-critical baseline touch is true.",
                    )
                )

    return issues, payload


def validate_late_data_consequence_summary(
    payload: object,
    location: str,
    path: str,
    *,
    total_finding_count: object,
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must retain a structured late-data consequence summary.",
            )
        )
        return issues, None

    if payload.get("summary_profile_code") != LATE_DATA_SUMMARY_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.summary_profile_code must be `{LATE_DATA_SUMMARY_PROFILE}`.",
            )
        )
    if payload.get("replay_lineage_policy") != LATE_DATA_REPLAY_LINEAGE_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.replay_lineage_policy must be `{LATE_DATA_REPLAY_LINEAGE_POLICY}`.",
            )
        )

    count_fields = (
        "true_post_baseline_event_count",
        "pre_cutoff_preexisting_late_arrival_count",
        "post_cutoff_discovery_pre_baseline_fact_count",
        "authority_posting_lag_count",
        "temporally_unproved_count",
    )
    summary_total = 0
    for field_name in count_fields:
        value = payload.get(field_name)
        if not is_non_negative_int(value):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.{field_name} must stay a non-negative integer.",
                )
            )
            continue
        summary_total += int(value)

    if is_non_negative_int(total_finding_count) and summary_total != total_finding_count:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} classification counts must sum to `total_finding_count` ({total_finding_count}).",
            )
        )

    highest_legal_consequence = payload.get("highest_legal_consequence")
    retroactive_impact_required = payload.get("retroactive_impact_required")
    trust_invalidation_required = payload.get("trust_invalidation_required")
    proof_staleness_required = payload.get("proof_staleness_required")
    amendment_reuse_invalidated = payload.get("amendment_reuse_invalidated")
    blocking_temporal_uncertainty_present = payload.get("blocking_temporal_uncertainty_present")
    temporally_unproved_count = payload.get("temporally_unproved_count")
    reason_codes = payload.get("reason_codes", [])
    if not isinstance(reason_codes, list):
        reason_codes = []

    if summary_total == 0:
        if highest_legal_consequence != "NONE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.highest_legal_consequence must be `NONE` when no late-data findings remain.",
                )
            )
        for field_name, field_value in (
            ("retroactive_impact_required", retroactive_impact_required),
            ("trust_invalidation_required", trust_invalidation_required),
            ("proof_staleness_required", proof_staleness_required),
            ("amendment_reuse_invalidated", amendment_reuse_invalidated),
            ("blocking_temporal_uncertainty_present", blocking_temporal_uncertainty_present),
        ):
            if field_value is not False:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field_name} must be false when no late-data findings remain.",
                    )
                )
        if reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.reason_codes[] must be empty when no late-data findings remain.",
                )
            )
    if is_non_negative_int(temporally_unproved_count) and temporally_unproved_count > 0:
        if blocking_temporal_uncertainty_present is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.blocking_temporal_uncertainty_present must be true when temporally unproved findings remain.",
                )
            )
        if highest_legal_consequence != "TEMPORAL_UNCERTAINTY_BLOCK":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{path}.highest_legal_consequence must be `TEMPORAL_UNCERTAINTY_BLOCK` when temporally unproved findings remain.",
                )
            )
        for field_name, field_value in (
            ("trust_invalidation_required", trust_invalidation_required),
            ("proof_staleness_required", proof_staleness_required),
            ("amendment_reuse_invalidated", amendment_reuse_invalidated),
        ):
            if field_value is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{path}.{field_name} must be true when temporally unproved findings remain.",
                    )
                )
    if retroactive_impact_required is True and highest_legal_consequence not in {
        "RETROACTIVE_IMPACT_REVIEW",
        "TEMPORAL_UNCERTAINTY_BLOCK",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.highest_legal_consequence must encode retroactive impact when retroactive review is required.",
            )
        )
    if (
        any(
            field_value is True
            for field_value in (
                retroactive_impact_required,
                trust_invalidation_required,
                proof_staleness_required,
                amendment_reuse_invalidated,
                blocking_temporal_uncertainty_present,
            )
        )
        and not reason_codes
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path}.reason_codes[] must stay non-empty when downstream legal consequence is non-benign.",
            )
        )

    return issues, payload


def validate_temporal_propagation_event_refs(
    values: object,
    location: str,
    field_label: str,
) -> tuple[list[Issue], list[str]]:
    issues: list[Issue] = []
    normalized: list[str] = []
    if not isinstance(values, list):
        return issues, normalized
    issues.extend(validate_sorted_string_sequence(values, location, f"{field_label}[]"))
    normalized = [value for value in values if isinstance(value, str)]
    duplicates = duplicate_values(normalized)
    if duplicates:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}[] must stay unique; duplicates {duplicates}.",
            )
        )
    return issues, normalized


def validate_temporal_propagation_event(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    for field in (
        "affected_scope_refs",
        "affected_submission_refs",
        "source_late_data_finding_refs",
        "source_authority_basis_refs",
        "reason_codes",
    ):
        issues.extend(validate_sorted_string_sequence(payload.get(field), location, f"`{field}[]`"))

    if payload.get("historical_reuse_policy") != "NO_FRESH_RECLASSIFICATION":
        issues.append(
            Issue(
                "custom",
                location,
                "`historical_reuse_policy` must stay `NO_FRESH_RECLASSIFICATION`.",
            )
        )

    event_class = payload.get("event_class")
    trust_effect = payload.get("trust_effect")
    proof_effect = payload.get("proof_effect")
    baseline_effect = payload.get("baseline_effect")
    retroactive_effect = payload.get("retroactive_effect")
    amendment_effect = payload.get("amendment_effect")
    replay_effect = payload.get("replay_effect")
    mirror_reopen_effect = payload.get("mirror_reopen_effect")
    affected_submission_refs = payload.get("affected_submission_refs", [])
    reason_codes = payload.get("reason_codes", [])

    if not isinstance(reason_codes, list) or not reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`reason_codes[]` must stay non-empty so temporal propagation remains durable and attributable.",
            )
        )

    if retroactive_effect == "ANALYSIS_REQUIRED" and (not isinstance(affected_submission_refs, list) or not affected_submission_refs):
        issues.append(
            Issue(
                "custom",
                location,
                "`affected_submission_refs[]` must stay non-empty when `retroactive_effect = ANALYSIS_REQUIRED`.",
            )
        )

    if event_class == "LATE_DATA_INVALIDATION":
        if amendment_effect not in {"INVALIDATE_READINESS_REUSE", "RECONCILE_FIRST"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`LATE_DATA_INVALIDATION` must invalidate amendment reuse or force reconcile-first posture.",
                )
            )
    elif event_class == "AUTHORITY_CORRECTION":
        if trust_effect != "RECALC_REQUIRED" or proof_effect != "STALE_REVALIDATION_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTHORITY_CORRECTION` must invalidate trust and proof posture across the affected lineage.",
                )
            )
        if amendment_effect not in {"INVALIDATE_READINESS_REUSE", "RECONCILE_FIRST"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTHORITY_CORRECTION` must invalidate amendment reuse or force reconcile-first posture.",
                )
            )
    elif event_class == "OUT_OF_BAND_DISCOVERY":
        if trust_effect != "RECALC_REQUIRED" or proof_effect != "STALE_REVALIDATION_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`OUT_OF_BAND_DISCOVERY` must invalidate trust and proof posture before the new truth can be reused.",
                )
            )
        if baseline_effect != "SCOPE_SLICED_REBUILD_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`OUT_OF_BAND_DISCOVERY` must force `baseline_effect = SCOPE_SLICED_REBUILD_REQUIRED`.",
                )
            )
        if amendment_effect != "RECONCILE_FIRST":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`OUT_OF_BAND_DISCOVERY` must force `amendment_effect = RECONCILE_FIRST`.",
                )
            )
        if replay_effect != "HISTORICAL_EVENT_REQUIRED" or mirror_reopen_effect != "REOPEN_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`OUT_OF_BAND_DISCOVERY` must require historical event reuse and mirror reopen.",
                )
            )
    elif event_class == "TEMPORAL_UNCERTAINTY_BLOCK":
        if amendment_effect != "RECONCILE_FIRST":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`TEMPORAL_UNCERTAINTY_BLOCK` must force `amendment_effect = RECONCILE_FIRST`.",
                )
            )
        if replay_effect != "LIMITED_COMPARISON_ONLY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`TEMPORAL_UNCERTAINTY_BLOCK` must force `replay_effect = LIMITED_COMPARISON_ONLY`.",
                )
            )
    return issues


def validate_rejected_path_entries(
    entries: object,
    rejected_path_refs: object,
    primary_path_ref: object,
    location: str,
    path: str,
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(entries, list):
        entries = []
    if not isinstance(rejected_path_refs, list):
        rejected_path_refs = []

    entry_path_refs = [
        entry.get("path_ref")
        for entry in entries
        if isinstance(entry, dict) and isinstance(entry.get("path_ref"), str)
    ]
    if rejected_path_refs != entry_path_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must exactly mirror `rejected_path_refs[]` in recorded order.",
            )
        )

    if isinstance(primary_path_ref, str) and primary_path_ref in entry_path_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must not include `primary_path_ref`.",
            )
        )

    duplicate_entry_refs = duplicate_values(entry_path_refs)
    if duplicate_entry_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must not duplicate path refs; duplicates {duplicate_entry_refs}.",
            )
        )

    path_ranks = [
        entry.get("path_rank")
        for entry in entries
        if isinstance(entry, dict) and isinstance(entry.get("path_rank"), int)
    ]
    if path_ranks and path_ranks != list(range(2, 2 + len(path_ranks))):
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} path ranks must form a contiguous sequence starting at 2.",
            )
        )

    expected_order = sorted(
        [entry for entry in entries if isinstance(entry, dict)],
        key=lambda entry: (entry.get("path_rank", 0), entry.get("path_ref", "")),
    )
    if [entry for entry in entries if isinstance(entry, dict)] != expected_order:
        issues.append(
            Issue(
                "custom",
                location,
                f"{path} must be ordered by `path_rank asc`, then `path_ref asc`.",
            )
        )

    return issues


def stable_query_string(query_params: dict[str, object]) -> str:
    pairs: list[str] = []
    for key in sorted(query_params):
        raw_value = query_params[key]
        if isinstance(raw_value, list):
            values = raw_value
        else:
            values = [raw_value]
        encoded_key = quote(str(key), safe="-._~")
        for value in values:
            pairs.append(f"{encoded_key}={quote(str(value), safe='-._~')}")
    return "&".join(pairs)


def stable_path(resource_template: object, resolved_path_params: object) -> str | None:
    if not isinstance(resource_template, str) or not resource_template:
        return None
    if not isinstance(resolved_path_params, dict):
        return None

    missing_keys: list[str] = []

    def replace(match: re.Match[str]) -> str:
        key = match.group(1)
        value = resolved_path_params.get(key)
        if not isinstance(value, str) or not value:
            missing_keys.append(key)
            return match.group(0)
        return quote(value, safe="-._~")

    canonical_path = PATH_TEMPLATE_PARAM_PATTERN.sub(replace, resource_template)
    if missing_keys or "{" in canonical_path or "}" in canonical_path:
        return None
    return canonical_path


def normalized_optional_identity_value(value: object) -> str:
    if isinstance(value, str) and value:
        return value
    return NONE_SENTINEL


def normalized_string_sequence(values: object) -> list[str]:
    if not isinstance(values, list) or not values:
        return [NONE_SENTINEL]
    return list(values)


def derive_authority_identity_namespace_hash(payload: dict) -> str:
    return stable_json_hash(
        {
            "identity_profile_version": AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION,
            "authority_name": payload.get("authority_name"),
            "authority_product_profile": payload.get("authority_product_profile"),
            "provider_environment": payload.get("provider_environment"),
            "authority_scope": payload.get("authority_scope"),
            "operation_family": payload.get("operation_family"),
            "operation_profile": payload.get("operation_profile"),
            "provider_api_version": payload.get("provider_api_version"),
            "binding_lineage_ref": payload.get("binding_lineage_ref"),
        }
    )


def derive_authority_duplicate_meaning_key(
    payload: dict,
    canonical_path: str,
    canonical_query: str,
    normalized_obligation_ref: str,
    normalized_basis_type: str,
) -> str:
    return stable_json_hash(
        {
            "identity_profile_version": AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION,
            "identity_namespace_hash": derive_authority_identity_namespace_hash(payload),
            "tenant_id": payload.get("tenant_id"),
            "client_id": payload.get("client_id"),
            "attempt_lineage_manifest_id": payload.get("attempt_lineage_manifest_id"),
            "business_partition_refs": normalized_string_sequence(payload.get("business_partition_refs")),
            "normalized_obligation_ref": normalized_obligation_ref,
            "normalized_basis_type": normalized_basis_type,
            "http_method": payload.get("http_method"),
            "canonical_path": canonical_path,
            "canonical_query": canonical_query,
            "request_body_hash": payload.get("request_body_hash"),
            "access_binding_hash": payload.get("access_binding_hash"),
        }
    )


def derive_authority_request_hash(
    payload: dict,
    duplicate_meaning_key: str,
) -> str:
    return stable_json_hash(
        {
            "identity_profile_version": AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION,
            "identity_namespace_hash": derive_authority_identity_namespace_hash(payload),
            "duplicate_meaning_key": duplicate_meaning_key,
            "header_profile_refs": payload.get("header_profile_refs"),
            "token_binding_ref": payload.get("token_binding_ref"),
            "authority_binding_ref": payload.get("authority_binding_ref"),
            "authority_link_ref": payload.get("authority_link_ref"),
            "delegation_grant_ref": normalized_optional_identity_value(payload.get("delegation_grant_ref")),
            "subject_ref": payload.get("subject_ref"),
            "acting_party_ref": payload.get("acting_party_ref"),
            "policy_snapshot_hash": payload.get("policy_snapshot_hash"),
        }
    )


def derive_authority_idempotency_key(duplicate_meaning_key: str) -> str:
    return stable_json_hash(
        {
            "identity_profile_version": AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION,
            "duplicate_meaning_key": duplicate_meaning_key,
        }
    )


def validate_authority_request_identity_contract(
    payload: object,
    location: str,
    field_path: str,
    *,
    expected_binding_scope_class: str,
) -> tuple[list[Issue], dict | None]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must be present as an object so request identity never has to be reconstructed from adjacent artifacts.",
            )
        )
        return issues, None

    if payload.get("contract_version") != AUTHORITY_REQUEST_IDENTITY_CONTRACT_VERSION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.contract_version must remain `{AUTHORITY_REQUEST_IDENTITY_CONTRACT_VERSION}`.",
            )
        )
    if payload.get("binding_scope_class") != expected_binding_scope_class:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.binding_scope_class must equal `{expected_binding_scope_class}`.",
            )
        )
    issues.extend(validate_sorted_string_sequence(payload.get("header_profile_refs"), location, f"{field_path}.header_profile_refs[]"))
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("business_partition_refs"),
            location,
            f"{field_path}.business_partition_refs[]",
        )
    )
    for field in (
        "request_id",
        "tenant_id",
        "client_id",
        "manifest_id",
        "manifest_hash",
        "execution_basis_hash",
        "attempt_lineage_manifest_id",
        "operation_id",
        "authority_name",
        "authority_product_profile",
        "provider_environment",
        "authority_scope",
        "operation_family",
        "operation_profile",
        "provider_api_version",
        "http_method",
        "canonical_path",
        "identity_namespace_hash",
        "normalized_obligation_ref",
        "normalized_basis_type",
        "request_body_hash",
        "duplicate_meaning_key",
        "request_hash",
        "idempotency_key",
        "access_binding_hash",
        "policy_snapshot_hash",
        "authority_binding_ref",
        "authority_link_ref",
        "subject_ref",
        "acting_party_ref",
        "token_binding_ref",
        "binding_lineage_ref",
    ):
        if not isinstance(payload.get(field), str) or not payload.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.{field} must be a non-empty persisted request identity field.",
                )
            )
    if not isinstance(payload.get("canonical_query"), str):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.canonical_query must remain a persisted string, even when empty.",
            )
        )
    for field in ("delegation_grant_ref_or_null", "obligation_ref_or_null", "basis_type_or_null"):
        value = payload.get(field)
        if value is not None and (not isinstance(value, str) or not value):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.{field} must be null or a non-empty string.",
                )
            )
    if payload.get("identity_profile_version") != AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.identity_profile_version must remain `{AUTHORITY_REQUEST_IDENTITY_PROFILE_VERSION}`.",
            )
        )
    return issues, payload


def validate_authority_ingress_proof_contract_payload(payload: object, location: str) -> list[Issue]:
    issues, _ = validate_authority_ingress_proof_contract(
        payload,
        location,
        "`authority_ingress_proof_contract`",
        require_non_null=True,
    )
    return issues


def validate_authority_ingress_proof_contract(
    payload: object,
    location: str,
    field_path: str,
    *,
    require_non_null: bool,
    expected_binding_scope_class: object = CACHE_ISOLATION_UNSET,
    expected_ingress_channel_class_or_null: object = CACHE_ISOLATION_UNSET,
    expected_authenticated_channel_state: object = CACHE_ISOLATION_UNSET,
    expected_provider_delivery_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_response_body_hash_or_null: object = CACHE_ISOLATION_UNSET,
    expected_ingress_channel_metadata_hash_or_null: object = CACHE_ISOLATION_UNSET,
    expected_delivery_dedupe_key_or_null: object = CACHE_ISOLATION_UNSET,
    expected_correlation_status_or_null: object = CACHE_ISOLATION_UNSET,
    expected_canonical_ingress_receipt_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_bound_interaction_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_authority_reference_or_null: object = CACHE_ISOLATION_UNSET,
    expected_request_hash_or_null: object = CACHE_ISOLATION_UNSET,
    expected_idempotency_key_or_null: object = CACHE_ISOLATION_UNSET,
    expected_identity_namespace_hash_or_null: object = CACHE_ISOLATION_UNSET,
    expected_duplicate_meaning_key_or_null: object = CACHE_ISOLATION_UNSET,
    expected_mutation_gate_state: object = CACHE_ISOLATION_UNSET,
    expected_normalized_response_ref_or_null: object = CACHE_ISOLATION_UNSET,
) -> tuple[list[Issue], dict | None]:
    issues: list[Issue] = []
    if payload is None:
        if require_non_null:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path} must be present as an object so ingress authentication and request-lineage proof never have to be inferred from adjacent artifacts.",
                )
            )
        return issues, None
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must be null or an object.",
            )
        )
        return issues, None

    if payload.get("contract_version") != AUTHORITY_INGRESS_PROOF_CONTRACT_VERSION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.contract_version must remain `{AUTHORITY_INGRESS_PROOF_CONTRACT_VERSION}`.",
            )
        )
    if (
        expected_binding_scope_class is not CACHE_ISOLATION_UNSET
        and payload.get("binding_scope_class") != expected_binding_scope_class
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.binding_scope_class must equal `{expected_binding_scope_class}`.",
            )
        )

    issues.extend(
        validate_sorted_string_sequence(
            payload.get("authentication_evidence_modes"),
            location,
            f"{field_path}.authentication_evidence_modes[]",
        )
    )
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("authentication_evidence_refs"),
            location,
            f"{field_path}.authentication_evidence_refs[]",
        )
    )

    authenticated_channel_state = payload.get("authenticated_channel_state")
    ingress_channel_class = payload.get("ingress_channel_class_or_null")
    correlation_status = payload.get("correlation_status_or_null")
    lineage_binding_basis = payload.get("lineage_binding_basis")
    mutation_gate_state = payload.get("mutation_gate_state")
    normalized_response_ref = payload.get("normalized_response_ref_or_null")
    canonical_ingress_receipt_ref = payload.get("canonical_ingress_receipt_ref_or_null")
    bound_interaction_ref = payload.get("bound_interaction_ref_or_null")
    authority_reference = payload.get("authority_reference_or_null")
    request_hash = payload.get("request_hash_or_null")
    idempotency_key = payload.get("idempotency_key_or_null")
    identity_namespace_hash = payload.get("identity_namespace_hash_or_null")
    duplicate_meaning_key = payload.get("duplicate_meaning_key_or_null")
    request_lineage_proof_hash = payload.get("request_lineage_proof_hash_or_null")
    authentication_evidence_modes = (
        payload.get("authentication_evidence_modes")
        if isinstance(payload.get("authentication_evidence_modes"), list)
        else []
    )
    authentication_evidence_mode_set = {
        mode for mode in authentication_evidence_modes if isinstance(mode, str)
    }
    authentication_evidence_refs = (
        payload.get("authentication_evidence_refs")
        if isinstance(payload.get("authentication_evidence_refs"), list)
        else []
    )

    if payload.get("delivery_identity_basis") != "PROVIDER_DELIVERY_REF_RESPONSE_BODY_HASH_INGRESS_CHANNEL_METADATA_HASH":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.delivery_identity_basis must remain `PROVIDER_DELIVERY_REF_RESPONSE_BODY_HASH_INGRESS_CHANNEL_METADATA_HASH`.",
            )
        )
    if payload.get("heuristic_correlation_policy") != "DETERMINISTIC_ONLY_NO_RECENT_REQUEST_HEURISTICS":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.heuristic_correlation_policy must remain `DETERMINISTIC_ONLY_NO_RECENT_REQUEST_HEURISTICS`.",
            )
        )
    if payload.get("transport_memory_mutation_policy") != "FORBIDDEN_UNTIL_PERSISTED_PROOF":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.transport_memory_mutation_policy must remain `FORBIDDEN_UNTIL_PERSISTED_PROOF`.",
            )
        )

    if authenticated_channel_state == "NOT_APPLICABLE":
        if authentication_evidence_mode_set:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authentication_evidence_modes[] must stay empty when `authenticated_channel_state = NOT_APPLICABLE`.",
                )
            )
        if authentication_evidence_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authentication_evidence_refs[] must stay empty when `authenticated_channel_state = NOT_APPLICABLE`.",
                )
            )
        if any(
            payload.get(field) is not None
            for field in (
                "ingress_channel_class_or_null",
                "provider_delivery_ref_or_null",
                "response_body_hash_or_null",
                "ingress_channel_metadata_hash_or_null",
                "delivery_dedupe_key_or_null",
                "correlation_status_or_null",
                "canonical_ingress_receipt_ref_or_null",
                "bound_interaction_ref_or_null",
                "authority_reference_or_null",
                "request_hash_or_null",
                "idempotency_key_or_null",
                "identity_namespace_hash_or_null",
                "duplicate_meaning_key_or_null",
                "request_lineage_proof_hash_or_null",
                "normalized_response_ref_or_null",
            )
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path} must clear ingress and lineage fields when `authenticated_channel_state = NOT_APPLICABLE`.",
                )
            )
        if lineage_binding_basis != "NOT_APPLICABLE" or mutation_gate_state != "NOT_APPLICABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path} must keep `lineage_binding_basis = NOT_APPLICABLE` and `mutation_gate_state = NOT_APPLICABLE` when no ingress proof applies.",
                )
            )
    else:
        for field in (
            "ingress_channel_class_or_null",
            "provider_delivery_ref_or_null",
            "response_body_hash_or_null",
            "ingress_channel_metadata_hash_or_null",
            "delivery_dedupe_key_or_null",
            "canonical_ingress_receipt_ref_or_null",
        ):
            value = payload.get(field)
            if not isinstance(value, str) or not value:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_path}.{field} must be a non-empty string for authenticated or failed ingress proof.",
                    )
                )
        if not authentication_evidence_mode_set:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authentication_evidence_modes[] must retain one or more channel-auth evidence modes.",
                )
            )
        if not authentication_evidence_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authentication_evidence_refs[] must retain one or more concrete auth-evidence refs.",
                )
            )
        if ingress_channel_class == "CALLBACK":
            if not (authentication_evidence_mode_set & AUTHORITY_INGRESS_CALLBACK_AUTH_EVIDENCE_MODES):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_path}.authentication_evidence_modes[] must prove callback auth via signature, mTLS, allowlist, or equivalent frozen callback evidence.",
                    )
                )
        required_modes = AUTHORITY_INGRESS_REQUIRED_AUTH_EVIDENCE_BY_CHANNEL.get(ingress_channel_class)
        if required_modes is not None and not required_modes.issubset(authentication_evidence_mode_set):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authentication_evidence_modes[] must include {sorted(required_modes)} for `{ingress_channel_class}` ingress.",
                )
            )

    if correlation_status == "BOUND":
        if lineage_binding_basis not in AUTHORITY_INGRESS_BOUND_LINEAGE_BASES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.lineage_binding_basis must retain an exact request-lineage basis when `correlation_status_or_null = BOUND`.",
                )
            )
        for field_name, field_value in (
            ("bound_interaction_ref_or_null", bound_interaction_ref),
            ("authority_reference_or_null", authority_reference),
            ("request_hash_or_null", request_hash),
            ("idempotency_key_or_null", idempotency_key),
            ("identity_namespace_hash_or_null", identity_namespace_hash),
            ("duplicate_meaning_key_or_null", duplicate_meaning_key),
            ("request_lineage_proof_hash_or_null", request_lineage_proof_hash),
        ):
            if not isinstance(field_value, str) or not field_value:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_path}.{field_name} must be non-empty when `correlation_status_or_null = BOUND`.",
                    )
                )
    if correlation_status == "BOUND_WITH_AUTHORITY_REFERENCE_ONLY":
        if lineage_binding_basis != "AUTHORITY_REFERENCE_ONLY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.lineage_binding_basis must remain `AUTHORITY_REFERENCE_ONLY` for weak authority-reference-only binds.",
                )
            )
        if not isinstance(authority_reference, str) or not authority_reference:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.authority_reference_or_null must be non-empty when `correlation_status_or_null = BOUND_WITH_AUTHORITY_REFERENCE_ONLY`.",
                )
            )
        for field_name, field_value in (
            ("bound_interaction_ref_or_null", bound_interaction_ref),
            ("request_hash_or_null", request_hash),
            ("idempotency_key_or_null", idempotency_key),
            ("identity_namespace_hash_or_null", identity_namespace_hash),
            ("duplicate_meaning_key_or_null", duplicate_meaning_key),
            ("request_lineage_proof_hash_or_null", request_lineage_proof_hash),
        ):
            if field_value is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_path}.{field_name} must stay null for weak authority-reference-only binds.",
                    )
                )
    if correlation_status == "AMBIGUOUS" and lineage_binding_basis != "AMBIGUOUS_MULTI_MATCH":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.lineage_binding_basis must remain `AMBIGUOUS_MULTI_MATCH` when `correlation_status_or_null = AMBIGUOUS`.",
            )
        )
    if correlation_status == "UNBOUND" and lineage_binding_basis != "UNBOUND_NO_MATCH":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.lineage_binding_basis must remain `UNBOUND_NO_MATCH` when `correlation_status_or_null = UNBOUND`.",
            )
        )

    if mutation_gate_state == "STATE_MUTATION_ATTRIBUTED_TO_PERSISTED_RECEIPT":
        if authenticated_channel_state != "AUTHENTICATED" or correlation_status != "BOUND":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path} state mutation may be attributed to persisted ingress only after authenticated, exact-bound lineage proof.",
                )
            )
        if not isinstance(normalized_response_ref, str) or not normalized_response_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.normalized_response_ref_or_null must be non-empty when `mutation_gate_state = STATE_MUTATION_ATTRIBUTED_TO_PERSISTED_RECEIPT`.",
                )
            )
    if mutation_gate_state in {"QUARANTINE_ONLY", "DUPLICATE_SUPPRESSED_NO_MUTATION"} and normalized_response_ref is not None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.normalized_response_ref_or_null must stay null when `mutation_gate_state` forbids state mutation.",
            )
        )

    for field_name, expected_value in (
        ("binding_scope_class", expected_binding_scope_class),
        ("ingress_channel_class_or_null", expected_ingress_channel_class_or_null),
        ("authenticated_channel_state", expected_authenticated_channel_state),
        ("provider_delivery_ref_or_null", expected_provider_delivery_ref_or_null),
        ("response_body_hash_or_null", expected_response_body_hash_or_null),
        ("ingress_channel_metadata_hash_or_null", expected_ingress_channel_metadata_hash_or_null),
        ("delivery_dedupe_key_or_null", expected_delivery_dedupe_key_or_null),
        ("correlation_status_or_null", expected_correlation_status_or_null),
        ("canonical_ingress_receipt_ref_or_null", expected_canonical_ingress_receipt_ref_or_null),
        ("bound_interaction_ref_or_null", expected_bound_interaction_ref_or_null),
        ("authority_reference_or_null", expected_authority_reference_or_null),
        ("request_hash_or_null", expected_request_hash_or_null),
        ("idempotency_key_or_null", expected_idempotency_key_or_null),
        ("identity_namespace_hash_or_null", expected_identity_namespace_hash_or_null),
        ("duplicate_meaning_key_or_null", expected_duplicate_meaning_key_or_null),
        ("mutation_gate_state", expected_mutation_gate_state),
        ("normalized_response_ref_or_null", expected_normalized_response_ref_or_null),
    ):
        if expected_value is CACHE_ISOLATION_UNSET:
            continue
        if payload.get(field_name) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_path}.{field_name} must mirror `{expected_value}`.",
                )
            )

    return issues, payload


def validate_manifest_output_refs(
    payload: object,
    location: str,
    field_path: str,
    *,
    manifest_id: object,
    decision_bundle_hash: object,
    replay_attestation_ref: object,
    submission_refs: list[str],
    drift_refs: list[str],
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        return issues
    if not isinstance(submission_refs, list):
        submission_refs = []
    if not isinstance(drift_refs, list):
        drift_refs = []

    seen_decision_bundle = False
    seen_replay_attestation = False
    seen_submission_refs: set[str] = set()
    seen_drift_refs: set[str] = set()

    for key, entry in payload.items():
        entry_path = f"{field_path}.{key}"
        if not isinstance(entry, dict):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{entry_path} must be a structured output-link entry, not a bare ref string.",
                )
            )
            continue
        if entry.get("produced_by_manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{entry_path}.produced_by_manifest_id must mirror `manifest_id`.",
                )
            )
        role = entry.get("linkage_role_code")
        artifact_ref = entry.get("artifact_ref")
        if role == "DECISION_BUNDLE":
            seen_decision_bundle = True
            if entry.get("artifact_hash_or_null") != decision_bundle_hash:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{entry_path}.artifact_hash_or_null must mirror `decision_bundle_hash` for `DECISION_BUNDLE` links.",
                    )
                )
            if not isinstance(artifact_ref, str) or not artifact_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{entry_path}.artifact_ref must remain non-empty for `DECISION_BUNDLE` links.",
                    )
                )
        elif role == "REPLAY_ATTESTATION":
            seen_replay_attestation = True
            if artifact_ref != replay_attestation_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{entry_path}.artifact_ref must mirror `replay_attestation_ref` for `REPLAY_ATTESTATION` links.",
                    )
                )
        elif role == "SUBMISSION_RECORD" and isinstance(artifact_ref, str):
            seen_submission_refs.add(artifact_ref)
            if artifact_ref not in submission_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{entry_path}.artifact_ref must stay within `submission_refs[]` for `SUBMISSION_RECORD` links.",
                    )
                )
        elif role == "DRIFT_RECORD" and isinstance(artifact_ref, str):
            seen_drift_refs.add(artifact_ref)
            if artifact_ref not in drift_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{entry_path}.artifact_ref must stay within `drift_refs[]` for `DRIFT_RECORD` links.",
                    )
                )

    if decision_bundle_hash is not None and not seen_decision_bundle:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must carry a `DECISION_BUNDLE` link whenever `decision_bundle_hash` is present.",
            )
        )
    if replay_attestation_ref is not None and not seen_replay_attestation:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must carry a `REPLAY_ATTESTATION` link whenever `replay_attestation_ref` is present.",
            )
        )
    missing_submission_links = [ref for ref in submission_refs if ref not in seen_submission_refs]
    if missing_submission_links:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must preserve structured `SUBMISSION_RECORD` links for every `submission_refs[]` member; missing {missing_submission_links}.",
            )
        )
    missing_drift_links = [ref for ref in drift_refs if ref not in seen_drift_refs]
    if missing_drift_links:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path} must preserve structured `DRIFT_RECORD` links for every `drift_refs[]` member; missing {missing_drift_links}.",
            )
        )
    return issues


