def expected_manifest_branch_reason_code(branch_action: object, run_kind: object) -> str | None:
    if branch_action == "NEW_MANIFEST":
        return "NO_PRIOR_MANIFEST"
    if branch_action == "RETURN_EXISTING_BUNDLE":
        return "TERMINAL_IDEMPOTENT_RETRY"
    if branch_action == "REUSE_SEALED_MANIFEST":
        return "PRESTART_SEALED_CONTEXT_REUSE"
    if branch_action == "REPLAY_CHILD":
        return "REPLAY_REQUESTED_EXACT"
    if branch_action == "RECOVERY_CHILD":
        return "STARTED_ATTEMPT_RECOVERY"
    if branch_action == "CONTINUATION_CHILD":
        return "NIGHTLY_WINDOW_ADVANCED" if run_kind == "NIGHTLY" else "POST_TERMINAL_CONTINUATION_REQUIRED"
    if branch_action == "NEW_REQUEST_CHILD":
        return "REQUEST_IDENTITY_CHANGED"
    return None
