AUTHORITY_TRUTH_CONFIRMING_TEXT_FRAGMENTS = {
    "confirmed": "confirmation language",
    "accepted": "acceptance language",
    "filed": "filed-complete language",
    "submission complete": "completion language",
    "fully received": "terminal acceptance language",
}


def authority_truth_confirming_text_markers(text: object) -> list[str]:
    if not isinstance(text, str) or not text:
        return []
    normalized = text.casefold()
    return [
        label
        for fragment, label in AUTHORITY_TRUTH_CONFIRMING_TEXT_FRAGMENTS.items()
        if fragment in normalized
    ]


