def validate_command_truth_boundary_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_artifact_role: str | None = None,
    expected_authoritative_record_families: list[str] | None = None,
    expected_observable_projection_families: list[str] | None = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a structured command-side truth boundary contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "COMMAND_TRUTH_BOUNDARY_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `COMMAND_TRUTH_BOUNDARY_V1`.",
            )
        )

    artifact_role = contract.get("artifact_role")
    if expected_artifact_role is not None and artifact_role != expected_artifact_role:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.artifact_role must stay `{expected_artifact_role}`.",
            )
        )

    expected_policies = COMMAND_TRUTH_BOUNDARY_POLICIES_BY_ROLE.get(artifact_role)
    if expected_policies is not None:
        for field, expected_value in expected_policies.items():
            if contract.get(field) != expected_value:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_name}.{field} must stay `{expected_value}` when `{field_name}.artifact_role = {artifact_role}`.",
                    )
                )

    for field_name_inner, expected_values in (
        ("authoritative_record_families", expected_authoritative_record_families),
        ("observable_projection_families", expected_observable_projection_families),
    ):
        raw_values = contract.get(field_name_inner)
        if not isinstance(raw_values, list):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field_name_inner} must remain an ordered unique string array.",
                )
            )
            continue
        normalized_values = [value for value in raw_values if isinstance(value, str) and value]
        if len(normalized_values) != len(raw_values):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field_name_inner} must contain only non-empty strings.",
                )
            )
        duplicate_values_in_field = duplicate_values(normalized_values)
        if duplicate_values_in_field:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field_name_inner} must stay unique; duplicates {duplicate_values_in_field}.",
                )
            )
        if expected_values is not None and normalized_values != expected_values:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field_name_inner} must stay {expected_values}.",
                )
            )

    return issues, contract


def validate_authority_layer_boundary_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_binding_scope_class: str | None = None,
    expected_integration_capability: str | None = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a structured authority-layer boundary contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "AUTHORITY_LAYER_BOUNDARY_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `AUTHORITY_LAYER_BOUNDARY_V1`.",
            )
        )

    binding_scope_class = contract.get("binding_scope_class")
    if expected_binding_scope_class is not None and binding_scope_class != expected_binding_scope_class:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.binding_scope_class must stay `{expected_binding_scope_class}`.",
            )
        )

    integration_capability = contract.get("integration_capability")
    if expected_integration_capability is not None and integration_capability != expected_integration_capability:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.integration_capability must stay `{expected_integration_capability}`.",
            )
        )

    for policy_field, expected_value in AUTHORITY_LAYER_BOUNDARY_POLICY_FIELDS.items():
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    for prohibited_field in (
        "service_human_gate_satisfaction_permitted",
        "exceptional_authority_may_substitute_for_delegation",
        "exceptional_authority_may_override_authority_truth",
        "exceptional_authority_may_widen_client_scope",
        "exceptional_authority_may_widen_partition_scope",
    ):
        if contract.get(prohibited_field) is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{prohibited_field} must stay `false`.",
                )
            )

    active_principal_class = contract.get("active_principal_class")
    client_delegation_state = contract.get("client_delegation_state")
    delegation_basis = contract.get("delegation_basis")
    delegation_freshness_state = contract.get("delegation_freshness_state")
    authority_link_state = contract.get("authority_link_state")
    exceptional_authority_state = contract.get("exceptional_authority_state")
    human_gate_requirement = contract.get("human_gate_requirement")
    human_gate_resolution_state = contract.get("human_gate_resolution_state")

    if human_gate_requirement == "NOT_REQUIRED" and human_gate_resolution_state != "NOT_REQUIRED":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.human_gate_resolution_state must stay `NOT_REQUIRED` when no human gate is required.",
            )
        )
    if human_gate_requirement != "NOT_REQUIRED" and human_gate_resolution_state not in {
        "PENDING_EVIDENCE",
        "EVIDENCE_FROZEN",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.human_gate_resolution_state must stay pending or frozen when a human gate is required.",
            )
        )
    if active_principal_class == "SERVICE" and human_gate_resolution_state == "EVIDENCE_FROZEN":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must not serialize a service principal as having satisfied a human-gated boundary.",
            )
        )

    if client_delegation_state == "NOT_REQUIRED" and delegation_basis not in {
        "SELF_ACTING",
        "TENANT_INTERNAL",
        "SYSTEM_ASSIGNED",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.delegation_basis must stay self/internal/system when client delegation is not required.",
            )
        )
    if client_delegation_state in {"SATISFIED", "LIMITED", "MISSING", "EXPIRED"} and delegation_basis not in {
        "CLIENT_GRANTED",
        "SELF_ASSESSMENT_IMPORTED",
        "DIGITAL_HANDSHAKE",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.delegation_basis must stay client-granted or imported when client delegation posture is explicit.",
            )
        )

    if delegation_basis in {"SELF_ASSESSMENT_IMPORTED", "DIGITAL_HANDSHAKE"}:
        if delegation_freshness_state not in {"CURRENT", "REVALIDATION_REQUIRED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.delegation_freshness_state must stay current or revalidation-required for imported or handshake delegation.",
                )
            )
    elif delegation_freshness_state != "NOT_APPLICABLE":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.delegation_freshness_state must stay `NOT_APPLICABLE` for non-imported delegation bases.",
            )
        )

    if integration_capability == "INTERNAL_ONLY":
        if client_delegation_state != "NOT_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.client_delegation_state must stay `NOT_REQUIRED` for internal-only posture.",
                )
            )
        if authority_link_state != "NOT_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.authority_link_state must stay `NOT_REQUIRED` for internal-only posture.",
                )
            )
    if integration_capability == "AUTHORITY_INTEGRATED" and authority_link_state == "NOT_REQUIRED":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.authority_link_state must stay explicit for authority-integrated posture.",
            )
        )

    if exceptional_authority_state == "BOUNDED_INTERNAL_EXCEPTION" and human_gate_resolution_state != "EVIDENCE_FROZEN":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must not mark exceptional authority active before the approving human evidence is frozen.",
            )
        )

    if binding_scope_class in AUTHORITY_LAYER_BOUNDARY_SENDABLE_SCOPE_CLASSES:
        if contract.get("tenant_permission_state") != "SATISFIED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.tenant_permission_state must stay `SATISFIED` for sendable authority artifacts.",
                )
            )
        if human_gate_requirement != "NOT_REQUIRED" and human_gate_resolution_state != "EVIDENCE_FROZEN":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name} must not persist a sendable authority artifact while human-gate evidence is still pending.",
                )
            )
        if active_principal_class == "SERVICE" and human_gate_requirement != "NOT_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name} must not allow a service principal to carry a satisfied step-up or approval boundary into a sendable authority artifact.",
                )
            )
        if client_delegation_state not in AUTHORITY_LAYER_BOUNDARY_LIVE_DELEGATION_STATES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.client_delegation_state must stay live-usable for sendable authority artifacts.",
                )
            )
        if authority_link_state not in {"AUTHORISED_ACTIVE", "AUTHORISED_LIMITED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.authority_link_state must stay active or explicitly limited for sendable authority artifacts.",
                )
            )

    return issues, contract


