def validate_invariant_enforcement_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_boundary_scope: str | None = None,
    expected_error_record_ref: object = INVARIANT_ENFORCEMENT_UNSET,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain the shared invariant-enforcement and fail-closed contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "INVARIANT_ENFORCEMENT_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `INVARIANT_ENFORCEMENT_V1`.",
            )
        )

    boundary_scope = contract.get("boundary_scope")
    if expected_boundary_scope is not None and boundary_scope != expected_boundary_scope:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.boundary_scope must stay `{expected_boundary_scope}`.",
            )
        )

    expected_binding_policy = INVARIANT_ENFORCEMENT_BOUNDARY_POLICIES_BY_SCOPE.get(boundary_scope)
    if expected_binding_policy is not None and contract.get("boundary_specific_binding_policy") != expected_binding_policy:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.boundary_specific_binding_policy must stay `{expected_binding_policy}` when `{field_name}.boundary_scope = {boundary_scope}`.",
            )
        )

    for policy_field, expected_value in (
        ("typed_error_policy", "INVARIANTS_MUST_PERSIST_FAMILY_SPECIFIC_ERROR_RECORDS"),
        ("partial_write_policy", "NO_PARTIAL_MUTATION_OR_SIDE_EFFECT_AFTER_INVARIANT_FAILURE"),
        ("audit_evidence_policy", "INVARIANTS_REQUIRE_ERROR_AND_TERMINAL_AUDIT_EVIDENCE"),
        ("lifecycle_mapping_policy", "PRESTART_INVARIANTS_BLOCK_POSTSTART_INVARIANTS_FAIL"),
        (
            "assertion_conversion_policy",
            "ASSERTIONS_AND_GENERIC_EXCEPTIONS_MUST_COLLAPSE_TO_TYPED_FAIL_CLOSED_OUTCOMES",
        ),
        ("normalization_rejection_policy", "IMPOSSIBLE_STATES_REJECTED_NEVER_NORMALIZED"),
    ):
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    invariant_failure_state = contract.get("invariant_failure_state")
    if invariant_failure_state == "NOT_TRIGGERED":
        for instance_field in INVARIANT_ENFORCEMENT_INSTANCE_FIELDS:
            if contract.get(instance_field) is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_name}.{instance_field} must be null when `invariant_failure_state = NOT_TRIGGERED`.",
                    )
                )
    elif invariant_failure_state == "TRIGGERED":
        for instance_field in INVARIANT_ENFORCEMENT_INSTANCE_FIELDS:
            value = contract.get(instance_field)
            if value is None or (isinstance(value, str) and not value):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_name}.{instance_field} must remain non-null when `invariant_failure_state = TRIGGERED`.",
                    )
                )
    else:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.invariant_failure_state must stay inside `{{NOT_TRIGGERED, TRIGGERED}}`.",
            )
        )

    invariant_class = contract.get("invariant_class_or_null")
    expected_error_family = INVARIANT_ENFORCEMENT_ERROR_FAMILY_BY_CLASS.get(invariant_class)
    if expected_error_family is not None and contract.get("error_family_or_null") != expected_error_family:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.error_family_or_null must stay `{expected_error_family}` for invariant class `{invariant_class}`.",
            )
        )

    expected_error_codes = INVARIANT_ENFORCEMENT_ERROR_CODES_BY_CLASS.get(invariant_class)
    if expected_error_codes is not None and contract.get("error_code_or_null") not in expected_error_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.error_code_or_null must stay inside {sorted(expected_error_codes)} for invariant class `{invariant_class}`.",
            )
        )

    failure_stage = contract.get("failure_stage_or_null")
    expected_terminal_state = INVARIANT_ENFORCEMENT_TERMINAL_STATE_BY_STAGE.get(failure_stage)
    if expected_terminal_state is not None and contract.get("terminal_manifest_state_or_null") != expected_terminal_state:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.terminal_manifest_state_or_null must stay `{expected_terminal_state}` for failure stage `{failure_stage}`.",
            )
        )

    expected_terminal_audit_event = INVARIANT_ENFORCEMENT_TERMINAL_AUDIT_EVENT_BY_STAGE.get(failure_stage)
    if (
        expected_terminal_audit_event is not None
        and contract.get("terminal_audit_event_type_or_null") != expected_terminal_audit_event
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.terminal_audit_event_type_or_null must stay `{expected_terminal_audit_event}` for failure stage `{failure_stage}`.",
            )
        )

    if failure_stage in {"PRESTART", "POSTSTART"} and contract.get("transition_event_code_or_null") != "system_fault":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.transition_event_code_or_null must stay `system_fault` for invariant failure stage `{failure_stage}`.",
            )
        )

    if (
        expected_error_record_ref is not INVARIANT_ENFORCEMENT_UNSET
        and contract.get("error_record_ref_or_null") != expected_error_record_ref
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.error_record_ref_or_null must mirror the owning error id.",
            )
        )

    return issues, contract


def validate_invariant_enforcement_contract_payload(payload: dict, location: str) -> list[Issue]:
    return validate_invariant_enforcement_contract(
        payload,
        location,
        "`invariant_enforcement_contract`",
    )[0]


FAILURE_RESOLUTION_CONTRACT_POLICIES_BY_ROLE = {
    "ERROR_RECORD": "ERROR_RETAINS_OWNER_NEXT_ACTION_AND_CHILD_LINKS",
    "REMEDIATION_TASK": "TASK_CLOSURE_DECLARES_EFFECT_ON_ERROR",
    "COMPENSATION_RECORD": "COMPENSATION_RETAINS_OWNER_VERIFICATION_AND_CLOSURE",
    "FAILURE_INVESTIGATION": "INVESTIGATION_CLOSURE_RETAINS_OUTCOME_AND_EVIDENCE",
    "ACCEPTED_RISK_APPROVAL": "APPROVAL_RETAINS_SCOPE_EXPIRY_AND_AUTHORIZATION_BASIS",
}


def validate_failure_resolution_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_lifecycle_role: str | None = None,
    expected_role_specific_binding_policy: str | None = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a structured failure-resolution lifecycle contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "FAILURE_RESOLUTION_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `FAILURE_RESOLUTION_V1`.",
            )
        )

    lifecycle_role = contract.get("lifecycle_role")
    if expected_lifecycle_role is not None and lifecycle_role != expected_lifecycle_role:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.lifecycle_role must stay `{expected_lifecycle_role}`.",
            )
        )

    expected_policy = FAILURE_RESOLUTION_CONTRACT_POLICIES_BY_ROLE.get(lifecycle_role)
    if expected_policy is not None and contract.get("role_specific_binding_policy") != expected_policy:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.role_specific_binding_policy must stay `{expected_policy}` when `{field_name}.lifecycle_role = {lifecycle_role}`.",
            )
        )

    if (
        expected_role_specific_binding_policy is not None
        and contract.get("role_specific_binding_policy") != expected_role_specific_binding_policy
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.role_specific_binding_policy must stay `{expected_role_specific_binding_policy}`.",
            )
        )

    for policy_field, expected_value in (
        ("material_failure_policy", "NO_MATERIAL_FAILURE_WITHOUT_DURABLE_OBJECT"),
        ("ownership_policy", "OWNER_TYPE_AND_REF_OR_EXPLICIT_SYSTEM_OWNER_REQUIRED"),
        ("next_action_policy", "OPEN_FAILURES_REQUIRE_ONE_LAWFUL_NEXT_PATH"),
        ("retry_policy", "RETRY_CLASS_BUDGET_AND_PRECONDITIONS_BIND_EXECUTION"),
        ("closure_policy", "TERMINAL_OR_COMPLETED_STATES_REQUIRE_BASIS_EVIDENCE_AND_AUDIT"),
        ("accepted_risk_policy", "ACCEPTED_RISK_REQUIRES_APPROVAL_EXPIRY_AND_BOUNDED_SCOPE"),
        ("linkage_policy", "ERROR_TASK_COMPENSATION_INVESTIGATION_APPROVAL_LINKS_MUST_STAY_COHERENT"),
    ):
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    return issues, contract


def validate_failure_resolution_contract_payload(payload: dict, location: str) -> list[Issue]:
    return validate_failure_resolution_contract(
        payload,
        location,
        "`failure_resolution_contract`",
    )[0]


