def validate_state_transition_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_object_family: str | None,
    current_state: object,
    audit_refs: object = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain the shared state-transition governance contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "STATE_TRANSITION_CONTRACT_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `STATE_TRANSITION_CONTRACT_V1`.",
            )
        )

    object_family = expected_object_family or contract.get("object_family")
    spec = STATE_TRANSITION_MACHINE_SPECS.get(object_family)
    if spec is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.object_family must stay inside the governed FE-46 object-family set {sorted(STATE_TRANSITION_MACHINE_SPECS)}.",
            )
        )
        return issues, contract

    if contract.get("object_family") != object_family:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.object_family must stay `{object_family}`.",
            )
        )

    if contract.get("machine_code") != spec["machine_code"]:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.machine_code must stay `{spec['machine_code']}`.",
            )
        )

    if contract.get("state_field_name") != spec["state_field_name"]:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.state_field_name must stay `{spec['state_field_name']}`.",
            )
        )

    if current_state is not None and contract.get("current_state") != current_state:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.current_state must mirror the parent object's `{spec['state_field_name']}`.",
            )
        )

    for policy_field, expected_value in (
        ("transition_application_policy", "NAMED_EVENT_ONLY"),
        ("illegal_transition_policy", "REJECT_WITH_TYPED_REASON_AND_NO_PARTIAL_WRITE"),
        ("concurrency_guard_policy", "COMPARE_AND_SWAP_OR_SINGLE_WRITER_LEASE"),
        ("terminal_reentry_policy", "TERMINAL_STATES_REQUIRE_NEW_LINEAGE"),
        (
            "recovery_supersession_policy",
            "RECOVERY_AND_SUPERSESSION_ALLOCATE_SUCCESSOR_OR_SUPERSEDING_LINEAGE",
        ),
        ("audit_evidence_policy", "EVERY_TRANSITION_RETAINS_AUDIT_EVENT_REF"),
        ("typed_rejection_family", "ILLEGAL_STATE_TRANSITION"),
    ):
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    previous_state = contract.get("previous_state_or_null")
    event_code = contract.get("transition_event_code")
    contract_current_state = contract.get("current_state")
    legal_initial_transition = (
        previous_state is None
        and contract_current_state == spec["initial_state"]
        and event_code == spec["initial_event"]
    )
    legal_named_transition = (
        isinstance(previous_state, str)
        and isinstance(event_code, str)
        and isinstance(contract_current_state, str)
        and (previous_state, event_code, contract_current_state) in spec["allowed_transitions"]
    )

    if previous_state == contract_current_state and isinstance(contract_current_state, str):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.previous_state_or_null must not equal {field_name}.current_state.",
            )
        )

    if not legal_initial_transition and not legal_named_transition:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must encode a legal `{object_family}` transition tuple or the single legal initial event.",
            )
        )

    transition_applied_at = parse_datetime(contract.get("transition_applied_at"))
    if transition_applied_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.transition_applied_at must be a valid RFC 3339 timestamp.",
            )
        )

    transition_audit_ref = contract.get("transition_audit_ref")
    if not isinstance(transition_audit_ref, str) or not transition_audit_ref:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.transition_audit_ref must retain non-empty audit evidence for the applied transition.",
            )
        )
    elif isinstance(audit_refs, list) and audit_refs and transition_audit_ref not in audit_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.transition_audit_ref must appear in the parent object's audit refs when that tape is persisted inline.",
            )
        )

    return issues, contract


def validate_state_transition_contract_payload(payload: dict, location: str) -> list[Issue]:
    return validate_state_transition_contract(
        payload,
        location,
        "`state_transition_contract`",
        expected_object_family=payload.get("object_family") if isinstance(payload, dict) else None,
        current_state=payload.get("current_state") if isinstance(payload, dict) else None,
    )[0]


def validate_schema_reader_window_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_writer_schema_bundle_hash: object = None,
    expected_compatibility_window_ref: object = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain the shared schema-reader window contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "SCHEMA_READER_WINDOW_CONTRACT_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `SCHEMA_READER_WINDOW_CONTRACT_V1`.",
            )
        )

    if (
        expected_writer_schema_bundle_hash is not None
        and contract.get("writer_schema_bundle_hash") != expected_writer_schema_bundle_hash
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.writer_schema_bundle_hash must mirror the parent artifact's `schema_bundle_hash`.",
            )
        )

    if (
        expected_compatibility_window_ref is not None
        and contract.get("compatibility_window_ref") != expected_compatibility_window_ref
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.compatibility_window_ref must mirror the parent artifact's compatibility-window identity.",
            )
        )

    supported_reader_hashes = (
        contract.get("supported_reader_schema_bundle_hashes")
        if isinstance(contract.get("supported_reader_schema_bundle_hashes"), list)
        else []
    )
    protected_historical_hashes = (
        contract.get("protected_historical_schema_bundle_hashes")
        if isinstance(contract.get("protected_historical_schema_bundle_hashes"), list)
        else []
    )
    issues.extend(
        validate_sorted_string_sequence(
            supported_reader_hashes,
            location,
            f"{field_name}.supported_reader_schema_bundle_hashes[]",
            allow_empty=False,
        )
    )
    issues.extend(
        validate_sorted_string_sequence(
            protected_historical_hashes,
            location,
            f"{field_name}.protected_historical_schema_bundle_hashes[]",
        )
    )

    writer_hash = contract.get("writer_schema_bundle_hash")
    if isinstance(writer_hash, str) and writer_hash not in supported_reader_hashes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.supported_reader_schema_bundle_hashes[] must include `writer_schema_bundle_hash`.",
            )
        )

    if isinstance(writer_hash, str) and writer_hash in protected_historical_hashes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.protected_historical_schema_bundle_hashes[] must list historical bundles only, not the current writer bundle.",
            )
        )

    unsupported_historical_hashes = sorted(
        hash_value
        for hash_value in protected_historical_hashes
        if isinstance(hash_value, str) and hash_value not in supported_reader_hashes
    )
    if unsupported_historical_hashes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.protected_historical_schema_bundle_hashes[] must stay inside the supported-reader set; unsupported {unsupported_historical_hashes}.",
            )
        )

    for policy_field, expected_value in (
        (
            "historical_manifest_policy",
            "FROZEN_MANIFESTS_REQUIRE_RECORDED_BUNDLE_OR_COMPATIBLE_READER",
        ),
        ("destructive_change_policy", "DESTRUCTIVE_CHANGE_BLOCKED_UNTIL_WINDOW_CLOSED"),
        (
            "rollback_boundary_policy",
            "ROLLBACK_ALLOWED_ONLY_WHILE_PREVIOUS_READERS_SUPPORTED",
        ),
        (
            "fail_forward_policy",
            "FAIL_FORWARD_REQUIRED_AFTER_WINDOW_CLOSE_OR_BREAKING_CONTRACT",
        ),
        (
            "replay_restore_policy",
            "RESTORE_AND_REPLAY_REQUIRE_WINDOW_COMPATIBLE_READER",
        ),
    ):
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    return issues, contract


def validate_backfill_execution_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_migration_id: object = None,
    expected_target_version: object = None,
    expected_target_schema_bundle_hash: object = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain the shared backfill execution contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "BACKFILL_EXECUTION_CONTRACT_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `BACKFILL_EXECUTION_CONTRACT_V1`.",
            )
        )

    if expected_migration_id is not None and contract.get("migration_id") != expected_migration_id:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.migration_id must mirror the parent `migration_id`.",
            )
        )

    if expected_target_version is not None and contract.get("target_version") != expected_target_version:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.target_version must mirror the parent `target_version`.",
            )
        )

    if (
        expected_target_schema_bundle_hash is not None
        and contract.get("target_schema_bundle_hash") != expected_target_schema_bundle_hash
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.target_schema_bundle_hash must mirror the parent target schema bundle hash.",
            )
        )

    issues.extend(
        validate_sorted_string_sequence(
            contract.get("affected_artifact_types"),
            location,
            f"{field_name}.affected_artifact_types[]",
        )
    )
    issues.extend(
        validate_sorted_string_sequence(
            contract.get("backfill_audit_refs"),
            location,
            f"{field_name}.backfill_audit_refs[]",
        )
    )

    for policy_field, expected_value in (
        ("idempotency_policy", "REENTRANT_UPSERT_OR_COMPARE_AND_SWAP_ONLY"),
        ("meaning_preservation_policy", "HISTORICAL_MEANING_IMMUTABLE_APPEND_OR_DERIVE_ONLY"),
        (
            "lineage_recording_policy",
            "EVERY_BACKFILL_WRITE_RETAINS_LEDGER_AND_AUDIT_LINEAGE",
        ),
        ("retry_safety_policy", "DUPLICATE_SAFE_AND_PARTIAL_PROGRESS_RESUMABLE"),
    ):
        if contract.get(policy_field) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{policy_field} must stay `{expected_value}`.",
                )
            )

    execution_requirement = contract.get("execution_requirement")
    execution_state = contract.get("execution_state")
    affected_artifact_types = (
        contract.get("affected_artifact_types")
        if isinstance(contract.get("affected_artifact_types"), list)
        else []
    )
    backfill_audit_refs = (
        contract.get("backfill_audit_refs")
        if isinstance(contract.get("backfill_audit_refs"), list)
        else []
    )

    if execution_requirement == "NO_BACKFILL_REQUIRED":
        if execution_state != "NOT_APPLICABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.execution_requirement=NO_BACKFILL_REQUIRED must force `execution_state=NOT_APPLICABLE`.",
                )
            )
        if affected_artifact_types:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.execution_requirement=NO_BACKFILL_REQUIRED must keep `affected_artifact_types[]` empty.",
                )
            )
        if backfill_audit_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.execution_requirement=NO_BACKFILL_REQUIRED must keep `backfill_audit_refs[]` empty.",
                )
            )

    if execution_requirement == "IDEMPOTENT_BACKFILL_REQUIRED":
        if execution_state == "NOT_APPLICABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.execution_requirement=IDEMPOTENT_BACKFILL_REQUIRED must not use `execution_state=NOT_APPLICABLE`.",
                )
            )
        if not affected_artifact_types:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.execution_requirement=IDEMPOTENT_BACKFILL_REQUIRED must retain non-empty `affected_artifact_types[]`.",
                )
            )

    if execution_state in {"COMPLETE", "HALTED", "FAILED"} and not backfill_audit_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.execution_state={execution_state} must retain non-empty `backfill_audit_refs[]`.",
            )
        )

    if backfill_audit_refs and execution_requirement != "IDEMPOTENT_BACKFILL_REQUIRED":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.backfill_audit_refs[] must stay empty unless `execution_requirement=IDEMPOTENT_BACKFILL_REQUIRED`.",
            )
        )

    return issues, contract


def validate_release_candidate_identity_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    require_non_null: bool = True,
    expected_candidate_identity_hash: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_candidate_environment_ref: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_build_artifact_ref: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_artifact_digest: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_schema_bundle_hash: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_config_bundle_hash: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_migration_plan_ref_or_null: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_enabled_provider_profile_refs: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
    expected_supported_client_window_ref_or_null: object = RELEASE_CANDIDATE_IDENTITY_UNSET,
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if contract is None:
        if require_non_null:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name} must retain the shared release-candidate identity contract.",
                )
            )
        return issues, None
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain the shared release-candidate identity contract.",
            )
        )
        return issues, None

    issues.extend(
        validate_sorted_string_sequence(
            contract.get("enabled_provider_profile_refs"),
            location,
            f"{field_name}.enabled_provider_profile_refs[]",
        )
    )

    provider_profile_refs = (
        contract.get("enabled_provider_profile_refs")
        if isinstance(contract.get("enabled_provider_profile_refs"), list)
        else []
    )
    duplicate_provider_profile_refs = duplicate_values(
        [ref for ref in provider_profile_refs if isinstance(ref, str)]
    )
    if duplicate_provider_profile_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.enabled_provider_profile_refs[] must not repeat provider profiles; duplicates {duplicate_provider_profile_refs}.",
            )
        )

    for subfield, expected_value in (
        ("contract_version", "RELEASE_CANDIDATE_IDENTITY_V1"),
        ("array_canonicalization_policy", "SORTED_UNIQUE_ARRAY_COMPONENTS_ONLY"),
        (
            "suite_context_policy",
            "SUITE_SPECIFIC_DIMENSIONS_MUST_BE_DECLARED_OR_EXPLICITLY_NULL",
        ),
        (
            "admissibility_binding_policy",
            "GREEN_GATES_REQUIRE_EXACT_CANDIDATE_BINDING",
        ),
    ):
        if contract.get(subfield) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{subfield} must stay `{expected_value}`.",
                )
            )

    derived_candidate_identity_hash = derive_release_candidate_identity_hash(contract)
    if derived_candidate_identity_hash is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a complete canonical candidate tuple before a candidate hash can be derived.",
            )
        )
    elif contract.get("candidate_identity_hash") != derived_candidate_identity_hash:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.candidate_identity_hash must equal the canonical hash derived from the candidate tuple.",
            )
        )

    for subfield, expected_value, label in (
        ("candidate_identity_hash", expected_candidate_identity_hash, "candidate identity hash"),
        ("candidate_environment_ref", expected_candidate_environment_ref, "candidate environment ref"),
        ("build_artifact_ref", expected_build_artifact_ref, "build artifact ref"),
        ("artifact_digest", expected_artifact_digest, "artifact digest"),
        ("schema_bundle_hash", expected_schema_bundle_hash, "schema bundle hash"),
        ("config_bundle_hash", expected_config_bundle_hash, "config bundle hash"),
        ("migration_plan_ref_or_null", expected_migration_plan_ref_or_null, "migration plan ref"),
        (
            "enabled_provider_profile_refs",
            expected_enabled_provider_profile_refs,
            "enabled provider-profile set",
        ),
        (
            "supported_client_window_ref_or_null",
            expected_supported_client_window_ref_or_null,
            "supported-client window ref",
        ),
    ):
        if expected_value is RELEASE_CANDIDATE_IDENTITY_UNSET:
            continue
        if contract.get(subfield) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{subfield} must mirror the owning artifact's {label}.",
                )
            )

    return issues, contract


