def validate_schema_bundle_compatibility_gate_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    require_non_null: bool = True,
    expected_candidate_identity_hash: object = CACHE_ISOLATION_UNSET,
    expected_schema_bundle_hash: object = CACHE_ISOLATION_UNSET,
    expected_migration_plan_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_supported_client_window_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_compatibility_window_ref: object = CACHE_ISOLATION_UNSET,
    expected_reader_window_state: object = CACHE_ISOLATION_UNSET,
    expected_rollback_boundary_state: object = CACHE_ISOLATION_UNSET,
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if contract is None:
        if require_non_null:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name} must retain the shared schema-bundle compatibility gate contract.",
                )
            )
        return issues, None
    if not isinstance(contract, dict):
        issues.append(Issue("custom", location, f"{field_name} must be an object."))
        return issues, None

    issues.extend(
        validate_sorted_string_sequence(
            contract.get("migration_ledger_refs"),
            location,
            f"{field_name}.migration_ledger_refs[]",
        )
    )
    issues.extend(
        validate_sorted_string_sequence(
            contract.get("reason_codes"),
            location,
            f"{field_name}.reason_codes[]",
        )
    )

    if contract.get("contract_version") != SCHEMA_BUNDLE_COMPATIBILITY_GATE_VERSION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must remain `{SCHEMA_BUNDLE_COMPATIBILITY_GATE_VERSION}`.",
            )
        )

    for subfield, expected_value in (
        ("historical_manifest_policy", "FROZEN_MANIFESTS_REQUIRE_RECORDED_BUNDLE_OR_COMPATIBLE_READER"),
        ("destructive_change_policy", "DESTRUCTIVE_CHANGE_BLOCKED_UNTIL_WINDOW_CLOSED"),
        ("rollback_boundary_policy", "ROLLBACK_ALLOWED_ONLY_WHILE_PREVIOUS_READERS_SUPPORTED"),
        ("fail_forward_policy", "FAIL_FORWARD_REQUIRED_AFTER_WINDOW_CLOSE_OR_BREAKING_CONTRACT"),
        ("replay_restore_policy", "RESTORE_AND_REPLAY_REQUIRE_WINDOW_COMPATIBLE_READER"),
        ("client_persistence_policy", SCHEMA_BUNDLE_COMPATIBILITY_CLIENT_PERSISTENCE_POLICY),
        ("evidence_binding_policy", SCHEMA_BUNDLE_COMPATIBILITY_EVIDENCE_BINDING_POLICY),
    ):
        if contract.get(subfield) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{subfield} must remain `{expected_value}`.",
                )
            )

    candidate_identity_issues, candidate_identity_contract = validate_release_candidate_identity_contract(
        contract.get("candidate_identity_contract"),
        location,
        f"{field_name}.candidate_identity_contract",
        expected_candidate_identity_hash=contract.get("candidate_identity_hash"),
        expected_schema_bundle_hash=contract.get("schema_bundle_hash"),
        expected_migration_plan_ref_or_null=contract.get("migration_plan_ref_or_null"),
        expected_supported_client_window_ref_or_null=contract.get("supported_client_window_ref_or_null"),
    )
    issues.extend(candidate_identity_issues)

    reader_window_issues, reader_window_contract = validate_schema_reader_window_contract(
        contract.get("schema_reader_window_contract"),
        location,
        f"{field_name}.schema_reader_window_contract",
        expected_writer_schema_bundle_hash=contract.get("schema_bundle_hash"),
        expected_compatibility_window_ref=contract.get("compatibility_window_ref"),
    )
    issues.extend(reader_window_issues)

    if (
        isinstance(candidate_identity_contract, dict)
        and contract.get("schema_bundle_hash") != candidate_identity_contract.get("schema_bundle_hash")
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.schema_bundle_hash must mirror `{field_name}.candidate_identity_contract.schema_bundle_hash`.",
            )
        )

    if (
        isinstance(reader_window_contract, dict)
        and contract.get("reader_window_state") != reader_window_contract.get("window_state")
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.reader_window_state must mirror `{field_name}.schema_reader_window_contract.window_state`.",
            )
        )

    for field_label, expected_value in (
        ("candidate_identity_hash", expected_candidate_identity_hash),
        ("schema_bundle_hash", expected_schema_bundle_hash),
        ("migration_plan_ref_or_null", expected_migration_plan_ref_or_null),
        ("supported_client_window_ref_or_null", expected_supported_client_window_ref_or_null),
        ("compatibility_window_ref", expected_compatibility_window_ref),
        ("reader_window_state", expected_reader_window_state),
        ("rollback_boundary_state", expected_rollback_boundary_state),
    ):
        if expected_value is CACHE_ISOLATION_UNSET:
            continue
        if contract.get(field_label) != expected_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field_label} must mirror `{expected_value}`.",
                )
            )

    migration_plan_ref_or_null = contract.get("migration_plan_ref_or_null")
    migration_ledger_refs = (
        contract.get("migration_ledger_refs") if isinstance(contract.get("migration_ledger_refs"), list) else []
    )
    supported_client_window_ref_or_null = contract.get("supported_client_window_ref_or_null")
    reader_window_state = contract.get("reader_window_state")
    migration_chronology_state = contract.get("migration_chronology_state")
    native_client_window_state = contract.get("native_client_window_state")
    destructive_contract_state = contract.get("destructive_contract_state")
    rollback_boundary_state = contract.get("rollback_boundary_state")
    historical_manifest_guard_state = contract.get("historical_manifest_guard_state")
    replay_restore_guard_state = contract.get("replay_restore_guard_state")
    reason_codes = contract.get("reason_codes") if isinstance(contract.get("reason_codes"), list) else []

    if migration_plan_ref_or_null is None:
        if migration_ledger_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.migration_ledger_refs[] must be empty when `migration_plan_ref_or_null` is null.",
                )
            )
        if migration_chronology_state != "NOT_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.migration_chronology_state must be `NOT_REQUIRED` when no migration plan is bound.",
                )
            )
    else:
        if not migration_ledger_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.migration_ledger_refs[] must stay non-empty when `migration_plan_ref_or_null` is present.",
                )
            )
        expected_migration_state = SCHEMA_BUNDLE_COMPATIBILITY_MIGRATION_STATE_BY_WINDOW_STATE.get(reader_window_state)
        if migration_chronology_state != expected_migration_state:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.migration_chronology_state must mirror the reader-window phase as `{expected_migration_state}` when migration is required.",
                )
            )

    if supported_client_window_ref_or_null is None and native_client_window_state != "NOT_APPLICABLE":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.native_client_window_state must be `NOT_APPLICABLE` when `supported_client_window_ref_or_null` is null.",
            )
        )
    if supported_client_window_ref_or_null is not None and native_client_window_state == "NOT_APPLICABLE":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.native_client_window_state must not be `NOT_APPLICABLE` when a supported client window is promised.",
            )
        )

    if reader_window_state in SCHEMA_BUNDLE_COMPATIBILITY_OPEN_WINDOW_STATES:
        if destructive_contract_state != "BLOCKED_UNTIL_WINDOW_CLOSE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.destructive_contract_state must be `BLOCKED_UNTIL_WINDOW_CLOSE` while previous readers remain supported.",
                )
            )
        if rollback_boundary_state != "ROLLBACK_ALLOWED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.rollback_boundary_state must be `ROLLBACK_ALLOWED` while previous readers remain supported.",
                )
            )
    elif reader_window_state == "CONTRACT_ELIGIBLE_WINDOW_CLOSED":
        if destructive_contract_state != "ELIGIBLE_AFTER_WINDOW_CLOSE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.destructive_contract_state must be `ELIGIBLE_AFTER_WINDOW_CLOSE` once the reader window is closed.",
                )
            )
        if rollback_boundary_state != "FAIL_FORWARD_ONLY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.rollback_boundary_state must be `FAIL_FORWARD_ONLY` once the reader window is closed.",
                )
            )

    blocked_states = []
    if historical_manifest_guard_state == "BLOCKED":
        blocked_states.append("historical manifests")
    if replay_restore_guard_state == "BLOCKED":
        blocked_states.append("replay/restore")
    if native_client_window_state == "BLOCKED":
        blocked_states.append("supported clients")

    if blocked_states and not reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.reason_codes[] must explain blocked compatibility posture for {blocked_states}.",
            )
        )
    if not blocked_states and reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.reason_codes[] must stay empty when all compatibility guard states are unblocked.",
            )
        )

    derived_hash = derive_schema_bundle_compatibility_gate_hash(contract)
    if derived_hash is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a complete canonical compatibility tuple before `compatibility_gate_hash` can be derived.",
            )
        )
    elif contract.get("compatibility_gate_hash") != derived_hash:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.compatibility_gate_hash must equal the canonical hash derived from the compatibility gate tuple.",
            )
        )

    return issues, contract


def validate_schema_bundle_compatibility_gate_contract_payload(payload: dict, location: str) -> list[Issue]:
    compatibility_window_ref = None
    reader_window_state = None
    if isinstance(payload, dict) and isinstance(payload.get("schema_reader_window_contract"), dict):
        compatibility_window_ref = payload["schema_reader_window_contract"].get("compatibility_window_ref")
        reader_window_state = payload["schema_reader_window_contract"].get("window_state")
    return validate_schema_bundle_compatibility_gate_contract(
        payload,
        location,
        "`schema_bundle_compatibility_gate_contract`",
        expected_candidate_identity_hash=payload.get("candidate_identity_hash") if isinstance(payload, dict) else None,
        expected_schema_bundle_hash=payload.get("schema_bundle_hash") if isinstance(payload, dict) else None,
        expected_migration_plan_ref_or_null=(
            payload.get("migration_plan_ref_or_null") if isinstance(payload, dict) else None
        ),
        expected_supported_client_window_ref_or_null=(
            payload.get("supported_client_window_ref_or_null") if isinstance(payload, dict) else None
        ),
        expected_compatibility_window_ref=compatibility_window_ref,
        expected_reader_window_state=reader_window_state,
        expected_rollback_boundary_state=(
            payload.get("rollback_boundary_state") if isinstance(payload, dict) else None
        ),
    )[0]


def validate_config_version(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    state_transition_issues, state_transition_contract = validate_state_transition_contract(
        payload.get("state_transition_contract"),
        location,
        "`state_transition_contract`",
        expected_object_family="CONFIG_VERSION",
        current_state=payload.get("lifecycle_state"),
        audit_refs=payload.get("audit_refs"),
    )
    issues.extend(state_transition_issues)

    created_at = parse_datetime(payload.get("created_at"))
    state_changed_at = parse_datetime(payload.get("state_changed_at"))
    approved_at = parse_datetime(payload.get("approved_at_or_null"))
    retired_at = parse_datetime(payload.get("retired_at_or_null"))
    transition_applied_at = parse_datetime(
        state_transition_contract.get("transition_applied_at")
        if isinstance(state_transition_contract, dict)
        else None
    )

    if transition_applied_at is not None and state_changed_at is not None and transition_applied_at != state_changed_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`state_transition_contract.transition_applied_at` must mirror `state_changed_at`.",
            )
        )

    if created_at is not None and state_changed_at is not None and state_changed_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`state_changed_at` must not be earlier than `created_at`.",
            )
        )
    if created_at is not None and approved_at is not None and approved_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`approved_at_or_null` must not be earlier than `created_at`.",
            )
        )
    if state_changed_at is not None and retired_at is not None and retired_at < state_changed_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`retired_at_or_null` must not be earlier than `state_changed_at`.",
            )
        )

    lifecycle_state = payload.get("lifecycle_state")
    approvals = payload.get("approvals")
    if not isinstance(approvals, list):
        approvals = []

    if lifecycle_state == "APPROVED" and not approvals:
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state=APPROVED` must retain one or more approval refs.",
            )
        )
    if lifecycle_state == "DEPRECATED" and not isinstance(payload.get("superseded_by_version_id_or_null"), str):
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state=DEPRECATED` must retain `superseded_by_version_id_or_null`.",
            )
        )
    if lifecycle_state == "REVOKED" and not isinstance(payload.get("revocation_reason_code_or_null"), str):
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state=REVOKED` must retain `revocation_reason_code_or_null`.",
            )
        )
    if lifecycle_state == "RETIRED" and retired_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state=RETIRED` must retain `retired_at_or_null`.",
            )
        )

    return issues


