def validate_customer_safe_projection_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_boundary_scope: str | None = None,
    expected_projection_audience: str | None = None,
    expected_access_binding_hash: str | None = None,
    expected_masking_posture_fingerprint: str | None = None,
    expected_visibility_cache_partition_key: str | None = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a structured customer-safe projection contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "CUSTOMER_SAFE_PROJECTION_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `CUSTOMER_SAFE_PROJECTION_V1`.",
            )
        )

    if expected_boundary_scope is not None and contract.get("boundary_scope") != expected_boundary_scope:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.boundary_scope must stay `{expected_boundary_scope}`.",
            )
        )

    if expected_projection_audience is not None and contract.get("projection_audience") != expected_projection_audience:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.projection_audience must stay `{expected_projection_audience}`.",
            )
        )

    if contract.get("shell_family") != "CLIENT_PORTAL_SHELL":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.shell_family must stay `CLIENT_PORTAL_SHELL`.",
            )
        )

    for field in (
        "access_binding_hash",
        "masking_posture_fingerprint",
        "visibility_cache_partition_key",
    ):
        if not isinstance(contract.get(field), str) or not contract.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field} must stay a non-empty string.",
                )
            )

    for field, expected in {
        "status_derivation_policy": "CUSTOMER_SAFE_BLOCKS_ONLY",
        "staff_field_dependency_policy": "EXCLUDE_STAFF_FIELDS_AT_PROJECTION_SOURCE",
        "plain_language_status_policy": "CUSTOMER_SAFE_STATUS_VOCABULARY_ONLY",
        "plain_language_action_policy": "CUSTOMER_SAFE_ACTION_VOCABULARY_ONLY",
        "limitation_notice_policy": "EXPLICIT_CUSTOMER_SAFE_NOTICE_REQUIRED",
        "recovery_explanation_policy": "EXPLICIT_CUSTOMER_SAFE_RECOVERY_NOTICE_REQUIRED",
        "artifact_history_policy": "CURRENT_VERSUS_HISTORY_EXPLICIT",
        "hidden_activity_policy": "NO_HIDDEN_ACTIVITY_DERIVATION",
        "module_projection_policy": "CUSTOMER_SAFE_MODULES_AND_METADATA_ONLY",
        "attachment_visibility_policy": "CUSTOMER_VISIBLE_ATTACHMENTS_ONLY",
        "live_update_visibility_policy": "INTERNAL_ONLY_DELTA_EXCLUSION_REQUIRED",
        "draft_placeholder_policy": "CUSTOMER_SAFE_PROJECTIONS_EXCLUDE_INTERNAL_DRAFTS",
        "notification_navigation_policy": "PORTAL_SAME_SHELL_AND_VISIBILITY_ONLY",
        "export_visibility_policy": "CUSTOMER_VISIBLE_EXPORTS_ONLY",
    }.items():
        if contract.get(field) != expected:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field} must stay `{expected}`.",
                )
            )

    raw_blocked_signal_classes = contract.get("blocked_staff_signal_classes")
    if not isinstance(raw_blocked_signal_classes, list):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.blocked_staff_signal_classes must remain an ordered array of frozen staff-only signal classes.",
            )
        )
    else:
        normalized_blocked_signal_classes = [
            value for value in raw_blocked_signal_classes if isinstance(value, str) and value
        ]
        if len(normalized_blocked_signal_classes) != len(raw_blocked_signal_classes):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.blocked_staff_signal_classes must contain only non-empty strings.",
                )
            )
        duplicate_blocked_signal_classes = duplicate_values(normalized_blocked_signal_classes)
        if duplicate_blocked_signal_classes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.blocked_staff_signal_classes must stay unique; duplicates {duplicate_blocked_signal_classes}.",
                )
            )
        if normalized_blocked_signal_classes != CUSTOMER_SAFE_PROJECTION_BLOCKED_SIGNAL_CLASSES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.blocked_staff_signal_classes must stay {CUSTOMER_SAFE_PROJECTION_BLOCKED_SIGNAL_CLASSES}.",
                )
            )

    if (
        expected_access_binding_hash is not None
        and contract.get("access_binding_hash") != expected_access_binding_hash
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.access_binding_hash must stay `{expected_access_binding_hash}`.",
            )
        )

    if (
        expected_masking_posture_fingerprint is not None
        and contract.get("masking_posture_fingerprint") != expected_masking_posture_fingerprint
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.masking_posture_fingerprint must stay `{expected_masking_posture_fingerprint}`.",
            )
        )

    if (
        expected_visibility_cache_partition_key is not None
        and contract.get("visibility_cache_partition_key") != expected_visibility_cache_partition_key
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.visibility_cache_partition_key must stay `{expected_visibility_cache_partition_key}`.",
            )
        )

    return issues, contract


def derive_externalization_delivery_binding_hash(contract: object) -> str | None:
    if not isinstance(contract, dict):
        return None
    blocking_context_tokens = contract.get("blocking_context_tokens")
    if not isinstance(blocking_context_tokens, list):
        return None
    canonical_blocking_context_tokens: list[str] = []
    for token in blocking_context_tokens:
        if not isinstance(token, str) or not token:
            return None
        canonical_blocking_context_tokens.append(token)
    if len(set(canonical_blocking_context_tokens)) != len(canonical_blocking_context_tokens):
        return None

    canonical_payload = {
        "tenant_id": contract.get("tenant_id"),
        "boundary_scope": contract.get("boundary_scope"),
        "shell_family_or_null": contract.get("shell_family_or_null"),
        "context_anchor_ref": contract.get("context_anchor_ref"),
        "slice_binding_ref": contract.get("slice_binding_ref"),
        "delivery_surface_kind": contract.get("delivery_surface_kind"),
        "history_meaning_state": contract.get("history_meaning_state"),
        "eligibility_state": contract.get("eligibility_state"),
        "approval_state": contract.get("approval_state"),
        "access_binding_hash_or_null": contract.get("access_binding_hash_or_null"),
        "masking_state": contract.get("masking_state"),
        "masking_posture_fingerprint_or_null": contract.get("masking_posture_fingerprint_or_null"),
        "limitation_state": contract.get("limitation_state"),
        "visibility_cache_partition_key_or_null": contract.get("visibility_cache_partition_key_or_null"),
        "preview_target_ref_or_null": contract.get("preview_target_ref_or_null"),
        "download_target_ref_or_null": contract.get("download_target_ref_or_null"),
        "print_target_ref_or_null": contract.get("print_target_ref_or_null"),
        "external_handoff_target_ref_or_null": contract.get("external_handoff_target_ref_or_null"),
        "approval_requirement_token_or_null": contract.get("approval_requirement_token_or_null"),
        "blocking_context_tokens": sorted(canonical_blocking_context_tokens),
    }
    for field in (
        "tenant_id",
        "boundary_scope",
        "context_anchor_ref",
        "slice_binding_ref",
        "delivery_surface_kind",
        "history_meaning_state",
        "eligibility_state",
        "approval_state",
        "masking_state",
        "limitation_state",
    ):
        value = canonical_payload[field]
        if not isinstance(value, str) or not value:
            return None
    for field in (
        "shell_family_or_null",
        "access_binding_hash_or_null",
        "masking_posture_fingerprint_or_null",
        "visibility_cache_partition_key_or_null",
        "preview_target_ref_or_null",
        "download_target_ref_or_null",
        "print_target_ref_or_null",
        "external_handoff_target_ref_or_null",
        "approval_requirement_token_or_null",
    ):
        value = canonical_payload[field]
        if value is not None and (not isinstance(value, str) or not value):
            return None
    return stable_json_hash(canonical_payload)


def validate_externalization_governance_contract(
    contract: object,
    location: str,
    field_name: str,
    *,
    expected_boundary_scope: str | None = None,
    expected_tenant_id: str | None = None,
    expected_shell_family_or_null: object = CACHE_ISOLATION_UNSET,
    expected_context_anchor_ref: str | None = None,
    expected_slice_binding_ref: str | None = None,
    expected_delivery_surface_kind: str | None = None,
    expected_history_meaning_state: str | None = None,
    expected_eligibility_state: str | None = None,
    expected_approval_state: str | None = None,
    expected_access_binding_hash_or_null: object = CACHE_ISOLATION_UNSET,
    expected_masking_state: str | None = None,
    expected_masking_posture_fingerprint_or_null: object = CACHE_ISOLATION_UNSET,
    expected_limitation_state: str | None = None,
    expected_visibility_cache_partition_key_or_null: object = CACHE_ISOLATION_UNSET,
    expected_preview_target_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_download_target_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_print_target_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_external_handoff_target_ref_or_null: object = CACHE_ISOLATION_UNSET,
    expected_approval_requirement_token_or_null: object = CACHE_ISOLATION_UNSET,
    expected_blocking_context_tokens: list[str] | None = None,
) -> tuple[list[Issue], dict]:
    issues: list[Issue] = []
    if not isinstance(contract, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name} must retain a structured externalization governance contract.",
            )
        )
        return issues, {}

    if contract.get("contract_version") != "EXTERNALIZATION_GOVERNANCE_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.contract_version must stay `EXTERNALIZATION_GOVERNANCE_V1`.",
            )
        )

    if not isinstance(contract.get("tenant_id"), str) or not contract.get("tenant_id"):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.tenant_id must stay a non-empty string.",
            )
        )
    elif expected_tenant_id is not None and contract.get("tenant_id") != expected_tenant_id:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.tenant_id must stay `{expected_tenant_id}`.",
            )
        )

    if expected_boundary_scope is not None and contract.get("boundary_scope") != expected_boundary_scope:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.boundary_scope must stay `{expected_boundary_scope}`.",
            )
        )

    if not isinstance(contract.get("context_anchor_ref"), str) or not contract.get("context_anchor_ref"):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.context_anchor_ref must stay a non-empty string.",
            )
        )
    if not isinstance(contract.get("slice_binding_ref"), str) or not contract.get("slice_binding_ref"):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.slice_binding_ref must stay a non-empty string.",
            )
        )

    for field, expected in {
        "slice_binding_policy": "ACTIVE_GOVERNED_SLICE_REQUIRED",
        "background_scope_policy": "DETACHED_BACKGROUND_SCOPE_FORBIDDEN",
        "direct_url_policy": "DIRECT_URL_BYPASS_FORBIDDEN",
        "posture_preservation_policy": "CURRENT_HISTORY_MASKING_LIMITATION_AND_APPROVAL_PRESERVED",
        "handoff_target_policy": "EXTERNAL_TARGET_AND_BLOCKING_CONTEXT_EXPLICIT",
        "reentry_validation_policy": "RETURN_AND_DELIVERY_REQUIRE_GOVERNED_REVALIDATION",
        "delivery_context_policy": "TENANT_AND_SECURITY_CONTEXT_BOUND_AT_INVOCATION",
        "signed_url_binding_policy": "SIGNED_URLS_REQUIRE_CURRENT_GOVERNED_BINDING",
        "temporary_artifact_policy": "TEMP_FILES_AND_NATIVE_PREVIEWS_REQUIRE_MATCHING_BINDING",
    }.items():
        if contract.get(field) != expected:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field} must stay `{expected}`.",
                )
            )

    if expected_context_anchor_ref is not None and contract.get("context_anchor_ref") != expected_context_anchor_ref:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.context_anchor_ref must stay `{expected_context_anchor_ref}`.",
            )
        )
    if expected_slice_binding_ref is not None and contract.get("slice_binding_ref") != expected_slice_binding_ref:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.slice_binding_ref must stay `{expected_slice_binding_ref}`.",
            )
        )

    for field, expected in (
        ("shell_family_or_null", expected_shell_family_or_null),
        ("delivery_surface_kind", expected_delivery_surface_kind),
        ("history_meaning_state", expected_history_meaning_state),
        ("eligibility_state", expected_eligibility_state),
        ("approval_state", expected_approval_state),
        ("access_binding_hash_or_null", expected_access_binding_hash_or_null),
        ("masking_state", expected_masking_state),
        ("masking_posture_fingerprint_or_null", expected_masking_posture_fingerprint_or_null),
        ("limitation_state", expected_limitation_state),
        ("visibility_cache_partition_key_or_null", expected_visibility_cache_partition_key_or_null),
        ("preview_target_ref_or_null", expected_preview_target_ref_or_null),
        ("download_target_ref_or_null", expected_download_target_ref_or_null),
        ("print_target_ref_or_null", expected_print_target_ref_or_null),
        ("external_handoff_target_ref_or_null", expected_external_handoff_target_ref_or_null),
        ("approval_requirement_token_or_null", expected_approval_requirement_token_or_null),
    ):
        if expected is CACHE_ISOLATION_UNSET:
            continue
        if contract.get(field) != expected:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{field} must stay `{expected}`.",
                )
            )

    for security_field in (
        "access_binding_hash_or_null",
        "masking_posture_fingerprint_or_null",
        "visibility_cache_partition_key_or_null",
    ):
        value = contract.get(security_field)
        if value is not None and (not isinstance(value, str) or not value):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.{security_field} must stay null or a non-empty string.",
                )
            )

    blocking_context_tokens = contract.get("blocking_context_tokens")
    normalized_tokens: list[str] = []
    if not isinstance(blocking_context_tokens, list):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.blocking_context_tokens must remain an ordered array of non-empty strings.",
            )
        )
    else:
        normalized_tokens = [
            token for token in blocking_context_tokens if isinstance(token, str) and token
        ]
        if len(normalized_tokens) != len(blocking_context_tokens):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.blocking_context_tokens must contain only non-empty strings.",
                )
            )
        duplicate_tokens = duplicate_values(normalized_tokens)
        if duplicate_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_name}.blocking_context_tokens must stay unique; duplicates {duplicate_tokens}.",
                )
            )

    if expected_blocking_context_tokens is not None and normalized_tokens != expected_blocking_context_tokens:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.blocking_context_tokens must stay {expected_blocking_context_tokens}.",
            )
        )

    if contract.get("eligibility_state") in {"BLOCKED", "APPROVAL_REQUIRED"} and not normalized_tokens:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.blocking_context_tokens must remain non-empty when eligibility is blocked or approval-gated.",
            )
        )

    expected_delivery_binding_hash = derive_externalization_delivery_binding_hash(contract)
    if contract.get("delivery_binding_hash") != expected_delivery_binding_hash:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_name}.delivery_binding_hash must equal the canonical externalization delivery binding hash.",
            )
        )

    return issues, contract


