def portal_approval_pack_requires_action(pack: dict) -> bool:
    if pack.get("status") not in PORTAL_OUTSTANDING_APPROVAL_STATUSES:
        return False
    if pack.get("receipt_state") != "NOT_ISSUED":
        return False
    if pack.get("stale_protection_state") in {"SUPERSEDED", "EXPIRED"}:
        return False
    return True
