def derive_gate_override_dependency_state(decision: object, override_resolution_state: object) -> str | None:
    if decision == "OVERRIDABLE_BLOCK":
        return "OVERRIDE_REQUIRED_MISSING"
    if decision == "HARD_BLOCK":
        return "OVERRIDE_FORBIDDEN"
    if override_resolution_state == "VALID_OVERRIDE_ACTIVE":
        return "VALID_OVERRIDE_GOVERNED"
    if decision in {"PASS", "PASS_WITH_NOTICE", "MANUAL_REVIEW"}:
        return "OVERRIDE_INDEPENDENT"
    return None


def validate_gate_semantics_contract(
    payload: object,
    location: str,
    field_path: str,
    *,
    expected_decision: object,
    expected_override_resolution_state: object,
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(payload, dict):
        issues.append(Issue("custom", location, f"{field_path} must be an object."))
        return issues

    if payload.get("contract_version") != GATE_SEMANTICS_CONTRACT_VERSION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.contract_version must equal `{GATE_SEMANTICS_CONTRACT_VERSION}`.",
            )
        )
    if payload.get("evaluation_order_profile_code") != "NON_ACCESS_GATE_ORDER_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.evaluation_order_profile_code must equal `NON_ACCESS_GATE_ORDER_V1`.",
            )
        )
    if payload.get("reason_order_profile_code") != "NON_ACCESS_GATE_REASON_PRIORITY_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.reason_order_profile_code must equal `NON_ACCESS_GATE_REASON_PRIORITY_V1`.",
            )
        )
    if payload.get("severity_profile_code") != "NON_ACCESS_GATE_SEVERITY_V1":
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.severity_profile_code must equal `NON_ACCESS_GATE_SEVERITY_V1`.",
            )
        )

    expected_decision_rank = GATE_DECISION_RANK_BY_DECISION.get(expected_decision)
    if expected_decision_rank is not None and payload.get("decision_rank") != expected_decision_rank:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.decision_rank must equal `{expected_decision_rank}` when `decision = {expected_decision}`.",
            )
        )

    expected_progression_rank = GATE_PROGRESSION_RANK_BY_DECISION.get(expected_decision)
    if expected_progression_rank is not None and payload.get("progression_rank") != expected_progression_rank:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.progression_rank must equal `{expected_progression_rank}` when `decision = {expected_decision}`.",
            )
        )

    expected_blocking_class = GATE_BLOCKING_CLASS_BY_DECISION.get(expected_decision)
    if expected_blocking_class is not None and payload.get("blocking_class") != expected_blocking_class:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.blocking_class must equal `{expected_blocking_class}` when `decision = {expected_decision}`.",
            )
        )

    expected_progression_semantics = GATE_PROGRESSION_SEMANTICS_BY_DECISION.get(expected_decision)
    if expected_progression_semantics is not None and payload.get("progression_semantics") != expected_progression_semantics:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.progression_semantics must equal `{expected_progression_semantics}` when `decision = {expected_decision}`.",
            )
        )

    expected_override_dependency_state = derive_gate_override_dependency_state(
        expected_decision, expected_override_resolution_state
    )
    if (
        expected_override_dependency_state is not None
        and payload.get("override_dependency_state") != expected_override_dependency_state
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_path}.override_dependency_state must equal `{expected_override_dependency_state}` for the frozen decision/override posture.",
            )
        )

    return issues
