def validate_governance_interaction_layer(
    interaction_layer: object,
    expected_filter_chip_refs: list[str],
    expected_preserved_context_codes: list[str],
    location: str,
    label: str,
) -> list[Issue]:
    issues: list[Issue] = []
    if not isinstance(interaction_layer, dict):
        issues.append(Issue("custom", location, f"{label} must retain `interaction_layer`."))
        return issues

    if interaction_layer.get("foundation_contract") != GOVERNANCE_INTERACTION_LAYER_FOUNDATION:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.foundation_contract must retain the shared cross-shell token and interaction foundation for `GOVERNANCE_DENSITY_SHELL`.",
            )
        )

    if interaction_layer.get("selected_filter_chip_refs") != expected_filter_chip_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.selected_filter_chip_refs[] must be the exact canonical chip echo for the active governance filters.",
            )
        )

    if interaction_layer.get("density_profile") != GOVERNANCE_INTERACTION_DENSITY_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.density_profile must remain `{GOVERNANCE_INTERACTION_DENSITY_PROFILE}`.",
            )
        )

    if interaction_layer.get("inventory_filter_grammar") != GOVERNANCE_INTERACTION_FILTER_GRAMMAR:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.inventory_filter_grammar must remain `{GOVERNANCE_INTERACTION_FILTER_GRAMMAR}`.",
            )
        )

    if interaction_layer.get("support_surface_policy") != GOVERNANCE_INTERACTION_SUPPORT_SURFACE_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.support_surface_policy must remain `{GOVERNANCE_INTERACTION_SUPPORT_SURFACE_POLICY}`.",
            )
        )

    if interaction_layer.get("diff_basket_policy") != GOVERNANCE_INTERACTION_DIFF_BASKET_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.diff_basket_policy must remain `{GOVERNANCE_INTERACTION_DIFF_BASKET_POLICY}`.",
            )
        )

    if interaction_layer.get("export_binding_policy") != GOVERNANCE_INTERACTION_EXPORT_BINDING_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.export_binding_policy must remain `{GOVERNANCE_INTERACTION_EXPORT_BINDING_POLICY}`.",
            )
        )

    if interaction_layer.get("keyboard_focus_policy") != GOVERNANCE_INTERACTION_KEYBOARD_FOCUS_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.keyboard_focus_policy must remain `{GOVERNANCE_INTERACTION_KEYBOARD_FOCUS_POLICY}`.",
            )
        )

    if interaction_layer.get("selector_profile") != GOVERNANCE_INTERACTION_SELECTOR_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.selector_profile must remain `{GOVERNANCE_INTERACTION_SELECTOR_PROFILE}`.",
            )
        )

    if interaction_layer.get("selection_persistence_mode") != "PRESERVE_WHILE_OBJECT_RESOLVES":
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.selection_persistence_mode must remain `PRESERVE_WHILE_OBJECT_RESOLVES`.",
            )
        )

    if interaction_layer.get("focus_trap_mode") != "NON_MODAL":
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.focus_trap_mode must remain `NON_MODAL` for ordinary governance drawers and inspectors.",
            )
        )

    if interaction_layer.get("motion_profile") != GOVERNANCE_INTERACTION_MOTION_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.motion_profile must remain `{GOVERNANCE_INTERACTION_MOTION_PROFILE}`.",
            )
        )

    if interaction_layer.get("feedback_truth_policy") != GOVERNANCE_INTERACTION_FEEDBACK_TRUTH_POLICY:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.feedback_truth_policy must remain `{GOVERNANCE_INTERACTION_FEEDBACK_TRUTH_POLICY}`.",
            )
        )

    if interaction_layer.get("preserved_context_codes") != expected_preserved_context_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label}.preserved_context_codes[] must preserve the route's canonical resize/rebase context set.",
            )
        )

    compaction_mode = interaction_layer.get("compaction_mode")
    presentation = interaction_layer.get("auxiliary_surface_presentation")
    if compaction_mode == "WIDE" and presentation == "TRAY":
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} wide posture must not serialize the promoted auxiliary region as a tray.",
            )
        )
    if compaction_mode == "AUXILIARY_TRAY" and presentation != "TRAY":
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} tray compaction must serialize `auxiliary_surface_presentation = TRAY`.",
            )
        )
    if compaction_mode == "AUXILIARY_DRAWER" and presentation not in {"DRAWER", "INSPECTOR"}:
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} drawer compaction must serialize the promoted auxiliary region as a drawer or inspector.",
            )
        )
    if compaction_mode in {"AUXILIARY_DRAWER", "AUXILIARY_TRAY", "FOCUS_STACK"} and presentation == "SIDECAR":
        issues.append(
            Issue(
                "custom",
                location,
                f"{label} compact governance posture must not keep `auxiliary_surface_presentation = SIDECAR`.",
            )
        )

    return issues


def validate_governance_access_simulation(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_scope_sequence(payload.get("requested_scope"), location, "`requested_scope[]`"))
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("requested_partition_scope_refs"),
            location,
            "`requested_partition_scope_refs[]`",
        )
    )
    authority_layer_issues, authority_layer_boundary = validate_authority_layer_boundary_contract(
        payload.get("authority_layer_boundary"),
        location,
        "`authority_layer_boundary`",
        expected_binding_scope_class="GOVERNANCE_ACCESS_SIMULATION",
    )
    issues.extend(authority_layer_issues)

    authorization_decision = payload.get("authorization_decision")
    expected_decision = authorization_decision.get("decision") if isinstance(authorization_decision, dict) else None
    issues.extend(
        validate_authority_chain_layers(
            payload.get("authority_chain_layers"),
            expected_decision,
            location,
            "`authority_chain_layers[]`",
        )
    )
    if isinstance(authorization_decision, dict):
        issues.extend(
            validate_authorization_decision(
                authorization_decision,
                f"{location}.authorization_decision",
            )
        )
        for field in ("principal_context_ref", "resource_class", "action_family", "policy_snapshot_hash"):
            if authorization_decision.get(field) != payload.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`authorization_decision.{field}` must match the top-level governance simulation field.",
                    )
                )
        nested_authority_layer_boundary = authorization_decision.get("authority_layer_boundary")
        if isinstance(nested_authority_layer_boundary, dict) and isinstance(authority_layer_boundary, dict):
            comparable_top_level = {
                key: value for key, value in authority_layer_boundary.items() if key != "binding_scope_class"
            }
            comparable_nested = {
                key: value for key, value in nested_authority_layer_boundary.items() if key != "binding_scope_class"
            }
            if comparable_nested != comparable_top_level:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`authority_layer_boundary` must mirror the nested `authorization_decision.authority_layer_boundary` for every shared layer-state field.",
                    )
                )

    mutation_hazard = payload.get("mutation_hazard")
    mutation_basis_contract = payload.get("mutation_basis_contract")
    simulator_posture = payload.get("simulator_posture")
    if mutation_hazard is None:
        if isinstance(authorization_decision, dict) and any(
            authorization_decision.get(field) is not None
            for field in (
                "bounded_safe_mutation",
                "approval_requirement",
                "dependency_topology_hash",
                "simulation_basis_hash",
            )
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Simulations without `mutation_hazard` must keep governance mutation posture null on the nested `authorization_decision`.",
                )
            )
        if simulator_posture != "READ_ONLY_DECISION":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Simulations without `mutation_hazard` must keep `simulator_posture = READ_ONLY_DECISION`.",
                )
            )
        if mutation_basis_contract is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Simulations without `mutation_hazard` must keep `mutation_basis_contract = null`.",
                )
            )
        return issues

    if not isinstance(mutation_hazard, dict):
        return issues

    mutation_hazard_issues, parsed_mutation_hazard = validate_governance_mutation_hazard_contract(
        mutation_hazard,
        location,
        "`mutation_hazard`",
        expected_policy_snapshot_hash=payload.get("policy_snapshot_hash"),
        expected_access_binding_hash=authorization_decision.get("access_binding_hash"),
        expected_dependency_topology_hash=mutation_hazard.get("dependency_topology_hash")
        if isinstance(mutation_hazard.get("dependency_topology_hash"), str)
        else None,
        expected_simulation_basis_hash=mutation_hazard.get("simulation_basis_hash")
        if isinstance(mutation_hazard.get("simulation_basis_hash"), str)
        else None,
        expected_approval_requirement=mutation_hazard.get("approval_requirement")
        if isinstance(mutation_hazard.get("approval_requirement"), str)
        else None,
        expected_bounded_safe_mutation=mutation_hazard.get("bounded_safe_mutation")
        if mutation_hazard.get("bounded_safe_mutation") in {0, 1}
        else None,
        expected_required_approvals=mutation_hazard.get("required_approvals")
        if isinstance(mutation_hazard.get("required_approvals"), list)
        else None,
        expected_simulation_confidence_score=mutation_hazard.get("simulation_confidence_score")
        if isinstance(mutation_hazard.get("simulation_confidence_score"), int)
        else None,
        expected_predictability_score=mutation_hazard.get("predictability_score")
        if isinstance(mutation_hazard.get("predictability_score"), int)
        else None,
        expected_commit_authority_posture=mutation_hazard.get("commit_authority_posture")
        if isinstance(mutation_hazard.get("commit_authority_posture"), str)
        else None,
    )
    issues.extend(mutation_hazard_issues)

    if not isinstance(authorization_decision, dict):
        return issues

    mutation_basis_contract_issues, parsed_mutation_basis_contract = validate_governance_mutation_basis_contract(
        mutation_basis_contract,
        location,
        "`mutation_basis_contract`",
        expected_policy_snapshot_hash=payload.get("policy_snapshot_hash"),
        expected_access_binding_hash=authorization_decision.get("access_binding_hash"),
        expected_dependency_topology_hash=mutation_hazard.get("dependency_topology_hash"),
        expected_simulation_basis_hash=mutation_hazard.get("simulation_basis_hash"),
        expected_hazard_contract_hash=parsed_mutation_hazard.get("hazard_contract_hash")
        if isinstance(parsed_mutation_hazard, dict)
        else None,
        expected_approval_requirement=mutation_hazard.get("approval_requirement"),
        expected_bounded_safe_mutation=mutation_hazard.get("bounded_safe_mutation"),
        expected_required_approvals=mutation_hazard.get("required_approvals"),
        expected_simulation_confidence_score=mutation_hazard.get("simulation_confidence_score"),
        expected_predictability_score=mutation_hazard.get("predictability_score"),
        expected_commit_authority_posture=mutation_hazard.get("commit_authority_posture"),
    )
    issues.extend(mutation_basis_contract_issues)

    for field in (
        "bounded_safe_mutation",
        "approval_requirement",
        "dependency_topology_hash",
        "simulation_basis_hash",
    ):
        if authorization_decision.get(field) != mutation_hazard.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`authorization_decision.{field}` must match `mutation_hazard.{field}`.",
                )
            )
    if authorization_decision.get("required_approvals") != mutation_hazard.get("required_approvals"):
        issues.append(
            Issue(
                "custom",
                location,
                "`authorization_decision.required_approvals[]` must match `mutation_hazard.required_approvals[]`.",
            )
        )

    simulation_confidence_score = mutation_hazard.get("simulation_confidence_score")
    predictability_score = mutation_hazard.get("predictability_score")
    if (
        isinstance(simulation_confidence_score, int)
        and isinstance(predictability_score, int)
    ):
        if simulation_confidence_score < 80 or predictability_score < 75:
            expected_simulator_posture = "ADVISORY_ONLY"
        elif mutation_hazard.get("bounded_safe_mutation") == 1:
            expected_simulator_posture = "BOUNDED_SAFE"
        else:
            expected_simulator_posture = "APPROVAL_GATED"
        if simulator_posture != expected_simulator_posture:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`simulator_posture` must remain `{expected_simulator_posture}` for the serialized confidence, predictability, and mutation-boundedness posture.",
                )
            )
        if parsed_mutation_basis_contract:
            expected_commit_authority_posture = {
                "ADVISORY_ONLY": "PREVIEW_ONLY",
                "APPROVAL_GATED": "APPROVAL_GATED",
                "BOUNDED_SAFE": "BOUNDED_SAFE",
            }.get(expected_simulator_posture)
            if (
                expected_commit_authority_posture is not None
                and parsed_mutation_basis_contract.get("commit_authority_posture")
                != expected_commit_authority_posture
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`mutation_basis_contract.commit_authority_posture` must mirror the current `simulator_posture` mapping used for governance commits.",
                    )
                )

    return issues


def validate_principal_access_view(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_cache_isolation_contract(
            payload.get("cache_isolation_contract"),
            location,
            "`cache_isolation_contract`",
            expected_scope="PRINCIPAL_ACCESS_VIEW",
            expected_tenant_id=payload.get("tenant_id"),
            expected_client_id_or_null=None,
            expected_route_identity_ref=payload.get("object_anchor_ref"),
            expected_canonical_object_ref=payload.get("object_anchor_ref"),
            expected_shell_family=payload.get("shell_family"),
            expected_projection_version_ref=payload.get("last_modified_at"),
            expected_access_binding_hash_or_null=None,
            expected_masking_posture_fingerprint_or_null=None,
            expected_visibility_cache_partition_key_or_null=None,
            expected_customer_safe_projection=False,
            expected_preview_subject_ref_or_null=None,
            expected_shell_stability_ref_or_null=None,
        )[0]
    )

    access_workspace = payload.get("access_workspace")
    selected_action_detail = payload.get("selected_action_detail")
    focus_anchor_ref = payload.get("focus_anchor_ref")
    principal_id = payload.get("principal_id")

    action_matrix = [
        cell for cell in payload.get("action_matrix", []) if isinstance(cell, dict)
    ]
    cell_refs = [
        cell.get("cell_ref")
        for cell in action_matrix
        if isinstance(cell.get("cell_ref"), str)
    ]
    duplicate_cell_refs = duplicate_values(cell_refs)
    if duplicate_cell_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`action_matrix[].cell_ref` must remain unique; duplicates {duplicate_cell_refs}.",
            )
        )

    action_cell_by_ref = {
        cell.get("cell_ref"): cell
        for cell in action_matrix
        if isinstance(cell.get("cell_ref"), str)
    }

    for cell in action_matrix:
        issues.extend(
            validate_authority_chain_layers(
                cell.get("authority_chain_layers"),
                cell.get("decision"),
                location,
                f"`action_matrix[{cell.get('cell_ref')!r}].authority_chain_layers[]`",
            )
        )

    if isinstance(access_workspace, dict):
        issues.extend(
            validate_governance_interaction_layer(
                payload.get("interaction_layer"),
                expected_principal_access_filter_chip_refs(access_workspace.get("active_filters")),
                GOVERNANCE_INTERACTION_ACCESS_PERSISTED_CONTEXT,
                location,
                "`interaction_layer`",
            )
        )
        if access_workspace.get("surface_order") != GOVERNANCE_ACCESS_SURFACE_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`access_workspace.surface_order` must preserve the fixed access-and-roles reading order.",
                )
            )

        workspace_mode = access_workspace.get("workspace_mode")
        selected_principal_ref = access_workspace.get("selected_principal_ref")
        selected_role_template_ref = access_workspace.get("selected_role_template_ref")
        selected_cell_ref = access_workspace.get("selected_cell_ref")
        latest_simulation_ref = access_workspace.get("latest_simulation_ref")
        promoted_support_surface = access_workspace.get("promoted_support_surface")
        role_editor_pending_change_refs = access_workspace.get("role_editor_pending_change_refs")

        if workspace_mode == "PRINCIPALS" and selected_principal_ref != principal_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`workspace_mode = PRINCIPALS` must keep `selected_principal_ref` aligned to the mounted `principal_id`.",
                )
            )
        if workspace_mode != "ROLES" and role_editor_pending_change_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`role_editor_pending_change_refs[]` must clear outside `workspace_mode = ROLES`.",
                )
            )
        if workspace_mode == "SIMULATOR":
            if latest_simulation_ref is None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`workspace_mode = SIMULATOR` must retain `latest_simulation_ref`.",
                    )
                )
            if promoted_support_surface != "POLICY_SIMULATOR":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`workspace_mode = SIMULATOR` must keep `promoted_support_surface = POLICY_SIMULATOR`.",
                    )
                )
        if latest_simulation_ref is not None and workspace_mode != "SIMULATOR":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`latest_simulation_ref` must only appear when `workspace_mode = SIMULATOR`.",
                )
            )
        if workspace_mode == "ROLES" and selected_role_template_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`workspace_mode = ROLES` must keep one `selected_role_template_ref` mounted.",
                )
            )
        if selected_cell_ref is not None:
            if focus_anchor_ref != selected_cell_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`focus_anchor_ref` must stay pinned to `access_workspace.selected_cell_ref` for keyboard-stable matrix navigation.",
                    )
                )
            if selected_cell_ref not in action_cell_by_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`access_workspace.selected_cell_ref` must resolve to one serialized action-matrix cell.",
                    )
                )
        if promoted_support_surface == "AUTHORITY_CHAIN_PANEL" and selected_action_detail is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "The promoted `AUTHORITY_CHAIN_PANEL` must stay bound to one mounted `selected_action_detail`.",
                )
            )

    if isinstance(selected_action_detail, dict):
        issues.extend(
            validate_authority_chain_layers(
                selected_action_detail.get("authority_chain_layers"),
                selected_action_detail.get("decision"),
                location,
                "`selected_action_detail.authority_chain_layers[]`",
            )
        )

        matching_cell = action_cell_by_ref.get(selected_action_detail.get("cell_ref"))
        if matching_cell is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`selected_action_detail.cell_ref` must resolve to one serialized action-matrix cell.",
                )
            )
        else:
            detail_projection = (
                selected_action_detail.get("resource_class"),
                selected_action_detail.get("action_family"),
                selected_action_detail.get("decision"),
                selected_action_detail.get("reason_codes"),
                selected_action_detail.get("effective_scope"),
                selected_action_detail.get("masking_rules"),
                selected_action_detail.get("required_approvals"),
                selected_action_detail.get("required_authn_level"),
                selected_action_detail.get("policy_path_ref"),
                selected_action_detail.get("authority_chain_layers"),
            )
            matrix_projection = (
                matching_cell.get("resource_class"),
                matching_cell.get("action_family"),
                matching_cell.get("decision"),
                matching_cell.get("reason_codes"),
                matching_cell.get("effective_scope"),
                matching_cell.get("masking_rules"),
                matching_cell.get("required_approvals"),
                matching_cell.get("required_authn_level"),
                matching_cell.get("policy_path_ref"),
                matching_cell.get("authority_chain_layers"),
            )
            if detail_projection != matrix_projection:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`selected_action_detail` must mirror the mounted action-matrix cell exactly, including policy path and authority-chain explanation.",
                    )
                )

        if (
            isinstance(access_workspace, dict)
            and access_workspace.get("selected_cell_ref") != selected_action_detail.get("cell_ref")
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`selected_action_detail.cell_ref` must match `access_workspace.selected_cell_ref`.",
                )
            )

    return issues


def validate_role_template_matrix(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_cache_isolation_contract(
            payload.get("cache_isolation_contract"),
            location,
            "`cache_isolation_contract`",
            expected_scope="ROLE_TEMPLATE_MATRIX",
            expected_tenant_id=payload.get("tenant_id"),
            expected_client_id_or_null=None,
            expected_route_identity_ref=payload.get("object_anchor_ref"),
            expected_canonical_object_ref=payload.get("object_anchor_ref"),
            expected_shell_family=payload.get("shell_family"),
            expected_projection_version_ref=payload.get("version_hash"),
            expected_access_binding_hash_or_null=None,
            expected_masking_posture_fingerprint_or_null=None,
            expected_visibility_cache_partition_key_or_null=None,
            expected_customer_safe_projection=False,
            expected_preview_subject_ref_or_null=None,
            expected_shell_stability_ref_or_null=None,
        )[0]
    )

    role_id = payload.get("role_id")
    focus_anchor_ref = payload.get("focus_anchor_ref")
    role_matrix_workspace = payload.get("role_matrix_workspace")
    selected_action_detail = payload.get("selected_action_detail")

    matrix_cells = [
        cell for cell in payload.get("matrix_cells", []) if isinstance(cell, dict)
    ]
    cell_refs = [
        cell.get("cell_ref")
        for cell in matrix_cells
        if isinstance(cell.get("cell_ref"), str)
    ]
    duplicate_cell_refs = duplicate_values(cell_refs)
    if duplicate_cell_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`matrix_cells[].cell_ref` must remain unique; duplicates {duplicate_cell_refs}.",
            )
        )

    cell_by_ref = {
        cell.get("cell_ref"): cell
        for cell in matrix_cells
        if isinstance(cell.get("cell_ref"), str)
    }

    row_classes: list[str] = []
    for row in payload.get("matrix_rows", []):
        if not isinstance(row, dict):
            continue
        resource_class = row.get("resource_class")
        if isinstance(resource_class, str):
            row_classes.append(resource_class)
        for cell_ref in row.get("cell_refs", []):
            cell = cell_by_ref.get(cell_ref)
            if cell is None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`matrix_rows[{resource_class!r}].cell_refs[]` must resolve to serialized matrix cells; missing {cell_ref!r}.",
                    )
                )
                continue
            if cell.get("resource_class") != resource_class:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`matrix_rows[{resource_class!r}].cell_refs[]` must only contain cells for that resource class.",
                    )
                )

    duplicate_row_classes = duplicate_values(row_classes)
    if duplicate_row_classes:
        issues.append(
            Issue(
                "custom",
                location,
                f"`matrix_rows[].resource_class` must remain unique; duplicates {duplicate_row_classes}.",
            )
        )

    column_families: list[str] = []
    for column in payload.get("matrix_columns", []):
        if not isinstance(column, dict):
            continue
        action_family = column.get("action_family")
        if isinstance(action_family, str):
            column_families.append(action_family)
    duplicate_column_families = duplicate_values(column_families)
    if duplicate_column_families:
        issues.append(
            Issue(
                "custom",
                location,
                f"`matrix_columns[].action_family` must remain unique; duplicates {duplicate_column_families}.",
            )
        )

    row_class_set = set(row_classes)
    column_family_set = set(column_families)
    for cell in matrix_cells:
        resource_class = cell.get("resource_class")
        action_family = cell.get("action_family")
        if isinstance(resource_class, str) and resource_class not in row_class_set:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`matrix_cells[{cell.get('cell_ref')!r}].resource_class` must appear in `matrix_rows[]`.",
                )
            )
        if isinstance(action_family, str) and action_family not in column_family_set:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`matrix_cells[{cell.get('cell_ref')!r}].action_family` must appear in `matrix_columns[]`.",
                )
            )

    if isinstance(role_matrix_workspace, dict):
        issues.extend(
            validate_governance_interaction_layer(
                payload.get("interaction_layer"),
                expected_role_template_matrix_filter_chip_refs(role_matrix_workspace.get("active_filters")),
                GOVERNANCE_INTERACTION_ACCESS_PERSISTED_CONTEXT,
                location,
                "`interaction_layer`",
            )
        )
        if role_matrix_workspace.get("surface_order") != GOVERNANCE_ACCESS_SURFACE_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`role_matrix_workspace.surface_order` must preserve the fixed access-and-roles reading order.",
                )
            )

        active_filters = role_matrix_workspace.get("active_filters", {})
        if isinstance(active_filters, dict):
            issues.extend(
                validate_sorted_string_sequence(
                    active_filters.get("resource_classes"),
                    location,
                    "`role_matrix_workspace.active_filters.resource_classes[]`",
                )
            )
            issues.extend(
                validate_sorted_string_sequence(
                    active_filters.get("action_families"),
                    location,
                    "`role_matrix_workspace.active_filters.action_families[]`",
                )
            )
            issues.extend(
                validate_ordered_enum_sequence(
                    active_filters.get("decision_outcomes"),
                    location,
                    "`role_matrix_workspace.active_filters.decision_outcomes[]`",
                    ACCESS_DECISION_SEVERITY,
                )
            )

        if role_matrix_workspace.get("selected_role_template_ref") != role_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`role_matrix_workspace.selected_role_template_ref` must stay aligned to the mounted `role_id`.",
                )
            )

        selected_cell_ref = role_matrix_workspace.get("selected_cell_ref")
        inspector_state = role_matrix_workspace.get("inspector_state")
        latest_simulation_ref = role_matrix_workspace.get("latest_simulation_ref")
        promoted_support_surface = role_matrix_workspace.get("promoted_support_surface")
        role_editor_pending_change_refs = role_matrix_workspace.get("role_editor_pending_change_refs")

        if latest_simulation_ref is not None and promoted_support_surface != "POLICY_SIMULATOR":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`latest_simulation_ref` must only appear when `promoted_support_surface = POLICY_SIMULATOR`.",
                )
            )
        if role_editor_pending_change_refs and inspector_state != "ROLE_EDITING":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`role_editor_pending_change_refs[]` must only remain populated while `inspector_state = ROLE_EDITING`.",
                )
            )
        if inspector_state == "HIDDEN":
            if selected_cell_ref is not None or selected_action_detail is not None or focus_anchor_ref is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`inspector_state = HIDDEN` must clear selected cell, focus anchor, and `selected_action_detail`.",
                    )
                )
        if inspector_state in {"CELL_SELECTED", "ROLE_EDITING"} and selected_cell_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`inspector_state = {inspector_state}` must keep one `selected_cell_ref` mounted.",
                )
            )
        if selected_cell_ref is not None:
            if focus_anchor_ref != selected_cell_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`focus_anchor_ref` must stay pinned to `role_matrix_workspace.selected_cell_ref` for keyboard-stable matrix navigation.",
                    )
                )
            if selected_cell_ref not in cell_by_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`role_matrix_workspace.selected_cell_ref` must resolve to one serialized matrix cell.",
                    )
                )

    if isinstance(selected_action_detail, dict):
        matching_cell = cell_by_ref.get(selected_action_detail.get("cell_ref"))
        if matching_cell is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`selected_action_detail.cell_ref` must resolve to one serialized matrix cell.",
                )
            )
        else:
            detail_projection = (
                selected_action_detail.get("resource_class"),
                selected_action_detail.get("action_family"),
                selected_action_detail.get("decision"),
                selected_action_detail.get("reason_codes"),
                selected_action_detail.get("effective_scope"),
                selected_action_detail.get("masking_rules"),
                selected_action_detail.get("required_approvals"),
                selected_action_detail.get("required_authn_level"),
                selected_action_detail.get("policy_path_ref"),
                selected_action_detail.get("pending_change_ref_or_null"),
            )
            matrix_projection = (
                matching_cell.get("resource_class"),
                matching_cell.get("action_family"),
                matching_cell.get("decision"),
                matching_cell.get("reason_codes"),
                matching_cell.get("effective_scope"),
                matching_cell.get("masking_rules"),
                matching_cell.get("required_approvals"),
                matching_cell.get("required_authn_level"),
                matching_cell.get("policy_path_ref"),
                matching_cell.get("pending_change_ref_or_null"),
            )
            if detail_projection != matrix_projection:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`selected_action_detail` must mirror the mounted role-matrix cell exactly, including policy path and pending-change posture.",
                    )
                )

        if (
            isinstance(role_matrix_workspace, dict)
            and role_matrix_workspace.get("selected_cell_ref") != selected_action_detail.get("cell_ref")
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`selected_action_detail.cell_ref` must match `role_matrix_workspace.selected_cell_ref`.",
                )
            )

    return issues


def validate_authority_link_inventory_item(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []

    authority_link_id = payload.get("authority_link_id")
    binding_health = payload.get("binding_health")
    delegation_state = payload.get("delegation_state")
    token_client_binding_state = payload.get("token_client_binding_state")
    lifecycle_state = payload.get("lifecycle_state")
    focus_anchor_ref = payload.get("focus_anchor_ref")

    if payload.get("object_anchor_ref") != authority_link_id:
        issues.append(
            Issue(
                "custom",
                location,
                "`object_anchor_ref` must stay pinned to the mounted `authority_link_id`.",
            )
        )

    workspace = payload.get("authority_link_workspace")
    workspace_prominent_issue_ref = None
    if isinstance(workspace, dict):
        issues.extend(
            validate_governance_interaction_layer(
                payload.get("interaction_layer"),
                expected_authority_link_filter_chip_refs(workspace.get("active_filters")),
                GOVERNANCE_INTERACTION_AUTHORITY_LINK_PERSISTED_CONTEXT,
                location,
                "`interaction_layer`",
            )
        )
        if workspace.get("surface_order") != AUTHORITY_LINK_SURFACE_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`authority_link_workspace.surface_order` must preserve the fixed authority-links reading order.",
                )
            )
        if workspace.get("selected_authority_link_ref") != authority_link_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`authority_link_workspace.selected_authority_link_ref` must stay aligned to the mounted `authority_link_id`.",
                )
            )
        if workspace.get("detail_module_order") != AUTHORITY_LINK_DETAIL_MODULE_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`authority_link_workspace.detail_module_order` must preserve the fixed authority-link detail-module order.",
                )
            )

        active_filters = workspace.get("active_filters", {})
        if isinstance(active_filters, dict):
            for field in (
                "authority_scopes",
                "client_refs",
                "provider_environments",
                "lifecycle_states",
                "binding_health_states",
                "expiry_risk_bands",
            ):
                issues.extend(
                    validate_sorted_string_sequence(
                        active_filters.get(field),
                        location,
                        f"`authority_link_workspace.active_filters.{field}[]`",
                    )
                )

        workspace_prominent_issue_ref = workspace.get("prominent_issue_ref_or_null")

    stepper = payload.get("guided_handshake_stepper")
    stepper_flow_state = stepper.get("flow_state") if isinstance(stepper, dict) else None
    if isinstance(stepper, dict):
        if stepper.get("step_order") != AUTHORITY_LINK_HANDSHAKE_STEP_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`guided_handshake_stepper.step_order` must preserve the canonical guided-handshake sequence.",
                )
            )

        completed_step_codes = stepper.get("completed_step_codes", [])
        if isinstance(completed_step_codes, list) and all(
            isinstance(step_code, str) for step_code in completed_step_codes
        ):
            expected_prefix = AUTHORITY_LINK_HANDSHAKE_STEP_ORDER[: len(completed_step_codes)]
            if completed_step_codes != expected_prefix:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`guided_handshake_stepper.completed_step_codes[]` must remain a gap-free prefix of the guided handshake sequence.",
                    )
                )

        current_step_code = stepper.get("current_step_code")
        if stepper_flow_state == "LINKED":
            if (
                completed_step_codes != AUTHORITY_LINK_HANDSHAKE_STEP_ORDER
                or current_step_code != AUTHORITY_LINK_HANDSHAKE_STEP_ORDER[-1]
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`guided_handshake_stepper.flow_state = LINKED` must keep all handshake steps complete and the current step on `VALIDATE_BINDING`.",
                    )
                )
        elif isinstance(completed_step_codes, list) and len(completed_step_codes) < len(
            AUTHORITY_LINK_HANDSHAKE_STEP_ORDER
        ):
            expected_current_step = AUTHORITY_LINK_HANDSHAKE_STEP_ORDER[len(completed_step_codes)]
            if current_step_code != expected_current_step:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`guided_handshake_stepper.current_step_code` must stay aligned with the next incomplete guided-handshake step.",
                    )
                )

        if stepper_flow_state == "LINKED" and stepper.get("preflight_blocking_check_refs"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`guided_handshake_stepper.preflight_blocking_check_refs[]` must clear once the link is fully validated.",
                )
            )

    if lifecycle_state == "LINK_INITIATED" and stepper_flow_state not in {
        "IN_PROGRESS",
        "HANDOFF_PENDING",
        "VALIDATION_PENDING",
        "BLOCKED",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state = LINK_INITIATED` must keep the guided handshake in progress, handoff pending, validation pending, or blocked posture.",
            )
        )
    if lifecycle_state in {"AUTHORISED_ACTIVE", "AUTHORISED_LIMITED"} and stepper_flow_state == "NOT_STARTED":
        issues.append(
            Issue(
                "custom",
                location,
                "Authorised authority links must not render the guided handshake as `NOT_STARTED`.",
            )
        )
    if lifecycle_state == "UNLINKED" and stepper_flow_state not in {None, "NOT_STARTED", "BLOCKED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state = UNLINKED` must keep the guided handshake either untouched or explicitly blocked.",
            )
        )
    if stepper_flow_state == "LINKED" and lifecycle_state not in {None, "AUTHORISED_ACTIVE", "AUTHORISED_LIMITED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`guided_handshake_stepper.flow_state = LINKED` is only legal for authorised authority-link lifecycle states.",
            )
        )

    if isinstance(workspace, dict):
        guided_flow_mode = workspace.get("guided_flow_mode")
        if stepper_flow_state in {"IN_PROGRESS", "HANDOFF_PENDING", "VALIDATION_PENDING", "BLOCKED"} and guided_flow_mode not in {
            "LINK",
            "RELINK",
        }:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "In-flight or blocked handshake posture must keep `authority_link_workspace.guided_flow_mode` in `LINK` or `RELINK`.",
                )
            )

    timeline = payload.get("binding_health_timeline")
    timeline_promoted_issue_ref = None
    if isinstance(timeline, dict):
        if timeline.get("current_binding_health") != binding_health:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`binding_health_timeline.current_binding_health` must mirror the top-level `binding_health`.",
                )
            )
        if timeline.get("current_delegation_state") != delegation_state:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`binding_health_timeline.current_delegation_state` must mirror the top-level `delegation_state`.",
                )
            )
        if timeline.get("current_token_client_binding_state") != token_client_binding_state:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`binding_health_timeline.current_token_client_binding_state` must mirror the top-level `token_client_binding_state`.",
                )
            )
        timeline_promoted_issue_ref = timeline.get("promoted_issue_ref_or_null")

    if delegation_state == "MISSING" and binding_health != "DELEGATION_GAP":
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state = MISSING` must render `binding_health = DELEGATION_GAP`.",
            )
        )
    if delegation_state == "EXPIRED" and binding_health not in {"DELEGATION_GAP", "EXPIRED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state = EXPIRED` must keep authority-link health in `DELEGATION_GAP` or `EXPIRED` posture.",
            )
        )

    if binding_health in AUTHORITY_LINK_PROMINENT_HEALTH_STATES:
        if not (
            isinstance(workspace_prominent_issue_ref, str)
            and isinstance(timeline_promoted_issue_ref, str)
            and workspace_prominent_issue_ref == timeline_promoted_issue_ref
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Critical authority-link mismatch states must publish one shared prominent issue ref in both `authority_link_workspace` and `binding_health_timeline`.",
                )
            )

    history = payload.get("handshake_history")
    selected_attempt_ref = None
    history_latest_attempt_state = None
    if isinstance(history, dict):
        attempt_refs = history.get("attempt_refs", [])
        if not isinstance(attempt_refs, list):
            attempt_refs = []
        selected_attempt_ref = history.get("selected_attempt_ref_or_null")
        history_latest_attempt_state = history.get("latest_attempt_state")
        if selected_attempt_ref is not None and selected_attempt_ref not in attempt_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`handshake_history.selected_attempt_ref_or_null` must resolve to one serialized handshake attempt.",
                )
            )
        if history_latest_attempt_state != "NONE_RECORDED" and not attempt_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Recorded handshake-history states must retain at least one `attempt_refs[]` entry.",
                )
            )
        if stepper_flow_state in {"HANDOFF_PENDING", "VALIDATION_PENDING"} and history_latest_attempt_state != "PENDING_RETURN":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Pending external handoff or validation posture must keep `handshake_history.latest_attempt_state = PENDING_RETURN`.",
                )
            )
        if history_latest_attempt_state == "PENDING_RETURN" and stepper_flow_state not in {
            "HANDOFF_PENDING",
            "VALIDATION_PENDING",
        }:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`handshake_history.latest_attempt_state = PENDING_RETURN` must align with pending handoff or validation posture in the guided stepper.",
                )
            )
        if stepper_flow_state not in {None, "NOT_STARTED"} and history_latest_attempt_state == "NONE_RECORDED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Any mounted guided-handshake progress must retain a non-empty handshake-history state.",
                )
            )

    checklist = payload.get("preflight_checklist")
    checklist_blocking_refs: list[str] = []
    checklist_check_refs: list[str] = []
    if isinstance(checklist, dict):
        checks = checklist.get("checks", [])
        if not isinstance(checks, list):
            checks = []
        check_codes = [
            check.get("check_code") for check in checks if isinstance(check, dict)
        ]
        if check_codes != AUTHORITY_LINK_PREFLIGHT_CHECK_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preflight_checklist.checks[].check_code` must preserve the canonical preflight-check order.",
                )
            )

        checklist_check_refs = [
            check.get("check_ref") for check in checks if isinstance(check.get("check_ref"), str)
        ]
        duplicate_check_refs = duplicate_values(checklist_check_refs)
        if duplicate_check_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`preflight_checklist.checks[].check_ref` must remain unique; duplicates {duplicate_check_refs}.",
                )
            )

        blocked_from_checks: list[str] = []
        for check in checks:
            if not isinstance(check, dict):
                continue
            check_state = check.get("check_state")
            check_ref = check.get("check_ref")
            reason_refs = check.get("reason_refs", [])
            if check_state == "BLOCKED":
                if isinstance(check_ref, str):
                    blocked_from_checks.append(check_ref)
                if not reason_refs:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`preflight_checklist.checks[{check_ref!r}]` must retain `reason_refs[]` when blocked.",
                        )
                    )
            if check_state == "NOT_RUN" and reason_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`preflight_checklist.checks[{check_ref!r}]` must clear `reason_refs[]` while `check_state = NOT_RUN`.",
                    )
                )

        checklist_blocking_refs = checklist.get("blocking_check_refs", [])
        if not isinstance(checklist_blocking_refs, list):
            checklist_blocking_refs = []
        if checklist_blocking_refs != blocked_from_checks:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preflight_checklist.blocking_check_refs[]` must mirror the blocked preflight checks in checklist order.",
                )
            )

        last_run_at = checklist.get("last_run_at_or_null")
        if last_run_at is None and any(
            isinstance(check, dict) and check.get("check_state") != "NOT_RUN" for check in checks
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preflight_checklist.last_run_at_or_null` must be populated once any preflight check has executed.",
                )
            )
        if last_run_at is not None and all(
            isinstance(check, dict) and check.get("check_state") == "NOT_RUN" for check in checks
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preflight_checklist.last_run_at_or_null` must clear when every preflight check remains `NOT_RUN`.",
                )
            )

        if isinstance(stepper, dict) and stepper.get("preflight_blocking_check_refs") != checklist_blocking_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`guided_handshake_stepper.preflight_blocking_check_refs[]` must mirror `preflight_checklist.blocking_check_refs[]`.",
                )
            )

    operations = payload.get("affected_operation_list")
    primary_blocked_operation_ref = None
    operation_refs: set[str] = set()
    if isinstance(operations, dict):
        if operations.get("section_order") != ["PREFLIGHT", "SUBMISSION", "RECONCILIATION", "AMENDMENT"]:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`affected_operation_list.section_order` must preserve the canonical affected-operation order.",
                )
            )

        preflight_refs = operations.get("preflight_refs", [])
        submission_refs = operations.get("submission_refs", [])
        reconciliation_refs = operations.get("reconciliation_refs", [])
        amendment_refs = operations.get("amendment_refs", [])
        if not isinstance(preflight_refs, list):
            preflight_refs = []
        if not isinstance(submission_refs, list):
            submission_refs = []
        if not isinstance(reconciliation_refs, list):
            reconciliation_refs = []
        if not isinstance(amendment_refs, list):
            amendment_refs = []

        counts = payload.get("affected_operation_counts", {})
        if isinstance(counts, dict):
            expected_lengths = {
                "preflight_refs": counts.get("preflight_count"),
                "submission_refs": counts.get("submission_count"),
                "reconciliation_refs": counts.get("reconciliation_count"),
                "amendment_refs": counts.get("amendment_count"),
            }
            actual_lengths = {
                "preflight_refs": len(preflight_refs),
                "submission_refs": len(submission_refs),
                "reconciliation_refs": len(reconciliation_refs),
                "amendment_refs": len(amendment_refs),
            }
            for field, expected_length in expected_lengths.items():
                if isinstance(expected_length, int) and actual_lengths[field] != expected_length:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`affected_operation_list.{field}` must contain exactly {expected_length} refs to match `affected_operation_counts`.",
                        )
                    )

        operation_refs = set(preflight_refs) | set(submission_refs) | set(reconciliation_refs) | set(amendment_refs)
        primary_blocked_operation_ref = operations.get("primary_blocked_operation_ref_or_null")
        if primary_blocked_operation_ref is not None and primary_blocked_operation_ref not in operation_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`affected_operation_list.primary_blocked_operation_ref_or_null` must resolve to one serialized affected operation ref.",
                )
            )

    allowed_focus_refs = {authority_link_id}
    for candidate in (
        workspace_prominent_issue_ref,
        timeline_promoted_issue_ref,
        selected_attempt_ref,
        primary_blocked_operation_ref,
    ):
        if isinstance(candidate, str):
            allowed_focus_refs.add(candidate)
    allowed_focus_refs.update(ref for ref in checklist_check_refs if isinstance(ref, str))
    allowed_focus_refs.update(ref for ref in checklist_blocking_refs if isinstance(ref, str))
    allowed_focus_refs.update(ref for ref in operation_refs if isinstance(ref, str))
    if focus_anchor_ref not in allowed_focus_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`focus_anchor_ref` must remain bound to the mounted authority link, a promoted issue, a preflight check, an affected operation, or the selected handshake attempt.",
            )
        )

    authority_handoff_target = (
        stepper.get("external_handoff_ref_or_null") if isinstance(stepper, dict) else None
    )
    authority_externalization_eligibility = "READY"
    if stepper_flow_state == "BLOCKED":
        authority_externalization_eligibility = "BLOCKED"
    elif stepper_flow_state in {"HANDOFF_PENDING", "VALIDATION_PENDING"}:
        authority_externalization_eligibility = "PENDING_RETURN"
    authority_externalization_limitation = (
        "PREFLIGHT_BLOCKED" if checklist_blocking_refs else "FULL"
    )
    externalization_issues, _ = validate_externalization_governance_contract(
        payload.get("externalization_governance_contract"),
        location,
        "`externalization_governance_contract`",
        expected_boundary_scope="AUTHORITY_LINK_HANDOFF",
        expected_tenant_id=payload.get("tenant_id"),
        expected_shell_family_or_null="GOVERNANCE_DENSITY_SHELL",
        expected_context_anchor_ref=authority_link_id,
        expected_slice_binding_ref=authority_link_id,
        expected_delivery_surface_kind="AUTHORITY_LINK_EXTERNAL_HANDOFF",
        expected_history_meaning_state="HANDOFF_TARGET_EXPLICIT",
        expected_eligibility_state=authority_externalization_eligibility,
        expected_approval_state="NOT_REQUIRED",
        expected_access_binding_hash_or_null=None,
        expected_masking_state="NOT_APPLICABLE",
        expected_masking_posture_fingerprint_or_null=None,
        expected_limitation_state=authority_externalization_limitation,
        expected_visibility_cache_partition_key_or_null=None,
        expected_preview_target_ref_or_null=None,
        expected_download_target_ref_or_null=None,
        expected_print_target_ref_or_null=None,
        expected_external_handoff_target_ref_or_null=authority_handoff_target,
        expected_approval_requirement_token_or_null=None,
        expected_blocking_context_tokens=checklist_blocking_refs,
    )
    issues.extend(externalization_issues)

    return issues


def validate_retention_governance_frame(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []

    workspace = payload.get("retention_workspace")
    policy_matrix = payload.get("retention_policy_matrix")
    legal_hold_register = payload.get("legal_hold_register")
    erasure_queue = payload.get("erasure_queue")
    impact_preview = payload.get("retention_impact_preview")
    focus_anchor_ref = payload.get("focus_anchor_ref")
    object_anchor_ref = payload.get("object_anchor_ref")

    if isinstance(workspace, dict):
        issues.extend(
            validate_governance_interaction_layer(
                payload.get("interaction_layer"),
                expected_retention_filter_chip_refs(workspace.get("active_filters")),
                GOVERNANCE_INTERACTION_RETENTION_PERSISTED_CONTEXT,
                location,
                "`interaction_layer`",
            )
        )

    artifact_rows = [
        row for row in payload.get("artifact_rows", []) if isinstance(row, dict)
    ]
    row_refs = [
        row.get("row_ref")
        for row in artifact_rows
        if isinstance(row.get("row_ref"), str)
    ]
    duplicate_row_refs = duplicate_values(row_refs)
    if duplicate_row_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`artifact_rows[].row_ref` must remain unique; duplicates {duplicate_row_refs}.",
            )
        )
    row_by_ref = {
        row.get("row_ref"): row
        for row in artifact_rows
        if isinstance(row.get("row_ref"), str)
    }

    calculated_limitation_count = 0
    for row in artifact_rows:
        limitation_count = row.get("limitation_count")
        if isinstance(limitation_count, int):
            calculated_limitation_count += limitation_count

        warning_posture = row.get("warning_posture")
        blocking_reason_refs = row.get("blocking_reason_refs")
        if warning_posture == "STATUTORY_BLOCK" and not blocking_reason_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`artifact_rows[{row.get('row_ref')!r}]` must retain `blocking_reason_refs[]` for statutory blockers.",
                )
            )
        if warning_posture == "APPROVAL_OR_STEP_UP_REQUIRED" and row.get("staged_change_ref_or_null") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`artifact_rows[{row.get('row_ref')!r}]` must retain `staged_change_ref_or_null` when approval or step-up review is required.",
                )
            )
        if row.get("legal_hold_count") == 0 and row.get("legal_hold_register_ref_or_null") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`artifact_rows[{row.get('row_ref')!r}]` must clear `legal_hold_register_ref_or_null` when no legal holds remain.",
                )
            )
        if row.get("erasure_eligible_count") == 0 and row.get("erasure_queue_ref_or_null") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`artifact_rows[{row.get('row_ref')!r}]` must clear `erasure_queue_ref_or_null` when nothing is erasure-eligible.",
                )
            )

    if payload.get("limitation_count") != calculated_limitation_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`limitation_count` must equal the summed `artifact_rows[].limitation_count` projection.",
            )
        )

    if isinstance(policy_matrix, dict):
        if policy_matrix.get("column_order") != RETENTION_POLICY_MATRIX_COLUMN_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`retention_policy_matrix.column_order` must preserve the canonical retention-matrix reading order.",
                )
            )
        if policy_matrix.get("row_refs") != row_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`retention_policy_matrix.row_refs[]` must mirror `artifact_rows[].row_ref` in published matrix order.",
                )
            )
        selected_row_ref = policy_matrix.get("selected_row_ref")
        if selected_row_ref is not None and selected_row_ref not in row_by_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`retention_policy_matrix.selected_row_ref` must resolve to one serialized artifact row.",
                )
            )

    legal_hold_count = 0
    hold_refs: list[str] = []
    blocking_hold_refs: list[str] = []
    release_candidate_hold_refs: list[str] = []
    if isinstance(legal_hold_register, dict):
        if legal_hold_register.get("column_order") != RETENTION_LEGAL_HOLD_COLUMN_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`legal_hold_register.column_order` must preserve the canonical legal-hold register columns.",
                )
            )
        hold_refs = [
            ref
            for ref in legal_hold_register.get("hold_refs", [])
            if isinstance(ref, str)
        ]
        legal_hold_count = len(hold_refs)
        if payload.get("legal_hold_count") != legal_hold_count:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`legal_hold_count` must equal `legal_hold_register.hold_refs[]` length.",
                )
            )
        blocking_hold_refs = [
            ref
            for ref in legal_hold_register.get("blocking_hold_refs", [])
            if isinstance(ref, str)
        ]
        release_candidate_hold_refs = [
            ref
            for ref in legal_hold_register.get("release_candidate_hold_refs", [])
            if isinstance(ref, str)
        ]
        for field_name, refs in (
            ("blocking_hold_refs", blocking_hold_refs),
            ("release_candidate_hold_refs", release_candidate_hold_refs),
        ):
            missing_refs = [ref for ref in refs if ref not in hold_refs]
            if missing_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`legal_hold_register.{field_name}[]` must stay within `hold_refs[]`; missing {missing_refs}.",
                    )
                )
        selected_hold_ref = legal_hold_register.get("selected_hold_ref_or_null")
        if selected_hold_ref is not None and selected_hold_ref not in hold_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`legal_hold_register.selected_hold_ref_or_null` must resolve to one serialized hold ref.",
                )
            )

    erasure_item_refs: list[str] = []
    blocked_item_refs: list[str] = []
    pending_review_item_refs: list[str] = []
    if isinstance(erasure_queue, dict):
        if erasure_queue.get("section_order") != RETENTION_ERASURE_SECTION_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`erasure_queue.section_order` must preserve the canonical eligible/blocked/pending-review order.",
                )
            )
        eligible_item_refs = [
            ref
            for ref in erasure_queue.get("eligible_item_refs", [])
            if isinstance(ref, str)
        ]
        blocked_item_refs = [
            ref
            for ref in erasure_queue.get("blocked_item_refs", [])
            if isinstance(ref, str)
        ]
        pending_review_item_refs = [
            ref
            for ref in erasure_queue.get("pending_review_item_refs", [])
            if isinstance(ref, str)
        ]
        erasure_item_refs = eligible_item_refs + blocked_item_refs + pending_review_item_refs
        duplicate_erasure_refs = duplicate_values(erasure_item_refs)
        if duplicate_erasure_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`erasure_queue` refs must be disjoint across sections; duplicates {duplicate_erasure_refs}.",
                )
            )
        if payload.get("erasure_queue_count") != len(erasure_item_refs):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`erasure_queue_count` must equal the total serialized erasure-queue refs across all sections.",
                )
            )
        selected_item_ref = erasure_queue.get("selected_item_ref_or_null")
        if selected_item_ref is not None and selected_item_ref not in erasure_item_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`erasure_queue.selected_item_ref_or_null` must resolve to one serialized erasure-queue ref.",
                )
            )
        primary_blocker_ref = erasure_queue.get("primary_blocker_ref_or_null")
        if primary_blocker_ref is not None and primary_blocker_ref not in blocked_item_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`erasure_queue.primary_blocker_ref_or_null` must resolve to one blocked queue ref.",
                )
            )

    if isinstance(workspace, dict):
        if workspace.get("surface_order") != RETENTION_GOVERNANCE_SURFACE_ORDER:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`retention_workspace.surface_order` must preserve the fixed retention/privacy route reading order.",
                )
            )
        active_filters = workspace.get("active_filters", {})
        if isinstance(active_filters, dict):
            for field in (
                "artifact_classes",
                "retention_classes",
                "client_refs",
                "legal_hold_states",
                "release_eligibility_states",
                "erasure_readiness_states",
            ):
                issues.extend(
                    validate_sorted_string_sequence(
                        active_filters.get(field),
                        location,
                        f"`retention_workspace.active_filters.{field}[]`",
                    )
                )

        workspace_mode = workspace.get("workspace_mode")
        selected_policy_row_ref = workspace.get("selected_policy_row_ref")
        selected_legal_hold_ref = workspace.get("selected_legal_hold_ref")
        selected_erasure_item_ref = workspace.get("selected_erasure_item_ref")
        promoted_support_surface = workspace.get("promoted_support_surface")
        workspace_warning_posture = workspace.get("warning_posture")

        if workspace_mode == "POLICIES":
            if selected_policy_row_ref not in row_by_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`workspace_mode = POLICIES` must keep one mounted `selected_policy_row_ref`.",
                    )
                )
            if isinstance(policy_matrix, dict) and policy_matrix.get("selected_row_ref") != selected_policy_row_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`retention_policy_matrix.selected_row_ref` must match `retention_workspace.selected_policy_row_ref`.",
                    )
                )
            if object_anchor_ref != selected_policy_row_ref or focus_anchor_ref != selected_policy_row_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Policy mode must pin both `object_anchor_ref` and `focus_anchor_ref` to the selected retention-policy row.",
                    )
                )
            selected_row = row_by_ref.get(selected_policy_row_ref)
            if isinstance(selected_row, dict) and workspace_warning_posture != selected_row.get("warning_posture"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`retention_workspace.warning_posture` must mirror the selected retention-policy row warning posture.",
                    )
                )
            if isinstance(impact_preview, dict):
                if impact_preview.get("preview_mode") != "POLICY_CHANGE":
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Policy mode must keep `retention_impact_preview.preview_mode = POLICY_CHANGE`.",
                        )
                    )
                if impact_preview.get("preview_subject_ref_or_null") != selected_policy_row_ref:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "`retention_impact_preview.preview_subject_ref_or_null` must track the selected policy row in policy mode.",
                        )
                    )
                if (
                    isinstance(selected_row, dict)
                    and selected_row.get("warning_posture") != "NONE"
                    and promoted_support_surface != "RETENTION_IMPACT_PREVIEW"
                ):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Rows with visible retention warnings must promote `RETENTION_IMPACT_PREVIEW` instead of leaving blocker review buried in the audit sidecar.",
                        )
                    )

        if workspace_mode == "LEGAL_HOLDS":
            if selected_legal_hold_ref not in hold_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`workspace_mode = LEGAL_HOLDS` must keep one mounted `selected_legal_hold_ref` from the legal-hold register.",
                    )
                )
            if (
                isinstance(legal_hold_register, dict)
                and legal_hold_register.get("selected_hold_ref_or_null") != selected_legal_hold_ref
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`legal_hold_register.selected_hold_ref_or_null` must match `retention_workspace.selected_legal_hold_ref`.",
                    )
                )
            if object_anchor_ref != selected_legal_hold_ref or focus_anchor_ref != selected_legal_hold_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Legal-hold mode must pin both `object_anchor_ref` and `focus_anchor_ref` to the selected hold.",
                    )
                )
            if isinstance(legal_hold_register, dict):
                release_preview_ref = legal_hold_register.get("release_preview_ref_or_null")
                if release_preview_ref is None:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Selected legal holds must retain `release_preview_ref_or_null` so release consequences stay visible before action.",
                        )
                    )
                if isinstance(impact_preview, dict):
                    if impact_preview.get("preview_mode") != "HOLD_RELEASE":
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                "Legal-hold mode must keep `retention_impact_preview.preview_mode = HOLD_RELEASE`.",
                            )
                        )
                    if impact_preview.get("preview_subject_ref_or_null") != release_preview_ref:
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                "`retention_impact_preview.preview_subject_ref_or_null` must follow `legal_hold_register.release_preview_ref_or_null` in legal-hold mode.",
                            )
                        )
                    if workspace_warning_posture != impact_preview.get("warning_posture"):
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                "`retention_workspace.warning_posture` must mirror the mounted legal-hold impact preview warning posture.",
                            )
                        )

        if workspace_mode == "ERASURE":
            if selected_erasure_item_ref not in erasure_item_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`workspace_mode = ERASURE` must keep one mounted `selected_erasure_item_ref` from the erasure queue.",
                    )
                )
            if isinstance(erasure_queue, dict) and erasure_queue.get("selected_item_ref_or_null") != selected_erasure_item_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`erasure_queue.selected_item_ref_or_null` must match `retention_workspace.selected_erasure_item_ref`.",
                    )
                )
            if object_anchor_ref != selected_erasure_item_ref or focus_anchor_ref != selected_erasure_item_ref:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Erasure mode must pin both `object_anchor_ref` and `focus_anchor_ref` to the selected erasure candidate.",
                    )
                )
            if promoted_support_surface != "RETENTION_IMPACT_PREVIEW":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Erasure mode must promote `RETENTION_IMPACT_PREVIEW` while destructive review is active.",
                    )
                )
            if isinstance(impact_preview, dict):
                if impact_preview.get("preview_mode") != "ERASURE_ACTION":
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Erasure mode must keep `retention_impact_preview.preview_mode = ERASURE_ACTION`.",
                        )
                    )
                if impact_preview.get("preview_subject_ref_or_null") != selected_erasure_item_ref:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "`retention_impact_preview.preview_subject_ref_or_null` must track the selected erasure candidate.",
                        )
                    )
                if workspace_warning_posture != impact_preview.get("warning_posture"):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "`retention_workspace.warning_posture` must mirror the mounted erasure impact preview warning posture.",
                        )
                    )
                if selected_erasure_item_ref in blocked_item_refs and impact_preview.get("action_posture") != "BLOCKED":
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Blocked erasure candidates must keep `retention_impact_preview.action_posture = BLOCKED`.",
                        )
                    )
                if (
                    selected_erasure_item_ref in blocked_item_refs
                    and impact_preview.get("warning_posture") != "LEGAL_HOLD_BLOCK"
                ):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Blocked erasure candidates must keep `retention_impact_preview.warning_posture = LEGAL_HOLD_BLOCK`.",
                        )
                    )
                if (
                    selected_erasure_item_ref in blocked_item_refs
                    and not impact_preview.get("blocked_reason_refs")
                ):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Blocked erasure candidates must retain `blocked_reason_refs[]` in the impact preview.",
                        )
                    )
                if (
                    selected_erasure_item_ref in (set(erasure_item_refs) - set(blocked_item_refs))
                    and impact_preview.get("action_posture") == "READ_ONLY"
                ):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "Non-blocked erasure candidates must not collapse back to `READ_ONLY` posture.",
                        )
                    )

    return issues


def validate_set_wrapper(
    payload: dict, location: str, artifact_type: str, item_id_field: str
) -> list[Issue]:
    if payload.get("artifact_type") != artifact_type:
        return []
    item_ids = [item[item_id_field] for item in payload.get("items", [])]
    duplicates = duplicate_values(item_ids)
    if duplicates:
        return [
            Issue(
                "custom",
                location,
                f"`{artifact_type}.items[]` contains duplicate logical ids for `{item_id_field}`: {duplicates}.",
            )
        ]
    return []


def validate_candidate_fact(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    for field in (
        "non_compliance_config_refs",
        "source_record_refs",
        "supporting_evidence_refs",
        "partition_scope_refs",
        "conflict_membership_refs",
    ):
        issues.extend(validate_sorted_string_sequence(payload.get(field), location, f"`{field}[]`"))

    partition_scope = payload.get("partition_scope")
    partition_scope_refs = payload.get("partition_scope_refs")
    if isinstance(partition_scope, str) and isinstance(partition_scope_refs, list):
        if partition_scope_refs != [partition_scope]:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`partition_scope_refs[]` must contain exactly the same single exact partition scope as `partition_scope`.",
                )
            )

    promotion_readiness = payload.get("promotion_readiness")
    if isinstance(promotion_readiness, dict):
        blocking_conflict_ids = promotion_readiness.get("blocking_conflict_ids")
        issues.extend(
            validate_sorted_string_sequence(
                blocking_conflict_ids,
                location,
                "`promotion_readiness.blocking_conflict_ids[]`",
            )
        )
        readiness_state = promotion_readiness.get("readiness_state")
        blocking_conflict_count = promotion_readiness.get("blocking_conflict_count")
        if readiness_state == "CONFLICT_BLOCKED" and (
            not isinstance(blocking_conflict_count, int) or blocking_conflict_count < 1
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`promotion_readiness.readiness_state = CONFLICT_BLOCKED` requires `blocking_conflict_count >= 1`.",
                )
            )
        if readiness_state == "READY_FOR_CANONICAL" and payload.get("promotion_state") not in {
            "CANDIDATE",
            "PROVISIONAL",
        }:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`READY_FOR_CANONICAL` candidates must stay in pre-canonical candidate posture.",
                )
            )

    if payload.get("promotion_state") == "CONTESTED" and not payload.get("conflict_membership_refs"):
        issues.append(
            Issue(
                "custom",
                location,
                "`promotion_state = CONTESTED` requires non-empty `conflict_membership_refs[]`.",
            )
        )

    if payload.get("visibility_basis") != "UNMASKED_AUTHORITATIVE_ONLY":
        issues.append(
            Issue(
                "custom",
                location,
                "`visibility_basis` must stay `UNMASKED_AUTHORITATIVE_ONLY` for candidate promotion input.",
            )
        )

    return issues


def validate_canonical_fact(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    for field in (
        "non_compliance_config_refs",
        "source_record_refs",
        "supporting_evidence_refs",
        "partition_scope_refs",
        "promoted_from_candidate_fact_refs",
        "conflict_membership_refs",
    ):
        issues.extend(validate_sorted_string_sequence(payload.get(field), location, f"`{field}[]`"))

    partition_scope = payload.get("partition_scope")
    partition_scope_refs = payload.get("partition_scope_refs")
    if isinstance(partition_scope, str) and isinstance(partition_scope_refs, list):
        if partition_scope_refs != [partition_scope]:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`partition_scope_refs[]` must contain exactly the same single exact partition scope as `partition_scope`.",
                )
            )

    promotion_record = payload.get("promotion_record")
    if isinstance(promotion_record, dict):
        issues.extend(
            validate_sorted_string_sequence(
                promotion_record.get("blocking_conflict_ids_at_promotion"),
                location,
                "`promotion_record.blocking_conflict_ids_at_promotion[]`",
            )
        )

    promotion_state = payload.get("promotion_state")
    if promotion_state == "CANONICAL":
        if isinstance(promotion_record, dict):
            if promotion_record.get("blocking_conflict_count_at_promotion") != 0:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`promotion_state = CANONICAL` requires `blocking_conflict_count_at_promotion = 0`.",
                    )
                )
            if promotion_record.get("resolution_frontier_at_promotion") not in {"CLEAR", "MONITORING_ONLY"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`promotion_state = CANONICAL` requires non-blocking promotion frontier.",
                    )
                )
    if promotion_state == "CONTESTED" and not payload.get("conflict_membership_refs"):
        issues.append(
            Issue(
                "custom",
                location,
                "`promotion_state = CONTESTED` requires non-empty `conflict_membership_refs[]`.",
            )
        )
    if payload.get("execution_mode") == "COMPLIANCE" and promotion_state == "PROVISIONAL":
        issues.append(
            Issue(
                "custom",
                location,
                "Compliance canonical facts must not stay `PROVISIONAL`.",
            )
        )
    if payload.get("source_strength_tier") == "TIER_8_GOVERNANCE_ONLY" and payload.get("fact_family") != "WORKFLOW_CONTEXT_FACT":
        issues.append(
            Issue(
                "custom",
                location,
                "Governance-only source strength must not become canonical truth outside `WORKFLOW_CONTEXT_FACT`.",
            )
        )
    if payload.get("visibility_basis") != "UNMASKED_AUTHORITATIVE_ONLY":
        issues.append(
            Issue(
                "custom",
                location,
                "`visibility_basis` must stay `UNMASKED_AUTHORITATIVE_ONLY` for canonical truth.",
            )
        )

    return issues


def validate_candidate_fact_set(payload: dict, location: str) -> list[Issue]:
    issues = validate_set_wrapper(payload, location, "CandidateFactSet", "candidate_fact_id")
    items = payload.get("items", [])
    manifest_id = payload.get("manifest_id")
    dedupe_keys: list[str] = []
    identity_hashes: list[str] = []
    sort_keys: list[tuple[str, str, str]] = []
    for index, item in enumerate(items):
        if not isinstance(item, dict):
            continue
        issues.extend(validate_candidate_fact(item, f"{location}.items[{index}]"))
        if isinstance(manifest_id, str) and item.get("manifest_id") not in {None, manifest_id}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`CandidateFactSet.items[].manifest_id` must mirror the set `manifest_id`.",
                )
            )
        dedupe_key = item.get("dedupe_key")
        candidate_identity_hash = item.get("candidate_identity_hash")
        if isinstance(dedupe_key, str):
            dedupe_keys.append(dedupe_key)
        if isinstance(candidate_identity_hash, str):
            identity_hashes.append(candidate_identity_hash)
        sort_key = (
            item.get("partition_scope") if isinstance(item.get("partition_scope"), str) else "",
            item.get("fact_family") if isinstance(item.get("fact_family"), str) else "",
            candidate_identity_hash if isinstance(candidate_identity_hash, str) else "",
        )
        sort_keys.append(sort_key)

    duplicate_dedupe_keys = duplicate_values(dedupe_keys)
    if duplicate_dedupe_keys:
        issues.append(
            Issue(
                "custom",
                location,
                f"`CandidateFactSet.items[].dedupe_key` must stay unique; duplicates {duplicate_dedupe_keys}.",
            )
        )
    duplicate_identity_hashes = duplicate_values(identity_hashes)
    if duplicate_identity_hashes:
        issues.append(
            Issue(
                "custom",
                location,
                f"`CandidateFactSet.items[].candidate_identity_hash` must stay unique; duplicates {duplicate_identity_hashes}.",
            )
        )
    if sort_keys and sort_keys != sorted(sort_keys):
        issues.append(
            Issue(
                "custom",
                location,
                "`CandidateFactSet.items[]` must stay in deterministic `(partition_scope, fact_family, candidate_identity_hash)` order.",
            )
        )
    return issues


def validate_canonical_fact_set(payload: dict, location: str) -> list[Issue]:
    issues = validate_set_wrapper(payload, location, "CanonicalFactSet", "canonical_fact_id")
    items = payload.get("items", [])
    manifest_id = payload.get("manifest_id")
    dedupe_keys: list[str] = []
