def validate_conflict_set(payload: dict, location: str) -> list[Issue]:
    issues = validate_set_wrapper(payload, location, "ConflictSet", "conflict_id")
    items = payload.get("items", [])
    open_states = {"OPEN", "IN_PROGRESS", "MONITORING"}
    expected_open_ids = [
        item["conflict_id"] for item in items if item.get("resolution_state") in open_states
    ]
    expected_blocking_ids = [
        item["conflict_id"]
        for item in items
        if item.get("resolution_state") in open_states and item.get("blocking_class") != "NON_BLOCKING"
    ]
    frontier = payload.get("resolution_frontier")
    expected_frontier = (
        "BLOCKING_PRESENT"
        if expected_blocking_ids
        else "MONITORING_ONLY"
        if expected_open_ids
        else "CLEAR"
    )

    if payload.get("open_conflict_ids") != expected_open_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "`open_conflict_ids[]` must match unresolved conflict ids in item order.",
            )
        )
    if payload.get("blocking_conflict_ids") != expected_blocking_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "`blocking_conflict_ids[]` must match blocking unresolved conflict ids in item order.",
            )
        )
    if payload.get("open_conflict_count") != len(expected_open_ids):
        issues.append(
            Issue(
                "custom",
                location,
                f"`open_conflict_count` must equal {len(expected_open_ids)}.",
            )
        )
    if payload.get("blocking_conflict_count") != len(expected_blocking_ids):
        issues.append(
            Issue(
                "custom",
                location,
                f"`blocking_conflict_count` must equal {len(expected_blocking_ids)}.",
            )
        )
    if frontier != expected_frontier:
        issues.append(
            Issue(
                "custom",
                location,
                f"`resolution_frontier` must be `{expected_frontier}` for the current item mix.",
            )
        )
    return issues


def validate_source_plan(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    required_domains = payload.get("required_domains")
    issues.extend(
        validate_sorted_string_sequence(
            required_domains,
            location,
            "`required_domains[]`",
            allow_empty=False,
        )
    )

    planned_sources = payload.get("planned_sources", [])
    if not isinstance(planned_sources, list):
        return issues

    required_domain_set = (
        {domain for domain in required_domains if isinstance(domain, str)}
        if isinstance(required_domains, list)
        else set()
    )
    planned_domains: list[str] = []
    planned_domain_positions: list[str] = []
    for index, planned_source in enumerate(planned_sources):
        if not isinstance(planned_source, dict):
            continue
        source_domain = planned_source.get("source_domain")
        if isinstance(source_domain, str):
            planned_domains.append(source_domain)
            planned_domain_positions.append(source_domain)
            if required_domain_set and source_domain not in required_domain_set:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`planned_sources[{index}].source_domain` must appear in `required_domains[]`.",
                    )
                )

        issues.extend(
            validate_sorted_string_sequence(
                planned_source.get("partition_scope_refs"),
                location,
                f"`planned_sources[{index}].partition_scope_refs[]`",
                allow_empty=False,
            )
        )
        issues.extend(
            validate_sorted_string_sequence(
                planned_source.get("required_schema_refs"),
                location,
                f"`planned_sources[{index}].required_schema_refs[]`",
                allow_empty=False,
            )
        )
        issues.extend(
            validate_sorted_string_sequence(
                planned_source.get("required_source_class_refs"),
                location,
                f"`planned_sources[{index}].required_source_class_refs[]`",
            )
        )

    duplicate_planned_domains = duplicate_values(planned_domains)
    if duplicate_planned_domains:
        issues.append(
            Issue(
                "custom",
                location,
                f"`planned_sources[].source_domain` must stay unique; duplicates {duplicate_planned_domains}.",
            )
        )
    expected_planned_domain_order = sorted(planned_domain_positions)
    if planned_domain_positions and planned_domain_positions != expected_planned_domain_order:
        issues.append(
            Issue(
                "custom",
                location,
                f"`planned_sources[]` must stay in canonical source-domain order {expected_planned_domain_order}.",
            )
        )

    if required_domain_set:
        missing_domains = sorted(required_domain_set - set(planned_domains))
        if missing_domains:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`planned_sources[]` must cover every `required_domains[]` entry; missing {missing_domains}.",
                )
            )

    return issues


def validate_source_window(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    collection_started_at = parse_datetime(payload.get("collection_started_at"))
    collection_completed_at = parse_datetime(payload.get("collection_completed_at"))
    read_cutoff_at = parse_datetime(payload.get("read_cutoff_at"))

    ensure_datetime_order(
        collection_started_at,
        collection_completed_at,
        issues,
        location,
        "`collection_completed_at` must not be earlier than `collection_started_at`.",
    )
    ensure_datetime_order(
        collection_completed_at,
        read_cutoff_at,
        issues,
        location,
        "`read_cutoff_at` must not be earlier than `collection_completed_at`.",
    )
    ensure_datetime_order(
        collection_started_at,
        read_cutoff_at,
        issues,
        location,
        "`read_cutoff_at` must not be earlier than `collection_started_at`.",
    )
    return issues


def validate_collection_boundary(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    source_boundaries = payload.get("source_boundaries", [])
    if not isinstance(source_boundaries, list):
        return issues

    boundary_domains: list[str] = []
    for index, source_boundary in enumerate(source_boundaries):
        if not isinstance(source_boundary, dict):
            continue
        source_domain = source_boundary.get("source_domain")
        if isinstance(source_domain, str):
            boundary_domains.append(source_domain)
        issues.extend(
            validate_sorted_string_sequence(
                source_boundary.get("partition_scope_refs"),
                location,
                f"`source_boundaries[{index}].partition_scope_refs[]`",
            )
        )
        issues.extend(
            validate_scope_sequence(
                source_boundary.get("runtime_scope_refs"),
                location,
                f"`source_boundaries[{index}].runtime_scope_refs[]`",
                allow_empty=True,
            )
        )

    duplicate_boundary_domains = duplicate_values(boundary_domains)
    if duplicate_boundary_domains:
        issues.append(
            Issue(
                "custom",
                location,
                f"`source_boundaries[].source_domain` must stay unique; duplicates {duplicate_boundary_domains}.",
            )
        )
    expected_boundary_order = sorted(boundary_domains)
    if boundary_domains and boundary_domains != expected_boundary_order:
        issues.append(
            Issue(
                "custom",
                location,
                f"`source_boundaries[]` must stay in canonical source-domain order {expected_boundary_order}.",
            )
        )

    return issues


def validate_schema_bundle(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_schema_reader_window_contract(
            payload.get("schema_reader_window_contract"),
            location,
            "`schema_reader_window_contract`",
            expected_writer_schema_bundle_hash=payload.get("schema_bundle_hash"),
        )[0]
    )
    entries = payload.get("entries", [])
    if not isinstance(entries, list):
        return issues

    schema_ids = [
        entry.get("schema_id")
        for entry in entries
        if isinstance(entry, dict) and isinstance(entry.get("schema_id"), str)
    ]
    artifact_types = [
        entry.get("artifact_type")
        for entry in entries
        if isinstance(entry, dict) and isinstance(entry.get("artifact_type"), str)
    ]

    duplicate_schema_ids = duplicate_values(schema_ids)
    if duplicate_schema_ids:
        issues.append(
            Issue(
                "custom",
                location,
                f"`entries[].schema_id` must be unique; duplicates {duplicate_schema_ids}.",
            )
        )

    duplicate_artifact_types = duplicate_values(artifact_types)
    if duplicate_artifact_types:
        issues.append(
            Issue(
                "custom",
                location,
                f"`entries[].artifact_type` must be unique within one bundle; duplicates {duplicate_artifact_types}.",
            )
        )

    for index, entry in enumerate(entries):
        if not isinstance(entry, dict):
            continue
        schema_id = entry.get("schema_id")
        supersedes_schema_id = entry.get("supersedes_schema_id")
        if (
            isinstance(schema_id, str)
            and isinstance(supersedes_schema_id, str)
            and schema_id == supersedes_schema_id
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`entries[{index}].supersedes_schema_id` must not equal its own `schema_id`.",
                )
            )

    return issues


def validate_config_freeze(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    entries = payload.get("entries", [])
    config_types: list[str] = []
    if isinstance(entries, list):
        for index, entry in enumerate(entries):
            if not isinstance(entry, dict):
                continue
            config_type = entry.get("config_type")
            if isinstance(config_type, str):
                config_types.append(config_type)
            issues.extend(
                validate_sorted_string_sequence(
                    entry.get("test_suite_refs"),
                    location,
                    f"`entries[{index}].test_suite_refs[]`",
                )
            )
            issues.extend(
                validate_sorted_string_sequence(
                    entry.get("environment_allowlist"),
                    location,
                    f"`entries[{index}].environment_allowlist[]`",
                )
            )

    duplicate_types = duplicate_values(config_types)
    if duplicate_types:
        issues.append(
            Issue(
                "custom",
                location,
                f"`entries[].config_type` must stay unique inside one `ConfigFreeze`; duplicates {duplicate_types}.",
            )
        )

    observed_required_types = [config_type for config_type in config_types if config_type in REQUIRED_CONFIG_TYPE_ORDER]
    if observed_required_types != REQUIRED_CONFIG_TYPE_ORDER:
        issues.append(
            Issue(
                "custom",
                location,
                f"`entries[]` must retain the canonical mandatory config-type order {REQUIRED_CONFIG_TYPE_ORDER}.",
            )
        )

    if payload.get("required_config_types_present") != REQUIRED_CONFIG_TYPE_ORDER:
        issues.append(
            Issue(
                "custom",
                location,
                "`required_config_types_present[]` must equal the canonical mandatory config-type set in order.",
            )
        )

    if payload.get("config_completeness_state") != "COMPLETE_REQUIRED_CONFIG_SET":
        issues.append(
            Issue(
                "custom",
                location,
                "`config_completeness_state` must stay `COMPLETE_REQUIRED_CONFIG_SET`.",
            )
        )

    if payload.get("config_consumption_mode") != "FROZEN_CONFIG_ONLY":
        issues.append(
            Issue(
                "custom",
                location,
                "`config_consumption_mode` must stay `FROZEN_CONFIG_ONLY`.",
            )
        )

    resolution_basis = payload.get("config_resolution_basis")
    source_ref = payload.get("source_config_freeze_ref")
    source_hash = payload.get("source_config_freeze_hash")
    source_surface_hash = payload.get("source_config_surface_hash")
    if resolution_basis == "DIRECT_REQUEST_RESOLUTION":
        if any(value is not None for value in (source_ref, source_hash, source_surface_hash)):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`DIRECT_REQUEST_RESOLUTION` must keep all `source_config_*` lineage fields null.",
                )
            )
    elif resolution_basis in {"REPLAY_EXACT_REUSE", "RECOVERY_EXACT_REUSE", "HISTORICAL_EXPLICIT_REUSE"}:
        missing_source_fields = [
            label
            for label, value in (
                ("source_config_freeze_ref", source_ref),
                ("source_config_freeze_hash", source_hash),
                ("source_config_surface_hash", source_surface_hash),
            )
            if not isinstance(value, str) or not value
        ]
        if missing_source_fields:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{resolution_basis}` must preserve non-empty `source_config_*` lineage; missing {missing_source_fields}.",
                )
            )
        if source_hash is not None and payload.get("config_freeze_hash") != source_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`config_freeze_hash` must equal `source_config_freeze_hash` for `{resolution_basis}`.",
                )
            )
        if source_surface_hash is not None and payload.get("config_surface_hash") != source_surface_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`config_surface_hash` must equal `source_config_surface_hash` for `{resolution_basis}`.",
                )
            )

    return issues


def validate_input_freeze(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    sorted_string_fields = (
        "provider_environment_refs",
        "provider_api_versions",
        "provider_schema_versions",
        "cursor_checkpoint_refs",
        "request_audit_refs",
        "source_record_refs",
        "evidence_item_refs",
        "candidate_fact_refs",
        "canonical_fact_refs",
        "conflict_refs",
        "exclusion_refs",
        "no_data_confirmed_declarations",
        "missing_source_declarations",
        "stale_source_declarations",
        "artifact_contract_refs",
    )
    for field in sorted_string_fields:
        issues.extend(
            validate_sorted_string_sequence(payload.get(field), location, f"`{field}[]`")
        )

    source_record_refs = payload.get("source_record_refs", [])
    evidence_item_refs = payload.get("evidence_item_refs", [])
    candidate_fact_refs = payload.get("candidate_fact_refs", [])
    canonical_fact_refs = payload.get("canonical_fact_refs", [])
    conflict_refs = payload.get("conflict_refs", [])
    exclusion_refs = payload.get("exclusion_refs", [])
    no_data_confirmed_declarations = payload.get("no_data_confirmed_declarations", [])
    missing_source_declarations = payload.get("missing_source_declarations", [])
    stale_source_declarations = payload.get("stale_source_declarations", [])
    artifact_contract_refs = payload.get("artifact_contract_refs", [])
    source_domain_postures = payload.get("source_domain_postures", [])
    open_conflict_count = payload.get("open_conflict_count")
    blocking_conflict_count = payload.get("blocking_conflict_count")
    has_candidate_or_canonical_facts = (
        (isinstance(candidate_fact_refs, list) and bool(candidate_fact_refs))
        or (isinstance(canonical_fact_refs, list) and bool(canonical_fact_refs))
    )

    exclusion_set = {value for value in exclusion_refs if isinstance(value, str)}
    no_data_set = {value for value in no_data_confirmed_declarations if isinstance(value, str)}
    missing_set = {value for value in missing_source_declarations if isinstance(value, str)}
    stale_set = {value for value in stale_source_declarations if isinstance(value, str)}

    for left_label, left_values, right_label, right_values in (
        ("`exclusion_refs[]`", exclusion_set, "`no_data_confirmed_declarations[]`", no_data_set),
        ("`exclusion_refs[]`", exclusion_set, "`missing_source_declarations[]`", missing_set),
        ("`exclusion_refs[]`", exclusion_set, "`stale_source_declarations[]`", stale_set),
        (
            "`no_data_confirmed_declarations[]`",
            no_data_set,
            "`missing_source_declarations[]`",
            missing_set,
        ),
        (
            "`no_data_confirmed_declarations[]`",
            no_data_set,
            "`stale_source_declarations[]`",
            stale_set,
        ),
        (
            "`missing_source_declarations[]`",
            missing_set,
            "`stale_source_declarations[]`",
            stale_set,
        ),
    ):
        overlap = sorted(left_values & right_values)
        if overlap:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{left_label} and {right_label} must stay disjoint; overlapping {overlap}.",
                )
            )

    if (
        isinstance(source_record_refs, list)
        and isinstance(exclusion_refs, list)
        and isinstance(no_data_confirmed_declarations, list)
        and isinstance(missing_source_declarations, list)
        and isinstance(stale_source_declarations, list)
        and not source_record_refs
        and not exclusion_refs
        and not no_data_confirmed_declarations
        and not missing_source_declarations
        and not stale_source_declarations
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "An empty source intake must still declare exclusion, confirmed no-data, missing, or stale source posture explicitly.",
            )
        )

    if isinstance(open_conflict_count, int) and isinstance(conflict_refs, list) and open_conflict_count > len(
        conflict_refs
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`open_conflict_count` must not exceed the number of persisted `conflict_refs[]`.",
            )
        )
    if (
        isinstance(open_conflict_count, int)
        and isinstance(blocking_conflict_count, int)
        and blocking_conflict_count > open_conflict_count
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`blocking_conflict_count` must not exceed `open_conflict_count`.",
            )
        )

    if has_candidate_or_canonical_facts and isinstance(evidence_item_refs, list) and not evidence_item_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "Candidate or canonical facts require non-empty `evidence_item_refs[]` in the frozen intake set.",
            )
        )

    if isinstance(canonical_fact_refs, list) and canonical_fact_refs:
        if not isinstance(candidate_fact_refs, list) or not candidate_fact_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Canonical fact promotion requires non-empty `candidate_fact_refs[]`.",
                )
            )

    if isinstance(artifact_contract_refs, list) and len(artifact_contract_refs) < 10:
        issues.append(
            Issue(
                "custom",
                location,
                "`artifact_contract_refs[]` must cover the full pre-seal intake pack and therefore contain at least 10 refs.",
            )
        )

    posture_domains: list[str] = []
    collected_domains: set[str] = set()
    no_data_posture_domains: set[str] = set()
    excluded_posture_domains: set[str] = set()
    missing_posture_domains: set[str] = set()
    stale_posture_domains: set[str] = set()
    if isinstance(source_domain_postures, list):
        for index, posture in enumerate(source_domain_postures):
            if not isinstance(posture, dict):
                continue
            source_domain = posture.get("source_domain")
            if isinstance(source_domain, str):
                posture_domains.append(source_domain)
            issues.extend(
                validate_sorted_string_sequence(
                    posture.get("partition_scope_refs"),
                    location,
                    f"`source_domain_postures[{index}].partition_scope_refs[]`",
                )
            )
            issues.extend(
                validate_scope_sequence(
                    posture.get("runtime_scope_refs"),
                    location,
                    f"`source_domain_postures[{index}].runtime_scope_refs[]`",
                    allow_empty=True,
                )
            )

            disposition = posture.get("boundary_disposition")
            counts = {
                field: posture.get(field)
                for field in (
                    "source_record_count",
                    "evidence_item_count",
                    "candidate_fact_count",
                    "canonical_fact_count",
                    "conflict_count",
                )
            }
            nonzero_count_fields = sorted(
                field for field, value in counts.items() if isinstance(value, int) and value > 0
            )
            if disposition == "IN_SCOPE_COLLECTED":
                if not isinstance(counts.get("source_record_count"), int) or counts["source_record_count"] < 1:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`source_domain_postures[{index}].source_record_count` must be >= 1 when `boundary_disposition = IN_SCOPE_COLLECTED`.",
                        )
                    )
                if isinstance(source_domain, str):
                    collected_domains.add(source_domain)
            elif disposition == "NO_DATA_CONFIRMED_AT_CUTOFF":
                if nonzero_count_fields:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`source_domain_postures[{index}]` must keep all count fields at 0 when `boundary_disposition = NO_DATA_CONFIRMED_AT_CUTOFF`; found {nonzero_count_fields}.",
                        )
                    )
                if isinstance(source_domain, str):
                    no_data_posture_domains.add(source_domain)
            elif disposition == "EXCLUDED_BY_POLICY":
                if nonzero_count_fields:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`source_domain_postures[{index}]` must keep all count fields at 0 when `boundary_disposition = EXCLUDED_BY_POLICY`; found {nonzero_count_fields}.",
                        )
                    )
                if isinstance(source_domain, str):
                    excluded_posture_domains.add(source_domain)
            elif disposition == "MISSING_AT_CUTOFF":
                if nonzero_count_fields:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`source_domain_postures[{index}]` must keep all count fields at 0 when `boundary_disposition = MISSING_AT_CUTOFF`; found {nonzero_count_fields}.",
                        )
                    )
                if isinstance(source_domain, str):
                    missing_posture_domains.add(source_domain)
            elif disposition == "STALE_AT_CUTOFF":
                if nonzero_count_fields:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`source_domain_postures[{index}]` must keep all count fields at 0 when `boundary_disposition = STALE_AT_CUTOFF`; found {nonzero_count_fields}.",
                        )
                    )
                if isinstance(source_domain, str):
                    stale_posture_domains.add(source_domain)

        duplicate_posture_domains = duplicate_values(posture_domains)
        if duplicate_posture_domains:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`source_domain_postures[].source_domain` must stay unique; duplicates {duplicate_posture_domains}.",
                )
            )
        expected_posture_order = sorted(posture_domains)
        if posture_domains and posture_domains != expected_posture_order:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`source_domain_postures[]` must stay in canonical source-domain order {expected_posture_order}.",
                )
            )

    if exclusion_set != excluded_posture_domains:
        issues.append(
            Issue(
                "custom",
                location,
                "`exclusion_refs[]` must exactly mirror the domains marked `EXCLUDED_BY_POLICY` in `source_domain_postures[]`.",
            )
        )
    if no_data_set != no_data_posture_domains:
        issues.append(
            Issue(
                "custom",
                location,
                "`no_data_confirmed_declarations[]` must exactly mirror the domains marked `NO_DATA_CONFIRMED_AT_CUTOFF` in `source_domain_postures[]`.",
            )
        )
    if missing_set != missing_posture_domains:
        issues.append(
            Issue(
                "custom",
                location,
                "`missing_source_declarations[]` must exactly mirror the domains marked `MISSING_AT_CUTOFF` in `source_domain_postures[]`.",
            )
        )
    if stale_set != stale_posture_domains:
        issues.append(
            Issue(
                "custom",
                location,
                "`stale_source_declarations[]` must exactly mirror the domains marked `STALE_AT_CUTOFF` in `source_domain_postures[]`.",
            )
        )

    if has_candidate_or_canonical_facts and not collected_domains:
        issues.append(
            Issue(
                "custom",
                location,
                "Candidate or canonical facts require at least one `source_domain_postures[]` entry with `boundary_disposition = IN_SCOPE_COLLECTED`.",
            )
        )

    return issues


def validate_twin_state_snapshot(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    assembly_state = payload.get("assembly_state")
    comparison_basis_ref = payload.get("comparison_basis_ref")
    comparison_key_profile_code = payload.get("comparison_key_profile_code")
    subject_count = payload.get("subject_count", 0)
    comparable_subject_count = payload.get("comparable_subject_count", 0)
    non_comparable_subject_count = payload.get("non_comparable_subject_count", 0)
    if (
        isinstance(subject_count, int)
        and isinstance(comparable_subject_count, int)
        and comparable_subject_count > subject_count
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`comparable_subject_count` must not exceed `subject_count`.",
            )
        )
    if (
        isinstance(subject_count, int)
        and isinstance(comparable_subject_count, int)
        and isinstance(non_comparable_subject_count, int)
        and comparable_subject_count + non_comparable_subject_count != subject_count
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`subject_count` must equal `comparable_subject_count + non_comparable_subject_count`.",
            )
        )

    component_refs = payload.get("component_refs", [])
    subject_key_collision_refs = payload.get("subject_key_collision_refs", [])
    contradictory_component_refs = payload.get("contradictory_component_refs", [])
    limitation_codes = payload.get("limitation_codes", [])
    if not isinstance(component_refs, list):
        component_refs = []
    if not isinstance(subject_key_collision_refs, list):
        subject_key_collision_refs = []
    if not isinstance(contradictory_component_refs, list):
        contradictory_component_refs = []
    if not isinstance(limitation_codes, list):
        limitation_codes = []
    component_ref_set = set(component_refs)
    missing_collision_refs = [ref for ref in subject_key_collision_refs if ref not in component_ref_set]
    if missing_collision_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`subject_key_collision_refs[]` must stay within `component_refs[]`; missing {missing_collision_refs}.",
            )
        )
    missing_contradictory_refs = [
        ref for ref in contradictory_component_refs if ref not in component_ref_set
    ]
    if missing_contradictory_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`contradictory_component_refs[]` must stay within `component_refs[]`; missing {missing_contradictory_refs}.",
            )
        )

    as_of = parse_datetime(payload.get("as_of"))
    stale_after = parse_datetime(payload.get("stale_after"))
    ensure_datetime_order(
        as_of,
        stale_after,
        issues,
        location,
        "`stale_after` must not predate `as_of`.",
    )

    if payload.get("assembly_state") == "UNAVAILABLE" and (
        payload.get("subject_count", 0) != 0 or payload.get("comparable_subject_count", 0) != 0
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`assembly_state = UNAVAILABLE` must clear `subject_count`, `comparable_subject_count`, and `non_comparable_subject_count`.",
            )
        )
    if payload.get("assembly_state") == "UNAVAILABLE" and payload.get("non_comparable_subject_count", 0) != 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`assembly_state = UNAVAILABLE` must clear `non_comparable_subject_count`.",
            )
        )
    if assembly_state in TWIN_NON_UNAVAILABLE_ASSEMBLY_STATES:
        if not isinstance(comparison_basis_ref, str):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-`UNAVAILABLE` twin snapshots must retain non-null `comparison_basis_ref`.",
                )
            )
        if not component_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-`UNAVAILABLE` twin snapshots must retain non-empty `component_refs[]`.",
                )
            )
        if comparison_key_profile_code != TWIN_COMPARISON_KEY_PROFILE:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Non-`UNAVAILABLE` twin snapshots must use `comparison_key_profile_code = {TWIN_COMPARISON_KEY_PROFILE}`.",
                )
            )
    if assembly_state == "UNAVAILABLE":
        if comparison_basis_ref is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`assembly_state = UNAVAILABLE` must clear `comparison_basis_ref`.",
                )
            )
        if component_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`assembly_state = UNAVAILABLE` must clear `component_refs[]`.",
                )
            )
        if subject_key_collision_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`assembly_state = UNAVAILABLE` must clear `subject_key_collision_refs[]`.",
                )
            )
        if contradictory_component_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`assembly_state = UNAVAILABLE` must clear `contradictory_component_refs[]`.",
                )
            )
    if subject_key_collision_refs and assembly_state != "CONTRADICTORY":
        issues.append(
            Issue(
                "custom",
                location,
                "Non-empty `subject_key_collision_refs[]` must force `assembly_state = CONTRADICTORY`.",
            )
        )
    if assembly_state == "CONTRADICTORY" and not (
        subject_key_collision_refs or contradictory_component_refs
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`assembly_state = CONTRADICTORY` must retain `subject_key_collision_refs[]`, `contradictory_component_refs[]`, or both.",
            )
        )
    if (
        (subject_key_collision_refs or contradictory_component_refs)
        and payload.get("non_comparable_subject_count", 0) < 1
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Contradictory twin snapshots must retain `non_comparable_subject_count >= 1`.",
            )
        )
    if subject_key_collision_refs and not limitation_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "Twin snapshots with `subject_key_collision_refs[]` must retain at least one `limitation_codes[]` entry.",
            )
        )
    return issues


def validate_twin_view(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    for field, expected in [
        ("comparison_key_profile_code", TWIN_COMPARISON_KEY_PROFILE),
        ("delta_precedence_profile_code", TWIN_DELTA_PRECEDENCE_PROFILE),
        ("mismatch_ranking_profile_code", TWIN_MISMATCH_SORT_PROFILE),
    ]:
        if payload.get(field) != expected:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field}` must be `{expected}`.",
                )
            )
    internal_state_ref = payload.get("internal_state_ref")
    authority_state_ref = payload.get("authority_state_ref")
    if (
        isinstance(internal_state_ref, str)
        and isinstance(authority_state_ref, str)
        and internal_state_ref == authority_state_ref
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`internal_state_ref` and `authority_state_ref` must stay distinct.",
            )
        )

    subordinate_refs = [
        payload.get("internal_state_ref"),
        payload.get("authority_state_ref"),
        payload.get("timeline_ref"),
        payload.get("mismatch_summary_ref"),
        payload.get("readiness_ref"),
        payload.get("reconciliation_state_ref"),
        payload.get("interpretation_state_ref"),
    ]
    subordinate_refs = [ref for ref in subordinate_refs if isinstance(ref, str)]
    duplicate_subordinate_refs = duplicate_values(subordinate_refs)
    if duplicate_subordinate_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"Twin root subordinate refs must stay distinct object identities; duplicates {duplicate_subordinate_refs}.",
            )
        )

    built_at = parse_datetime(payload.get("built_at"))
    stale_at = parse_datetime(payload.get("stale_at"))
    superseded_at = parse_datetime(payload.get("superseded_at"))
    ensure_datetime_order(
        built_at,
        stale_at,
        issues,
        location,
        "`stale_at` must not predate `built_at`.",
    )
    ensure_datetime_order(
        built_at,
        superseded_at,
        issues,
        location,
        "`superseded_at` must not predate `built_at`.",
    )
    if payload.get("lifecycle_state") in TWIN_BUILT_ROOT_STATES and not payload.get("cross_source_delta_refs"):
        issues.append(
            Issue(
                "custom",
                location,
                "Built, stale, or superseded twins must retain non-empty `cross_source_delta_refs[]`.",
            )
        )
    return issues


def validate_twin_mismatch_summary(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    if payload.get("ranking_profile_code") != TWIN_MISMATCH_SORT_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"`ranking_profile_code` must be `{TWIN_MISMATCH_SORT_PROFILE}`.",
            )
        )
    total_subject_count = payload.get("total_subject_count", 0)
    matched_count = payload.get("matched_count", 0)
    mismatch_count = payload.get("mismatch_count", 0)
    top_mismatch_refs = payload.get("top_mismatch_refs", [])
    top_ranked_mismatches = payload.get("top_ranked_mismatches", [])
    if not isinstance(top_mismatch_refs, list):
        top_mismatch_refs = []
    if not isinstance(top_ranked_mismatches, list):
        top_ranked_mismatches = []
    class_bucket_sum = (
        payload.get("blocking_count", 0)
        + payload.get("material_count", 0)
        + payload.get("review_count", 0)
        + payload.get("informational_count", 0)
    )
    mismatch_partition_sum = (
        payload.get("comparable_mismatch_count", 0)
        + payload.get("waiting_count", 0)
        + payload.get("partial_ack_count", 0)
        + payload.get("non_comparable_count", 0)
        + payload.get("contradictory_count", 0)
        + payload.get("out_of_band_count", 0)
    )

    if matched_count + mismatch_count != total_subject_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`total_subject_count` must equal `matched_count + mismatch_count`.",
            )
        )
    if mismatch_partition_sum != mismatch_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`mismatch_count` must equal comparable, waiting, partial-ack, non-comparable, contradictory, and out-of-band partition counts.",
            )
        )
    if class_bucket_sum != mismatch_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`mismatch_count` must equal the sum of blocking/material/review/informational mismatch buckets.",
            )
        )
    if payload.get("suppressed_match_count", 0) > matched_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`suppressed_match_count` must not exceed `matched_count`.",
            )
        )
    if len(top_mismatch_refs) > mismatch_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`top_mismatch_refs[]` must not contain more items than `mismatch_count`.",
            )
        )
    if len(top_ranked_mismatches) > mismatch_count:
        issues.append(
            Issue(
                "custom",
                location,
                "`top_ranked_mismatches[]` must not contain more items than `mismatch_count`.",
            )
        )

    expected_highest = "NONE"
    if payload.get("blocking_count", 0) > 0:
        expected_highest = "BLOCKING"
    elif payload.get("material_count", 0) > 0:
        expected_highest = "MATERIAL"
    elif payload.get("review_count", 0) > 0:
        expected_highest = "REVIEW"
    elif payload.get("informational_count", 0) > 0:
        expected_highest = "INFORMATIONAL"

    if payload.get("highest_materiality_class") != expected_highest:
        issues.append(
            Issue(
                "custom",
                location,
                f"`highest_materiality_class` must be `{expected_highest}` for the current mismatch buckets.",
            )
        )
    ranked_delta_refs = [
        entry.get("delta_arc_ref")
        for entry in top_ranked_mismatches
        if isinstance(entry, dict)
    ]
    if top_mismatch_refs != ranked_delta_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`top_mismatch_refs[]` must exactly mirror the ordered `delta_arc_ref` projection from `top_ranked_mismatches[]`.",
            )
        )
    duplicate_ranked_refs = duplicate_values(
        [ref for ref in ranked_delta_refs if isinstance(ref, str)]
    )
    if duplicate_ranked_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`top_ranked_mismatches[]` must not duplicate `delta_arc_ref`; duplicates {duplicate_ranked_refs}.",
            )
        )
    for index, entry in enumerate(top_ranked_mismatches):
        if not isinstance(entry, dict):
            continue
        comparability_state = entry.get("comparability_state")
        comparability_reason_code = entry.get("comparability_reason_code")
        if comparability_state == "COMPARABLE" and comparability_reason_code != "NONE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must keep `comparability_reason_code = NONE` when `comparability_state = COMPARABLE`.",
                )
            )
        if comparability_state == "WAITING_ON_AUTHORITY" and comparability_reason_code != "ACK_PENDING":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must keep `comparability_reason_code = ACK_PENDING` when waiting on authority.",
                )
            )
        if comparability_state == "PARTIALLY_COMPARABLE" and comparability_reason_code != "ACK_PARTIAL":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must keep `comparability_reason_code = ACK_PARTIAL` when partially comparable.",
                )
            )
        if comparability_state == "NON_COMPARABLE" and comparability_reason_code not in {
            "BASELINE_MISSING",
            "STALE_COMPARISON",
            "LIMITED_VISIBILITY",
            "REPLAY_NON_AUTHORITATIVE",
        }:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must use a non-comparable reason code when `comparability_state = NON_COMPARABLE`.",
                )
            )
        if comparability_state == "OUT_OF_BAND" and comparability_reason_code != "OUT_OF_BAND":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must keep `comparability_reason_code = OUT_OF_BAND` when `comparability_state = OUT_OF_BAND`.",
                )
            )
        if comparability_state == "CONTRADICTORY" and comparability_reason_code not in {
            "ACK_CONTRADICTORY",
            "CONTRADICTION_COMPONENTS",
        }:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`top_ranked_mismatches[{index}]` must keep a contradiction reason code when `comparability_state = CONTRADICTORY`.",
                )
            )
    if top_ranked_mismatches:
        expected_order = sorted(top_ranked_mismatches, key=twin_mismatch_ordering_key)
        if top_ranked_mismatches != expected_order:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`top_ranked_mismatches[]` must be ordered by `priority_rank desc`, `last_compared_at desc`, then `comparison_key asc`.",
                )
            )
        first_entry = top_ranked_mismatches[0] if isinstance(top_ranked_mismatches[0], dict) else {}
        if payload.get("highest_priority_rank") != first_entry.get("priority_rank"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`highest_priority_rank` must equal the first ranked mismatch entry's `priority_rank`.",
                )
            )
        if payload.get("highest_materiality_class") != first_entry.get("materiality_class"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`highest_materiality_class` must equal the first ranked mismatch entry's `materiality_class`.",
                )
            )
    elif payload.get("highest_priority_rank", 0) != 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`highest_priority_rank` must be `0` when `top_ranked_mismatches[]` is empty.",
            )
        )
    return issues


def validate_twin_portfolio_summary(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    total = payload.get("total_twin_count", 0)
    bucket_sum = (
        payload.get("ready_count", 0)
        + payload.get("review_required_count", 0)
        + payload.get("waiting_on_authority_count", 0)
        + payload.get("reconciliation_required_count", 0)
        + payload.get("blocked_count", 0)
    )

    if bucket_sum != total:
        issues.append(
            Issue(
                "custom",
                location,
                "`total_twin_count` must equal the sum of the readiness-class buckets.",
            )
        )
    if total > 0 and not payload.get("top_twin_refs"):
        issues.append(
            Issue(
                "custom",
                location,
                "`top_twin_refs[]` must be non-empty when `total_twin_count > 0`.",
            )
        )
    if total > 0 and payload.get("highest_attention_rank", 0) < 1:
        issues.append(
            Issue(
                "custom",
                location,
                "`highest_attention_rank` must be positive when the portfolio contains at least one twin.",
            )
        )
    if len(payload.get("top_twin_refs", [])) > total:
        issues.append(
            Issue(
                "custom",
                location,
                "`top_twin_refs[]` must not contain more items than `total_twin_count`.",
            )
        )
    return issues


def validate_twin_readiness_state(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, execution_mode_boundary_contract = (
        validate_execution_mode_boundary_contract(
            payload.get("execution_mode_boundary_contract"),
            location,
            "`execution_mode_boundary_contract`",
            require_non_null=True,
        )
    )
    issues.extend(execution_mode_boundary_contract_issues)
    if (
        payload.get("safe_action_state") != "NO_SAFE_ACTION"
        and payload.get("no_safe_action_reason_codes")
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`no_safe_action_reason_codes[]` must be empty unless `safe_action_state = NO_SAFE_ACTION`.",
            )
        )

    usefulness_cap_reason_codes = payload.get("usefulness_cap_reason_codes", [])
    if not isinstance(usefulness_cap_reason_codes, list):
        usefulness_cap_reason_codes = []
    action_bucket_fields = [
        "blocking_mismatch_refs",
        "review_mismatch_refs",
        "waiting_mismatch_refs",
        "reconciliation_mismatch_refs",
    ]
    action_bucket_owner: dict[str, str] = {}
    for field in action_bucket_fields:
        refs = payload.get(field, [])
        if not isinstance(refs, list):
            refs = []
        for ref in refs:
            prior_field = action_bucket_owner.get(ref)
            if prior_field is not None and prior_field != field:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`{ref}` must not appear in multiple readiness action buckets; seen in `{prior_field}` and `{field}`.",
                    )
                )
            else:
                action_bucket_owner[ref] = field

    non_comparable_mismatch_refs = payload.get("non_comparable_mismatch_refs", [])
    out_of_band_mismatch_refs = payload.get("out_of_band_mismatch_refs", [])
    contradictory_mismatch_refs = payload.get("contradictory_mismatch_refs", [])
    if not isinstance(non_comparable_mismatch_refs, list):
        non_comparable_mismatch_refs = []
    if not isinstance(out_of_band_mismatch_refs, list):
        out_of_band_mismatch_refs = []
    if not isinstance(contradictory_mismatch_refs, list):
        contradictory_mismatch_refs = []

    if payload.get("decision_usefulness") == "HIGH" and (
        usefulness_cap_reason_codes
        or non_comparable_mismatch_refs
        or out_of_band_mismatch_refs
        or contradictory_mismatch_refs
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`decision_usefulness = HIGH` must clear usefulness-cap and explicit non-comparable/out-of-band/contradictory mismatch refs.",
            )
        )

    if non_comparable_mismatch_refs:
        if payload.get("safe_action_state") not in {"REFRESH_REQUIRED", "NO_SAFE_ACTION"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-comparable twin readiness must cap `safe_action_state` at `REFRESH_REQUIRED` or `NO_SAFE_ACTION`.",
                )
            )
        if payload.get("decision_usefulness") not in {"LOW", "NONE"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-comparable twin readiness must cap `decision_usefulness` at `LOW` or `NONE`.",
                )
            )
        if not usefulness_cap_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-comparable twin readiness must retain at least one `usefulness_cap_reason_codes[]` entry.",
                )
            )

    if out_of_band_mismatch_refs:
        if payload.get("twin_readiness_class") not in {"RECONCILIATION_REQUIRED", "BLOCKED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Out-of-band twin readiness must remain `RECONCILIATION_REQUIRED` or `BLOCKED`.",
                )
            )
        if payload.get("decision_usefulness") not in {"LOW", "NONE"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Out-of-band twin readiness must cap `decision_usefulness` at `LOW` or `NONE`.",
                )
            )

    if contradictory_mismatch_refs:
        if payload.get("twin_readiness_class") not in {"RECONCILIATION_REQUIRED", "BLOCKED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Contradictory twin readiness must remain `RECONCILIATION_REQUIRED` or `BLOCKED`.",
                )
            )
        if payload.get("safe_action_state") == "SAFE_TO_ACT":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Contradictory twin readiness must not claim `SAFE_TO_ACT`.",
                )
            )
        if payload.get("decision_usefulness") not in {"LOW", "NONE"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Contradictory twin readiness must cap `decision_usefulness` at `LOW` or `NONE`.",
                )
            )

    if payload.get("authority_posture") in {"PARTIAL", "STALE", "UNKNOWN", "OUT_OF_BAND"}:
        if payload.get("decision_usefulness") not in {"LOW", "NONE"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Limited or stale authority posture must cap `decision_usefulness` at `LOW` or `NONE`.",
                )
            )
        if not usefulness_cap_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Limited or stale authority posture must persist `usefulness_cap_reason_codes[]`.",
                )
            )

    if payload.get("twin_readiness_class") == "READY" and usefulness_cap_reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`twin_readiness_class = READY` must clear `usefulness_cap_reason_codes[]`.",
            )
        )
    if execution_mode_boundary_contract.get("legal_effect_boundary") != "COMPLIANCE_CAPABLE":
        if payload.get("filing_readiness") == "READY_TO_SUBMIT":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Modeled or replay-only twin readiness must not publish `filing_readiness = READY_TO_SUBMIT`.",
                )
            )
        if payload.get("safe_action_state") == "SAFE_TO_ACT":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Modeled or replay-only twin readiness must not publish `safe_action_state = SAFE_TO_ACT`.",
                )
            )
        if "NON_LIVE_EXECUTION_BOUNDARY" not in usefulness_cap_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`usefulness_cap_reason_codes[]` must include `NON_LIVE_EXECUTION_BOUNDARY` when twin readiness is modeled or replay-only.",
                )
            )

    return issues


def validate_twin_reconciliation_state(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    if payload.get("auto_attempt_count", 0) > payload.get("max_auto_attempts", 0):
        issues.append(
            Issue(
                "custom",
                location,
                "`auto_attempt_count` must not exceed `max_auto_attempts`.",
            )
        )

    workflow_item_refs = payload.get("workflow_item_refs", [])
    if not isinstance(workflow_item_refs, list):
        workflow_item_refs = []
    primary_workflow_item_ref = payload.get("primary_workflow_item_ref_or_null")
    if (
        isinstance(primary_workflow_item_ref, str)
        and primary_workflow_item_ref not in workflow_item_refs
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_workflow_item_ref_or_null` must appear in `workflow_item_refs[]` when present.",
            )
        )

    target_mismatch_refs = set(payload.get("target_mismatch_refs", []))
    missing_blocking_refs = [
        ref for ref in payload.get("blocking_mismatch_refs", []) if ref not in target_mismatch_refs
    ]
    if missing_blocking_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`blocking_mismatch_refs[]` must be a subset of `target_mismatch_refs[]`; missing {missing_blocking_refs}.",
            )
        )

    lifecycle_state = payload.get("lifecycle_state")
    reconciliation_budget_state = payload.get("reconciliation_budget_state")
    next_action_owner = payload.get("next_action_owner")
    next_action_due_at = parse_datetime(payload.get("next_action_due_at"))
    reconciliation_deadline_at = parse_datetime(payload.get("reconciliation_deadline_at"))
    last_attempted_at = parse_datetime(payload.get("last_attempted_at"))
    resolved_at = parse_datetime(payload.get("resolved_at"))
    ensure_datetime_order(
        last_attempted_at,
        next_action_due_at,
        issues,
        location,
        "`next_action_due_at` must not predate `last_attempted_at`.",
    )
    ensure_datetime_order(
        last_attempted_at,
        resolved_at,
        issues,
        location,
        "`resolved_at` must not predate `last_attempted_at`.",
    )
    if lifecycle_state == "NOT_REQUIRED":
        if reconciliation_budget_state != "NOT_APPLICABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`lifecycle_state = NOT_REQUIRED` must use `reconciliation_budget_state = NOT_APPLICABLE`.",
                )
            )
        if next_action_owner != "NONE" or payload.get("next_action_due_at") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`lifecycle_state = NOT_REQUIRED` must clear `next_action_owner` and `next_action_due_at`.",
                )
            )
    if lifecycle_state == "WAITING_ON_AUTHORITY":
        if next_action_owner != "AUTHORITY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`WAITING_ON_AUTHORITY` reconciliation must keep `next_action_owner = AUTHORITY`.",
                )
            )
        if next_action_due_at is None or reconciliation_deadline_at is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`WAITING_ON_AUTHORITY` reconciliation must retain both `next_action_due_at` and `reconciliation_deadline_at`.",
                )
            )
    if lifecycle_state == "WAITING_ON_OPERATOR":
        if next_action_owner != "OPERATOR":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`WAITING_ON_OPERATOR` reconciliation must keep `next_action_owner = OPERATOR`.",
                )
            )
        if next_action_due_at is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`WAITING_ON_OPERATOR` reconciliation must retain `next_action_due_at`.",
                )
            )
        if primary_workflow_item_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`WAITING_ON_OPERATOR` reconciliation must retain `primary_workflow_item_ref_or_null`.",
                )
            )
    if lifecycle_state in {"RESOLVED", "SUPERSEDED"} and (
        next_action_owner != "NONE" or payload.get("next_action_due_at") is not None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Resolved or superseded reconciliation state must clear next-action ownership and due timing.",
            )
        )
    if reconciliation_budget_state == "NOT_APPLICABLE" and lifecycle_state != "NOT_REQUIRED":
        issues.append(
            Issue(
                "custom",
                location,
                "Only `lifecycle_state = NOT_REQUIRED` may use `reconciliation_budget_state = NOT_APPLICABLE`.",
            )
        )
    if (
        reconciliation_budget_state == "WITHIN_BUDGET"
        and payload.get("auto_attempt_count", 0) >= payload.get("max_auto_attempts", 0)
        and payload.get("max_auto_attempts", 0) > 0
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`reconciliation_budget_state = WITHIN_BUDGET` is invalid once the automatic attempt budget is exhausted.",
            )
        )
    if (
        reconciliation_budget_state == "EXHAUSTED"
        and payload.get("auto_attempt_count", 0) < payload.get("max_auto_attempts", 0)
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`reconciliation_budget_state = EXHAUSTED` requires `auto_attempt_count >= max_auto_attempts`.",
            )
        )
    if reconciliation_budget_state == "MANUAL_ESCALATION" and not workflow_item_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`reconciliation_budget_state = MANUAL_ESCALATION` must retain workflow ownership.",
            )
        )
    return issues


def validate_twin_interpretation_state(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    dominant_attention_state = payload.get("dominant_attention_state")
    dominant_delta_arc_ref = payload.get("dominant_delta_arc_ref_or_null")
    dominant_reconciliation_state_ref = payload.get("dominant_reconciliation_state_ref_or_null")
    summary_priority_mode = payload.get("summary_priority_mode")
    default_noise_filter = payload.get("default_noise_filter")

    if dominant_attention_state == "READY" and (
        dominant_delta_arc_ref is not None or dominant_reconciliation_state_ref is not None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`dominant_attention_state = READY` must clear dominant delta and reconciliation refs.",
            )
        )

    if dominant_attention_state in {"WAITING_ON_AUTHORITY", "RECONCILIATION_REQUIRED", "OUT_OF_BAND", "CONTRADICTORY"}:
        if dominant_reconciliation_state_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Waiting, reconciliation, out-of-band, and contradictory interpretation states must retain `dominant_reconciliation_state_ref_or_null`.",
                )
            )
        if payload.get("authority_first_summary") is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Authority-first summary must stay enabled when reconciliation semantics dominate interpretation.",
                )
            )

    if dominant_attention_state in {"REVIEW_REQUIRED", "NON_COMPARABLE"} and (
        dominant_delta_arc_ref is None and dominant_reconciliation_state_ref is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Review-required and non-comparable interpretation states must keep a dominant delta or reconciliation ref.",
            )
        )

    if dominant_attention_state != "READY" and default_noise_filter == "ALL_MISMATCHES":
        issues.append(
            Issue(
                "custom",
                location,
                "Non-ready interpretation states must not default to `ALL_MISMATCHES` because it hides the dominant action meaning behind audit noise.",
            )
        )

    if summary_priority_mode == "AUDIT_FIRST" and dominant_attention_state != "READY":
        issues.append(
            Issue(
                "custom",
                location,
                "`summary_priority_mode = AUDIT_FIRST` is valid only when `dominant_attention_state = READY`.",
            )
        )

    return issues


def validate_twin_timeline(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    window_start = parse_datetime(payload.get("window_start_at"))
    window_end = parse_datetime(payload.get("window_end_at"))
    if window_start and window_end and window_start > window_end:
        issues.append(
            Issue(
                "custom",
                location,
                "`window_start_at` must not be later than `window_end_at`.",
            )
        )

    total_anchor_count = (
        payload.get("aligned_anchor_count", 0)
        + payload.get("contradictory_anchor_count", 0)
        + payload.get("unpaired_anchor_count", 0)
    )
    primary_anchor_ref = payload.get("primary_anchor_ref")
    if total_anchor_count == 0 and primary_anchor_ref is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_anchor_ref` must be null when the timeline contains no comparable anchors.",
            )
        )
    if total_anchor_count > 0 and primary_anchor_ref is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_anchor_ref` must be present when the timeline contains comparable anchors.",
            )
        )

    lane_event_refs = {
        ref
        for lane in payload.get("lanes", [])
        for ref in lane.get("event_refs", [])
    }
    if primary_anchor_ref is not None and primary_anchor_ref not in lane_event_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_anchor_ref` must resolve to one of the persisted lane event refs.",
            )
        )
    return issues


def validate_twin_delta_arc(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    if payload.get("comparison_key_profile_code") != TWIN_COMPARISON_KEY_PROFILE:
        issues.append(
            Issue(
                "custom",
                location,
                f"`comparison_key_profile_code` must be `{TWIN_COMPARISON_KEY_PROFILE}`.",
            )
        )
    expected_comparison_key = derive_twin_comparison_key(payload)
    if expected_comparison_key is not None and payload.get("comparison_key") != expected_comparison_key:
        issues.append(
            Issue(
                "custom",
                location,
                "`comparison_key` must equal the canonical twin comparison-key hash derived from the persisted subject identity and scope components.",
            )
        )
    expected_precedence = TWIN_DELTA_PRECEDENCE_BY_CLASS.get(payload.get("delta_class"))
    if expected_precedence is not None and payload.get("delta_precedence_rank") != expected_precedence:
        issues.append(
            Issue(
                "custom",
                location,
                f"`delta_precedence_rank` must equal the frozen precedence rank for `{payload.get('delta_class')}` ({expected_precedence}).",
            )
        )
    expected_comparability = derive_twin_delta_comparability(payload)
    if expected_comparability is not None:
        expected_state, expected_reason = expected_comparability
        if payload.get("comparability_state") != expected_state:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`comparability_state` must equal `{expected_state}` for `{payload.get('delta_class')}`.",
                )
            )
        if payload.get("comparability_reason_code") != expected_reason:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`comparability_reason_code` must equal `{expected_reason}` for the current delta posture.",
                )
            )
        if expected_state != "COMPARABLE" and payload.get("delta_class") in TWIN_MATCH_DELTA_CLASSES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Match delta classes must stay `COMPARABLE`.",
                )
            )
        if expected_state == "COMPARABLE" and payload.get("comparability_reason_code") != "NONE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Comparable deltas must clear `comparability_reason_code` back to `NONE`.",
                )
            )
    materiality_weight = {
        "NONE": 0,
        "INFORMATIONAL": 1,
        "REVIEW": 2,
        "MATERIAL": 3,
        "BLOCKING": 4,
    }
    resolution_weight = {
        "NONE": 0,
        "REFRESH_TWIN": 1,
        "WAIT_FOR_AUTHORITY": 1,
        "OPEN_REVIEW": 2,
        "RUN_RECONCILIATION": 3,
        "PREPARE_AMENDMENT": 4,
    }
    subject_weight = {
        "FACT": 1,
        "TOTAL": 2,
        "STATUS": 2,
        "OBLIGATION": 2,
        "FILING": 3,
        "ACKNOWLEDGEMENT": 3,
        "DECLARED_BASIS": 3,
    }
    authority_escalation = 1 if payload.get("delta_class") in {
        "STATUS_MISMATCH",
        "ACK_PARTIAL",
        "ACK_CONTRADICTORY",
        "REJECTED_OR_REVERSED",
        "OUT_OF_BAND",
        "AUTHORITY_ONLY",
    } else 0
    freshness_escalation = 1 if payload.get("freshness_state") in {"STALE", "LIMITED"} else 0
    confidence_escalation = 1 if payload.get("confidence_state") in {"LOW", "LIMITED"} else 0
    expected_rank = (
        100 * materiality_weight.get(payload.get("materiality_class"), 0)
        + 15 * resolution_weight.get(payload.get("resolution_class") or "NONE", 0)
        + 10 * subject_weight.get(payload.get("subject_class"), 0)
        + 5 * authority_escalation
        + 2 * freshness_escalation
        + confidence_escalation
    )
    if payload.get("delta_class") in TWIN_MATCH_DELTA_CLASSES:
        expected_rank = 0

    if payload.get("priority_rank") != expected_rank:
        issues.append(
            Issue(
                "custom",
                location,
                f"`priority_rank` must equal the frozen twin ranking formula result ({expected_rank}).",
            )
        )

    if payload.get("materiality_class") == "BLOCKING" and not payload.get("blocking_reason_codes"):
        issues.append(
            Issue(
                "custom",
                location,
                "Blocking delta arcs must carry at least one `blocking_reason_codes[]` entry.",
            )
        )
    left_subject_refs = payload.get("left_subject_refs", [])
    right_subject_refs = payload.get("right_subject_refs", [])
    contradiction_component_refs = payload.get("contradiction_component_refs", [])
    equivalence_reason_codes = payload.get("equivalence_reason_codes", [])
    if not isinstance(left_subject_refs, list):
        left_subject_refs = []
    if not isinstance(right_subject_refs, list):
        right_subject_refs = []
    if not isinstance(contradiction_component_refs, list):
        contradiction_component_refs = []
    if not isinstance(equivalence_reason_codes, list):
        equivalence_reason_codes = []
    if payload.get("delta_class") == "INTERNAL_ONLY":
        if not left_subject_refs or right_subject_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`delta_class = INTERNAL_ONLY` must retain only `left_subject_refs[]`.",
                )
            )
    elif payload.get("delta_class") == "AUTHORITY_ONLY":
        if left_subject_refs or not right_subject_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`delta_class = AUTHORITY_ONLY` must retain only `right_subject_refs[]`.",
                )
            )
    elif not left_subject_refs or not right_subject_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "All non-one-sided delta arcs must retain both `left_subject_refs[]` and `right_subject_refs[]`.",
            )
        )
    if payload.get("delta_class") == "MATCH_EXACT" and equivalence_reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`MATCH_EXACT` delta arcs must clear `equivalence_reason_codes[]`.",
            )
        )
    if payload.get("delta_class") == "MATCH_EQUIVALENT" and not equivalence_reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`MATCH_EQUIVALENT` delta arcs must retain non-empty `equivalence_reason_codes[]`.",
            )
        )
    subject_ref_set = set(left_subject_refs) | set(right_subject_refs)
    missing_contradiction_refs = [
        ref for ref in contradiction_component_refs if ref not in subject_ref_set
    ]
    if missing_contradiction_refs:
        issues.append(
            Issue(
                "custom",
                location,
                f"`contradiction_component_refs[]` must stay within the persisted lane subject refs; missing {missing_contradiction_refs}.",
            )
        )
    if contradiction_component_refs and payload.get("delta_class") not in TWIN_CONTRADICTION_DELTA_CLASSES:
        issues.append(
            Issue(
                "custom",
                location,
                "Only contradiction-capable delta classes may retain `contradiction_component_refs[]`.",
            )
        )
    return issues


def validate_proof_bundle(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    manifest_id = payload.get("manifest_id")
    manifest_refs = payload.get("manifest_refs", [])
    issues.extend(
        validate_manifest_ref_spine(
            manifest_id,
            manifest_refs,
            location,
            "`manifest_refs[]`",
        )
    )
    partition_issues, _ = validate_provenance_partition_contract(
        payload.get("partition_contract"),
        location,
        "`partition_contract`",
    )
    issues.extend(partition_issues)
    issues.extend(
        validate_retention_limited_explainability_contract(
            payload.get("retention_limited_explainability_contract"),
            location,
            "`retention_limited_explainability_contract`",
            expected_boundary_scope="PROOF_BUNDLE",
            expected_surface_role="FILING_PROOF_ARTIFACT",
            expected_surface_specific_binding_policy=(
                "PROOF_BUNDLE_RETAINS_DECISIVE_LIMITATION_AND_RETENTION_BINDING"
            ),
        )[0]
    )
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("lineage_boundary_refs"),
            location,
            "`lineage_boundary_refs[]`",
        )
    )
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("decisive_lineage_boundary_refs"),
            location,
            "`decisive_lineage_boundary_refs[]`",
        )
    )
    primary_path_ref = payload.get("primary_path_ref")
    decisive_path_refs = payload.get("decisive_path_refs", [])
    rejected_path_refs = payload.get("rejected_path_refs", [])
    rejected_path_entries = payload.get("rejected_path_entries", [])
    stale_reason_codes = payload.get("stale_reason_codes", [])
    staleness_dependency_refs = payload.get("staleness_dependency_refs", [])
    limitation_notes = payload.get("limitation_notes")
    if not isinstance(limitation_notes, list):
        limitation_notes = []
    retention_binding = payload.get("retention_binding") if isinstance(payload.get("retention_binding"), dict) else {}
    limitation_behavior = retention_binding.get("limitation_behavior")
    temporal_event_issues, temporal_event_refs = validate_temporal_propagation_event_refs(
        payload.get("temporal_propagation_event_refs"),
        location,
        "`temporal_propagation_event_refs`",
    )
    issues.extend(temporal_event_issues)
    lineage_boundary_refs = payload.get("lineage_boundary_refs", [])
    decisive_lineage_boundary_refs = payload.get("decisive_lineage_boundary_refs", [])
    if not isinstance(stale_reason_codes, list):
        stale_reason_codes = []
    if not isinstance(staleness_dependency_refs, list):
        staleness_dependency_refs = []
    issues.extend(
        validate_rejected_path_entries(
            rejected_path_entries,
            rejected_path_refs,
            primary_path_ref,
            location,
            "`rejected_path_entries[]`",
        )
    )
    if primary_path_ref is not None and primary_path_ref not in decisive_path_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_path_ref` must appear in `decisive_path_refs[]` when present.",
            )
        )
    if (
        isinstance(primary_path_ref, str)
        and isinstance(decisive_path_refs, list)
        and decisive_path_refs
        and decisive_path_refs[0] != primary_path_ref
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`decisive_path_refs[]` must begin with `primary_path_ref` when present.",
            )
        )

    overlap = sorted(set(decisive_path_refs) & set(rejected_path_refs))
    if overlap:
        issues.append(
            Issue(
                "custom",
                location,
                f"`decisive_path_refs[]` and `rejected_path_refs[]` must be disjoint; overlap {overlap}.",
            )
        )

    replay_recipe = payload.get("replay_recipe", {})
    replayable = replay_recipe.get("replayable") if isinstance(replay_recipe, dict) else None
    proof_closure_issues, _ = validate_proof_closure_contract(
        payload.get("proof_closure_contract"),
        location,
        "`proof_closure_contract`",
        support_state=payload.get("support_state"),
        closure_state=payload.get("closure_state"),
        replayable=replayable,
        contradiction_refs=payload.get("contradiction_refs"),
        stale_reason_codes=stale_reason_codes,
    )
    issues.extend(proof_closure_issues)

    if stale_reason_codes and not staleness_dependency_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`staleness_dependency_refs[]` must stay non-empty when stale reason codes are present.",
            )
        )
    if payload.get("support_state") == "STALE" and not temporal_event_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`support_state = STALE` must retain non-empty `temporal_propagation_event_refs[]` so decisive temporal invalidation stays replayable.",
            )
        )
    if staleness_dependency_refs and not stale_reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`staleness_dependency_refs[]` must clear when no stale reason codes are present.",
            )
        )
    missing_temporal_staleness_refs = [
        ref for ref in temporal_event_refs if ref not in staleness_dependency_refs
    ]
    if payload.get("support_state") == "STALE" and missing_temporal_staleness_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`staleness_dependency_refs[]` must include every temporal propagation event that invalidated the proof bundle; "
                f"missing {missing_temporal_staleness_refs}.",
            )
        )

    if payload.get("support_state") == "PARTIALLY_SUPPORTED" and not (
        payload.get("admissibility_state") == "LIMITED"
        and payload.get("closure_state") == "CLOSED"
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`PARTIALLY_SUPPORTED` proof bundles must remain `LIMITED` and `CLOSED`.",
            )
        )

    if payload.get("support_state") == "UNSUPPORTED" and (
        primary_path_ref is not None
        or decisive_path_refs
        or payload.get("closure_state") != "OPEN"
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`UNSUPPORTED` proof bundles must remain open and pathless.",
            )
        )

    if payload.get("support_state") == "CONTRADICTED" and payload.get("closure_state") != "OPEN":
        issues.append(
            Issue(
                "custom",
                location,
                "`CONTRADICTED` proof bundles must preserve `closure_state = OPEN`.",
            )
        )
    if payload.get("support_state") == "STALE" and payload.get("closure_state") != "OPEN":
        issues.append(
            Issue(
                "custom",
                location,
                "`STALE` proof bundles must preserve `closure_state = OPEN`.",
            )
        )

    if payload.get("support_state") != "UNSUPPORTED":
        if primary_path_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-`UNSUPPORTED` proof bundles must retain `primary_path_ref`.",
                )
            )
        if not decisive_path_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-`UNSUPPORTED` proof bundles must retain non-empty `decisive_path_refs[]`.",
                )
            )

    if isinstance(replay_recipe, dict):
        replay_manifest_refs = replay_recipe.get("manifest_refs", [])
        replay_lineage_boundary_refs = replay_recipe.get("lineage_boundary_refs", [])
        if isinstance(manifest_id, str) and isinstance(replay_manifest_refs, list) and manifest_id not in replay_manifest_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`replay_recipe.manifest_refs[]` must include the owning `manifest_id`.",
                )
            )
        if isinstance(manifest_refs, list) and isinstance(replay_manifest_refs, list) and manifest_refs != replay_manifest_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_refs[]` must exactly mirror `replay_recipe.manifest_refs[]` so replay never relies on ambient lineage context.",
                )
            )
        if (
            isinstance(lineage_boundary_refs, list)
            and isinstance(replay_lineage_boundary_refs, list)
            and lineage_boundary_refs != replay_lineage_boundary_refs
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`lineage_boundary_refs[]` must exactly mirror `replay_recipe.lineage_boundary_refs[]`.",
                )
            )
        required_artifact_refs = replay_recipe.get("required_artifact_refs", [])
        path_ref_order = replay_recipe.get("path_ref_order", [])
        deterministic_order_basis = replay_recipe.get("deterministic_order_basis", [])
        expected_path_ref_order = (
            ([primary_path_ref] if isinstance(primary_path_ref, str) else [])
            + [ref for ref in rejected_path_refs if isinstance(ref, str)]
        )
        if path_ref_order != expected_path_ref_order:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`replay_recipe.path_ref_order[]` must equal `[primary_path_ref] + rejected_path_refs[]` in recorded order.",
                )
            )
        if (
            isinstance(deterministic_order_basis, list)
            and PROOF_PATH_SELECTION_PROFILE not in deterministic_order_basis
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`replay_recipe.deterministic_order_basis[]` must include `{PROOF_PATH_SELECTION_PROFILE}`.",
                )
            )
        if payload.get("closure_state") == "CLOSED" and replay_recipe.get("replayable") is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Closed proof bundles must retain `replay_recipe.replayable = true`.",
                )
            )
        if isinstance(required_artifact_refs, list):
            required_artifact_ref_set = {
                ref for ref in required_artifact_refs if isinstance(ref, str)
            }
            graph_ref = payload.get("graph_ref")
            if isinstance(graph_ref, str) and graph_ref not in required_artifact_ref_set:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`replay_recipe.required_artifact_refs[]` must include `graph_ref`.",
                    )
                )
            required_path_refs = {
                ref
                for ref in (decisive_path_refs or []) + (rejected_path_refs or [])
                if isinstance(ref, str)
            }
            if isinstance(primary_path_ref, str):
                required_path_refs.add(primary_path_ref)
            missing_required_path_refs = sorted(required_path_refs - required_artifact_ref_set)
            if missing_required_path_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`replay_recipe.required_artifact_refs[]` must include every decisive and rejected path ref; missing {missing_required_path_refs}.",
                    )
                )
            missing_staleness_refs = sorted(
                ref
                for ref in staleness_dependency_refs
                if isinstance(ref, str) and ref not in required_artifact_ref_set
            )
            if missing_staleness_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`replay_recipe.required_artifact_refs[]` must include every `staleness_dependency_refs[]` entry; missing {missing_staleness_refs}.",
                    )
                )
            missing_temporal_event_refs = sorted(
                ref
                for ref in temporal_event_refs
                if isinstance(ref, str) and ref not in required_artifact_ref_set
            )
            if missing_temporal_event_refs:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`replay_recipe.required_artifact_refs[]` must include every `temporal_propagation_event_refs[]` entry; missing {missing_temporal_event_refs}.",
                    )
                )
    if isinstance(lineage_boundary_refs, list) and isinstance(decisive_lineage_boundary_refs, list):
        missing_decisive_boundary_refs = [
            ref for ref in decisive_lineage_boundary_refs if ref not in set(lineage_boundary_refs)
        ]
        if missing_decisive_boundary_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`decisive_lineage_boundary_refs[]` must stay within `lineage_boundary_refs[]`; "
                    f"missing {missing_decisive_boundary_refs}.",
                )
            )
    if isinstance(manifest_refs, list) and len(manifest_refs) > 1 and not lineage_boundary_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "Cross-manifest proof bundles must retain non-empty `lineage_boundary_refs[]`.",
            )
        )
    if isinstance(manifest_refs, list) and len(manifest_refs) == 1 and lineage_boundary_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "Single-manifest proof bundles must not retain `lineage_boundary_refs[]`.",
            )
        )

    render_refs = payload.get("render_refs", {})
    explanation_status = render_refs.get("explanation_status")
    render_ref_values = (
        render_refs.get("operator_render_ref"),
        render_refs.get("reviewer_render_ref"),
        render_refs.get("filing_artifact_ref"),
    )
    non_null_render_count = sum(value is not None for value in render_ref_values)
    if explanation_status == "AVAILABLE" and non_null_render_count != 3:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = AVAILABLE` requires all render refs to be present.",
            )
        )
    if explanation_status == "FAILED" and non_null_render_count != 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = FAILED` requires all render refs to be null.",
            )
        )
    if explanation_status == "LIMITED" and non_null_render_count == 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = LIMITED` requires at least one render ref to remain available.",
            )
        )
    proof_closure_contract = (
        payload.get("proof_closure_contract")
        if isinstance(payload.get("proof_closure_contract"), dict)
        else {}
    )
    if proof_closure_contract.get("silent_limitation_ambiguity_present") is True:
        issues.append(
            Issue(
                "custom",
                location,
                "Proof bundles must not persist `silent_limitation_ambiguity_present = true`; retention limits must be disclosed through `limitation_notes[]` and degraded explanation posture instead.",
            )
        )

    limitation_note_classes = {
        note.get("note_class")
        for note in limitation_notes
        if isinstance(note, dict) and isinstance(note.get("note_class"), str)
    }
    limitation_note_refs = {
        ref
        for note in limitation_notes
        if isinstance(note, dict)
        for ref in (note.get("affected_refs") or [])
        if isinstance(ref, str)
    }
    controlling_refs = {
        ref
        for ref in [payload.get("graph_ref"), primary_path_ref]
        if isinstance(ref, str)
    }
    decisive_evidence_refs = payload.get("decisive_evidence_refs", [])
    if isinstance(decisive_evidence_refs, list):
        controlling_refs.update(ref for ref in decisive_evidence_refs if isinstance(ref, str))
    if isinstance(decisive_path_refs, list):
        controlling_refs.update(ref for ref in decisive_path_refs if isinstance(ref, str))

    if limitation_behavior in {"LIMITED", "TOMBSTONED", "PSEUDONYMISED"}:
        if explanation_status == "AVAILABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited proof bundles must not advertise `explanation_status = AVAILABLE`.",
                )
            )
        if payload.get("admissibility_state") == "ADMISSIBLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited proof bundles must degrade `admissibility_state` below `ADMISSIBLE`.",
                )
            )
        if not limitation_notes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited proof bundles must retain non-empty `limitation_notes[]`.",
                )
            )
        if limitation_note_classes.isdisjoint({"RETENTION", "PRIVACY"}):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited proof bundles must retain at least one RETENTION or PRIVACY limitation note.",
                )
            )
        if controlling_refs and limitation_note_refs.isdisjoint(controlling_refs):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited proof bundles must bind `limitation_notes[]` to decisive graph, path, or evidence refs.",
                )
            )
    if explanation_status in {"LIMITED", "FAILED"} and not limitation_notes:
        issues.append(
            Issue(
                "custom",
                location,
                "Non-`AVAILABLE` proof bundles must retain explicit `limitation_notes[]` instead of degrading into silent absence.",
            )
        )
    return issues


def validate_enquiry_pack(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    manifest_id = payload.get("manifest_id")
    manifest_refs = payload.get("manifest_refs", [])
    issues.extend(
        validate_manifest_ref_spine(
            manifest_id,
            manifest_refs,
            location,
            "`manifest_refs[]`",
        )
    )
    partition_issues, partition_contract = validate_provenance_partition_contract(
        payload.get("partition_contract"),
        location,
        "`partition_contract`",
    )
    issues.extend(partition_issues)
    issues.extend(
        validate_retention_limited_explainability_contract(
            payload.get("retention_limited_explainability_contract"),
            location,
            "`retention_limited_explainability_contract`",
            expected_boundary_scope="ENQUIRY_PACK",
            expected_surface_role="SCRUTINY_EXPORT_PACK",
            expected_surface_specific_binding_policy=(
                "ENQUIRY_PACK_RETAINS_LIMITATION_NOTES_OMISSIONS_AND_RETENTION_BINDING"
            ),
        )[0]
    )

    primary_path_ref = payload.get("primary_path_ref")
    critical_path_refs = payload.get("critical_path_refs", [])
    limitation_notes = payload.get("limitation_notes")
    if not isinstance(limitation_notes, list):
        limitation_notes = []
    omission_entries = payload.get("omission_entries")
    if not isinstance(omission_entries, list):
        omission_entries = []
    retention_binding = payload.get("retention_binding") if isinstance(payload.get("retention_binding"), dict) else {}
    limitation_behavior = retention_binding.get("limitation_behavior")
    if isinstance(critical_path_refs, list) and primary_path_ref not in critical_path_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_path_ref` must appear in `critical_path_refs[]`.",
            )
        )

    lineage_boundaries = payload.get("lineage_boundaries", [])
    boundary_issues, boundary_ids = validate_lineage_boundaries(
        lineage_boundaries,
        location,
        "`lineage_boundaries[]`",
        manifest_refs=manifest_refs,
        exposed_path_refs=critical_path_refs,
        partition_contract=partition_contract,
    )
    issues.extend(boundary_issues)
    if isinstance(manifest_refs, list) and len(manifest_refs) > 1 and not boundary_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "Cross-manifest enquiry packs must retain non-empty `lineage_boundaries[]`.",
            )
        )
    if isinstance(manifest_refs, list) and len(manifest_refs) == 1 and boundary_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "Single-manifest enquiry packs must not retain `lineage_boundaries[]`.",
            )
        )
    if isinstance(lineage_boundaries, list) and isinstance(manifest_refs, list) and len(manifest_refs) > 1:
        boundary_manifest_ids = {
            manifest
            for boundary in lineage_boundaries
            if isinstance(boundary, dict)
            for manifest in (boundary.get("from_manifest_id"), boundary.get("to_manifest_id"))
            if isinstance(manifest, str)
        }
        missing_boundary_manifests = [
            ref for ref in manifest_refs[1:] if isinstance(ref, str) and ref not in boundary_manifest_ids
        ]
        if missing_boundary_manifests:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Every non-home `manifest_refs[]` entry in a cross-manifest enquiry pack must appear in "
                    f"`lineage_boundaries[]`; missing {missing_boundary_manifests}.",
                )
            )

    render_contract = payload.get("render_contract", {})
    operator_render_ref = render_contract.get("operator_render_ref") if isinstance(render_contract, dict) else None
    reviewer_render_ref = render_contract.get("reviewer_render_ref") if isinstance(render_contract, dict) else None
    filing_artifact_ref = render_contract.get("filing_artifact_ref") if isinstance(render_contract, dict) else None
    non_null_render_count = sum(
        value is not None for value in (operator_render_ref, reviewer_render_ref, filing_artifact_ref)
    )
    explanation_status = payload.get("explanation_status")
    if explanation_status == "AVAILABLE" and non_null_render_count != 3:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = AVAILABLE` requires every render-contract ref to be present.",
            )
        )
    if explanation_status == "FAILED" and non_null_render_count != 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = FAILED` requires every render-contract ref to be null.",
            )
        )
    if explanation_status == "LIMITED" and non_null_render_count == 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`explanation_status = LIMITED` requires at least one surviving render-contract ref.",
            )
        )
    limitation_note_classes = {
        note.get("note_class")
        for note in limitation_notes
        if isinstance(note, dict) and isinstance(note.get("note_class"), str)
    }
    limitation_note_refs = {
        ref
        for note in limitation_notes
        if isinstance(note, dict)
        for ref in (note.get("affected_refs") or [])
        if isinstance(ref, str)
    }
    omission_classes = {
        entry.get("omission_class")
        for entry in omission_entries
        if isinstance(entry, dict) and isinstance(entry.get("omission_class"), str)
    }
    omission_refs = {
        ref
        for entry in omission_entries
        if isinstance(entry, dict)
        for ref in (entry.get("affected_refs") or [])
        if isinstance(ref, str)
    }
    critical_refs = {
        ref
        for ref in [primary_path_ref, payload.get("proof_bundle_ref")]
        if isinstance(ref, str)
    }
    if isinstance(critical_path_refs, list):
        critical_refs.update(ref for ref in critical_path_refs if isinstance(ref, str))

    if limitation_behavior in {"LIMITED", "TOMBSTONED", "PSEUDONYMISED"}:
        if explanation_status == "AVAILABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must not advertise `explanation_status = AVAILABLE`.",
                )
            )
        if not limitation_notes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must retain non-empty `limitation_notes[]`.",
                )
            )
        if not omission_entries:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must retain non-empty `omission_entries[]`.",
                )
            )
        if limitation_note_classes.isdisjoint({"RETENTION", "PRIVACY"}):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must retain at least one RETENTION or PRIVACY limitation note.",
                )
            )
        if omission_classes.isdisjoint({"RETENTION", "PRIVACY"}):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must retain at least one RETENTION or PRIVACY omission entry.",
                )
            )
        if critical_refs and limitation_note_refs.isdisjoint(critical_refs):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must bind `limitation_notes[]` to the primary path, critical paths, or controlling proof bundle.",
                )
            )
        if critical_refs and omission_refs.isdisjoint(critical_refs):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Retention-limited enquiry packs must bind `omission_entries[]` to the primary path, critical paths, or controlling proof bundle.",
                )
            )
    if explanation_status in {"LIMITED", "FAILED"} and not limitation_notes:
        issues.append(
            Issue(
                "custom",
                location,
                "Non-`AVAILABLE` enquiry packs must retain explicit `limitation_notes[]`.",
            )
        )

    enquiry_externalization_tokens = sorted(
        token
        for token in limitation_note_classes | omission_classes
        if isinstance(token, str) and token
    )
    if explanation_status == "LIMITED" and not enquiry_externalization_tokens:
        enquiry_externalization_tokens = ["LIMITED_EXPLANATION"]
    if explanation_status == "FAILED" and not enquiry_externalization_tokens:
        enquiry_externalization_tokens = ["RENDER_FAILED"]
    enquiry_externalization_eligibility = {
        "AVAILABLE": "READY",
        "LIMITED": "LIMITED_READY",
        "FAILED": "BLOCKED",
    }.get(explanation_status)
    enquiry_externalization_masking_state = {
        "NONE": "NONE",
        "MASKED": "MASKED_EXPORT_ONLY",
        "REDACTED": "MASKED_EXPORT_ONLY",
        "LIMITED_EXPORT": "LIMITED_EXPORT",
    }.get(payload.get("masking_posture"))
    enquiry_externalization_limitation = (
        "FULL"
        if limitation_behavior == "FULL" and explanation_status == "AVAILABLE"
        else "RETENTION_LIMITED"
    )
    externalization_issues, _ = validate_externalization_governance_contract(
        payload.get("externalization_governance_contract"),
        location,
        "`externalization_governance_contract`",
        expected_boundary_scope="ENQUIRY_PACK",
        expected_tenant_id=payload.get("tenant_id"),
        expected_shell_family_or_null=None,
        expected_context_anchor_ref=payload.get("target_ref"),
        expected_slice_binding_ref=payload.get("target_ref"),
        expected_delivery_surface_kind="EXPLANATION_EXPORT",
        expected_history_meaning_state="LIMITED_EXPLANATION_EXPLICIT",
        expected_eligibility_state=enquiry_externalization_eligibility,
        expected_approval_state="NOT_REQUIRED",
        expected_access_binding_hash_or_null=None,
        expected_masking_state=enquiry_externalization_masking_state,
        expected_masking_posture_fingerprint_or_null=None,
        expected_limitation_state=enquiry_externalization_limitation,
        expected_visibility_cache_partition_key_or_null=None,
        expected_preview_target_ref_or_null=(
            payload.get("human_readable_ref") if explanation_status != "FAILED" else None
        ),
        expected_download_target_ref_or_null=(
            payload.get("machine_readable_ref") if explanation_status != "FAILED" else None
        ),
        expected_print_target_ref_or_null=None,
        expected_external_handoff_target_ref_or_null=None,
        expected_approval_requirement_token_or_null=None,
        expected_blocking_context_tokens=enquiry_externalization_tokens,
    )
    issues.extend(externalization_issues)
    return issues


def validate_replay_attestation(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        expected_run_kind="REPLAY",
        expected_replay_class_or_null=payload.get("replay_class") if "replay_class" in payload else CACHE_ISOLATION_UNSET,
        expected_execution_mode=payload.get("execution_mode") if "execution_mode" in payload else CACHE_ISOLATION_UNSET,
        expected_analysis_only=payload.get("analysis_only") if "analysis_only" in payload else CACHE_ISOLATION_UNSET,
        expected_non_compliance_config_refs=(
            payload.get("non_compliance_config_refs")
            if "non_compliance_config_refs" in payload
            else CACHE_ISOLATION_UNSET
        ),
        expected_counterfactual_basis=(
            payload.get("counterfactual_basis")
            if "counterfactual_basis" in payload
            else CACHE_ISOLATION_UNSET
        ),
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    tolerance = 1e-6
    expected_basis_order = [
        "IDENTITY_AUTHORITY",
        "EXECUTABLE",
        "CONFIG",
        "INPUT",
        "POST_SEAL",
        "DETERMINISM",
    ]
    expected_outcome_order = REPLAY_OUTCOME_COMPONENT_ORDER

    def is_number(value: object) -> bool:
        return isinstance(value, (int, float)) and not isinstance(value, bool)

    def close_enough(actual: object, expected: float) -> bool:
        return is_number(actual) and abs(float(actual) - expected) <= tolerance

    basis_results = payload.get("basis_dimension_results", [])
    if isinstance(basis_results, list):
        basis_codes = [result.get("dimension_code") for result in basis_results if isinstance(result, dict)]
        if basis_codes != expected_basis_order:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`basis_dimension_results[]` must preserve the frozen basis-dimension order.",
                )
            )

    outcome_results = payload.get("outcome_component_results", [])
    if isinstance(outcome_results, list):
        outcome_codes = [
            result.get("component_class") for result in outcome_results if isinstance(result, dict)
        ]
        if outcome_codes != expected_outcome_order:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`outcome_component_results[]` must preserve the frozen outcome-component order.",
                )
            )
        for result in outcome_results:
            if not isinstance(result, dict):
                continue
            if result.get("comparison_state") in REPLAY_OBSERVABLE_COMPONENT_STATES and not isinstance(
                result.get("component_ref"), str
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"Observable replay component `{result.get('component_class')}` must retain non-null `component_ref`.",
                    )
                )

    mismatch_inventory = payload.get("mismatch_inventory", [])
    if isinstance(mismatch_inventory, list):
        for mismatch in mismatch_inventory:
            if not isinstance(mismatch, dict):
                continue
            if mismatch.get("component_class") in REPLAY_MISMATCH_ARTIFACT_COMPONENT_CLASSES and not isinstance(
                mismatch.get("component_ref"), str
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"Artifact-backed replay mismatch `{mismatch.get('component_class')}` must retain non-null `component_ref`.",
                    )
                )

    basis_weight_total = 0.0
    basis_observed_weight = 0.0
    basis_match_weight = 0.0
    basis_declared_weight = 0.0
    basis_undeclared_weight = 0.0
    basis_corrupt = False
    if isinstance(basis_results, list):
        for result in basis_results:
            if not isinstance(result, dict):
                continue
            weight = result.get("comparison_weight")
            if not is_number(weight) or float(weight) <= 0:
                continue
            weight = float(weight)
            state = result.get("comparison_state")
            basis_weight_total += weight
            if state in {"MATCH", "MISMATCH", "DECLARED_CHANGE"}:
                basis_observed_weight += weight
            if state == "MATCH":
                basis_match_weight += weight
            elif state == "DECLARED_CHANGE":
                basis_declared_weight += weight
            elif state == "MISMATCH":
                basis_undeclared_weight += weight
            elif state == "CORRUPT":
                basis_corrupt = True

    derived_basis_coverage = (
        0.0 if basis_weight_total == 0 else basis_observed_weight / basis_weight_total
    )
    derived_basis_match_ratio = (
        0.0 if basis_observed_weight == 0 else basis_match_weight / basis_observed_weight
    )
    derived_basis_declared_mass = (
        0.0 if basis_weight_total == 0 else basis_declared_weight / basis_weight_total
    )
    derived_basis_undeclared_mass = (
        0.0 if basis_weight_total == 0 else basis_undeclared_weight / basis_weight_total
    )
    if basis_corrupt:
        derived_basis_verdict = "CORRUPT"
    elif derived_basis_coverage == 1 and derived_basis_declared_mass == 0 and derived_basis_undeclared_mass == 0:
        derived_basis_verdict = "IDENTICAL"
    elif derived_basis_declared_mass + derived_basis_undeclared_mass > 0:
        derived_basis_verdict = "DIFFERENT"
    else:
        derived_basis_verdict = "UNDECIDABLE"

    outcome_weight_total = 0.0
    outcome_observed_weight = 0.0
    outcome_match_weight = 0.0
    material_weight_total = 0.0
    material_observed_weight = 0.0
    material_match_weight = 0.0
    declared_material_weight = 0.0
    undeclared_material_weight = 0.0
    outcome_corrupt = False
    if isinstance(outcome_results, list):
        for result in outcome_results:
            if not isinstance(result, dict):
                continue
            weight = result.get("comparison_weight")
            if not is_number(weight) or float(weight) <= 0:
                continue
            weight = float(weight)
            state = result.get("comparison_state")
            materiality = result.get("materiality")
            material = materiality in {"MATERIAL", "BLOCKING"}
            outcome_weight_total += weight
            if state in {"MATCH", "MISMATCH", "DECLARED_CHANGE"}:
                outcome_observed_weight += weight
            if state == "MATCH":
                outcome_match_weight += weight
            if material:
                material_weight_total += weight
                if state in {"MATCH", "MISMATCH", "DECLARED_CHANGE"}:
                    material_observed_weight += weight
                if state == "MATCH":
                    material_match_weight += weight
                elif state == "DECLARED_CHANGE":
                    declared_material_weight += weight
                elif state == "MISMATCH":
                    undeclared_material_weight += weight
            if state == "CORRUPT":
                outcome_corrupt = True

    derived_outcome_coverage = (
        0.0 if outcome_weight_total == 0 else outcome_observed_weight / outcome_weight_total
    )
    derived_outcome_match_ratio = (
        0.0 if outcome_observed_weight == 0 else outcome_match_weight / outcome_observed_weight
    )
    derived_material_coverage = (
        0.0 if material_weight_total == 0 else material_observed_weight / material_weight_total
    )
    derived_material_match_ratio = (
        0.0 if material_observed_weight == 0 else material_match_weight / material_observed_weight
    )

    expected_basis_hash = payload.get("expected_execution_basis_hash")
    actual_basis_hash = payload.get("actual_execution_basis_hash")
    expected_outcome_hash = payload.get("expected_deterministic_outcome_hash")
    actual_outcome_hash = payload.get("actual_deterministic_outcome_hash")

    if outcome_corrupt:
        derived_equivalence_verdict = "CORRUPT"
    elif (
        derived_material_coverage == 1
        and declared_material_weight == 0
        and undeclared_material_weight == 0
        and expected_outcome_hash == actual_outcome_hash
    ):
        derived_equivalence_verdict = "IDENTICAL"
    elif declared_material_weight + undeclared_material_weight > 0:
        derived_equivalence_verdict = "DIFFERENT"
    else:
        derived_equivalence_verdict = "UNDECIDABLE"

    if not close_enough(payload.get("basis_coverage"), derived_basis_coverage):
        issues.append(
            Issue(
                "custom",
                location,
                f"`basis_coverage` must equal the derived basis coverage ({derived_basis_coverage:.6f}).",
            )
        )
    if not close_enough(payload.get("basis_match_ratio"), derived_basis_match_ratio):
        issues.append(
            Issue(
                "custom",
                location,
                f"`basis_match_ratio` must equal the derived basis match ratio ({derived_basis_match_ratio:.6f}).",
            )
        )
    if not close_enough(payload.get("outcome_coverage"), derived_outcome_coverage):
        issues.append(
            Issue(
                "custom",
                location,
                f"`outcome_coverage` must equal the derived outcome coverage ({derived_outcome_coverage:.6f}).",
            )
        )
    if not close_enough(payload.get("outcome_match_ratio"), derived_outcome_match_ratio):
        issues.append(
            Issue(
                "custom",
                location,
                f"`outcome_match_ratio` must equal the derived outcome match ratio ({derived_outcome_match_ratio:.6f}).",
            )
        )
    if not close_enough(payload.get("material_outcome_coverage"), derived_material_coverage):
        issues.append(
            Issue(
                "custom",
                location,
                f"`material_outcome_coverage` must equal the derived material outcome coverage ({derived_material_coverage:.6f}).",
            )
        )
    if not close_enough(payload.get("material_outcome_match_ratio"), derived_material_match_ratio):
        issues.append(
            Issue(
                "custom",
                location,
                f"`material_outcome_match_ratio` must equal the derived material outcome match ratio ({derived_material_match_ratio:.6f}).",
            )
        )

    if payload.get("basis_identity_verdict") != derived_basis_verdict:
        issues.append(
            Issue(
                "custom",
                location,
                f"`basis_identity_verdict` must equal the derived replay verdict ({derived_basis_verdict}).",
            )
        )
    if payload.get("deterministic_equivalence_verdict") != derived_equivalence_verdict:
        issues.append(
            Issue(
                "custom",
                location,
                "`deterministic_equivalence_verdict` must equal the derived outcome-equivalence verdict "
                f"({derived_equivalence_verdict}).",
            )
        )

    if derived_basis_verdict == "IDENTICAL" and expected_basis_hash != actual_basis_hash:
        issues.append(
            Issue(
                "custom",
                location,
                "Identical basis verdicts must retain matching expected and actual execution-basis hashes.",
            )
        )
    if derived_basis_verdict == "DIFFERENT" and expected_basis_hash == actual_basis_hash:
        issues.append(
            Issue(
                "custom",
                location,
                "Differing basis verdicts must retain different expected and actual execution-basis hashes.",
            )
        )
    if derived_equivalence_verdict == "IDENTICAL" and expected_outcome_hash != actual_outcome_hash:
        issues.append(
            Issue(
                "custom",
                location,
                "Identical deterministic-equivalence verdicts must retain matching expected and actual outcome hashes.",
            )
        )
    if derived_equivalence_verdict == "DIFFERENT" and expected_outcome_hash == actual_outcome_hash:
        issues.append(
            Issue(
                "custom",
                location,
                "Differing deterministic-equivalence verdicts must retain different expected and actual outcome hashes.",
            )
        )

    execution_mode = payload.get("execution_mode")
    analysis_only = payload.get("analysis_only")
    replay_class = payload.get("replay_class")
    counterfactual_basis = payload.get("counterfactual_basis")
    comparison_mode = payload.get("comparison_mode")
    basis_validation_state = payload.get("basis_validation_state")
    outcome_class = payload.get("outcome_class")
    difference_reason_codes = payload.get("difference_reason_codes", [])
    limitation_codes = payload.get("limitation_codes", [])
    non_compliance_config_refs = payload.get("non_compliance_config_refs", [])
    signature_verification_state = payload.get("signature_verification_state")
    attestation_envelope_ref = payload.get("attestation_envelope_ref")
    verification_material_refs = payload.get("verification_material_refs", [])
    basis_integrity_issues, basis_integrity_contract = validate_replay_basis_integrity_contract(
        payload.get("basis_integrity_contract"),
        location,
        "`basis_integrity_contract`",
        replay_class=replay_class,
        comparison_mode=comparison_mode,
        basis_validation_state=basis_validation_state,
        actual_deterministic_outcome_hash=actual_outcome_hash,
    )
    issues.extend(basis_integrity_issues)
    declared_counterfactual_dimensions = (
        basis_integrity_contract.get("declared_counterfactual_dimensions", [])
        if isinstance(basis_integrity_contract, dict)
        and isinstance(basis_integrity_contract.get("declared_counterfactual_dimensions"), list)
        else []
    )
    undeclared_basis_drift_dimensions = (
        basis_integrity_contract.get("undeclared_basis_drift_dimensions", [])
        if isinstance(basis_integrity_contract, dict)
        and isinstance(basis_integrity_contract.get("undeclared_basis_drift_dimensions"), list)
        else []
    )
    exact_basis_integrity = isinstance(basis_integrity_contract, dict) and (
        replay_class in {"STANDARD_REPLAY", "AUDIT_REPLAY"}
        and basis_integrity_contract.get("config_basis_source_class") == "HISTORICAL_FROZEN_REUSED"
        and basis_integrity_contract.get("input_basis_source_class") == "HISTORICAL_FROZEN_REUSED"
        and basis_integrity_contract.get("preseal_gate_source_class") == "HISTORICAL_PRESEAL_TAPE_REUSED"
        and basis_integrity_contract.get("authority_basis_source_class") in {"HISTORICAL_POST_SEAL_REUSED", "NOT_MATERIAL"}
        and basis_integrity_contract.get("baseline_basis_source_class") in {"HISTORICAL_POST_SEAL_REUSED", "NOT_MATERIAL"}
        and basis_integrity_contract.get("late_data_basis_source_class") in {"HISTORICAL_POST_SEAL_REUSED", "NOT_MATERIAL"}
        and basis_integrity_contract.get("temporal_propagation_event_source_class")
        in {"HISTORICAL_POST_SEAL_REUSED", "NOT_MATERIAL"}
        and basis_integrity_contract.get("live_connector_read_class") == "NOT_PERFORMED"
        and basis_integrity_contract.get("live_authority_read_class") == "NOT_PERFORMED"
        and basis_integrity_contract.get("late_data_rescan_class") == "NOT_PERFORMED"
        and basis_integrity_contract.get("missing_basis_dimensions") == []
        and basis_integrity_contract.get("corrupt_basis_dimensions") == []
        and basis_integrity_contract.get("substituted_basis_dimensions") == []
        and basis_integrity_contract.get("declared_counterfactual_dimensions") == []
        and basis_integrity_contract.get("undeclared_basis_drift_dimensions") == []
        and basis_integrity_contract.get("non_persisted_outcome_component_classes") == []
    )

    if execution_mode == "COMPLIANCE":
        if analysis_only is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=COMPLIANCE` must force `analysis_only=false`.",
                )
            )
        if counterfactual_basis is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=COMPLIANCE` must keep `counterfactual_basis` null.",
                )
            )
        if isinstance(non_compliance_config_refs, list) and non_compliance_config_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=COMPLIANCE` must keep `non_compliance_config_refs[]` empty.",
                )
            )
        if replay_class not in {"STANDARD_REPLAY", "AUDIT_REPLAY"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=COMPLIANCE` is only valid for `STANDARD_REPLAY` or `AUDIT_REPLAY`.",
                )
            )

    if execution_mode == "ANALYSIS":
        if analysis_only is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=ANALYSIS` must force `analysis_only=true`.",
                )
            )
        if not isinstance(counterfactual_basis, str) or not counterfactual_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=ANALYSIS` must retain a non-empty `counterfactual_basis`.",
                )
            )
        if replay_class != "COUNTERFACTUAL_ANALYSIS":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`execution_mode=ANALYSIS` is only valid for `COUNTERFACTUAL_ANALYSIS` replay.",
                )
            )

    if replay_class == "COUNTERFACTUAL_ANALYSIS":
        if execution_mode != "ANALYSIS" or analysis_only is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`COUNTERFACTUAL_ANALYSIS` must retain analysis execution posture.",
                )
            )
        if not isinstance(counterfactual_basis, str) or not counterfactual_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`COUNTERFACTUAL_ANALYSIS` must retain a non-empty `counterfactual_basis`.",
                )
            )
        if not isinstance(difference_reason_codes, list) or len(difference_reason_codes) == 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`COUNTERFACTUAL_ANALYSIS` must retain explicit `difference_reason_codes[]`.",
                )
            )

    if replay_class in {"STANDARD_REPLAY", "AUDIT_REPLAY"}:
        if execution_mode != "COMPLIANCE" or analysis_only is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`STANDARD_REPLAY` and `AUDIT_REPLAY` must retain compliance execution posture.",
                )
            )
        if counterfactual_basis is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`STANDARD_REPLAY` and `AUDIT_REPLAY` must keep `counterfactual_basis` null.",
                )
            )
        if isinstance(difference_reason_codes, list) and difference_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`STANDARD_REPLAY` and `AUDIT_REPLAY` must not populate `difference_reason_codes[]`.",
                )
            )

    counterfactual_declared_basis = (
        replay_class == "COUNTERFACTUAL_ANALYSIS"
        and derived_basis_verdict == "DIFFERENT"
        and derived_basis_undeclared_mass == 0
        and isinstance(declared_counterfactual_dimensions, list)
        and len(declared_counterfactual_dimensions) > 0
        and isinstance(undeclared_basis_drift_dimensions, list)
        and len(undeclared_basis_drift_dimensions) == 0
    )
    corrupt_posture = (
        basis_validation_state == "CORRUPT"
        or derived_basis_verdict == "CORRUPT"
        or derived_equivalence_verdict == "CORRUPT"
    )
    exact_replay_claimable = (
        exact_basis_integrity
        and basis_validation_state == "VALID"
        and derived_basis_verdict == "IDENTICAL"
        and derived_equivalence_verdict == "IDENTICAL"
        and close_enough(payload.get("basis_coverage"), 1.0)
        and close_enough(payload.get("material_outcome_coverage"), 1.0)
        and expected_basis_hash == actual_basis_hash
        and expected_outcome_hash == actual_outcome_hash
    )
    expected_equivalence_claimable = (
        counterfactual_declared_basis
        and derived_equivalence_verdict == "IDENTICAL"
    )
    expected_difference_claimable = (
        counterfactual_declared_basis
        and derived_equivalence_verdict == "DIFFERENT"
        and undeclared_material_weight == 0
    )
    observed_any = basis_observed_weight > 0 or outcome_observed_weight > 0
    basis_incomplete_claimable = (
        not corrupt_posture
        and material_observed_weight == 0
    )
    limited_comparable_claimable = (
        not corrupt_posture
        and observed_any
        and material_observed_weight > 0
        and (derived_basis_coverage < 1 or derived_material_coverage < 1)
    )

    if corrupt_posture:
        derived_outcome_class = "BASIS_CORRUPT"
        derived_comparison_mode = "BASIS_CORRUPT"
    elif exact_replay_claimable:
        derived_outcome_class = "EXACT_MATCH"
        derived_comparison_mode = "EXACT_HASH_MATCH"
    elif expected_equivalence_claimable:
        derived_outcome_class = "EXPECTED_EQUIVALENCE"
        derived_comparison_mode = "COUNTERFACTUAL_DECLARED"
    elif expected_difference_claimable:
        derived_outcome_class = "EXPECTED_DIFFERENCE"
        derived_comparison_mode = "COUNTERFACTUAL_DECLARED"
    elif basis_incomplete_claimable:
        derived_outcome_class = "BASIS_INCOMPLETE"
        derived_comparison_mode = "BASIS_INCOMPLETE"
    elif limited_comparable_claimable:
        derived_outcome_class = "LIMITED_COMPARABLE"
        derived_comparison_mode = "LIMITED_HISTORICAL_COMPARISON"
    else:
        derived_outcome_class = "UNEXPECTED_MISMATCH"
        derived_comparison_mode = "COUNTERFACTUAL_DECLARED" if counterfactual_declared_basis else None

    if outcome_class != derived_outcome_class:
        issues.append(
            Issue(
                "custom",
                location,
                f"`outcome_class` must equal the derived replay classification ({derived_outcome_class}).",
            )
        )

    if derived_comparison_mode is not None and comparison_mode != derived_comparison_mode:
        issues.append(
            Issue(
                "custom",
                location,
                f"`comparison_mode` must equal the derived replay comparison posture ({derived_comparison_mode}).",
            )
        )

    if comparison_mode == "COUNTERFACTUAL_DECLARED" and not counterfactual_declared_basis:
        issues.append(
            Issue(
                "custom",
                location,
                "`COUNTERFACTUAL_DECLARED` requires declared basis variance without undeclared basis mismatch.",
            )
        )
    if comparison_mode == "LIMITED_HISTORICAL_COMPARISON" and not limited_comparable_claimable:
        issues.append(
            Issue(
                "custom",
                location,
                "`LIMITED_HISTORICAL_COMPARISON` requires partial but still material replay comparison coverage.",
            )
        )
    if comparison_mode == "BASIS_INCOMPLETE" and not basis_incomplete_claimable:
        issues.append(
            Issue(
                "custom",
                location,
                "`BASIS_INCOMPLETE` requires zero observable material outcome comparison coverage.",
            )
        )

    if outcome_class == "EXACT_MATCH" and not exact_replay_claimable:
        issues.append(
            Issue(
                "custom",
                location,
                "`EXACT_MATCH` requires identical validated basis, identical deterministic outcome, and matching root hashes.",
            )
        )
    if outcome_class == "EXPECTED_EQUIVALENCE" and not expected_equivalence_claimable:
        issues.append(
            Issue(
                "custom",
                location,
                "`EXPECTED_EQUIVALENCE` requires declared basis variance with identical deterministic outcome.",
            )
        )
    if outcome_class == "EXPECTED_DIFFERENCE" and not expected_difference_claimable:
        issues.append(
            Issue(
                "custom",
                location,
                "`EXPECTED_DIFFERENCE` requires declared basis variance with no undeclared material mismatch.",
            )
        )
    if outcome_class == "LIMITED_COMPARABLE":
        if not limited_comparable_claimable:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`LIMITED_COMPARABLE` requires partial but still material replay comparison coverage.",
                )
            )
        if not isinstance(limitation_codes, list) or len(limitation_codes) == 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`LIMITED_COMPARABLE` must retain explicit `limitation_codes[]`.",
                )
            )
    if outcome_class == "BASIS_INCOMPLETE":
        if not basis_incomplete_claimable:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`BASIS_INCOMPLETE` requires zero observable material outcome comparison coverage.",
                )
            )
        if derived_equivalence_verdict != "UNDECIDABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`BASIS_INCOMPLETE` requires `deterministic_equivalence_verdict = UNDECIDABLE`.",
                )
            )
        if not isinstance(limitation_codes, list) or len(limitation_codes) == 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`BASIS_INCOMPLETE` must retain explicit `limitation_codes[]`.",
                )
            )

    if signature_verification_state == "VERIFICATION_MATERIAL_MISSING":
        if not isinstance(attestation_envelope_ref, str) or not attestation_envelope_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`VERIFICATION_MATERIAL_MISSING` must retain a non-null `attestation_envelope_ref`.",
                )
            )
        if isinstance(verification_material_refs, list) and verification_material_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`VERIFICATION_MATERIAL_MISSING` must keep `verification_material_refs[]` empty.",
                )
            )

    sig_factor_map = {
        "VERIFIED": 1.0,
        "NOT_SIGNED": 0.85,
        "VERIFICATION_MATERIAL_MISSING": 0.50,
        "SIGNATURE_INVALID": 0.0,
    }
    sig_factor = sig_factor_map.get(signature_verification_state)
    if sig_factor is not None:
        coverage_factor = min(derived_basis_coverage, derived_material_coverage)
        undeclared_variance_factor = 1 - max(
            derived_basis_undeclared_mass,
            0.0 if material_weight_total == 0 else undeclared_material_weight / material_weight_total,
        )
        raw_confidence = 100 * sig_factor * coverage_factor * undeclared_variance_factor
        expected_confidence = (
            0
            if basis_validation_state == "CORRUPT"
            else min(100, max(0, int(raw_confidence + 0.5)))
        )
        if payload.get("attestation_confidence_score") != expected_confidence:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`attestation_confidence_score` must equal the frozen replay-attestation confidence ({expected_confidence}).",
                )
            )

        if expected_confidence >= 95:
            expected_band = "VERY_HIGH"
        elif expected_confidence >= 80:
            expected_band = "HIGH"
        elif expected_confidence >= 60:
            expected_band = "MODERATE"
        elif expected_confidence >= 30:
            expected_band = "LOW"
        else:
            expected_band = "INSUFFICIENT"
        if payload.get("attestation_confidence_band") != expected_band:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`attestation_confidence_band` must equal the derived confidence band ({expected_band}).",
                )
            )

    return issues


def validate_evidence_graph(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    manifest_id = payload.get("manifest_id")
    manifest_refs = payload.get("manifest_refs", [])
    issues.extend(
        validate_manifest_ref_spine(
            manifest_id,
            manifest_refs,
            location,
            "`manifest_refs[]`",
        )
    )
    partition_issues, partition_contract = validate_provenance_partition_contract(
        payload.get("partition_contract"),
        location,
        "`partition_contract`",
    )
    issues.extend(partition_issues)
    issues.extend(
        validate_retention_limited_explainability_contract(
            payload.get("retention_limited_explainability_contract"),
            location,
            "`retention_limited_explainability_contract`",
            expected_boundary_scope="EVIDENCE_GRAPH",
            expected_surface_role="GRAPH_EXPLANATION_INDEX",
            expected_surface_specific_binding_policy=(
                "EVIDENCE_GRAPH_RETAINS_LIMITATION_NOTES_AND_TARGET_EXPLANATION_POSTURE"
            ),
        )[0]
    )
    limitation_notes = payload.get("limitation_notes")
    if not isinstance(limitation_notes, list):
        limitation_notes = []

    target_assessments = payload.get("target_assessments", [])
    if not isinstance(target_assessments, list):
        target_assessments = []
    path_refs_in_graph: set[str] = set()
    root_primary_path_ref = payload.get("primary_path_ref")
    if isinstance(root_primary_path_ref, str):
        path_refs_in_graph.add(root_primary_path_ref)
    for assessment in target_assessments:
        if not isinstance(assessment, dict):
            continue
        primary_path_ref = assessment.get("primary_path_ref")
        if isinstance(primary_path_ref, str):
            path_refs_in_graph.add(primary_path_ref)
        rejected_path_refs = assessment.get("rejected_path_refs", [])
        if isinstance(rejected_path_refs, list):
            path_refs_in_graph.update(
                ref for ref in rejected_path_refs if isinstance(ref, str)
            )
    boundary_issues, boundary_ids = validate_lineage_boundaries(
        payload.get("lineage_boundaries"),
        location,
        "`lineage_boundaries[]`",
        manifest_refs=manifest_refs,
        exposed_path_refs=sorted(path_refs_in_graph),
        partition_contract=partition_contract,
    )
    issues.extend(boundary_issues)
    if isinstance(manifest_refs, list) and len(manifest_refs) > 1 and not boundary_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "Cross-manifest evidence graphs must retain non-empty `lineage_boundaries[]`.",
            )
        )
    if isinstance(manifest_refs, list) and len(manifest_refs) == 1 and boundary_ids:
        issues.append(
            Issue(
                "custom",
                location,
                "Single-manifest evidence graphs must not retain `lineage_boundaries[]`.",
            )
        )
    lineage_boundaries = payload.get("lineage_boundaries", [])
    if isinstance(lineage_boundaries, list) and isinstance(manifest_refs, list) and len(manifest_refs) > 1:
        boundary_manifest_ids = {
            manifest
            for boundary in lineage_boundaries
            if isinstance(boundary, dict)
            for manifest in (boundary.get("from_manifest_id"), boundary.get("to_manifest_id"))
            if isinstance(manifest, str)
        }
        missing_boundary_manifests = [
            ref for ref in manifest_refs[1:] if isinstance(ref, str) and ref not in boundary_manifest_ids
        ]
        if missing_boundary_manifests:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Every non-home `manifest_refs[]` entry in a cross-manifest evidence graph must appear in "
                    f"`lineage_boundaries[]`; missing {missing_boundary_manifests}.",
                )
            )
    target_refs = [assessment.get("target_ref") for assessment in target_assessments]
    duplicates = duplicate_values(target_refs)
    if duplicates:
        issues.append(
            Issue(
                "custom",
                location,
                f"`target_assessments[]` contains duplicate logical target refs: {duplicates}.",
            )
        )

    path_ranking_basis = payload.get("path_ranking_basis", [])
    if isinstance(path_ranking_basis, list):
        rank_orders = [
            basis.get("rank_order")
            for basis in path_ranking_basis
            if isinstance(basis, dict) and isinstance(basis.get("rank_order"), int)
        ]
        criteria = [
            basis.get("criterion")
            for basis in path_ranking_basis
            if isinstance(basis, dict) and isinstance(basis.get("criterion"), str)
        ]
        duplicate_rank_orders = duplicate_values([str(value) for value in rank_orders])
        if duplicate_rank_orders:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`path_ranking_basis[].rank_order` must remain unique; duplicates {duplicate_rank_orders}.",
                )
            )
        duplicate_criteria = duplicate_values(criteria)
        if duplicate_criteria:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`path_ranking_basis[].criterion` must remain unique; duplicates {duplicate_criteria}.",
                )
            )
        if rank_orders and rank_orders != list(range(1, len(rank_orders) + 1)):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`path_ranking_basis[].rank_order` must form a contiguous sequence starting at 1.",
                )
            )

    assessment_by_primary_path: dict[str, dict[str, Any]] = {}
    for index, assessment in enumerate(target_assessments):
        if not isinstance(assessment, dict):
            continue
        assessment_location = f"{location}:target_assessments[{index}]"
        support_state = assessment.get("support_state")
        contradiction_refs = assessment.get("contradiction_refs", [])
        stale_reason_codes = assessment.get("stale_reason_codes", [])
        staleness_dependency_refs = assessment.get("staleness_dependency_refs", [])
        temporal_event_issues, temporal_event_refs = validate_temporal_propagation_event_refs(
            assessment.get("temporal_propagation_event_refs"),
            assessment_location,
            "`temporal_propagation_event_refs`",
        )
        issues.extend(temporal_event_issues)
        replayable = assessment.get("replayable")
        closure_failure_reason_codes = assessment.get("closure_failure_reason_codes", [])
        if not isinstance(closure_failure_reason_codes, list):
            closure_failure_reason_codes = []
        if not isinstance(staleness_dependency_refs, list):
            staleness_dependency_refs = []
        closure_issues, closure_contract = validate_proof_closure_contract(
            assessment.get("proof_closure_contract"),
            assessment_location,
            "`proof_closure_contract`",
            support_state=support_state,
            closure_state=assessment.get("closure_state"),
            replayable=replayable,
            contradiction_refs=contradiction_refs,
            stale_reason_codes=stale_reason_codes,
        )
        issues.extend(closure_issues)
        if closure_contract is not None and closure_failure_reason_codes != closure_contract.get(
            "closure_failure_reason_codes", []
        ):
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`closure_failure_reason_codes[]` must exactly mirror `proof_closure_contract.closure_failure_reason_codes[]`.",
                )
            )
        rejected_path_refs = assessment.get("rejected_path_refs", [])
        primary_path_ref = assessment.get("primary_path_ref")
        if not isinstance(rejected_path_refs, list):
            rejected_path_refs = []
        if isinstance(primary_path_ref, str) and primary_path_ref in rejected_path_refs:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`rejected_path_refs[]` must not include `primary_path_ref`.",
                )
            )
        if support_state in {"SUPPORTED", "PARTIALLY_SUPPORTED"} and replayable is not True:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "Supported or partially supported target assessments must remain replayable.",
                )
            )
        if support_state == "STALE" and assessment.get("closure_state") != "OPEN":
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`support_state = STALE` must preserve `closure_state = OPEN`.",
                )
            )
        if support_state == "STALE" and not temporal_event_refs:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`support_state = STALE` must retain non-empty `temporal_propagation_event_refs[]`.",
                )
            )
        if stale_reason_codes and not staleness_dependency_refs:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`staleness_dependency_refs[]` must stay non-empty when stale reason codes are present.",
                )
            )
        if staleness_dependency_refs and not stale_reason_codes:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`staleness_dependency_refs[]` must clear when no stale reason codes are present.",
                )
            )
        missing_temporal_staleness_refs = [
            ref for ref in temporal_event_refs if ref not in staleness_dependency_refs
        ]
        if support_state == "STALE" and missing_temporal_staleness_refs:
            issues.append(
                Issue(
                    "custom",
                    assessment_location,
                    "`staleness_dependency_refs[]` must include every temporal propagation event that invalidated the target assessment; "
                    f"missing {missing_temporal_staleness_refs}.",
                )
            )
        if isinstance(primary_path_ref, str):
            assessment_by_primary_path[primary_path_ref] = assessment

    assessment_primary_paths = {
        assessment.get("primary_path_ref")
        for assessment in target_assessments
        if isinstance(assessment, dict) and isinstance(assessment.get("primary_path_ref"), str)
    }
    primary_path_ref = payload.get("primary_path_ref")
    if primary_path_ref is not None and primary_path_ref not in assessment_primary_paths:
        issues.append(
            Issue(
                "custom",
                location,
                "`primary_path_ref` must resolve to one current target assessment primary path.",
            )
        )
    if isinstance(primary_path_ref, str):
        controlling_assessment = assessment_by_primary_path.get(primary_path_ref)
        if isinstance(controlling_assessment, dict) and (
            controlling_assessment.get("support_state") not in {"SUPPORTED", "PARTIALLY_SUPPORTED"}
            or controlling_assessment.get("closure_state") != "CLOSED"
            or controlling_assessment.get("replayable") is not True
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`primary_path_ref` may only point at a closed, replayable supported or partially supported target assessment.",
                )
            )

    assessment_proof_bundle_refs = sorted(
        {
            assessment.get("proof_bundle_ref")
            for assessment in target_assessments
            if isinstance(assessment, dict) and isinstance(assessment.get("proof_bundle_ref"), str)
        }
    )
    graph_proof_bundle_refs = payload.get("proof_bundle_refs", [])
    if isinstance(graph_proof_bundle_refs, list) and sorted(graph_proof_bundle_refs) != assessment_proof_bundle_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`proof_bundle_refs[]` must mirror the non-null `target_assessments[].proof_bundle_ref` set exactly.",
            )
        )

    filing_critical = [assessment for assessment in target_assessments if assessment.get("filing_critical")]
    for assessment in filing_critical:
        support_state = assessment.get("support_state")
        if support_state != "UNSUPPORTED" and assessment.get("primary_path_ref") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Filing-critical target `{assessment.get('target_ref')}` must retain `primary_path_ref` whenever `support_state != UNSUPPORTED`.",
                )
            )
        if support_state != "UNSUPPORTED" and assessment.get("proof_bundle_ref") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Filing-critical target `{assessment.get('target_ref')}` must retain `proof_bundle_ref` whenever `support_state != UNSUPPORTED`.",
                )
            )

    unsupported_count = sum(
        assessment.get("support_state") == "UNSUPPORTED" for assessment in filing_critical
    )
    contradicted_count = sum(
        assessment.get("support_state") == "CONTRADICTED" for assessment in filing_critical
    )
    stale_count = sum(assessment.get("support_state") == "STALE" for assessment in filing_critical)
    open_count = sum(assessment.get("closure_state") == "OPEN" for assessment in filing_critical)
    replay_failure_count = sum(not assessment.get("replayable", True) for assessment in filing_critical)
    explanation_failure_count = sum(
        assessment.get("explanation_status") == "FAILED" for assessment in filing_critical
    )
    missing_proof_bundle_count = sum(
        assessment.get("support_state") != "UNSUPPORTED" and assessment.get("proof_bundle_ref") is None
        for assessment in filing_critical
    )

    integrity_summary = payload.get("integrity_summary", {})
    expected_integrity = {
        "unsupported_critical_target_count": unsupported_count,
        "contradicted_critical_target_count": contradicted_count,
        "stale_critical_target_count": stale_count,
        "open_critical_target_count": open_count,
        "replay_failure_target_count": replay_failure_count,
        "missing_proof_bundle_target_count": missing_proof_bundle_count,
        "explanation_failure_count": explanation_failure_count,
    }
    for field, expected in expected_integrity.items():
        if integrity_summary.get(field) != expected:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`integrity_summary.{field}` must equal {expected}.",
                )
            )

    quality = payload.get("quality")
    if quality is not None:
        if quality.get("unsupported_critical_target_count") != unsupported_count:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`quality.unsupported_critical_target_count` must match filing-critical target assessments.",
                )
            )
        if quality.get("contradicted_critical_target_count") != contradicted_count:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`quality.contradicted_critical_target_count` must match filing-critical target assessments.",
                )
            )
        if quality.get("stale_critical_target_count") != stale_count:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`quality.stale_critical_target_count` must match filing-critical target assessments.",
                )
            )
        if quality.get("replay_failure_target_count") != replay_failure_count:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`quality.replay_failure_target_count` must match filing-critical target assessments.",
                )
            )

        denominator = len(filing_critical)
        expected_coverage = 1.0 if denominator == 0 else (
            sum(assessment.get("proof_bundle_ref") is not None for assessment in filing_critical) / denominator
        )
        if abs(quality.get("proof_bundle_coverage", 0) - expected_coverage) > 1e-9:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`quality.proof_bundle_coverage` must equal {expected_coverage}.",
                )
            )
        critical_retention_limited_count = quality.get("critical_retention_limited_count", 0)
        critical_evidence_erased_count = quality.get("critical_evidence_erased_count", 0)
        retention_pressure_present = (
            isinstance(critical_retention_limited_count, int)
            and critical_retention_limited_count > 0
        ) or (
            isinstance(critical_evidence_erased_count, int)
            and critical_evidence_erased_count > 0
        )
        if retention_pressure_present:
            if not limitation_notes:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Evidence graphs with critical retention or erasure pressure must retain non-empty `limitation_notes[]`.",
                    )
                )
            if not any(
                assessment.get("filing_critical")
                and assessment.get("explanation_status") in {"LIMITED", "FAILED"}
                for assessment in filing_critical
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Critical retention-limited evidence graphs must degrade at least one filing-critical target `explanation_status` away from `AVAILABLE`.",
                    )
                )
            limited_target_refs = {
                ref
                for assessment in filing_critical
                if assessment.get("explanation_status") in {"LIMITED", "FAILED"}
                for ref in (
                    assessment.get("target_ref"),
                    assessment.get("primary_path_ref"),
                    assessment.get("proof_bundle_ref"),
                )
                if isinstance(ref, str)
            }
            limitation_note_classes = {
                note.get("note_class")
                for note in limitation_notes
                if isinstance(note, dict) and isinstance(note.get("note_class"), str)
            }
            limitation_note_refs = {
                ref
                for note in limitation_notes
                if isinstance(note, dict)
                for ref in (note.get("affected_refs") or [])
                if isinstance(ref, str)
            }
            if limitation_note_classes.isdisjoint({"RETENTION", "PRIVACY"}):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Critical retention-limited evidence graphs must retain at least one RETENTION or PRIVACY limitation note.",
                    )
                )
            if limited_target_refs and limitation_note_refs.isdisjoint(limited_target_refs):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Critical retention-limited evidence graphs must bind `limitation_notes[]` to the affected target, path, or proof-bundle refs.",
                    )
                )

    if payload.get("lifecycle_state") == "REBUILD_REQUIRED" and integrity_summary.get("rebuild_required") is not True:
        issues.append(
            Issue(
                "custom",
                location,
                "`lifecycle_state = REBUILD_REQUIRED` must keep `integrity_summary.rebuild_required = true`.",
            )
        )
    return issues


def validate_manifest_start_claim_contract(
    payload: object, location: str, field_label: str, *, require_non_null: bool
) -> tuple[list[Issue], dict[str, Any] | None]:
    issues: list[Issue] = []
    if payload is None:
        if require_non_null:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label} must be present once a manifest reaches the sealed start boundary so duplicate start outcomes stay durable and replay-safe.",
                )
            )
        return issues, None
    if not isinstance(payload, dict):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label} must be an object.",
            )
        )
        return issues, None

    for field in (
        "manifest_id",
        "manifest_hash",
        "execution_basis_hash",
        "access_binding_hash",
        "attempt_lineage_ref",
    ):
        if not isinstance(payload.get(field), str) or not payload.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.{field} must be a non-empty string.",
                )
            )

    claim_state = payload.get("claim_state")
    claim_status_code = payload.get("claim_status_code")
    claim_epoch = payload.get("claim_epoch")
    claim_holder_ref = payload.get("claim_holder_ref_or_null")
    claim_token = payload.get("claim_token_or_null")
    stage_dag_ref = payload.get("stage_dag_ref_or_null")
    outbox_batch_ref = payload.get("outbox_batch_ref_or_null")
    release_reason = payload.get("claim_release_reason_code_or_null")
    stale_reclaim_reason = payload.get("stale_reclaim_reason_code_or_null")
    publication_state = payload.get("publication_state")

    if claim_state not in MANIFEST_START_CLAIM_STATES:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_state must be one of {sorted(MANIFEST_START_CLAIM_STATES)}.",
            )
        )
    if claim_status_code not in MANIFEST_START_CLAIM_STATUS_CODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_status_code must be one of {sorted(MANIFEST_START_CLAIM_STATUS_CODES)}.",
            )
        )
    if release_reason is not None and release_reason not in MANIFEST_START_CLAIM_RELEASE_REASON_CODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_release_reason_code_or_null must be one of {sorted(MANIFEST_START_CLAIM_RELEASE_REASON_CODES)}.",
            )
        )
    if stale_reclaim_reason is not None and stale_reclaim_reason not in MANIFEST_START_CLAIM_STALE_RECLAIM_REASON_CODES:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.stale_reclaim_reason_code_or_null must be one of {sorted(MANIFEST_START_CLAIM_STALE_RECLAIM_REASON_CODES)}.",
            )
        )

    if claim_state == "UNCLAIMED_SEALED":
        if claim_status_code != "CLAIMABLE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_state = UNCLAIMED_SEALED must force `claim_status_code = CLAIMABLE`.",
                )
            )
        if claim_epoch != 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_epoch must be `0` while `claim_state = UNCLAIMED_SEALED`.",
                )
            )
        for field in (
            "claim_holder_ref_or_null",
            "claim_token_or_null",
            "claim_acquired_at_or_null",
            "claim_expires_at_or_null",
            "claim_released_at_or_null",
            "claim_release_reason_code_or_null",
            "stale_reclaim_reason_code_or_null",
            "stage_dag_ref_or_null",
            "outbox_batch_ref_or_null",
            "first_publication_committed_at_or_null",
        ):
            if payload.get(field) is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_label}.{field} must stay null while `claim_state = UNCLAIMED_SEALED`.",
                    )
                )
        if publication_state != "NOT_PUBLISHED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.publication_state must be `NOT_PUBLISHED` while `claim_state = UNCLAIMED_SEALED`.",
                )
            )

    if claim_state == "ACTIVE_LEASED":
        if claim_status_code != "ALREADY_ACTIVE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_state = ACTIVE_LEASED must force `claim_status_code = ALREADY_ACTIVE`.",
                )
            )
        if not isinstance(claim_epoch, int) or claim_epoch < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_epoch must be >= 1 while `claim_state = ACTIVE_LEASED`.",
                )
            )
        for field in (
            "claim_holder_ref_or_null",
            "claim_token_or_null",
            "claim_acquired_at_or_null",
            "claim_expires_at_or_null",
            "stage_dag_ref_or_null",
            "outbox_batch_ref_or_null",
            "first_publication_committed_at_or_null",
        ):
            if not isinstance(payload.get(field), str) or not payload.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_label}.{field} must be non-empty while `claim_state = ACTIVE_LEASED`.",
                    )
                )
        if payload.get("claim_released_at_or_null") is not None or release_reason is not None or stale_reclaim_reason is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label} active leases must not retain release or stale-reclaim reason fields.",
                )
            )
        if publication_state != "PUBLISHED_WITH_ACTIVE_LEASE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.publication_state must be `PUBLISHED_WITH_ACTIVE_LEASE` while `claim_state = ACTIVE_LEASED`.",
                )
            )

    if claim_state == "STALE_RECLAIM_REQUIRED":
        if claim_status_code != "STALE_RECLAIM_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_state = STALE_RECLAIM_REQUIRED must force matching `claim_status_code`.",
                )
            )
        if not isinstance(claim_epoch, int) or claim_epoch < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_epoch must be >= 1 while `claim_state = STALE_RECLAIM_REQUIRED`.",
                )
            )
        for field in (
            "claim_holder_ref_or_null",
            "claim_token_or_null",
            "claim_acquired_at_or_null",
            "claim_expires_at_or_null",
            "stage_dag_ref_or_null",
            "outbox_batch_ref_or_null",
            "first_publication_committed_at_or_null",
        ):
            if not isinstance(payload.get(field), str) or not payload.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_label}.{field} must be non-empty while `claim_state = STALE_RECLAIM_REQUIRED`.",
                    )
                )
        if not isinstance(stale_reclaim_reason, str) or stale_reclaim_reason not in MANIFEST_START_CLAIM_STALE_RECLAIM_REASON_CODES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.stale_reclaim_reason_code_or_null must be a typed stale-reclaim reason while `claim_state = STALE_RECLAIM_REQUIRED`.",
                )
            )
        if payload.get("claim_released_at_or_null") is not None or release_reason is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label} stale-reclaim posture must not retain release timing or release reason fields.",
                )
            )
        if publication_state != "PUBLISHED_STALE_RECLAIM_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.publication_state must be `PUBLISHED_STALE_RECLAIM_REQUIRED` while stale reclaim is required.",
                )
            )

    if claim_state == "TERMINAL_RESULT_RECORDED":
        if claim_status_code != "ALREADY_TERMINAL":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_state = TERMINAL_RESULT_RECORDED must force `claim_status_code = ALREADY_TERMINAL`.",
                )
            )
        if not isinstance(claim_epoch, int) or claim_epoch < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_epoch must be >= 1 while `claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )
        for field in (
            "claim_holder_ref_or_null",
            "claim_token_or_null",
            "claim_acquired_at_or_null",
            "claim_expires_at_or_null",
            "stage_dag_ref_or_null",
            "outbox_batch_ref_or_null",
            "first_publication_committed_at_or_null",
        ):
            if not isinstance(payload.get(field), str) or not payload.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_label}.{field} must be non-empty while `claim_state = TERMINAL_RESULT_RECORDED`.",
                    )
                )
        if not isinstance(payload.get("claim_released_at_or_null"), str) or not payload.get("claim_released_at_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_released_at_or_null must be non-empty while `claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )
        if release_reason not in MANIFEST_START_CLAIM_RELEASE_REASON_CODES:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.claim_release_reason_code_or_null must be a terminal release reason while `claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )
        if stale_reclaim_reason is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.stale_reclaim_reason_code_or_null must stay null once a terminal result is recorded.",
                )
            )
        if publication_state != "PUBLISHED_TERMINAL":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"{field_label}.publication_state must be `PUBLISHED_TERMINAL` while `claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )

    if claim_token is not None:
        for field in ("claim_holder_ref_or_null", "claim_acquired_at_or_null", "claim_expires_at_or_null"):
            if not isinstance(payload.get(field), str) or not payload.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"{field_label}.{field} must be non-empty whenever `claim_token_or_null` is present.",
                    )
                )
    if stage_dag_ref is not None and (not isinstance(outbox_batch_ref, str) or not outbox_batch_ref):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.stage_dag_ref_or_null must pair with non-empty `outbox_batch_ref_or_null`.",
            )
        )
    if outbox_batch_ref is not None and (not isinstance(stage_dag_ref, str) or not stage_dag_ref):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.outbox_batch_ref_or_null must pair with non-empty `stage_dag_ref_or_null`.",
            )
        )
    if (stage_dag_ref is not None or outbox_batch_ref is not None) and (
        not isinstance(payload.get("first_publication_committed_at_or_null"), str)
        or not payload.get("first_publication_committed_at_or_null")
    ):
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.first_publication_committed_at_or_null must be non-empty whenever publication refs are present.",
            )
        )

    acquired_at = parse_datetime(payload.get("claim_acquired_at_or_null"))
    expires_at = parse_datetime(payload.get("claim_expires_at_or_null"))
    released_at = parse_datetime(payload.get("claim_released_at_or_null"))
    first_publication_at = parse_datetime(payload.get("first_publication_committed_at_or_null"))
    if acquired_at is not None and expires_at is not None and expires_at < acquired_at:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_expires_at_or_null must not be earlier than `claim_acquired_at_or_null`.",
            )
        )
    if acquired_at is not None and first_publication_at is not None and first_publication_at < acquired_at:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.first_publication_committed_at_or_null must not be earlier than `claim_acquired_at_or_null`.",
            )
        )
    if acquired_at is not None and released_at is not None and released_at < acquired_at:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_released_at_or_null must not be earlier than `claim_acquired_at_or_null`.",
            )
        )
    if first_publication_at is not None and released_at is not None and released_at < first_publication_at:
        issues.append(
            Issue(
                "custom",
                location,
                f"{field_label}.claim_released_at_or_null must not be earlier than `first_publication_committed_at_or_null`.",
            )
        )

    return issues, payload


def validate_run_manifest(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_command_truth_boundary_contract(
            payload.get("truth_boundary_contract"),
            location,
            "`truth_boundary_contract`",
            expected_artifact_role="COMMAND_SIDE_AUTHORITY",
            expected_authoritative_record_families=[
                "RUN_MANIFEST",
                "GATE_DECISION_RECORD",
                "WORKFLOW_ITEM",
                "AUTHORITY_INTERACTION_RECORD",
                "AUDIT_EVENT",
            ],
            expected_observable_projection_families=[],
        )[0]
    )
    issues.extend(
        validate_schema_reader_window_contract(
            payload.get("schema_reader_window_contract"),
            location,
            "`schema_reader_window_contract`",
            expected_writer_schema_bundle_hash=payload.get("schema_bundle_hash"),
        )[0]
    )
    state_transition_issues, state_transition_contract = validate_state_transition_contract(
        payload.get("state_transition_contract"),
        location,
        "`state_transition_contract`",
        expected_object_family="RUN_MANIFEST",
        current_state=payload.get("lifecycle_state"),
        audit_refs=payload.get("audit_refs"),
    )
    issues.extend(state_transition_issues)
    invariant_contract_issues, invariant_enforcement_contract = validate_invariant_enforcement_contract(
        payload.get("invariant_enforcement_contract"),
        location,
        "`invariant_enforcement_contract`",
        expected_boundary_scope="RUN_MANIFEST",
    )
    issues.extend(invariant_contract_issues)
    manifest_id = payload.get("manifest_id")
    config_freeze = payload.get("config_freeze")
    input_freeze = payload.get("input_freeze")
    hash_set = payload.get("hash_set")
    access_decision = payload.get("access_decision")
    scope_execution_binding = payload.get("scope_execution_binding")
    frozen_execution_binding = payload.get("frozen_execution_binding")
    append_only_outcome_projection = payload.get("append_only_outcome_projection")
    manifest_branch_decision = payload.get("manifest_branch_decision")
    manifest_lineage_trace_refs = payload.get("manifest_lineage_trace_refs")
    issues.extend(validate_scope_sequence(payload.get("requested_scope"), location, "`requested_scope[]`"))
    scope_binding_issues, scope_binding = validate_scope_execution_binding(
        scope_execution_binding,
        location,
        "`scope_execution_binding`",
    )
    issues.extend(scope_binding_issues)
    authorized_scope = (
        scope_binding.get("executable_scope")
        if isinstance(scope_binding, dict)
        else access_decision.get("effective_scope")
        if isinstance(access_decision, dict)
        else None
    )
    if authorized_scope is None:
        authorized_scope = payload.get("requested_scope", [])
    continuation_set = payload.get("continuation_set", {})
    continuation_basis = payload.get("continuation_basis")
    child_bases = CHILD_CONTINUATION_BASES
    submission_refs = payload.get("submission_refs") if isinstance(payload.get("submission_refs"), list) else []
    drift_refs = payload.get("drift_refs") if isinstance(payload.get("drift_refs"), list) else []
    invariant_failure_state = (
        invariant_enforcement_contract.get("invariant_failure_state")
        if isinstance(invariant_enforcement_contract, dict)
        else None
    )
    transition_event_code = (
        state_transition_contract.get("transition_event_code")
        if isinstance(state_transition_contract, dict)
        else None
    )
    mirror_fields = (
        "root_manifest_id",
        "parent_manifest_id",
        "continuation_of_manifest_id",
        "replay_of_manifest_id",
        "supersedes_manifest_id",
        "manifest_generation",
    )
    for field in mirror_fields:
        if payload.get(field) != continuation_set.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field}` must exactly mirror `continuation_set.{field}`.",
                )
            )

    if not isinstance(manifest_lineage_trace_refs, list) or not manifest_lineage_trace_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`RunManifest.manifest_lineage_trace_refs[]` must retain at least one persisted `ManifestLineageTrace` ref.",
            )
        )
    elif duplicate_values([ref for ref in manifest_lineage_trace_refs if isinstance(ref, str)]):
        issues.append(
            Issue(
                "custom",
                location,
                "`RunManifest.manifest_lineage_trace_refs[]` must stay unique.",
            )
        )

    branch_decision_issues, branch_decision = validate_manifest_branch_decision(
        manifest_branch_decision,
        location,
        "`manifest_branch_decision`",
    )
    issues.extend(branch_decision_issues)
    if isinstance(branch_decision, dict):
        if branch_decision.get("branch_action") != continuation_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.branch_action` must equal the persisted `continuation_basis` on `RunManifest`.",
                )
            )
        if branch_decision.get("selected_manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.selected_manifest_id` must mirror `manifest_id`.",
                )
            )
        if branch_decision.get("selected_manifest_continuation_basis") != continuation_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.selected_manifest_continuation_basis` must mirror `continuation_basis`.",
                )
            )
        for field, decision_field in (
            ("root_manifest_id", "root_manifest_id"),
            ("parent_manifest_id", "parent_manifest_id_or_null"),
            ("continuation_of_manifest_id", "continuation_of_manifest_id_or_null"),
            ("replay_of_manifest_id", "replay_of_manifest_id_or_null"),
            ("supersedes_manifest_id", "supersedes_manifest_id_or_null"),
            ("manifest_generation", "selected_manifest_generation"),
            ("idempotency_key", "idempotency_key"),
            ("access_binding_hash", "access_binding_hash"),
            ("mode", "mode"),
            ("run_kind", "run_kind"),
        ):
            if payload.get(field) != branch_decision.get(decision_field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`manifest_branch_decision.{decision_field}` must mirror `{field}`.",
                    )
                )
        if payload.get("requested_scope") != branch_decision.get("requested_scope"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.requested_scope[]` must mirror `requested_scope[]`.",
                )
            )
        if authorized_scope != branch_decision.get("effective_scope"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.effective_scope[]` must mirror the manifest's authorized executable scope.",
                )
            )
        if payload.get("replay_class") != branch_decision.get("replay_class_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.replay_class_or_null` must mirror `replay_class`.",
                )
            )
        if payload.get("nightly_window_key") != branch_decision.get("nightly_window_key_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.nightly_window_key_or_null` must mirror `nightly_window_key`.",
                )
            )
        if continuation_set.get("config_inheritance_mode") != branch_decision.get("config_inheritance_mode_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.config_inheritance_mode_or_null` must mirror `continuation_set.config_inheritance_mode`.",
                )
            )
        if continuation_set.get("input_inheritance_mode") != branch_decision.get("input_inheritance_mode_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.input_inheritance_mode_or_null` must mirror `continuation_set.input_inheritance_mode`.",
                )
            )
        if continuation_basis in child_bases:
            if branch_decision.get("prior_manifest_id_or_null") != payload.get("parent_manifest_id"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_branch_decision.prior_manifest_id_or_null` must mirror `parent_manifest_id` for child manifests.",
                    )
                )
            if branch_decision.get("prior_manifest_hash_at_decision_or_null") != continuation_set.get(
                "parent_manifest_hash_at_branch"
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`manifest_branch_decision.prior_manifest_hash_at_decision_or_null` must mirror `continuation_set.parent_manifest_hash_at_branch`.",
                    )
                )
        elif branch_decision.get("prior_manifest_hash_at_decision_or_null") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_branch_decision.prior_manifest_hash_at_decision_or_null` must stay null for root manifests.",
                )
            )
        if branch_decision.get("returned_decision_bundle_hash_or_null") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest` must not persist a bundle-return branch action inside `manifest_branch_decision`.",
                )
            )

    if isinstance(frozen_execution_binding, dict):
        frozen_scope_binding_issues, frozen_scope_binding = validate_scope_execution_binding(
            frozen_execution_binding.get("scope_execution_binding"),
            location,
            "`frozen_execution_binding.scope_execution_binding`",
        )
        issues.extend(frozen_scope_binding_issues)
        issues.extend(
            validate_scope_sequence(
                frozen_execution_binding.get("requested_scope"),
                location,
                "`frozen_execution_binding.requested_scope[]`",
            )
        )
        issues.extend(
            validate_scope_sequence(
                frozen_execution_binding.get("executable_scope"),
                location,
                "`frozen_execution_binding.executable_scope[]`",
            )
        )
        for field in (
            "manifest_id",
            "continuation_basis",
            "root_manifest_id",
            "parent_manifest_id",
            "continuation_of_manifest_id",
            "replay_of_manifest_id",
            "supersedes_manifest_id",
            "manifest_generation",
            "access_binding_hash",
            "environment_ref",
            "provider_environment_refs",
            "code_build_id",
            "schema_bundle_hash",
            "feature_flag_snapshot_hash",
            "deterministic_seed",
            "authority_context_ref",
        ):
            if payload.get(field) != frozen_execution_binding.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`frozen_execution_binding.{field}` must exactly mirror the parent manifest field.",
                    )
                )

        if payload.get("requested_scope") != frozen_execution_binding.get("requested_scope"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.requested_scope[]` must exactly mirror `requested_scope[]`.",
                )
            )
        for field in (
            "root_manifest_id",
            "parent_manifest_id",
            "continuation_of_manifest_id",
            "replay_of_manifest_id",
            "supersedes_manifest_id",
            "manifest_generation",
            "parent_manifest_hash_at_branch",
            "config_inheritance_mode",
            "input_inheritance_mode",
            "inherited_config_freeze_ref",
            "fresh_resolution_reason_code",
            "inherited_input_freeze_ref",
            "fresh_collection_reason_code",
        ):
            if frozen_execution_binding.get(field) != continuation_set.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`frozen_execution_binding.{field}` must mirror `continuation_set.{field}`.",
                    )
                )
        if isinstance(frozen_scope_binding, dict):
            if frozen_execution_binding.get("requested_scope") != frozen_scope_binding.get("requested_scope"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`frozen_execution_binding.requested_scope[]` must mirror `frozen_execution_binding.scope_execution_binding.requested_scope[]`.",
                    )
                )
            if frozen_execution_binding.get("executable_scope") != frozen_scope_binding.get("executable_scope"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`frozen_execution_binding.executable_scope[]` must mirror `frozen_execution_binding.scope_execution_binding.executable_scope[]`.",
                    )
                )
            if scope_binding is not None:
                for field in (
                    "execution_mode_or_null",
                    "requested_scope_family",
                    "executable_scope_family",
                    "requested_scope",
                    "executable_scope",
                    "executable_partition_scope_refs",
                    "access_decision",
                    "reduction_posture",
                    "mutation_atomicity",
                    "masking_rules",
                    "required_approvals",
                    "required_authn_level",
                    "access_binding_hash",
                    "reason_codes",
                ):
                    if scope_binding.get(field) != frozen_scope_binding.get(field):
                        issues.append(
                            Issue(
                                "custom",
                                location,
                                f"`frozen_execution_binding.scope_execution_binding.{field}` must mirror `scope_execution_binding.{field}`.",
                            )
                        )

        if not isinstance(hash_set, dict) or frozen_execution_binding.get("manifest_hash") != hash_set.get("manifest_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.manifest_hash` must mirror `hash_set.manifest_hash`.",
                )
            )
        if not isinstance(hash_set, dict) or frozen_execution_binding.get("execution_basis_hash") != hash_set.get(
            "execution_basis_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.execution_basis_hash` must mirror `hash_set.execution_basis_hash`.",
                )
            )
        if not isinstance(config_freeze, dict) or frozen_execution_binding.get("config_freeze_ref") != config_freeze.get(
            "config_freeze_id"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.config_freeze_ref` must mirror `config_freeze.config_freeze_id`.",
                )
            )
        if not isinstance(config_freeze, dict) or frozen_execution_binding.get("config_freeze_hash") != config_freeze.get(
            "config_freeze_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.config_freeze_hash` must mirror `config_freeze.config_freeze_hash`.",
                )
            )
        if not isinstance(config_freeze, dict) or frozen_execution_binding.get("config_surface_hash") != config_freeze.get(
            "config_surface_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.config_surface_hash` must mirror `config_freeze.config_surface_hash`.",
                )
            )
        if not isinstance(config_freeze, dict) or frozen_execution_binding.get("config_resolution_basis") != config_freeze.get(
            "config_resolution_basis"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.config_resolution_basis` must mirror `config_freeze.config_resolution_basis`.",
                )
            )
        if not isinstance(config_freeze, dict) or frozen_execution_binding.get("config_consumption_mode") != config_freeze.get(
            "config_consumption_mode"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.config_consumption_mode` must mirror `config_freeze.config_consumption_mode`.",
                )
            )
        if not isinstance(input_freeze, dict) or frozen_execution_binding.get("input_freeze_ref") != input_freeze.get(
            "input_freeze_id"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.input_freeze_ref` must mirror `input_freeze.input_freeze_id`.",
                )
            )
        if not isinstance(input_freeze, dict) or frozen_execution_binding.get("input_set_hash") != input_freeze.get(
            "input_set_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.input_set_hash` must mirror `input_freeze.input_set_hash`.",
                )
            )
        if isinstance(input_freeze, dict):
            for field in (
                "source_plan_ref",
                "source_plan_hash",
                "source_window_ref",
                "source_window_hash",
                "collection_boundary_ref",
                "collection_boundary_hash",
                "normalization_context_ref",
                "normalization_context_hash",
                "input_consumption_mode",
            ):
                if frozen_execution_binding.get(field) != input_freeze.get(field):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`frozen_execution_binding.{field}` must mirror `input_freeze.{field}`.",
                        )
                    )
        if isinstance(access_decision, dict) and frozen_execution_binding.get("executable_scope") != access_decision.get(
            "effective_scope"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.executable_scope[]` must mirror `access_decision.effective_scope[]`.",
                )
            )
        if frozen_execution_binding.get("worker_consumption_mode") != "MANIFEST_BOUND_ONLY":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`frozen_execution_binding.worker_consumption_mode` must stay `MANIFEST_BOUND_ONLY`.",
                )
            )

    if isinstance(append_only_outcome_projection, dict):
        issues.extend(
            validate_manifest_output_refs(
                append_only_outcome_projection.get("output_refs"),
                location,
                "`append_only_outcome_projection.output_refs`",
                manifest_id=manifest_id,
                decision_bundle_hash=append_only_outcome_projection.get("decision_bundle_hash"),
                replay_attestation_ref=append_only_outcome_projection.get("replay_attestation_ref"),
                submission_refs=append_only_outcome_projection.get("submission_refs", []),
                drift_refs=append_only_outcome_projection.get("drift_refs", []),
            )
        )
        for field in (
            "gating_decisions",
            "output_refs",
            "audit_refs",
            "submission_refs",
            "drift_refs",
            "decision_bundle_hash",
            "deterministic_outcome_hash",
            "replay_attestation_ref",
        ):
            if payload.get(field) != append_only_outcome_projection.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`append_only_outcome_projection.{field}` must exactly mirror the parent manifest field.",
                    )
                )

        post_seal_basis = append_only_outcome_projection.get("post_seal_basis")
        if isinstance(post_seal_basis, dict):
            if (post_seal_basis.get("authority_context_ref") is None) != (post_seal_basis.get("authority_context_hash") is None):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis` must pair `authority_context_ref` with `authority_context_hash`.",
                    )
                )
            if (post_seal_basis.get("late_data_monitor_result_ref") is None) != (
                post_seal_basis.get("late_data_monitor_result_hash") is None
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis` must pair `late_data_monitor_result_ref` with `late_data_monitor_result_hash`.",
                    )
                )
            baseline_envelope_refs = post_seal_basis.get("baseline_envelope_refs", [])
            baseline_envelope_hashes = post_seal_basis.get("baseline_envelope_hashes", [])
            if isinstance(baseline_envelope_refs, list) and isinstance(baseline_envelope_hashes, list) and len(
                baseline_envelope_refs
            ) != len(baseline_envelope_hashes):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis.baseline_envelope_refs[]` and hashes must stay length-aligned.",
                    )
                )
            temporal_event_refs = post_seal_basis.get("temporal_propagation_event_refs", [])
            temporal_event_hashes = post_seal_basis.get("temporal_propagation_event_hashes", [])
            if isinstance(temporal_event_refs, list) and isinstance(temporal_event_hashes, list) and len(
                temporal_event_refs
            ) != len(temporal_event_hashes):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis.temporal_propagation_event_refs[]` and hashes must stay length-aligned.",
                    )
                )
            authority_calc_refs = post_seal_basis.get("authority_calculation_result_refs", [])
            authority_calc_hashes = post_seal_basis.get("authority_calculation_result_hashes", [])
            if isinstance(authority_calc_refs, list) and isinstance(authority_calc_hashes, list) and len(authority_calc_refs) != len(
                authority_calc_hashes
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis.authority_calculation_result_refs[]` and hashes must stay length-aligned.",
                    )
                )
            drift_basis_refs = post_seal_basis.get("drift_record_refs", [])
            drift_basis_hashes = post_seal_basis.get("drift_record_hashes", [])
            if isinstance(drift_basis_refs, list) and isinstance(drift_basis_hashes, list) and len(drift_basis_refs) != len(
                drift_basis_hashes
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis.drift_record_refs[]` and hashes must stay length-aligned.",
                    )
                )
            if (
                post_seal_basis.get("authority_context_ref") is not None
                and payload.get("authority_context_ref") != post_seal_basis.get("authority_context_ref")
            ):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`append_only_outcome_projection.post_seal_basis.authority_context_ref` must mirror `authority_context_ref` when material.",
                    )
                )
            manifest_drift_refs = payload.get("drift_refs") if isinstance(payload.get("drift_refs"), list) else []
            if isinstance(drift_basis_refs, list):
                missing_drift_refs = [ref for ref in drift_basis_refs if ref not in manifest_drift_refs]
                if missing_drift_refs:
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            f"`append_only_outcome_projection.post_seal_basis.drift_record_refs[]` must stay within `drift_refs[]`; missing {missing_drift_refs}.",
                        )
                    )
                if post_seal_basis.get("basis_state") == "MATERIAL" and not any(
                    [
                        post_seal_basis.get("authority_context_ref") is not None,
                        post_seal_basis.get("late_data_monitor_result_ref") is not None,
                        bool(baseline_envelope_refs),
                        bool(temporal_event_refs),
                        bool(authority_calc_refs),
                        bool(drift_basis_refs),
                    ]
                ):
                    issues.append(
                        Issue(
                            "custom",
                            location,
                            "`append_only_outcome_projection.post_seal_basis` must bind at least one historical post-seal artifact when `basis_state = MATERIAL`.",
                        )
                    )

    issues.extend(
        validate_manifest_output_refs(
            payload.get("output_refs"),
            location,
            "`output_refs`",
            manifest_id=manifest_id,
            decision_bundle_hash=payload.get("decision_bundle_hash"),
            replay_attestation_ref=payload.get("replay_attestation_ref"),
            submission_refs=submission_refs,
            drift_refs=drift_refs,
        )
    )

    if payload.get("deterministic_outcome_hash") is not None and payload.get("decision_bundle_hash") is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`deterministic_outcome_hash` must not appear without `decision_bundle_hash`.",
            )
        )
    if payload.get("replay_attestation_ref") is not None and payload.get("deterministic_outcome_hash") is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`replay_attestation_ref` must not appear without `deterministic_outcome_hash`.",
            )
        )
    if payload.get("run_kind") == "REPLAY" and payload.get("deterministic_outcome_hash") is not None and payload.get(
        "replay_attestation_ref"
    ) is None:
        issues.append(
            Issue(
                "custom",
                location,
                "Replay manifests must not publish `deterministic_outcome_hash` before `replay_attestation_ref` is durably linked.",
            )
        )
    if isinstance(append_only_outcome_projection, dict):
        if (
            append_only_outcome_projection.get("deterministic_outcome_hash") is not None
            and append_only_outcome_projection.get("decision_bundle_hash") is None
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`append_only_outcome_projection.deterministic_outcome_hash` must not appear without `append_only_outcome_projection.decision_bundle_hash`.",
                )
            )
        if (
            append_only_outcome_projection.get("replay_attestation_ref") is not None
            and append_only_outcome_projection.get("deterministic_outcome_hash") is None
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`append_only_outcome_projection.replay_attestation_ref` must not appear without `append_only_outcome_projection.deterministic_outcome_hash`.",
                )
            )

    continuation_parent_hash = continuation_set.get("parent_manifest_hash_at_branch")
    if continuation_basis == "NEW_MANIFEST":
        if manifest_id is not None and payload.get("root_manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`NEW_MANIFEST` runs must bind `root_manifest_id` to `manifest_id`.",
                )
            )
        if payload.get("manifest_generation") != 0:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`NEW_MANIFEST` runs must keep `manifest_generation = 0`.",
                )
            )
        unexpected_root_lineage = [
            field
            for field in (
                "parent_manifest_id",
                "continuation_of_manifest_id",
                "replay_of_manifest_id",
                "supersedes_manifest_id",
            )
            if payload.get(field) is not None
        ]
        if unexpected_root_lineage:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`NEW_MANIFEST` runs must clear child lineage refs; found {unexpected_root_lineage}.",
                )
            )
        if continuation_parent_hash is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`NEW_MANIFEST` runs must not carry `continuation_set.parent_manifest_hash_at_branch`.",
                )
            )
    elif continuation_basis in child_bases:
        missing_child_lineage = [
            field
            for field in ("root_manifest_id", "parent_manifest_id")
            if not isinstance(payload.get(field), str) or not payload.get(field)
        ]
        if missing_child_lineage:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Child manifests must bind non-empty lineage refs; missing {missing_child_lineage}.",
                )
            )
        if not isinstance(continuation_parent_hash, str) or not continuation_parent_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Child manifests must bind non-empty `continuation_set.parent_manifest_hash_at_branch`.",
                )
            )
        if not isinstance(payload.get("manifest_generation"), int) or payload.get("manifest_generation", 0) < 1:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Child manifests must keep `manifest_generation >= 1`.",
                )
            )
        if continuation_basis == "REPLAY_CHILD" and payload.get("parent_manifest_id") != payload.get(
            "replay_of_manifest_id"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`REPLAY_CHILD` manifests must bind `parent_manifest_id` and `replay_of_manifest_id` to the same source manifest.",
                )
            )

    if isinstance(config_freeze, dict):
        issues.extend(validate_config_freeze(config_freeze, location))
        if config_freeze.get("manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`config_freeze.manifest_id` must equal the parent `manifest_id`.",
                )
            )
        if config_freeze.get("schema_bundle_hash") != payload.get("schema_bundle_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`config_freeze.schema_bundle_hash` must mirror the manifest-level `schema_bundle_hash`.",
                )
            )
        if config_freeze.get("feature_flag_snapshot_hash") != payload.get("feature_flag_snapshot_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`config_freeze.feature_flag_snapshot_hash` must mirror the manifest-level `feature_flag_snapshot_hash`.",
                )
            )
        expected_config_basis = CONFIG_RESOLUTION_BASIS_BY_INHERITANCE_MODE.get(
            continuation_set.get("config_inheritance_mode")
        )
        if config_freeze.get("config_resolution_basis") != expected_config_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`config_freeze.config_resolution_basis` must match `continuation_set.config_inheritance_mode` ({expected_config_basis}).",
                )
            )
        if continuation_set.get("config_inheritance_mode") in {"REPLAY_EXACT", "RECOVERY_EXACT", "HISTORICAL_EXPLICIT"}:
            if continuation_set.get("inherited_config_freeze_ref") != config_freeze.get("source_config_freeze_ref"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`continuation_set.inherited_config_freeze_ref` must mirror `config_freeze.source_config_freeze_ref`.",
                    )
                )

    if isinstance(input_freeze, dict):
        if input_freeze.get("manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`input_freeze.manifest_id` must equal the parent `manifest_id`.",
                )
            )
        issues.extend(validate_input_freeze(input_freeze, location))

    if isinstance(hash_set, dict):
        for field in ("execution_basis_hash", "manifest_hash"):
            if not isinstance(hash_set.get(field), str) or not hash_set.get(field):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`hash_set.{field}` must be a non-empty frozen hash string when `hash_set` is present.",
                    )
                )
        if hash_set.get("access_binding_hash") != payload.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`hash_set.access_binding_hash` must mirror the manifest-level `access_binding_hash`.",
                )
            )
        if isinstance(config_freeze, dict):
            if hash_set.get("config_freeze_hash") != config_freeze.get("config_freeze_hash"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`hash_set.config_freeze_hash` must mirror `config_freeze.config_freeze_hash`.",
                    )
                )
            if hash_set.get("config_surface_hash") != config_freeze.get("config_surface_hash"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`hash_set.config_surface_hash` must mirror `config_freeze.config_surface_hash`.",
                    )
                )
        if isinstance(input_freeze, dict) and hash_set.get("input_set_hash") != input_freeze.get("input_set_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`hash_set.input_set_hash` must mirror `input_freeze.input_set_hash`.",
                )
            )

    if payload.get("frozen_at") is not None:
        missing_frozen_basis = [
            field
            for field in (
                "config_freeze",
                "input_freeze",
                "hash_set",
                "frozen_execution_binding",
                "append_only_outcome_projection",
            )
            if payload.get(field) is None
        ]
        if missing_frozen_basis:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Frozen manifests must preserve `config_freeze`, `input_freeze`, and `hash_set`; missing {missing_frozen_basis}.",
                )
            )

    if payload.get("lifecycle_state") == "SEALED":
        if payload.get("opened_at") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`SEALED` manifests must remain pre-start and keep `opened_at = null`.",
                )
            )
        if payload.get("output_refs"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`SEALED` manifests must not carry `output_refs{...}` before the single-writer start claim succeeds.",
                )
            )
        if payload.get("submission_refs"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`SEALED` manifests must not carry `submission_refs[]` before run start.",
                )
            )
        if payload.get("drift_refs"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`SEALED` manifests must not carry `drift_refs[]` before run start.",
                )
            )
        unexpected_sealed_outcomes = [
            field
            for field in ("decision_bundle_hash", "deterministic_outcome_hash", "replay_attestation_ref")
            if payload.get(field) is not None
        ]
        if unexpected_sealed_outcomes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`SEALED` manifests must not carry post-start outcome projections; found {unexpected_sealed_outcomes}.",
                )
            )

    lifecycle_state = payload.get("lifecycle_state")
    if transition_event_code == "system_fault" and invariant_failure_state != "TRIGGERED":
        issues.append(
            Issue(
                "custom",
                location,
                "Run-manifest `system_fault` transitions must retain `invariant_enforcement_contract.invariant_failure_state = TRIGGERED`.",
            )
        )
    if invariant_failure_state == "TRIGGERED":
        expected_terminal_state = invariant_enforcement_contract.get("terminal_manifest_state_or_null")
        if lifecycle_state != expected_terminal_state:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`invariant_enforcement_contract.terminal_manifest_state_or_null` must mirror `lifecycle_state` when invariant failure is triggered.",
                )
            )
        if transition_event_code != invariant_enforcement_contract.get("transition_event_code_or_null"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`state_transition_contract.transition_event_code` must mirror `invariant_enforcement_contract.transition_event_code_or_null` for invariant failures.",
                )
            )
        audit_refs = payload.get("audit_refs")
        if not isinstance(audit_refs, list) or not audit_refs:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Invariant-failed manifests must retain non-empty `audit_refs[]`.",
                )
            )
        failure_stage = invariant_enforcement_contract.get("failure_stage_or_null")
        previous_state = (
            state_transition_contract.get("previous_state_or_null")
            if isinstance(state_transition_contract, dict)
            else None
        )
        if failure_stage == "PRESTART":
            if payload.get("opened_at") is not None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Pre-start invariant failures must keep `opened_at = null`.",
                    )
                )
            if previous_state not in {"ALLOCATED", "FROZEN", "SEALED"}:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Pre-start invariant failures must transition from `ALLOCATED`, `FROZEN`, or `SEALED`.",
                    )
                )
        elif failure_stage == "POSTSTART":
            if payload.get("opened_at") is None:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Post-start invariant failures must retain non-null `opened_at`.",
                    )
                )
            if previous_state != "IN_PROGRESS":
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "Post-start invariant failures must transition from `IN_PROGRESS`.",
                    )
                )

    timestamp_allowed_states = {
        "frozen_at": {
            "FROZEN",
            "SEALED",
            "IN_PROGRESS",
            "COMPLETED",
            "BLOCKED",
            "FAILED",
            "SUPERSEDED",
            "REPLAY_ONLY",
            "RETIRED",
        },
        "sealed_at": {
            "SEALED",
            "IN_PROGRESS",
            "COMPLETED",
            "BLOCKED",
            "FAILED",
            "SUPERSEDED",
            "REPLAY_ONLY",
            "RETIRED",
        },
        "opened_at": {
            "IN_PROGRESS",
            "COMPLETED",
            "BLOCKED",
            "FAILED",
            "SUPERSEDED",
            "REPLAY_ONLY",
            "RETIRED",
        },
        "completed_at": {"COMPLETED", "SUPERSEDED", "REPLAY_ONLY", "RETIRED"},
        "superseded_at": {"SUPERSEDED", "RETIRED"},
        "retired_at": {"RETIRED"},
    }
    for field, allowed_states in timestamp_allowed_states.items():
        if payload.get(field) is not None and lifecycle_state not in allowed_states:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field}` is not legal while `lifecycle_state = {lifecycle_state}`.",
                )
            )

    ordered_timestamps = [
        ("created_at", parse_datetime(payload.get("created_at"))),
        ("frozen_at", parse_datetime(payload.get("frozen_at"))),
        ("sealed_at", parse_datetime(payload.get("sealed_at"))),
        ("opened_at", parse_datetime(payload.get("opened_at"))),
        ("completed_at", parse_datetime(payload.get("completed_at"))),
        ("superseded_at", parse_datetime(payload.get("superseded_at"))),
        ("retired_at", parse_datetime(payload.get("retired_at"))),
    ]
    previous_name = None
    previous_value = None
    for field_name, field_value in ordered_timestamps:
        if field_value is None:
            continue
        if previous_value is not None and field_value < previous_value:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field_name}` must not be earlier than `{previous_name}`.",
                )
            )
        previous_name = field_name
        previous_value = field_value

    gating_decisions = payload.get("gating_decisions", [])
    gate_codes = [gate.get("gate_code") for gate in gating_decisions]
    duplicate_gate_codes = duplicate_values(gate_codes)
    if duplicate_gate_codes:
        issues.append(
            Issue(
                "custom",
                location,
                f"`gating_decisions[]` must not repeat known gate codes; duplicates {duplicate_gate_codes}.",
            )
        )

    stage_indexes = [gate.get("gate_stage_index") for gate in gating_decisions]
    if all(isinstance(stage_index, int) for stage_index in stage_indexes) and stage_indexes != sorted(stage_indexes):
        issues.append(
            Issue(
                "custom",
                location,
                "`gating_decisions[]` must remain ordered by ascending `gate_stage_index`.",
            )
        )

    mismatched_gate_manifests = [
        gate.get("gate_decision_id", "<unknown>")
        for gate in gating_decisions
        if gate.get("manifest_id") != manifest_id
    ]
    if mismatched_gate_manifests:
        issues.append(
            Issue(
                "custom",
                location,
                f"`gating_decisions[]` must stay manifest-bound; mismatched ids {mismatched_gate_manifests}.",
            )
        )

    access_decision = payload.get("access_decision", {})
    if isinstance(access_decision, dict) and access_decision:
        decision = access_decision.get("decision")
        if decision not in {"ALLOW", "ALLOW_MASKED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest.access_decision.decision` must be `ALLOW` or `ALLOW_MASKED`; blocked access exits do not allocate manifests.",
                )
            )
        issues.extend(
            validate_scope_sequence(
                access_decision.get("effective_scope"),
                location,
                "`access_decision.effective_scope[]`",
            )
        )
        requested_scope = payload.get("requested_scope", [])
        missing_effective_scope_tokens = [
            token
            for token in access_decision.get("effective_scope", [])
            if token not in requested_scope
        ]
        if missing_effective_scope_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`access_decision.effective_scope[]` must stay within `requested_scope[]`; missing {missing_effective_scope_tokens}.",
                )
            )
        if decision == "ALLOW" and access_decision.get("masking_rules"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest.access_decision.masking_rules[]` must be empty for `ALLOW` decisions.",
                )
            )
        if decision == "ALLOW_MASKED" and not access_decision.get("masking_rules"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest.access_decision` must carry `masking_rules[]` when `decision = ALLOW_MASKED`.",
                )
            )
        if access_decision.get("required_approvals"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest.access_decision.required_approvals[]` must stay empty because approval-gated access exits occur before manifest allocation.",
                )
            )
        if access_decision.get("required_authn_level") is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RunManifest.access_decision.required_authn_level` must be null because step-up-gated access exits occur before manifest allocation.",
                )
            )
        if isinstance(scope_binding, dict):
            if payload.get("requested_scope") != scope_binding.get("requested_scope"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.requested_scope[]` must exactly mirror `requested_scope[]`.",
                    )
                )
            if payload.get("mode") != scope_binding.get("execution_mode_or_null"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.execution_mode_or_null` must mirror manifest `mode`.",
                    )
                )
            if access_decision.get("effective_scope") != scope_binding.get("executable_scope"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.executable_scope[]` must mirror `access_decision.effective_scope[]`.",
                    )
                )
            if decision != scope_binding.get("access_decision"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.access_decision` must mirror `access_decision.decision`.",
                    )
                )
            if access_decision.get("masking_rules") != scope_binding.get("masking_rules"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.masking_rules[]` must mirror `access_decision.masking_rules[]`.",
                    )
                )
            if access_decision.get("required_approvals") != scope_binding.get("required_approvals"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.required_approvals[]` must mirror `access_decision.required_approvals[]`.",
                    )
                )
            if access_decision.get("required_authn_level") != scope_binding.get("required_authn_level"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.required_authn_level` must mirror `access_decision.required_authn_level`.",
                    )
                )
            if payload.get("access_binding_hash") != scope_binding.get("access_binding_hash"):
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`scope_execution_binding.access_binding_hash` must mirror manifest `access_binding_hash`.",
                    )
                )

    preseal_gate_evaluation_issues, preseal_gate_evaluation = validate_preseal_gate_evaluation_contract(
        payload.get("preseal_gate_evaluation"),
        location,
        "`preseal_gate_evaluation`",
        require_non_null=payload.get("frozen_at") is not None,
    )
    issues.extend(preseal_gate_evaluation_issues)
    if isinstance(preseal_gate_evaluation, dict):
        if preseal_gate_evaluation.get("manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.manifest_id` must equal the parent `manifest_id`.",
                )
            )
        if preseal_gate_evaluation.get("access_binding_hash") != payload.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.access_binding_hash` must mirror manifest `access_binding_hash`.",
                )
            )
        if preseal_gate_evaluation.get("authorized_scope") != authorized_scope:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.authorized_scope[]` must mirror the manifest's authorized executable scope.",
                )
            )
        if not isinstance(hash_set, dict) or preseal_gate_evaluation.get("execution_basis_hash") != hash_set.get(
            "execution_basis_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.execution_basis_hash` must mirror `hash_set.execution_basis_hash`.",
                )
            )

        preseal_completion_state = preseal_gate_evaluation.get("completion_state")
        preseal_evaluated_gate_codes = (
            preseal_gate_evaluation.get("evaluated_gate_codes")
            if isinstance(preseal_gate_evaluation.get("evaluated_gate_codes"), list)
            else []
        )
        preseal_gate_decision_ids = (
            preseal_gate_evaluation.get("ordered_gate_decision_ids")
            if isinstance(preseal_gate_evaluation.get("ordered_gate_decision_ids"), list)
            else []
        )
        preseal_prefix = gating_decisions[: len(preseal_evaluated_gate_codes)]
        preseal_prefix_codes = [gate.get("gate_code") for gate in preseal_prefix]
        if preseal_prefix_codes != preseal_evaluated_gate_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.evaluated_gate_codes[]` must exactly mirror the ordered pre-seal gate prefix on `gating_decisions[]`.",
                )
            )
        preseal_prefix_gate_ids = [gate.get("gate_decision_id") for gate in preseal_prefix]
        if preseal_prefix_gate_ids != preseal_gate_decision_ids:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.ordered_gate_decision_ids[]` must exactly mirror the ordered pre-seal gate ids on `gating_decisions[]`.",
                )
            )

        if preseal_completion_state == "PENDING_PREREQUISITES" and gating_decisions:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`gating_decisions[]` must stay empty while `preseal_gate_evaluation.completion_state = PENDING_PREREQUISITES`.",
                )
            )

        later_gate_stage_drift_ids = [
            gate.get("gate_decision_id", "<unknown>")
            for gate in gating_decisions[len(preseal_evaluated_gate_codes) :]
            if not isinstance(gate.get("gate_stage_index"), int)
            or gate.get("gate_stage_index") < POSTSEAL_GATE_STAGE_INDEX_MIN
        ]
        if later_gate_stage_drift_ids:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"Post-seal `gating_decisions[]` appends must start after the frozen pre-seal prefix; mismatched ids {later_gate_stage_drift_ids}.",
                )
            )

        actual_preseal_blocking_gate_codes = [
            gate.get("gate_code")
            for gate in preseal_prefix
            if gate.get("decision") in BLOCKING_GATE_DECISIONS
        ]
        if preseal_gate_evaluation.get("blocking_gate_codes") != actual_preseal_blocking_gate_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.blocking_gate_codes[]` must exactly mirror the blocking decisions in the pre-seal gate prefix.",
                )
            )

        prestart_blocked = (
            payload.get("lifecycle_state") == "BLOCKED"
            and payload.get("sealed_at") is None
            and payload.get("opened_at") is None
        )
        if prestart_blocked and preseal_completion_state != "COMPLETE_BLOCKED_PRESTART":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Pre-start blocked manifests must keep `preseal_gate_evaluation.completion_state = COMPLETE_BLOCKED_PRESTART`.",
                )
            )
        if preseal_completion_state == "COMPLETE_BLOCKED_PRESTART" and not prestart_blocked:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.completion_state = COMPLETE_BLOCKED_PRESTART` is only legal for pre-start blocked manifests.",
                )
            )

        manifests_requiring_seal_ready_preseal = {
            "SEALED",
            "IN_PROGRESS",
            "COMPLETED",
            "FAILED",
            "SUPERSEDED",
            "REPLAY_ONLY",
            "RETIRED",
        }
        if payload.get("lifecycle_state") in manifests_requiring_seal_ready_preseal and preseal_completion_state != "COMPLETE_READY_TO_SEAL":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`preseal_gate_evaluation.completion_state` must be `COMPLETE_READY_TO_SEAL` once `lifecycle_state = {payload.get('lifecycle_state')}`.",
                )
            )
        if payload.get("sealed_at") is not None and preseal_completion_state != "COMPLETE_READY_TO_SEAL":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`preseal_gate_evaluation.completion_state` must be `COMPLETE_READY_TO_SEAL` once `sealed_at` is present.",
                )
            )

    manifest_start_claim_issues, manifest_start_claim = validate_manifest_start_claim_contract(
        payload.get("manifest_start_claim"),
        location,
        "`manifest_start_claim`",
        require_non_null=payload.get("sealed_at") is not None,
    )
    issues.extend(manifest_start_claim_issues)
    if isinstance(manifest_start_claim, dict):
        if manifest_start_claim.get("manifest_id") != manifest_id:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.manifest_id` must equal the parent `manifest_id`.",
                )
            )
        if manifest_start_claim.get("access_binding_hash") != payload.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.access_binding_hash` must mirror manifest `access_binding_hash`.",
                )
            )
        if not isinstance(hash_set, dict) or manifest_start_claim.get("manifest_hash") != hash_set.get("manifest_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.manifest_hash` must mirror `hash_set.manifest_hash`.",
                )
            )
        if not isinstance(hash_set, dict) or manifest_start_claim.get("execution_basis_hash") != hash_set.get(
            "execution_basis_hash"
        ):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.execution_basis_hash` must mirror `hash_set.execution_basis_hash`.",
                )
            )

        claim_state = manifest_start_claim.get("claim_state")
        sealed = payload.get("sealed_at") is not None
        opened_at = payload.get("opened_at")
        if opened_at is not None and manifest_start_claim.get("claim_acquired_at_or_null") != opened_at:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`opened_at` must exactly mirror `manifest_start_claim.claim_acquired_at_or_null` once run start has committed.",
                )
            )
        if claim_state == "UNCLAIMED_SEALED" and opened_at is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.claim_state = UNCLAIMED_SEALED` is only legal while `opened_at = null`.",
                )
            )
        if claim_state in {"ACTIVE_LEASED", "STALE_RECLAIM_REQUIRED", "TERMINAL_RESULT_RECORDED"} and opened_at is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Started or recoverable manifests must retain non-null `opened_at` aligned to `manifest_start_claim`.",
                )
            )

        lifecycle_state = payload.get("lifecycle_state")
        if lifecycle_state == "SEALED" and claim_state != "UNCLAIMED_SEALED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`SEALED` manifests must keep `manifest_start_claim.claim_state = UNCLAIMED_SEALED`.",
                )
            )
        if lifecycle_state == "IN_PROGRESS" and claim_state not in {"ACTIVE_LEASED", "STALE_RECLAIM_REQUIRED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`IN_PROGRESS` manifests must keep `manifest_start_claim.claim_state` inside `{ACTIVE_LEASED, STALE_RECLAIM_REQUIRED}`.",
                )
            )
        if lifecycle_state == "FAILED" and claim_state not in {"STALE_RECLAIM_REQUIRED", "TERMINAL_RESULT_RECORDED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`FAILED` manifests must distinguish reclaim-required from terminal-result posture in `manifest_start_claim.claim_state`.",
                )
            )
        if sealed and lifecycle_state in {"COMPLETED", "SUPERSEDED", "REPLAY_ONLY", "RETIRED"} and claim_state != "TERMINAL_RESULT_RECORDED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` manifests must keep `manifest_start_claim.claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )
        if sealed and lifecycle_state == "BLOCKED" and claim_state != "TERMINAL_RESULT_RECORDED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Post-start blocked manifests must keep `manifest_start_claim.claim_state = TERMINAL_RESULT_RECORDED`.",
                )
            )
        if claim_state == "TERMINAL_RESULT_RECORDED":
            expected_release_reason = {
                "COMPLETED": "COMPLETED",
                "FAILED": "FAILED",
                "BLOCKED": "BLOCKED",
                "SUPERSEDED": "SUPERSEDED",
                "REPLAY_ONLY": "REPLAY_ONLY",
                "RETIRED": "RETIRED",
            }.get(lifecycle_state)
            if expected_release_reason is not None and manifest_start_claim.get("claim_release_reason_code_or_null") != expected_release_reason:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        f"`manifest_start_claim.claim_release_reason_code_or_null` must equal `{expected_release_reason}` once `lifecycle_state = {lifecycle_state}`.",
                    )
                )
        if payload.get("continuation_basis") == "RECOVERY_CHILD" and claim_state == "STALE_RECLAIM_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`RECOVERY_CHILD` manifests must represent the successor attempt itself; stale reclaim remains on the predecessor manifest start claim, not the child.",
                )
            )
        if manifest_start_claim.get("publication_state") == "NOT_PUBLISHED" and opened_at is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.publication_state = NOT_PUBLISHED` is illegal once `opened_at` is present.",
                )
            )
        if manifest_start_claim.get("stale_reclaim_reason_code_or_null") is not None and lifecycle_state not in {"IN_PROGRESS", "FAILED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`manifest_start_claim.stale_reclaim_reason_code_or_null` is only legal while the manifest is still running or awaiting failed-attempt reclaim.",
                )
            )

    inconsistent_gate_scope_ids = [
        gate.get("gate_decision_id", "<unknown>")
        for gate in gating_decisions
        if gate.get("effective_scope") != authorized_scope
    ]
    if inconsistent_gate_scope_ids:
        issues.append(
            Issue(
                "custom",
                location,
                f"`gating_decisions[].effective_scope` must mirror the manifest's authorized scope; mismatched ids {inconsistent_gate_scope_ids}.",
            )
        )

    executable_scope_tokens = set(authorized_scope) if isinstance(authorized_scope, list) else set()
    if "AMENDMENT_GATE" in gate_codes and executable_scope_tokens.isdisjoint({"amendment_intent", "amendment_submit"}):
        issues.append(
            Issue(
                "custom",
                location,
                "`AMENDMENT_GATE` may only appear when amendment intent or amendment submit scope remains executable.",
            )
        )
    if "FILING_GATE" in gate_codes and executable_scope_tokens.isdisjoint(
        {"prepare_submission", "submit", "amendment_submit"}
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`FILING_GATE` may only appear for filing-capable executable manifest scopes.",
            )
        )
    if "SUBMISSION_GATE" in gate_codes and executable_scope_tokens.isdisjoint({"submit", "amendment_submit"}):
        issues.append(
            Issue(
                "custom",
                location,
                "`SUBMISSION_GATE` may only appear for submit-capable executable manifest scopes.",
            )
        )
    return issues


def validate_authority_operation(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    for field in ("manifest_hash", "execution_basis_hash", "access_binding_hash", "policy_snapshot_hash"):
        if not isinstance(payload.get(field), str) or not payload.get(field):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field}` must retain the sealed manifest-bound hash identity for worker execution.",
                )
            )
    authority_layer_issues, authority_layer_boundary = validate_authority_layer_boundary_contract(
        payload.get("authority_layer_boundary"),
        location,
        "`authority_layer_boundary`",
        expected_binding_scope_class="AUTHORITY_OPERATION",
        expected_integration_capability="AUTHORITY_INTEGRATED",
    )
    issues.extend(authority_layer_issues)
    requested_scope = payload.get("requested_scope")
    runtime_scope = payload.get("runtime_scope")
    scope_binding_issues, scope_binding = validate_scope_execution_binding(
        payload.get("scope_execution_binding"),
        location,
        "`scope_execution_binding`",
    )
    issues.extend(scope_binding_issues)
    issues.extend(validate_scope_sequence(requested_scope, location, "`requested_scope[]`"))
    issues.extend(validate_scope_sequence(runtime_scope, location, "`runtime_scope[]`"))
    issues.extend(
        validate_sorted_string_sequence(payload.get("business_partitions"), location, "`business_partitions[]`")
    )
    if isinstance(requested_scope, list) and isinstance(runtime_scope, list):
        missing_runtime_tokens = [token for token in runtime_scope if token not in requested_scope]
        if missing_runtime_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`runtime_scope[]` must stay within `requested_scope[]`; missing {missing_runtime_tokens}.",
                )
            )
    if isinstance(scope_binding, dict):
        if scope_binding.get("requested_scope") != requested_scope:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`scope_execution_binding.requested_scope[]` must mirror `requested_scope[]`.",
                )
            )
        if scope_binding.get("executable_scope") != runtime_scope:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`scope_execution_binding.executable_scope[]` must mirror `runtime_scope[]`.",
                )
            )
        if scope_binding.get("access_binding_hash") != payload.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`scope_execution_binding.access_binding_hash` must mirror `access_binding_hash`.",
                )
            )
        if scope_binding.get("executable_partition_scope_refs") != payload.get("business_partitions"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`business_partitions[]` must mirror `scope_execution_binding.executable_partition_scope_refs[]`.",
                )
            )
    subject_ref = payload.get("subject_ref")
    acting_party_ref = payload.get("acting_party_ref")
    delegation_grant_ref = payload.get("delegation_grant_ref")
    if acting_party_ref is not None and subject_ref is not None:
        if acting_party_ref != subject_ref and delegation_grant_ref is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`delegation_grant_ref` must be populated when `acting_party_ref` differs from `subject_ref`.",
                )
            )
        if acting_party_ref == subject_ref and delegation_grant_ref is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Self-acting authority operations must not retain `delegation_grant_ref`.",
                )
            )

    client_delegation_state = authority_layer_boundary.get("client_delegation_state")
    if isinstance(subject_ref, str) and isinstance(acting_party_ref, str):
        if acting_party_ref != subject_ref and client_delegation_state not in {"SATISFIED", "LIMITED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Delegated authority operations must keep `authority_layer_boundary.client_delegation_state` live-usable instead of inferring coverage from tenant permission or link presence.",
                )
            )
        if acting_party_ref == subject_ref and client_delegation_state != "NOT_REQUIRED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Self-acting authority operations must keep `authority_layer_boundary.client_delegation_state = NOT_REQUIRED`.",
                )
            )
    if authority_layer_boundary.get("active_principal_class") == "SERVICE" and authority_layer_boundary.get("human_gate_requirement") != "NOT_REQUIRED":
        issues.append(
            Issue(
                "custom",
                location,
                "Service principals must not carry satisfied step-up or approval posture into `AuthorityOperation`.",
            )
        )
    if client_delegation_state in {"SATISFIED", "LIMITED"} and authority_layer_boundary.get("delegation_basis") in {
        "SELF_ASSESSMENT_IMPORTED",
        "DIGITAL_HANDSHAKE",
    } and authority_layer_boundary.get("delegation_freshness_state") != "CURRENT":
        issues.append(
            Issue(
                "custom",
                location,
                "Live authority operations must keep imported or handshake delegation freshness current.",
            )
        )
    operation_family = payload.get("operation_family")
    business_partitions = payload.get("business_partitions") if isinstance(payload.get("business_partitions"), list) else []
    runtime_scope_tokens = set(runtime_scope) if isinstance(runtime_scope, list) else set()
    if operation_family in {
        "AUTH_CREATE_OR_AMEND_DATA",
        "AUTH_DELETE_DATA",
        "AUTH_TRIGGER_CALCULATION",
        "AUTH_SUBMIT_FINAL_DECLARATION",
        "AUTH_SUBMIT_PERIODIC_UPDATE",
        "AUTH_SUBMIT_POST_FINALISATION_AMENDMENT",
    } and not business_partitions:
        issues.append(
            Issue(
                "custom",
                location,
                "Mutation-capable, calculation, and submit `AuthorityOperation`s must retain non-empty `business_partitions[]`.",
            )
        )
    if operation_family in {
        "AUTH_READ_REFERENCE",
        "AUTH_READ_OBLIGATIONS",
        "AUTH_READ_CALCULATION",
        "AUTH_TRIGGER_CALCULATION",
        "AUTH_RECONCILE_STATUS",
    } and runtime_scope_tokens.intersection({"submit", "amendment_submit"}):
        issues.append(
            Issue(
                "custom",
                location,
                "Read, calculation, and reconciliation `AuthorityOperation`s must not carry live submit tokens in `runtime_scope[]`.",
            )
        )
    if operation_family == "AUTH_SUBMIT_PERIODIC_UPDATE":
        if not {"quarterly_update", "submit"}.issubset(runtime_scope_tokens):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_PERIODIC_UPDATE` must retain both `quarterly_update` and `submit` in `runtime_scope[]`.",
                )
            )
        if payload.get("target_obligation_ref") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_PERIODIC_UPDATE` must retain `target_obligation_ref`.",
                )
            )
    if operation_family == "AUTH_SUBMIT_FINAL_DECLARATION":
        if not {"year_end", "submit"}.issubset(runtime_scope_tokens):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_FINAL_DECLARATION` must retain both `year_end` and `submit` in `runtime_scope[]`.",
                )
            )
        if payload.get("basis_type") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_FINAL_DECLARATION` must retain `basis_type`.",
                )
            )
    if operation_family == "AUTH_SUBMIT_POST_FINALISATION_AMENDMENT":
        if not {"year_end", "amendment_submit"}.issubset(runtime_scope_tokens):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_POST_FINALISATION_AMENDMENT` must retain both `year_end` and `amendment_submit` in `runtime_scope[]`.",
                )
            )
        if payload.get("basis_type") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_SUBMIT_POST_FINALISATION_AMENDMENT` must retain `basis_type`.",
                )
            )
    if operation_family == "AUTH_TRIGGER_CALCULATION":
        if not runtime_scope_tokens.intersection({"prepare_submission", "amendment_intent"}):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_TRIGGER_CALCULATION` must retain either `prepare_submission` or `amendment_intent` in `runtime_scope[]`.",
                )
            )
        if payload.get("basis_type") is None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_TRIGGER_CALCULATION` must retain `basis_type`.",
                )
            )
        if "submit" in runtime_scope_tokens or "amendment_submit" in runtime_scope_tokens:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`AUTH_TRIGGER_CALCULATION` must not carry submit tokens in `runtime_scope[]`.",
                )
            )
    return issues


def validate_authority_calculation_request(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    runtime_scope = payload.get("runtime_scope")
    scope_binding_issues, scope_binding = validate_scope_execution_binding(
        payload.get("scope_execution_binding"),
        location,
        "`scope_execution_binding`",
    )
    issues.extend(scope_binding_issues)
    issues.extend(validate_scope_sequence(runtime_scope, location, "`runtime_scope[]`"))
    issues.extend(validate_sorted_string_sequence(payload.get("reason_codes"), location, "`reason_codes[]`"))
    if not isinstance(payload.get("access_binding_hash"), str) or not payload.get("access_binding_hash"):
        issues.append(
            Issue(
                "custom",
                location,
                "`access_binding_hash` must retain the executable scope identity for authority-calculation requests.",
            )
        )
    if isinstance(scope_binding, dict):
        if scope_binding.get("executable_scope") != runtime_scope:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`scope_execution_binding.executable_scope[]` must mirror `runtime_scope[]`.",
                )
            )
        if scope_binding.get("access_binding_hash") != payload.get("access_binding_hash"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`scope_execution_binding.access_binding_hash` must mirror `access_binding_hash`.",
                )
            )

    live_authority_call_executed = payload.get("live_authority_call_executed")
    authority_operation_ref = payload.get("authority_operation_ref")
    calculation_type = payload.get("calculation_type")

    if live_authority_call_executed is False and authority_operation_ref is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_operation_ref` must be null when `live_authority_call_executed = false`.",
            )
        )

    scope_tokens = runtime_scope if isinstance(runtime_scope, list) else []
    if any(token in {"submit", "amendment_submit"} for token in scope_tokens):
        issues.append(
            Issue(
                "custom",
                location,
                "`runtime_scope[]` must not carry live submit tokens for authority-calculation requests.",
            )
        )

    if calculation_type == "intent-to-amend" and "prepare_submission" in scope_tokens:
        issues.append(
            Issue(
                "custom",
                location,
                "`runtime_scope[]` must not include `prepare_submission` for `intent-to-amend` requests.",
            )
        )

    if calculation_type in {"in-year", "intent-to-finalise", "final-declaration"} and "amendment_intent" in scope_tokens:
        issues.append(
            Issue(
                "custom",
                location,
                "`runtime_scope[]` must not include `amendment_intent` for non-amendment calculation requests.",
            )
        )

    return issues


def validate_authority_calculation_result(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("reason_codes"), location, "`reason_codes[]`"))

    result_state = payload.get("result_state")
    validation_outcome = payload.get("validation_outcome")
    retrieved_at = parse_datetime(payload.get("retrieved_at"))
    superseded_at = parse_datetime(payload.get("superseded_at"))

    if result_state == "MODELED" and validation_outcome == "PASS":
        issues.append(
            Issue(
                "custom",
                location,
                "`validation_outcome = PASS` is invalid for modeled calculation results.",
            )
        )

    if retrieved_at is not None and superseded_at is not None and superseded_at < retrieved_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_at` must not be earlier than `retrieved_at`.",
            )
        )

    return issues


def validate_calculation_basis(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("reason_codes"), location, "`reason_codes[]`"))

    basis_status = payload.get("basis_status")
    parity_reusable = payload.get("parity_reusable")
    filing_reusable = payload.get("filing_reusable")
    basis_payload_ref = payload.get("basis_payload_ref")
    basis_hash = payload.get("basis_hash")
    user_confirmation_ref = payload.get("user_confirmation_ref")
    captured_at = parse_datetime(payload.get("captured_at"))
    confirmed_at = parse_datetime(payload.get("confirmed_at"))
    superseded_at = parse_datetime(payload.get("superseded_at"))

    if not isinstance(basis_payload_ref, str) or not basis_payload_ref:
        issues.append(
            Issue(
                "custom",
                location,
                "`basis_payload_ref` must remain a non-empty string for every selected calculation basis.",
            )
        )

    if not isinstance(basis_hash, str) or not basis_hash:
        issues.append(
            Issue(
                "custom",
                location,
                "`basis_hash` must remain a non-empty string for every selected calculation basis.",
            )
        )

    if basis_status != "CONFIRMED" and (parity_reusable is True or filing_reusable is True):
        issues.append(
            Issue(
                "custom",
                location,
                "`parity_reusable` and `filing_reusable` may only be true for `basis_status = CONFIRMED`.",
            )
        )

    if basis_status == "CONFIRMED" and not (parity_reusable is True or filing_reusable is True):
        issues.append(
            Issue(
                "custom",
                location,
                "`basis_status = CONFIRMED` must retain at least one reusable posture flag.",
            )
        )

    if user_confirmation_ref is not None and basis_status not in {"CONFIRMED", "SUPERSEDED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "Non-null `user_confirmation_ref` requires `basis_status` to stay `CONFIRMED` or `SUPERSEDED`.",
            )
        )

    if superseded_at is not None and basis_status != "SUPERSEDED":
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_at` may only be populated when `basis_status = SUPERSEDED`.",
            )
        )

    if captured_at is not None and confirmed_at is not None and confirmed_at < captured_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`confirmed_at` must not be earlier than `captured_at`.",
            )
        )

    if captured_at is not None and superseded_at is not None and superseded_at < captured_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_at` must not be earlier than `captured_at`.",
            )
        )

    if confirmed_at is not None and superseded_at is not None and superseded_at < confirmed_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_at` must not be earlier than `confirmed_at`.",
            )
        )

    return issues


def validate_calculation_user_confirmation(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("reason_codes"), location, "`reason_codes[]`"))

    confirmation_state = payload.get("confirmation_state")
    reason_codes = payload.get("reason_codes")
    if confirmation_state == "CONFIRMED" and isinstance(reason_codes, list) and reason_codes:
        issues.append(
            Issue(
                "custom",
                location,
                "`reason_codes[]` must be empty when `confirmation_state = CONFIRMED`.",
            )
        )

    return issues


def validate_authority_calculation_readiness_context(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("reason_codes"), location, "`reason_codes[]`"))

    validation_outcome = payload.get("validation_outcome")
    live_authority_call_executed = payload.get("live_authority_call_executed")
    request_state = payload.get("request_state")
    result_state = payload.get("result_state")
    calculation_basis_ref = payload.get("calculation_basis_ref")
    basis_status = payload.get("basis_status")
    basis_hash = payload.get("basis_hash")
    user_confirmation_ref = payload.get("user_confirmation_ref")
    confirmation_state = payload.get("confirmation_state")
    parity_reusable = payload.get("parity_reusable")
    filing_reusable = payload.get("filing_reusable")
    calculation_hash = payload.get("calculation_hash")

    if request_state == "MODELED_ONLY" and live_authority_call_executed is not False:
        issues.append(
            Issue(
                "custom",
                location,
                "`request_state = MODELED_ONLY` requires `live_authority_call_executed = false`.",
            )
        )

    if result_state == "MODELED" and live_authority_call_executed is not False:
        issues.append(
            Issue(
                "custom",
                location,
                "`result_state = MODELED` requires `live_authority_call_executed = false`.",
            )
        )

    if live_authority_call_executed is False:
        if request_state != "MODELED_ONLY" or result_state != "MODELED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`live_authority_call_executed = false` must retain modeled request/result posture.",
                )
            )
        if any(value is not None for value in (calculation_hash, calculation_basis_ref, basis_status, basis_hash, user_confirmation_ref, confirmation_state)):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Modeled readiness contexts must clear calculation hash, basis refs/hashes, and confirmation posture.",
                )
            )
        if parity_reusable is not False or filing_reusable is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Modeled readiness contexts must clear reusable posture.",
                )
            )

    if validation_outcome in {"PASS", "PASS_WITH_NOTICE"}:
        if live_authority_call_executed is not True:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires `live_authority_call_executed = true`.",
                )
            )
        if request_state != "RETRIEVED" or result_state != "RETRIEVED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires retrieved request/result posture.",
                )
            )
        if not isinstance(calculation_hash, str) or not calculation_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires non-null `calculation_hash`.",
                )
            )
        if not isinstance(calculation_basis_ref, str) or not calculation_basis_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires non-null `calculation_basis_ref`.",
                )
            )
        if basis_status != "CONFIRMED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires `basis_status = CONFIRMED`.",
                )
            )
        if not isinstance(basis_hash, str) or not basis_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires non-null `basis_hash`.",
                )
            )
        if confirmation_state != "CONFIRMED" or not isinstance(user_confirmation_ref, str) or not user_confirmation_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires confirmed user-confirmation posture.",
                )
            )
        if not (parity_reusable is True or filing_reusable is True):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`validation_outcome = {validation_outcome}` requires at least one reusable posture flag.",
                )
            )

    if isinstance(calculation_basis_ref, str):
        if basis_status is None or not isinstance(basis_hash, str) or not basis_hash:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-null `calculation_basis_ref` requires non-null `basis_status` and `basis_hash`.",
                )
            )

    if basis_status == "SUPERSEDED":
        issues.append(
            Issue(
                "custom",
                location,
                "Active readiness contexts must not retain `basis_status = SUPERSEDED`.",
            )
        )

    if isinstance(user_confirmation_ref, str):
        if confirmation_state not in {"PENDING", "CONFIRMED", "DECLINED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-null `user_confirmation_ref` requires explicit `confirmation_state`.",
                )
            )

    if confirmation_state == "CONFIRMED":
        if basis_status != "CONFIRMED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`confirmation_state = CONFIRMED` requires `basis_status = CONFIRMED`.",
                )
            )
        if not (parity_reusable is True or filing_reusable is True):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`confirmation_state = CONFIRMED` requires at least one reusable posture flag.",
                )
            )

    if confirmation_state == "DECLINED" and (parity_reusable is True or filing_reusable is True):
        issues.append(
            Issue(
                "custom",
                location,
                "`confirmation_state = DECLINED` must clear reusable posture.",
            )
        )

    return issues


def validate_connector_binding(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("scopes"), location, "`scopes[]`"))
    issues.extend(
        validate_sorted_string_sequence(payload.get("partition_scope_refs"), location, "`partition_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("blocked_reason_codes"), location, "`blocked_reason_codes[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("source_evidence_refs"), location, "`source_evidence_refs[]`")
    )

    binding_id = payload.get("binding_id")
    superseded_by_binding_id = payload.get("superseded_by_binding_id")
    health_state = payload.get("health_state")
    delegation_state = payload.get("delegation_state")
    client_binding_state = payload.get("client_binding_state")
    last_validated_at = parse_datetime(payload.get("last_validated_at"))
    expires_at = parse_datetime(payload.get("expires_at"))

    if binding_id is not None and superseded_by_binding_id == binding_id:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_by_binding_id` must not point back to `binding_id`.",
            )
        )

    if health_state in {"HEALTHY", "EXPIRING_SOON"} and client_binding_state != "BOUND":
        issues.append(
            Issue(
                "custom",
                location,
                "`client_binding_state` must be `BOUND` when `health_state` is healthy or expiring soon.",
            )
        )

    if health_state in {"HEALTHY", "EXPIRING_SOON"} and delegation_state not in {"NOT_REQUIRED", "SATISFIED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state` must remain `NOT_REQUIRED` or `SATISFIED` when `health_state` is healthy or expiring soon.",
            )
        )

    if health_state == "CLIENT_BINDING_MISMATCH" and client_binding_state != "MISMATCH":
        issues.append(
            Issue(
                "custom",
                location,
                "`health_state = CLIENT_BINDING_MISMATCH` must retain `client_binding_state = MISMATCH`.",
            )
        )

    if health_state == "DELEGATION_GAP" and delegation_state not in {"MISSING", "EXPIRED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`health_state = DELEGATION_GAP` must retain `delegation_state` in `MISSING` or `EXPIRED`.",
            )
        )

    if health_state == "EXPIRING_SOON" and expires_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must be populated when `health_state = EXPIRING_SOON`.",
            )
        )

    if (
        health_state in {"HEALTHY", "EXPIRING_SOON"}
        and expires_at is not None
        and last_validated_at is not None
        and expires_at <= last_validated_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must remain later than `last_validated_at` while the binding is healthy or expiring soon.",
            )
        )

    if (
        health_state == "EXPIRED"
        and expires_at is not None
        and last_validated_at is not None
        and expires_at > last_validated_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must not be later than `last_validated_at` when `health_state = EXPIRED`.",
            )
        )

    return issues


def validate_delegation_grant(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_sorted_string_sequence(payload.get("authority_scope_refs"), location, "`authority_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("partition_scope_refs"), location, "`partition_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("basis_evidence_refs"), location, "`basis_evidence_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("limitation_reason_codes"), location, "`limitation_reason_codes[]`"
        )
    )

    delegation_grant_id = payload.get("delegation_grant_id")
    superseded_by_grant_id = payload.get("superseded_by_grant_id")
    basis_type = payload.get("basis_type")
    effective_from = parse_datetime(payload.get("effective_from"))
    expires_at = parse_datetime(payload.get("expires_at"))
    revoked_at = parse_datetime(payload.get("revoked_at"))
    last_validated_at = parse_datetime(payload.get("last_validated_at"))
    imported_evidence_fresh_until = parse_datetime(payload.get("imported_evidence_fresh_until"))
    lifecycle_state = payload.get("lifecycle_state")

    if delegation_grant_id is not None and superseded_by_grant_id == delegation_grant_id:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_by_grant_id` must not point back to `delegation_grant_id`.",
            )
        )

    if basis_type in {"TENANT_INTERNAL", "SYSTEM_ASSIGNED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`DelegationGrant` may encode only client-authorized bases; internal tenant/service authority belongs in `PrincipalContext` / `AuthorizationDecision`.",
            )
        )

    if (
        basis_type not in {"SELF_ASSESSMENT_IMPORTED", "DIGITAL_HANDSHAKE"}
        and payload.get("imported_evidence_fresh_until") is not None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`imported_evidence_fresh_until` may only appear for imported or digital-handshake delegation bases.",
            )
        )

    if (
        imported_evidence_fresh_until is not None
        and effective_from is not None
        and imported_evidence_fresh_until < effective_from
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`imported_evidence_fresh_until` must not be earlier than `effective_from`.",
            )
        )

    if (
        basis_type in {"SELF_ASSESSMENT_IMPORTED", "DIGITAL_HANDSHAKE"}
        and lifecycle_state in {"ACTIVE", "LIMITED_SCOPE"}
        and imported_evidence_fresh_until is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Active imported or digital-handshake delegation grants must retain `imported_evidence_fresh_until` so live authority mutation cannot treat imported delegation as evergreen.",
            )
        )

    if (
        basis_type in {"SELF_ASSESSMENT_IMPORTED", "DIGITAL_HANDSHAKE"}
        and lifecycle_state in {"ACTIVE", "LIMITED_SCOPE"}
        and last_validated_at is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Active imported or digital-handshake delegation grants must retain `last_validated_at` for freshness enforcement.",
            )
        )

    if (
        basis_type in {"SELF_ASSESSMENT_IMPORTED", "DIGITAL_HANDSHAKE"}
        and lifecycle_state in {"ACTIVE", "LIMITED_SCOPE"}
        and last_validated_at is not None
        and imported_evidence_fresh_until is not None
        and last_validated_at > imported_evidence_fresh_until
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Active imported or digital-handshake delegation grants must not outlive `imported_evidence_fresh_until`; stale imported delegation must fail closed until revalidated.",
            )
        )

    ensure_datetime_order(
        effective_from,
        expires_at,
        issues,
        location,
        "`expires_at` must not be earlier than `effective_from`.",
    )
    ensure_datetime_order(
        effective_from,
        revoked_at,
        issues,
        location,
        "`revoked_at` must not be earlier than `effective_from`.",
    )

    return issues


def validate_authority_link(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_sorted_string_sequence(payload.get("partition_scope_refs"), location, "`partition_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("source_evidence_refs"), location, "`source_evidence_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("blocked_reason_codes"), location, "`blocked_reason_codes[]`")
    )

    authority_link_id = payload.get("authority_link_id")
    superseded_by_link_id = payload.get("superseded_by_link_id")
    binding_health = payload.get("binding_health")
    delegation_state = payload.get("delegation_state")
    token_client_binding_state = payload.get("token_client_binding_state")
    authorised_party_ref = payload.get("authorised_party_ref")
    reporting_subject_ref = payload.get("reporting_subject_ref")
    validated_at = parse_datetime(payload.get("validated_at"))
    last_binding_check_at = parse_datetime(payload.get("last_binding_check_at"))
    expires_at = parse_datetime(payload.get("expires_at"))

    if authority_link_id is not None and superseded_by_link_id == authority_link_id:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_by_link_id` must not point back to `authority_link_id`.",
            )
        )

    if binding_health in {"HEALTHY", "EXPIRING_SOON"} and token_client_binding_state != "BOUND":
        issues.append(
            Issue(
                "custom",
                location,
                "`token_client_binding_state` must be `BOUND` when `binding_health` is healthy or expiring soon.",
            )
        )

    if binding_health in {"HEALTHY", "EXPIRING_SOON"} and delegation_state not in {"NOT_REQUIRED", "SATISFIED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state` must remain `NOT_REQUIRED` or `SATISFIED` when `binding_health` is healthy or expiring soon.",
            )
        )

    if binding_health == "CLIENT_BINDING_MISMATCH" and token_client_binding_state != "MISMATCH":
        issues.append(
            Issue(
                "custom",
                location,
                "`binding_health = CLIENT_BINDING_MISMATCH` must retain `token_client_binding_state = MISMATCH`.",
            )
        )

    if binding_health == "DELEGATION_GAP" and delegation_state not in {"MISSING", "EXPIRED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`binding_health = DELEGATION_GAP` must retain `delegation_state` in `MISSING` or `EXPIRED`.",
            )
        )

    if authorised_party_ref is not None and reporting_subject_ref is not None:
        if delegation_state == "NOT_REQUIRED" and authorised_party_ref != reporting_subject_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Non-delegated authority links must keep `authorised_party_ref` equal to `reporting_subject_ref`.",
                )
            )
        if delegation_state != "NOT_REQUIRED" and authorised_party_ref == reporting_subject_ref:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Delegated authority links must not silently collapse `authorised_party_ref` back to `reporting_subject_ref`.",
                )
            )

    if validated_at is not None and last_binding_check_at is not None and last_binding_check_at < validated_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`last_binding_check_at` must not be earlier than `validated_at`.",
            )
        )

    if binding_health == "EXPIRING_SOON" and expires_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must be populated when `binding_health = EXPIRING_SOON`.",
            )
        )

    if (
        binding_health in {"HEALTHY", "EXPIRING_SOON"}
        and expires_at is not None
        and last_binding_check_at is not None
        and expires_at <= last_binding_check_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must remain later than `last_binding_check_at` while the authority link is healthy or expiring soon.",
            )
        )

    if (
        binding_health == "EXPIRED"
        and expires_at is not None
        and last_binding_check_at is not None
        and expires_at > last_binding_check_at
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must not be later than `last_binding_check_at` when `binding_health = EXPIRED`.",
            )
        )

    return issues


def validate_exceptional_authority_grant(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_sorted_string_sequence(payload.get("partition_scope_refs"), location, "`partition_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(
            payload.get("compensating_control_refs"), location, "`compensating_control_refs[]`"
        )
    )

    requesting_principal_ref = payload.get("requesting_principal_ref")
    approving_principal_ref = payload.get("approving_principal_ref")
    usage_limit = payload.get("usage_limit")
    remaining_uses = payload.get("remaining_uses")
    activated_at = parse_datetime(payload.get("activated_at"))
    expires_at = parse_datetime(payload.get("expires_at"))
    revoked_at = parse_datetime(payload.get("revoked_at"))

    if requesting_principal_ref is not None and approving_principal_ref == requesting_principal_ref:
        issues.append(
            Issue(
                "custom",
                location,
                "`requesting_principal_ref` and `approving_principal_ref` must remain distinct for exceptional authority.",
            )
        )

    for field in (
        "delegation_substitution_permitted",
        "silent_client_widening_permitted",
        "authority_acknowledgement_override_permitted",
        "truth_confirmation_override_permitted",
        "silent_partition_widening_permitted",
    ):
        if payload.get(field) is not False:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{field}` must stay `false` on `ExceptionalAuthorityGrant`.",
                )
            )

    if isinstance(usage_limit, int) and isinstance(remaining_uses, int) and remaining_uses > usage_limit:
        issues.append(
            Issue(
                "custom",
                location,
                "`remaining_uses` must not exceed `usage_limit`.",
            )
        )

    ensure_datetime_order(
        activated_at,
        expires_at,
        issues,
        location,
        "`expires_at` must not be earlier than `activated_at`.",
    )
    ensure_datetime_order(
        activated_at,
        revoked_at,
        issues,
        location,
        "`revoked_at` must not be earlier than `activated_at`.",
    )

    return issues


def validate_authority_operation_profile(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(validate_sorted_string_sequence(payload.get("required_scopes"), location, "`required_scopes[]`"))

    fraud_header_profile_ref = payload.get("fraud_header_profile_ref")
    fraud_header_exemption_reason = payload.get("fraud_header_exemption_reason")
    if (fraud_header_profile_ref is None) == (fraud_header_exemption_reason is None):
        issues.append(
            Issue(
                "custom",
                location,
                "Exactly one of `fraud_header_profile_ref` or `fraud_header_exemption_reason` must be populated.",
            )
        )

    success_status_codes = payload.get("success_response_rules", {}).get("success_status_codes")
    if isinstance(success_status_codes, list) and success_status_codes:
        expected_codes = sorted(success_status_codes)
        if success_status_codes != expected_codes:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`success_response_rules.success_status_codes[]` must use canonical ascending order {expected_codes}.",
                )
            )

    reconciliation_rules = payload.get("reconciliation_rules")
    pending_unknown_rules = payload.get("pending_unknown_rules")
    if isinstance(reconciliation_rules, dict):
        method = reconciliation_rules.get("method")
        authoritative_result_source = reconciliation_rules.get("authoritative_result_source")
        if method == "NONE" and authoritative_result_source != "DIRECT_RESPONSE":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`reconciliation_rules.method = NONE` must retain `authoritative_result_source = DIRECT_RESPONSE`.",
                )
            )
        if method == "MANUAL_ONLY" and authoritative_result_source != "MANUAL_REVIEW":
            issues.append(
                Issue(
                    "custom",
                    location,
                    "`reconciliation_rules.method = MANUAL_ONLY` must retain `authoritative_result_source = MANUAL_REVIEW`.",
                )
            )
        if isinstance(pending_unknown_rules, dict):
            retry_class = pending_unknown_rules.get("retry_class")
            escalation_required = pending_unknown_rules.get("escalation_required")
            if method in AUTHORITY_RECONCILIATION_AUTO_METHODS and retry_class not in AUTHORITY_PENDING_UNKNOWN_AUTO_RETRY_CLASSES:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`pending_unknown_rules.retry_class` must remain reconciliation-owned for automatic reconciliation methods and may not drift to `SAFE_RETRY` or `REBUILD_THEN_RETRY`.",
                    )
                )
            if method in {"NONE", "MANUAL_ONLY"} and retry_class not in AUTHORITY_PENDING_UNKNOWN_MANUAL_RETRY_CLASSES:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`pending_unknown_rules.retry_class` must remain manual-review-owned when `reconciliation_rules.method` disables automatic follow-up.",
                    )
                )
            if method in AUTHORITY_RECONCILIATION_AUTO_METHODS | {"NONE", "MANUAL_ONLY"} and escalation_required is not True:
                issues.append(
                    Issue(
                        "custom",
                        location,
                        "`pending_unknown_rules.escalation_required` must stay `true` so unresolved authority ambiguity always hands off explicitly instead of reopening blind resend.",
                    )
                )

    return issues


def validate_authority_binding(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    issues.extend(
        validate_sorted_string_sequence(payload.get("partition_scope_refs"), location, "`partition_scope_refs[]`")
    )
    issues.extend(
        validate_sorted_string_sequence(payload.get("blocked_reason_codes"), location, "`blocked_reason_codes[]`")
    )
    authority_layer_issues, authority_layer_boundary = validate_authority_layer_boundary_contract(
        payload.get("authority_layer_boundary"),
        location,
        "`authority_layer_boundary`",
        expected_binding_scope_class="AUTHORITY_BINDING",
        expected_integration_capability="AUTHORITY_INTEGRATED",
    )
    issues.extend(authority_layer_issues)

    binding_health = payload.get("binding_health")
    token_client_binding_state = payload.get("token_client_binding_state")
    delegation_state = payload.get("delegation_state")
    authority_link_state = payload.get("authority_link_state")
    last_validated_at = parse_datetime(payload.get("last_validated_at"))
    expires_at = parse_datetime(payload.get("expires_at"))
    binding_resolved_at = parse_datetime(payload.get("binding_resolved_at"))
    delegation_grant_ref = payload.get("delegation_grant_ref")
    subject_ref = payload.get("subject_ref")
    acting_party_ref = payload.get("acting_party_ref")

    if authority_layer_boundary.get("client_delegation_state") != delegation_state:
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_layer_boundary.client_delegation_state` must mirror `delegation_state`.",
            )
        )
    if authority_layer_boundary.get("authority_link_state") != authority_link_state:
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_layer_boundary.authority_link_state` must mirror `authority_link_state`.",
            )
        )

    if binding_health in {"HEALTHY", "EXPIRING_SOON"} and token_client_binding_state != "BOUND":
        issues.append(
            Issue(
                "custom",
                location,
                "`token_client_binding_state` must be `BOUND` when `binding_health` is healthy or expiring soon.",
            )
        )

    if binding_health in {"HEALTHY", "EXPIRING_SOON"} and delegation_state not in {"NOT_REQUIRED", "SATISFIED"}:
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state` must remain `NOT_REQUIRED` or `SATISFIED` when `binding_health` is healthy or expiring soon.",
            )
        )

    if binding_health in {"HEALTHY", "EXPIRING_SOON"} and authority_link_state != "AUTHORISED_ACTIVE":
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_link_state` must remain `AUTHORISED_ACTIVE` when `binding_health` is healthy or expiring soon.",
            )
        )

    if binding_health == "CLIENT_BINDING_MISMATCH" and token_client_binding_state != "MISMATCH":
        issues.append(
            Issue(
                "custom",
                location,
                "`binding_health = CLIENT_BINDING_MISMATCH` must retain `token_client_binding_state = MISMATCH`.",
            )
        )

    if binding_health in {"EXPIRING_SOON", "EXPIRED"} and expires_at is None:
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must be populated for expiring or expired authority bindings.",
            )
        )

    if binding_health == "LIMITED_SCOPE" and delegation_state != "LIMITED" and authority_link_state != "AUTHORISED_LIMITED":
        issues.append(
            Issue(
                "custom",
                location,
                "`binding_health = LIMITED_SCOPE` must be explained by limited delegation or an `AUTHORISED_LIMITED` authority link.",
            )
        )

    if delegation_state == "LIMITED" and binding_health != "LIMITED_SCOPE":
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state = LIMITED` must retain `binding_health = LIMITED_SCOPE`.",
            )
        )

    if authority_link_state == "AUTHORISED_LIMITED" and binding_health != "LIMITED_SCOPE":
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_link_state = AUTHORISED_LIMITED` must retain `binding_health = LIMITED_SCOPE`.",
            )
        )

    if authority_link_state == "TOKEN_INVALID" and binding_health != "TOKEN_INVALID":
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_link_state = TOKEN_INVALID` must retain `binding_health = TOKEN_INVALID`.",
            )
        )

    if authority_link_state == "REVOKED" and binding_health != "REVOKED":
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_link_state = REVOKED` must retain `binding_health = REVOKED`.",
            )
        )

    if authority_link_state == "EXPIRED" and binding_health != "EXPIRED":
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_link_state = EXPIRED` must retain `binding_health = EXPIRED`.",
            )
        )

    if authority_link_state in {"UNLINKED", "LINK_INITIATED", "SUPERSEDED"} and binding_health in {"HEALTHY", "EXPIRING_SOON"}:
        issues.append(
            Issue(
                "custom",
                location,
                "Unlinked, handshake-only, or superseded authority-link posture must not serialize as healthy executable binding.",
            )
        )

    if last_validated_at is not None and binding_resolved_at is not None and binding_resolved_at < last_validated_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`binding_resolved_at` must not be earlier than `last_validated_at`.",
            )
        )

    if binding_health == "EXPIRED" and expires_at is not None and binding_resolved_at is not None and expires_at > binding_resolved_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`expires_at` must not be later than `binding_resolved_at` when `binding_health = EXPIRED`.",
            )
        )

    step_up_state = payload.get("step_up_state")
    approval_state = payload.get("approval_state")
    if step_up_state == "SATISFIED" and approval_state == "SATISFIED":
        expected_human_gate_requirement = "REQUIRE_STEP_UP_AND_APPROVAL"
        expected_human_gate_resolution = "EVIDENCE_FROZEN"
    elif approval_state == "SATISFIED":
        expected_human_gate_requirement = "REQUIRE_APPROVAL"
        expected_human_gate_resolution = "EVIDENCE_FROZEN"
    elif step_up_state == "SATISFIED":
        expected_human_gate_requirement = "REQUIRE_STEP_UP"
        expected_human_gate_resolution = "EVIDENCE_FROZEN"
    else:
        expected_human_gate_requirement = "NOT_REQUIRED"
        expected_human_gate_resolution = "NOT_REQUIRED"

    if authority_layer_boundary.get("human_gate_requirement") != expected_human_gate_requirement:
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_layer_boundary.human_gate_requirement` must mirror the frozen binding step-up and approval posture.",
            )
        )
    if authority_layer_boundary.get("human_gate_resolution_state") != expected_human_gate_resolution:
        issues.append(
            Issue(
                "custom",
                location,
                "`authority_layer_boundary.human_gate_resolution_state` must mirror the frozen binding step-up and approval evidence posture.",
            )
        )
    if (
        authority_layer_boundary.get("active_principal_class") == "SERVICE"
        and (step_up_state == "SATISFIED" or approval_state == "SATISFIED")
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "Service principals must not satisfy step-up or approval on executable authority bindings.",
            )
        )
    if delegation_state in {"SATISFIED", "LIMITED"} and authority_layer_boundary.get("delegation_basis") in {
        "SELF_ASSESSMENT_IMPORTED",
        "DIGITAL_HANDSHAKE",
    } and authority_layer_boundary.get("delegation_freshness_state") != "CURRENT":
        issues.append(
            Issue(
                "custom",
                location,
                "Executable authority bindings must keep imported or handshake delegation freshness current while delegation is live-usable.",
            )
        )
    if delegation_state in {"MISSING", "EXPIRED"} and authority_layer_boundary.get("delegation_freshness_state") not in {
        "REVALIDATION_REQUIRED",
        "NOT_APPLICABLE",
    }:
        issues.append(
            Issue(
                "custom",
                location,
                "Non-live delegation posture must keep `authority_layer_boundary.delegation_freshness_state` stale or not-applicable rather than current.",
            )
        )

    if (
        isinstance(subject_ref, str)
        and isinstance(acting_party_ref, str)
        and subject_ref != acting_party_ref
        and delegation_grant_ref is None
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_grant_ref` must be populated when `acting_party_ref` differs from `subject_ref`.",
            )
        )

    if isinstance(subject_ref, str) and isinstance(acting_party_ref, str) and subject_ref == acting_party_ref:
        if delegation_grant_ref is not None:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Self-acting authority bindings must not retain `delegation_grant_ref`.",
                )
            )
        if delegation_state not in {None, "NOT_REQUIRED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Self-acting authority bindings must retain `delegation_state = NOT_REQUIRED`.",
                )
            )

    if delegation_state == "NOT_REQUIRED" and delegation_grant_ref is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`delegation_state = NOT_REQUIRED` must clear `delegation_grant_ref`.",
            )
        )

    if delegation_state in {"SATISFIED", "LIMITED", "EXPIRED"} and delegation_grant_ref is None:
        issues.append(
            Issue(
                "custom",
                location,
                f"`delegation_state = {delegation_state}` requires non-null `delegation_grant_ref`.",
            )
        )

    return issues


def validate_filing_case(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        require_live_compliance=True,
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    temporal_event_issues, temporal_event_refs = validate_temporal_propagation_event_refs(
        payload.get("temporal_propagation_event_refs"),
        location,
        "`temporal_propagation_event_refs`",
    )
    issues.extend(temporal_event_issues)
    state_transition_issues, state_transition_contract = validate_state_transition_contract(
        payload.get("state_transition_contract"),
        location,
        "`state_transition_contract`",
        expected_object_family="FILING_CASE",
        current_state=payload.get("lifecycle_state"),
    )
    issues.extend(state_transition_issues)
    transition_applied_at = parse_datetime(
        state_transition_contract.get("transition_applied_at")
        if isinstance(state_transition_contract, dict)
        else None
    )
    last_transition_at = parse_datetime(payload.get("last_transition_at"))
    if transition_applied_at is not None and last_transition_at is not None and transition_applied_at != last_transition_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`state_transition_contract.transition_applied_at` must mirror `last_transition_at`.",
            )
        )
    calculation_lineage_fields = [
        "authority_calculation_ref",
        "calculation_request_ref",
        "calculation_id",
        "calculation_type",
        "calculation_hash",
        "calculation_basis_ref",
        "user_confirmation_ref",
    ]

    if any(isinstance(payload.get(field), str) and payload.get(field) for field in calculation_lineage_fields):
        if not isinstance(payload.get("readiness_context_ref"), str) or not payload.get("readiness_context_ref"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Any active filing-case calculation lineage must retain `readiness_context_ref`.",
                )
            )

    if payload.get("lifecycle_state") == "NOT_STARTED" and payload.get("readiness_context_ref") is not None:
        issues.append(
            Issue(
                "custom",
                location,
                "`readiness_context_ref` must be null while `lifecycle_state = NOT_STARTED`.",
            )
        )

    trust_currency_state = payload.get("trust_currency_state")
    trust_invalidation_dependency_refs = payload.get("trust_invalidation_dependency_refs", [])
    if not isinstance(trust_invalidation_dependency_refs, list):
        trust_invalidation_dependency_refs = []
    if trust_currency_state == "RECALC_REQUIRED" and not trust_invalidation_dependency_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`trust_invalidation_dependency_refs[]` must stay non-empty when `trust_currency_state = RECALC_REQUIRED`.",
            )
        )
    if trust_currency_state == "RECALC_REQUIRED" and not temporal_event_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`trust_currency_state = RECALC_REQUIRED` must retain non-empty `temporal_propagation_event_refs[]`.",
            )
        )
    missing_temporal_invalidation_refs = [
        ref for ref in temporal_event_refs if ref not in trust_invalidation_dependency_refs
    ]
    if trust_currency_state == "RECALC_REQUIRED" and missing_temporal_invalidation_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`trust_invalidation_dependency_refs[]` must include every temporal propagation event that invalidated the filing case; "
                f"missing {missing_temporal_invalidation_refs}.",
            )
        )
    if trust_currency_state in {"CURRENT", "NOT_APPLICABLE_PRETRUST"} and trust_invalidation_dependency_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "`trust_invalidation_dependency_refs[]` must be empty unless trust currency is invalidated.",
            )
        )

    current_packet_ref = payload.get("current_packet_ref")
    packet_state = payload.get("packet_state")
    lifecycle_state = payload.get("lifecycle_state")
    if (current_packet_ref is None) != (packet_state is None):
        issues.append(
            Issue(
                "custom",
                location,
                "`current_packet_ref` and `packet_state` must either both be present or both be null.",
            )
        )

    allowed_case_states_by_packet_state = {
        "DRAFT": {"PREPARING"},
        "PREPARED": {"PREPARING", "READY_REVIEW"},
        "APPROVED_TO_SUBMIT": {"READY_TO_SUBMIT"},
        "SUBMITTED": {
            "SUBMITTED_PENDING",
            "FILED_CONFIRMED",
            "FILED_UNKNOWN",
            "REJECTED",
            "AMENDMENT_ELIGIBLE",
            "AMENDMENT_IN_PROGRESS",
            "AMENDED_CONFIRMED",
            "CLOSED",
        },
        "VOID": {"PREPARING", "READY_REVIEW"},
        "SUPERSEDED": {"PREPARING", "READY_REVIEW"},
    }
    allowed_case_states = allowed_case_states_by_packet_state.get(packet_state)
    if allowed_case_states is not None and lifecycle_state not in allowed_case_states:
        issues.append(
            Issue(
                "custom",
                location,
                f"`packet_state = {packet_state}` is illegal for `lifecycle_state = {lifecycle_state}`.",
            )
        )

    return issues


def validate_filing_packet(payload: dict, location: str) -> list[Issue]:
    issues: list[Issue] = []
    execution_mode_boundary_contract_issues, _ = validate_execution_mode_boundary_contract(
        payload.get("execution_mode_boundary_contract"),
        location,
        "`execution_mode_boundary_contract`",
        require_live_compliance=True,
        require_non_null=True,
    )
    issues.extend(execution_mode_boundary_contract_issues)
    state_transition_issues, state_transition_contract = validate_state_transition_contract(
        payload.get("state_transition_contract"),
        location,
        "`state_transition_contract`",
        expected_object_family="FILING_PACKET",
        current_state=payload.get("lifecycle_state"),
    )
    issues.extend(state_transition_issues)

    calculation_lineage_fields = [
        "calculation_basis_ref",
        "authority_calculation_ref",
        "user_confirmation_ref",
    ]
    if any(isinstance(payload.get(field), str) and payload.get(field) for field in calculation_lineage_fields):
        if not isinstance(payload.get("readiness_context_ref"), str) or not payload.get("readiness_context_ref"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    "Any packet carrying calculation lineage must retain `readiness_context_ref`.",
                )
            )

    notice_step_refs = payload.get("notice_step_refs")
    notice_resolution_ref = payload.get("notice_resolution_ref")
    if isinstance(notice_resolution_ref, str) and not notice_step_refs:
        issues.append(
            Issue(
                "custom",
                location,
                "A non-null `notice_resolution_ref` requires non-empty `notice_step_refs[]`.",
            )
        )
    if notice_resolution_ref is None and isinstance(notice_step_refs, list) and not notice_step_refs:
        pass
    elif notice_resolution_ref is not None and isinstance(notice_step_refs, list) and len(notice_step_refs) == 0:
        issues.append(
            Issue(
                "custom",
                location,
                "`notice_resolution_ref` must clear when `notice_step_refs[]` is empty.",
            )
        )

    lifecycle_state = payload.get("lifecycle_state")
    approval_state = payload.get("approval_state")
    declared_basis_ack_state = payload.get("declared_basis_ack_state")
    if lifecycle_state in {"APPROVED_TO_SUBMIT", "SUBMITTED"}:
        if approval_state not in {"NOT_REQUIRED", "SATISFIED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` packets must resolve `approval_state` to `NOT_REQUIRED` or `SATISFIED`.",
                )
            )
        if declared_basis_ack_state not in {"NOT_REQUIRED", "SATISFIED"}:
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` packets must resolve `declared_basis_ack_state` to `NOT_REQUIRED` or `SATISFIED`.",
                )
            )
        if not isinstance(payload.get("filing_gate_ref"), str) or not payload.get("filing_gate_ref"):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` packets must retain `filing_gate_ref`.",
                )
            )
        if payload.get("proof_closure_state") != "CLOSED":
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` packets must keep `proof_closure_state = CLOSED`.",
                )
            )
        if isinstance(notice_step_refs, list) and notice_step_refs and not isinstance(notice_resolution_ref, str):
            issues.append(
                Issue(
                    "custom",
                    location,
                    f"`{lifecycle_state}` packets with notice steps must retain `notice_resolution_ref`.",
                )
            )

    created_at = parse_datetime(payload.get("created_at"))
    approved_at = parse_datetime(payload.get("approved_at"))
    submitted_at = parse_datetime(payload.get("submitted_at"))
    voided_at = parse_datetime(payload.get("voided_at"))
    superseded_at = parse_datetime(payload.get("superseded_at"))
    state_changed_at = parse_datetime(payload.get("state_changed_at"))
    transition_applied_at = parse_datetime(
        state_transition_contract.get("transition_applied_at")
        if isinstance(state_transition_contract, dict)
        else None
    )

    if transition_applied_at is not None and state_changed_at is not None and transition_applied_at != state_changed_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`state_transition_contract.transition_applied_at` must mirror `state_changed_at`.",
            )
        )

    if created_at is not None and approved_at is not None and approved_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`approved_at` must not be earlier than `created_at`.",
            )
        )
    if created_at is not None and submitted_at is not None and submitted_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`submitted_at` must not be earlier than `created_at`.",
            )
        )
    if approved_at is not None and submitted_at is not None and submitted_at < approved_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`submitted_at` must not be earlier than `approved_at`.",
            )
        )
    if created_at is not None and voided_at is not None and voided_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`voided_at` must not be earlier than `created_at`.",
            )
        )
    if created_at is not None and superseded_at is not None and superseded_at < created_at:
        issues.append(
            Issue(
                "custom",
                location,
                "`superseded_at` must not be earlier than `created_at`.",
            )
        )

    terminal_timestamps = [timestamp for timestamp in [approved_at, submitted_at, voided_at, superseded_at] if timestamp is not None]
    latest_terminal_timestamp = max(terminal_timestamps) if terminal_timestamps else created_at
    if (
        latest_terminal_timestamp is not None
        and state_changed_at is not None
        and state_changed_at < latest_terminal_timestamp
    ):
        issues.append(
            Issue(
                "custom",
                location,
                "`state_changed_at` must not be earlier than the latest packet transition timestamp.",
            )
        )

    return issues


