def expected_baseline_submission_state_for_type(baseline_type: object) -> str | None:
    mapping = {
        "WORKING": "WORKING",
        "FILED": "FILED_CONFIRMED",
        "AMENDED": "AMEND_CONFIRMED",
        "AUTHORITY_CORRECTED": "AUTHORITY_CORRECTED",
        "OUT_OF_BAND": "OUT_OF_BAND_UNRECONCILED",
    }
    return mapping.get(baseline_type)


