def run_schema_validation(registry: Registry) -> list[Issue]:
    del registry
    issues: list[Issue] = []
    for schema_path in sorted(SCHEMA_DIR.glob("*.schema.json")):
        schema = load_json(schema_path)
        try:
            Draft202012Validator.check_schema(schema)
        except Exception as exc:  # pragma: no cover - exercised through command use
            issues.append(Issue("schema", str(schema_path), str(exc).splitlines()[0]))
    return issues


def run_schema_shape_validation() -> list[Issue]:
    issues: list[Issue] = []
    for schema_path in sorted(SCHEMA_DIR.glob("*.schema.json")):
        schema = load_json(schema_path)
        for path, node in walk_json(schema):
            if not isinstance(node, dict):
                continue
            if node.get("type") == "array" and "default" in node and "minItems" in node:
                default = node["default"]
                min_items = node["minItems"]
                if isinstance(default, list) and len(default) < min_items:
                    issues.append(
                        Issue(
                            "schema-shape",
                            f"{schema_path}:{'/'.join(path) or '<root>'}",
                            f"Array default length {len(default)} is shorter than minItems {min_items}.",
                        )
                    )
    return issues


def run_repo_coherence_checks() -> list[Issue]:
    issues: list[Issue] = []
    audit_findings = (ROOT / "AUDIT_FINDINGS.md").read_text()
    patch_resolution = (ROOT / "PATCH_RESOLUTION_INDEX.md").read_text()
    core_engine = (ROOT / "core_engine.md").read_text()
    modules = (ROOT / "modules.md").read_text()
    readme = (ROOT / "README.md").read_text()
    data_model = (ROOT / "data_model.md").read_text()
    glossary = (ROOT / "glossary.md").read_text()
    constraint_coverage = (ROOT / "constraint_coverage_index.md").read_text()
    constraint_traceability = load_json(ROOT / "constraint_traceability_register.json")
    contract_integrity = (ROOT / "contract_integrity_requirements.md").read_text()
    architecture_guardrails = (ROOT / "architecture_coherence_guardrails.md").read_text()
    implementation_conventions = (ROOT / "implementation_conventions.md").read_text()
    audit_and_provenance = (ROOT / "audit_and_provenance.md").read_text()
    embodiments_and_examples = (ROOT / "embodiments_and_examples.md").read_text()
    invention_boundary = (ROOT / "invention_and_system_boundary.md").read_text()
    state_machines = (ROOT / "state_machines.md").read_text()
    test_vectors = (ROOT / "test_vectors.md").read_text()
    constraint_traceability_register = load_json(CONSTRAINT_TRACEABILITY_REGISTER_PATH)
    constraint_traceability_schema = load_json(CONSTRAINT_TRACEABILITY_SCHEMA_PATH)
    experience_delta = load_json(SCHEMA_DIR / "experience_delta.schema.json")

    def require_terms(text: str, path: Path, terms: tuple[str, ...], message: str) -> None:
        lowered = text.lower()
        missing = [term for term in terms if term not in lowered]
        if missing:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(path),
                    f"{message} Missing: {', '.join(missing)}.",
                )
            )

    def extract_markdown_section(text: str, heading: str) -> str | None:
        match = re.search(rf"(?ms)^## {re.escape(heading)}\n(.*?)(?=^## |\Z)", text)
        if match is None:
            return None
        return match.group(1)

    def extract_readme_schema_inventory_line(text: str) -> str | None:
        for line in text.splitlines():
            if line.startswith("- JSON schemas + sample payloads in `schemas/`, including "):
                return line
        return None

    def resolve_readme_path_token(token: str) -> Path | None:
        if " " in token or token.startswith(("http://", "https://")):
            return None
        if "<" in token or ">" in token or "*" in token:
            return None
        if "/" not in token and not token.endswith((".md", ".json", ".py", ".txt")):
            return None
        return REPO_ROOT / token if token.startswith("Algorithm/") else ROOT / token

    def extract_embedded_repo_paths(token: str) -> list[str]:
        return re.findall(r"\b(?:Algorithm|schemas|scripts|tools)/[A-Za-z0-9_./<>*-]+\b", token)

    def extract_repo_python_script_paths(token: str) -> list[str]:
        return re.findall(r"\bAlgorithm/(?:scripts|tools)/[A-Za-z0-9_./-]+\.py\b", token)

    issues.extend(
        validate_live_constraint_traceability_register(
            constraint_traceability_register,
            schema=constraint_traceability_schema,
            coverage_index_text=constraint_coverage,
            doc_text_by_path=build_constraint_traceability_doc_cache(
                constraint_traceability_register,
                root=ROOT,
                preload={
                    "constraint_coverage_index.md": constraint_coverage,
                    "README.md": readme,
                    "architecture_coherence_guardrails.md": architecture_guardrails,
                    "implementation_conventions.md": implementation_conventions,
                    "test_vectors.md": test_vectors,
                },
            ),
            register_location=str(CONSTRAINT_TRACEABILITY_REGISTER_PATH),
            coverage_location=str(ROOT / "constraint_coverage_index.md"),
            root=ROOT,
        )
    )

    duplicate_validator = REPO_ROOT / "scripts" / "validate_algorithm_contracts.py"
    if duplicate_validator.exists():
        issues.append(
            Issue(
                "repo-coherence",
                str(duplicate_validator),
                "Validation must use the authoritative Algorithm/scripts entrypoint; duplicate root validators drift.",
            )
        )

    if "python3 scripts/validate_algorithm_contracts.py" in readme:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README still references the obsolete root validator command.",
            )
        )

    if "python3 Algorithm/scripts/validate_contracts.py --self-test" not in readme:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must point to `python3 Algorithm/scripts/validate_contracts.py --self-test` as the validation command.",
            )
        )

    if "`Algorithm/scripts/validate_contracts.py --self-test`" in readme:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must not advertise the non-runnable bare `Algorithm/scripts/validate_contracts.py --self-test` form; use `python3 ...`.",
            )
        )

    if re.search(r"(?<!Algorithm/)tools/forensic_contract_guard\.py", readme):
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must not reference the nonexistent root-level tools/forensic_contract_guard.py path.",
            )
        )

    if "python3 Algorithm/tools/forensic_contract_guard.py" not in readme:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must point to `python3 Algorithm/tools/forensic_contract_guard.py` when naming the standalone forensic guard entrypoint.",
            )
        )

    if "`Algorithm/tools/forensic_contract_guard.py`" in readme:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must not advertise the non-runnable bare `Algorithm/tools/forensic_contract_guard.py` form; use `python3 ...`.",
            )
        )

    if "forensic guardrail" not in readme.lower():
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must state that the main validator also runs the forensic guardrail suite.",
            )
        )

    what_you_get = extract_markdown_section(readme, "What you get")
    if what_you_get is None:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must include a `## What you get` section that inventories the top-level corpus docs.",
            )
        )
    else:
        inventory_doc_tokens = [Path(token).name for token in re.findall(r"`([^`]+\.md)`", what_you_get)]
        inventory_docs = set(inventory_doc_tokens)
        expected_docs = {path.name for path in ROOT.glob("*.md")} - {"README.md"}
        missing_inventory_docs = sorted(expected_docs - inventory_docs)
        unexpected_inventory_docs = sorted(inventory_docs - expected_docs)
        duplicate_inventory_docs = sorted(
            token for token in inventory_docs if inventory_doc_tokens.count(token) > 1
        )
        if missing_inventory_docs:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README `## What you get` must inventory every top-level markdown corpus document; missing "
                    + ", ".join(missing_inventory_docs)
                    + ".",
                )
            )
        if duplicate_inventory_docs:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README `## What you get` must list each top-level markdown corpus document exactly once; duplicate "
                    + ", ".join(duplicate_inventory_docs)
                    + ".",
                )
            )
        if unexpected_inventory_docs:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README `## What you get` must not list nonexistent top-level markdown docs; unexpected "
                    + ", ".join(unexpected_inventory_docs)
                    + ".",
                )
            )

    schema_inventory_line = extract_readme_schema_inventory_line(readme)
    if schema_inventory_line is None:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must include the schema inventory bullet under `## What you get`.",
            )
        )
    else:
        schema_names = {path.name[:-12] for path in SCHEMA_DIR.glob("*.schema.json")}
        wildcard_prefixes = {"source_*": "source_", "evidence_*": "evidence_", "candidate_*": "candidate_", "conflict_*": "conflict_", "canonical_*": "canonical_"}
        schema_tokens = re.findall(r"`([^`]+)`", schema_inventory_line)
        explicit_schema_tokens = [
            token for token in schema_tokens if token not in {"schemas/"} and "*" not in token
        ]
        missing_explicit_schema_tokens = sorted(
            token for token in explicit_schema_tokens if token not in schema_names
        )
        if missing_explicit_schema_tokens:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README schema inventory lists nonexistent schema names: "
                    + ", ".join(missing_explicit_schema_tokens)
                    + ".",
                )
            )
        duplicate_explicit_schema_tokens = sorted(
            token for token in set(explicit_schema_tokens) if explicit_schema_tokens.count(token) > 1
        )
        if duplicate_explicit_schema_tokens:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README schema inventory must not duplicate explicit schema names: "
                    + ", ".join(duplicate_explicit_schema_tokens)
                    + ".",
                )
            )
        for wildcard_token, prefix in wildcard_prefixes.items():
            if wildcard_token in schema_tokens and not any(
                path.name.startswith(prefix) for path in SCHEMA_DIR.glob("*.schema.json")
            ):
                issues.append(
                    Issue(
                        "repo-coherence",
                        str(ROOT / "README.md"),
                        f"README schema inventory wildcard `{wildcard_token}` must match at least one live schema file.",
                    )
                )

    unresolved_readme_path_tokens = sorted(
        {
            token
            for token in re.findall(r"`([^`]+)`", readme)
            for resolved in [resolve_readme_path_token(token)]
            if resolved is not None and not resolved.exists()
        }
    )
    if unresolved_readme_path_tokens:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README backticked repo-path tokens must resolve to live files or directories; unresolved "
                + ", ".join(unresolved_readme_path_tokens)
                + ".",
            )
        )
    unresolved_embedded_repo_paths = sorted(
        {
            embedded_path
            for token in re.findall(r"`([^`]+)`", readme)
            for embedded_path in extract_embedded_repo_paths(token)
            if "<" not in embedded_path
            and ">" not in embedded_path
            and "*" not in embedded_path
            and not (REPO_ROOT / embedded_path if embedded_path.startswith("Algorithm/") else ROOT / embedded_path).exists()
        }
    )
    if unresolved_embedded_repo_paths:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README embedded repo-relative command/example paths must resolve to live repo artifacts; unresolved "
                + ", ".join(unresolved_embedded_repo_paths)
                + ".",
            )
        )
    non_interpreted_repo_python_scripts = sorted(
        {
            script_path
            for token in re.findall(r"`([^`]+)`", readme)
            for script_path in extract_repo_python_script_paths(token)
            if not re.search(rf"\bpython3\s+{re.escape(script_path)}\b", token)
        }
    )
    if non_interpreted_repo_python_scripts:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README backticked command examples must invoke repo Python scripts through an explicit interpreter; non-interpreted "
                + ", ".join(non_interpreted_repo_python_scripts)
                + ".",
            )
        )

    validation_section = extract_markdown_section(readme, "Validation")
    if validation_section is None:
        issues.append(
            Issue(
                "repo-coherence",
                str(ROOT / "README.md"),
                "README must include a `## Validation` section.",
            )
        )
    else:
        if "python3 Algorithm/scripts/validate_contracts.py --self-test" not in validation_section:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "README.md"),
                    "README `## Validation` must include `python3 Algorithm/scripts/validate_contracts.py --self-test`.",
                )
            )
