    covered_findings: dict[int, str] = {}
    for row in audit_closure_rows:
        range_value = row["Finding Range"]
        match = re.fullmatch(r"AF-(\d+)\.\.AF-(\d+)", range_value)
        if match is None:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "AUDIT_FINDINGS.md"),
                    f"Forensic closure register range `{range_value}` must use `AF-<start>..AF-<end>` syntax.",
                )
            )
            continue

        start_id = int(match.group(1))
        end_id = int(match.group(2))
        if start_id > end_id:
            issues.append(
                Issue(
                    "repo-coherence",
                    str(ROOT / "AUDIT_FINDINGS.md"),
                    f"Forensic closure range `{range_value}` must not invert start and end.",
                )
            )
            continue

        status = row["Status"]
