def run_sample_validation(registry: Registry) -> list[Issue]:
    issues: list[Issue] = []
    for sample_path in sorted(SCHEMA_DIR.glob("sample_*.json")):
        schema_name = infer_schema_name(sample_path)
        schema_path = SCHEMA_DIR / schema_name
        if not schema_path.exists():
            issues.append(
                Issue(
                    "sample",
                    str(sample_path),
                    f"Expected schema `{schema_name}` was not found.",
                )
            )
            continue

        sample = load_json(sample_path)
        schema = load_json(schema_path)
        validator = Draft202012Validator(
            schema,
            registry=registry,
            format_checker=Draft202012Validator.FORMAT_CHECKER,
        )
        for error in sorted(validator.iter_errors(sample), key=lambda err: list(err.absolute_path)):
            absolute_path = "/".join(map(str, error.absolute_path)) or "<root>"
            issues.append(Issue("sample", f"{sample_path}:{absolute_path}", error.message))

        kind = infer_kind_from_name(sample_path)
        custom_validator = CUSTOM_VALIDATORS.get(kind)
        if custom_validator:
            issues.extend(custom_validator(sample, str(sample_path)))
    return issues


def run_guard_validation() -> list[Issue]:
    return [
        Issue("guard", str(ROOT / "tools" / "forensic_contract_guard.py"), failure)
        for failure in run_guard_checks()
    ]


def run_custom_regression_tests() -> list[Issue]:
    issues: list[Issue] = []

    def expect_custom_failure(kind: str, payload: dict, description: str) -> None:
        if not CUSTOM_VALIDATORS[kind](payload, f"<self-test:{description}>"):
            issues.append(
                Issue(
                    "self-test",
                    description,
                    f"Expected custom validator `{kind}` to fail.",
                )
            )

    def expect_custom_success(kind: str, payload: dict, description: str) -> None:
        failures = CUSTOM_VALIDATORS[kind](payload, f"<self-test:{description}>")
        if failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    f"Expected custom validator `{kind}` to pass, but it failed with: {failures[0].message}",
                )
            )

    def expect_portal_first_view_budget_failure(
        route_label: str,
        budget_key: str,
        values: tuple[object, ...],
        description: str,
    ) -> None:
        failures = validate_portal_first_view_budget(
            f"<self-test:{description}>",
            route_label,
            budget_key,
            *values,
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected portal first-view budget validator to fail.",
                )
            )

    def expect_portal_duplicate_support_copy_failure(
        fragments: list[tuple[str, object]],
        description: str,
    ) -> None:
        failures = validate_portal_duplicate_support_copy(
            f"<self-test:{description}>",
            fragments,
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected portal duplicate support-copy validator to fail.",
                )
            )

    def expect_collaboration_routing_contract_failure(payload: dict[str, Any], description: str) -> None:
        failures, _ = validate_collaboration_routing_contract(
            payload,
            f"<self-test:{description}>",
            "`routing_contract`",
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected collaboration routing contract validator to fail.",
                )
            )

    def expect_work_queue_health_contract_failure(payload: dict[str, Any], description: str) -> None:
        failures, _ = validate_work_queue_health_contract(
            payload,
            f"<self-test:{description}>",
            "`queue_health_contract`",
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected work queue health contract validator to fail.",
                )
            )

    def expect_queue_projection_contract_failure(payload: dict[str, Any], description: str) -> None:
        failures, _ = validate_collaboration_queue_projection_contract(
            payload,
            f"<self-test:{description}>",
            "`queue_projection`",
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected collaboration queue projection contract validator to fail.",
                )
            )

    def expect_semantic_contract_failure(
        payload: dict[str, Any],
        description: str,
        *,
        expected_shell_family: str,
        expected_selector_profile: str,
        expected_anchor_codes: list[str],
        expected_focus_order: list[str],
        expected_announced_change_kinds: list[str],
    ) -> None:
        if not validate_semantic_accessibility_contract(
            payload,
            f"<self-test:{description}>",
            "`semantic_accessibility_contract`",
            expected_shell_family=expected_shell_family,
            expected_selector_profile=expected_selector_profile,
            expected_anchor_codes=expected_anchor_codes,
            expected_focus_order=expected_focus_order,
            expected_announced_change_kinds=expected_announced_change_kinds,
        )[0]:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected semantic accessibility exact-contract validator to fail.",
                )
            )

    constraint_traceability_payload = load_json(ROOT / "constraint_traceability_register.json")
    expect_custom_success(
        "constraint_traceability_register",
        constraint_traceability_payload,
        "constraint_traceability_register_live_payload",
    )
    duplicate_constraint_traceability_payload = copy.deepcopy(constraint_traceability_payload)
    duplicate_constraint_traceability_payload["entries"][1]["constraint_id"] = duplicate_constraint_traceability_payload[
        "entries"
    ][0]["constraint_id"]
    expect_custom_failure(
        "constraint_traceability_register",
        duplicate_constraint_traceability_payload,
        "constraint_traceability_register_duplicate_constraint_id",
    )
    stale_name_constraint_traceability_payload = copy.deepcopy(constraint_traceability_payload)
    stale_name_constraint_traceability_payload["entries"][0][
        "constraint_name"
    ] = "Shared shell vocabulary could still drift"
    expect_custom_failure(
        "constraint_traceability_register",
        stale_name_constraint_traceability_payload,
        "constraint_traceability_register_stale_defect_phrasing",
    )
    live_constraint_coverage_index = (ROOT / "constraint_coverage_index.md").read_text()
    live_constraint_traceability_schema = load_json(CONSTRAINT_TRACEABILITY_SCHEMA_PATH)

    def traceability_doc_cache(
        register: dict[str, Any], coverage_index_text: str
    ) -> dict[str, str | None]:
        return build_constraint_traceability_doc_cache(
            register,
            root=ROOT,
            preload={
                "constraint_coverage_index.md": coverage_index_text,
                "README.md": (ROOT / "README.md").read_text(),
                "architecture_coherence_guardrails.md": (ROOT / "architecture_coherence_guardrails.md").read_text(),
                "implementation_conventions.md": (ROOT / "implementation_conventions.md").read_text(),
                "test_vectors.md": (ROOT / "test_vectors.md").read_text(),
            },
        )

    def expect_live_traceability_failure(
        register: dict[str, Any], coverage_index_text: str, description: str
    ) -> None:
        failures = validate_live_constraint_traceability_register(
            register,
            schema=live_constraint_traceability_schema,
            coverage_index_text=coverage_index_text,
            doc_text_by_path=traceability_doc_cache(register, coverage_index_text),
            register_location=f"<self-test:{description}>",
            coverage_location=f"<self-test:{description}:constraint_coverage_index.md>",
            root=ROOT,
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected live constraint-traceability validation to fail.",
                )
            )

    def expect_live_traceability_success(
        register: dict[str, Any], coverage_index_text: str, description: str
    ) -> None:
        failures = validate_live_constraint_traceability_register(
            register,
            schema=live_constraint_traceability_schema,
            coverage_index_text=coverage_index_text,
            doc_text_by_path=traceability_doc_cache(register, coverage_index_text),
            register_location=f"<self-test:{description}>",
            coverage_location=f"<self-test:{description}:constraint_coverage_index.md>",
            root=ROOT,
        )
        if failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    f"Expected live constraint-traceability validation to pass, but it failed with: {failures[0].message}",
                )
            )

    expect_live_traceability_success(
        constraint_traceability_payload,
        live_constraint_coverage_index,
        "live_constraint_traceability_register_and_index_alignment",
    )
    missing_term_live_constraint_traceability = copy.deepcopy(constraint_traceability_payload)
    missing_term_live_constraint_traceability["entries"][0]["authoritative_refs"][0]["required_terms"].append(
        "nonexistent_traceability_term_anchor"
    )
    expect_live_traceability_failure(
        missing_term_live_constraint_traceability,
        live_constraint_coverage_index,
        "live_constraint_traceability_missing_required_term",
    )
    name_drift_constraint_coverage_index = live_constraint_coverage_index.replace(
        "Shared shell and route-stability vocabulary stays authoritative across specialized surfaces",
        "Shared shell vocabulary drift row",
        1,
    )
    expect_live_traceability_failure(
        constraint_traceability_payload,
        name_drift_constraint_coverage_index,
        "live_constraint_traceability_index_name_drift",
    )
    history_leak_constraint_traceability = copy.deepcopy(constraint_traceability_payload)
    history_leak_constraint_traceability["entries"][0]["authoritative_refs"][0]["kind"] = "FORENSIC_HISTORY"
    expect_live_traceability_failure(
        history_leak_constraint_traceability,
        live_constraint_coverage_index,
        "live_constraint_traceability_history_leak",
    )

