    def expect_failure_resolution_contract_failure(
        payload: dict[str, Any],
        description: str,
        *,
        expected_lifecycle_role: str,
        expected_role_specific_binding_policy: str,
    ) -> None:
        if not validate_failure_resolution_contract(
            payload,
            f"<self-test:{description}>",
            "`failure_resolution_contract`",
            expected_lifecycle_role=expected_lifecycle_role,
            expected_role_specific_binding_policy=expected_role_specific_binding_policy,
        )[0]:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected failure resolution exact-contract validator to fail.",
                )
            )

