    def expect_artifact_affordance_contract_failure(
        payload: dict[str, Any],
        description: str,
        *,
        affordance_scope: str | None = None,
    ) -> None:
        failures, _ = validate_artifact_affordance_contract(
            payload,
            f"<self-test:{description}>",
            "`artifact_affordance`",
            affordance_scope=affordance_scope,
        )
        if not failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    "Expected artifact affordance contract validator to fail.",
                )
            )

    def expect_artifact_affordance_contract_success(
        payload: dict[str, Any],
        description: str,
        *,
        affordance_scope: str | None = None,
    ) -> None:
        failures, _ = validate_artifact_affordance_contract(
            payload,
            f"<self-test:{description}>",
            "`artifact_affordance`",
            affordance_scope=affordance_scope,
        )
        if failures:
            issues.append(
                Issue(
                    "self-test",
                    description,
                    f"Expected artifact affordance contract validator to pass, but it failed with: {failures[0].message}",
                )
            )

