    def late_data_temporal_contract(
        temporal_classification: str,
        *,
        baseline_scope_class: str = "CURRENT_SCOPE",
        filing_critical_baseline_touch: bool = True,
        t_cutoff: str = "2026-03-31T00:00:00+00:00",
        t_effective_or_null: str | None = "2026-03-30T12:00:00+00:00",
        t_visible_or_null: str | None = "2026-03-31T09:00:00+00:00",
        t_discovered: str = "2026-03-31T10:00:00+00:00",
        retroactive_impact_required: bool = False,
        trust_invalidation_required: bool = True,
        proof_staleness_required: bool = True,
        amendment_reuse_invalidated: bool = True,
        legal_effect_basis: str | None = None,
        temporal_certainty_state: str | None = None,
        reason_codes: list[str] | None = None,
    ) -> dict[str, Any]:
        if temporal_classification == "TEMPORALLY_UNPROVED":
            resolved_certainty = temporal_certainty_state or "UNPROVED"
            resolved_basis = legal_effect_basis or "UNKNOWN"
        elif temporal_classification == "AUTHORITY_POSTING_LAG":
            resolved_certainty = temporal_certainty_state or "PROVED"
            resolved_basis = legal_effect_basis or "AUTHORITY_PUBLICATION_TIME"
        else:
            resolved_certainty = temporal_certainty_state or "PROVED"
            resolved_basis = legal_effect_basis or "EFFECTIVE_TIME"
        return {
            "classification_profile_code": LATE_DATA_TEMPORAL_PROFILE,
            "temporal_classification": temporal_classification,
            "temporal_certainty_state": resolved_certainty,
            "legal_effect_basis": resolved_basis,
            "baseline_scope_class": baseline_scope_class,
            "filing_critical_baseline_touch": filing_critical_baseline_touch,
            "t_cutoff": t_cutoff,
            "t_effective_or_null": t_effective_or_null,
            "t_visible_or_null": t_visible_or_null,
            "t_discovered": t_discovered,
            "retroactive_impact_required": retroactive_impact_required,
            "trust_invalidation_required": trust_invalidation_required,
            "proof_staleness_required": proof_staleness_required,
            "amendment_reuse_invalidated": amendment_reuse_invalidated,
            "replay_lineage_policy": LATE_DATA_REPLAY_LINEAGE_POLICY,
            "reason_codes": reason_codes
            or (["TEMPORAL_CLASSIFIED"] if any(
                (
                    retroactive_impact_required,
                    trust_invalidation_required,
                    proof_staleness_required,
                    amendment_reuse_invalidated,
                )
            ) else []),
        }

