    def scope_execution_binding_contract(
        binding_scope_class: str,
        requested_scope: list[str],
        executable_scope: list[str] | None = None,
        *,
        execution_mode_or_null: str | None = "COMPLIANCE",
        executable_partition_scope_refs: list[str] | None = None,
        access_decision: str = "ALLOW",
        access_binding_hash: str = "binding-hash-1",
        masking_rules: list[str] | None = None,
        required_approvals: list[str] | None = None,
        required_authn_level: str | None = None,
        reason_codes: list[str] | None = None,
    ) -> dict[str, Any]:
        executable = requested_scope if executable_scope is None else executable_scope
        requested_family = derive_scope_family(requested_scope) or "READ_ONLY"
        executable_family = derive_scope_family(executable) or "READ_ONLY"
        return {
            "binding_scope_class": binding_scope_class,
            "execution_mode_or_null": execution_mode_or_null,
            "requested_scope_family": requested_family,
            "executable_scope_family": executable_family,
            "requested_scope": requested_scope,
            "executable_scope": executable,
            "executable_partition_scope_refs": sorted(executable_partition_scope_refs or []),
            "access_decision": access_decision,
            "reduction_posture": "UNCHANGED" if requested_scope == executable else "REDUCED_BY_AUTHORIZATION",
            "mutation_atomicity": expected_scope_mutation_atomicity(requested_scope) or "NARROWING_ALLOWED",
            "masking_rules": masking_rules or [],
            "required_approvals": sorted(required_approvals or []),
            "required_authn_level": required_authn_level,
            "access_binding_hash": access_binding_hash,
            "reason_codes": reason_codes or ["ACCESS_GRANTED"],
        }

    def governance_required_approvals_for_requirement(approval_requirement: str) -> list[str]:
        mapping = {
            "NOT_REQUIRED": [],
            "SINGLE_APPROVER": ["TENANT_ADMIN"],
            "DUAL_APPROVER": ["SECURITY_TEAM", "TENANT_ADMIN"],
            "SECURITY_REVIEW": ["SECURITY_TEAM"],
            "CHANGE_ADVISORY_QUORUM": ["CHANGE_BOARD", "SECURITY_TEAM", "TENANT_ADMIN"],
        }
        return sorted(mapping.get(approval_requirement, []))

    def governance_mutation_hazard_contract_payload(
        *,
        policy_snapshot_hash: str = "policy-1",
        access_binding_hash: str = "binding-hash-1",
        dependency_topology_hash: str = "topology-1",
        simulation_basis_hash: str = "sim-basis-1",
        impact_radius_lower_score: int = 10,
        impact_radius_upper_score: int = 30,
        impacted_principal_count: int = 1,
        impacted_client_count: int = 0,
        impacted_authority_operation_count: int = 0,
        impacted_workflow_count: int = 2,
        impacted_limitation_count: int = 0,
        privilege_gain_score: int = 20,
        scope_expansion_score: int = 5,
        masking_relaxation_score: int = 0,
        simulation_confidence_score: int = 92,
        predictability_score: int = 88,
        policy_risk_score: int | None = None,
        approval_necessity_score: int | None = None,
        approval_requirement: str | None = None,
        bounded_safe_mutation: int | None = None,
        required_approvals: list[str] | None = None,
        risk_driver_codes: list[str] | None = None,
        approval_trigger_codes: list[str] | None = None,
        confidence_limiter_codes: list[str] | None = None,
        bounded_safety_blocker_codes: list[str] | None = None,
        reason_codes: list[str] | None = None,
        commit_authority_posture: str | None = None,
    ) -> dict[str, Any]:
        payload: dict[str, Any] = {
            "contract_version": GOVERNANCE_MUTATION_HAZARD_CONTRACT_VERSION,
            "hazard_contract_hash": "",
            "policy_snapshot_hash": policy_snapshot_hash,
            "access_binding_hash": access_binding_hash,
            "dependency_topology_hash": dependency_topology_hash,
            "simulation_basis_hash": simulation_basis_hash,
            "count_class_profile_code": GOVERNANCE_IMPACT_COUNT_CLASS_PROFILE_CODE,
            "commit_authority_posture": "APPROVAL_GATED",
            "impact_radius_lower_score": impact_radius_lower_score,
            "impact_radius_upper_score": impact_radius_upper_score,
            "impacted_principal_count": impacted_principal_count,
            "impacted_principal_count_class": expected_governance_impacted_count_class(
                impacted_principal_count
            ),
            "impacted_client_count": impacted_client_count,
            "impacted_client_count_class": expected_governance_impacted_count_class(
                impacted_client_count
            ),
            "impacted_authority_operation_count": impacted_authority_operation_count,
            "impacted_authority_operation_count_class": expected_governance_impacted_count_class(
                impacted_authority_operation_count
            ),
            "impacted_workflow_count": impacted_workflow_count,
            "impacted_workflow_count_class": expected_governance_impacted_count_class(
                impacted_workflow_count
            ),
            "impacted_limitation_count": impacted_limitation_count,
            "impacted_limitation_count_class": expected_governance_impacted_count_class(
                impacted_limitation_count
            ),
            "privilege_gain_score": privilege_gain_score,
            "scope_expansion_score": scope_expansion_score,
            "masking_relaxation_score": masking_relaxation_score,
            "policy_risk_score": 0,
            "approval_necessity_score": 0,
            "approval_requirement": "SINGLE_APPROVER",
            "bounded_safe_mutation": 0,
            "required_approvals": [],
            "simulation_confidence_score": simulation_confidence_score,
            "predictability_score": predictability_score,
            "risk_driver_codes": [],
            "approval_trigger_codes": [],
            "confidence_limiter_codes": [],
            "bounded_safety_blocker_codes": [],
            "reason_codes": [],
        }
        payload["policy_risk_score"] = (
            policy_risk_score
            if policy_risk_score is not None
            else expected_governance_policy_risk_score(payload) or 0
        )
        payload["approval_necessity_score"] = (
            approval_necessity_score
            if approval_necessity_score is not None
            else expected_governance_approval_necessity_score(payload) or 0
        )
        payload["bounded_safe_mutation"] = (
            bounded_safe_mutation
            if bounded_safe_mutation is not None
            else expected_governance_bounded_safe_mutation(payload) or 0
        )
        payload["approval_requirement"] = approval_requirement or (
            expected_governance_approval_requirement(payload) or "SINGLE_APPROVER"
        )
        payload["required_approvals"] = sorted(
            required_approvals
            if required_approvals is not None
            else governance_required_approvals_for_requirement(payload["approval_requirement"])
        )
        payload["commit_authority_posture"] = commit_authority_posture or (
            expected_governance_commit_authority_posture(
                payload["simulation_confidence_score"],
                payload["predictability_score"],
                payload["bounded_safe_mutation"],
            )
            or "APPROVAL_GATED"
        )
        payload["risk_driver_codes"] = risk_driver_codes or expected_governance_mutation_risk_driver_codes(
            payload
        )
        payload["approval_trigger_codes"] = (
            approval_trigger_codes or expected_governance_mutation_approval_trigger_codes(payload)
        )
        payload["confidence_limiter_codes"] = confidence_limiter_codes or (
            expected_governance_mutation_confidence_limiter_codes(
                payload["simulation_confidence_score"],
                payload["predictability_score"],
            )
        )
        payload["bounded_safety_blocker_codes"] = (
            bounded_safety_blocker_codes or expected_governance_mutation_bounded_safety_blocker_codes(payload)
        )
        default_reason_codes = sorted(
            {
                *payload["risk_driver_codes"],
                *payload["approval_trigger_codes"],
                *payload["confidence_limiter_codes"],
                *payload["bounded_safety_blocker_codes"],
                *(
                    ["BOUNDED_SAFE_MUTATION"]
                    if payload["bounded_safe_mutation"] == 1
                    else []
                ),
                *(
                    ["UNCERTAIN_BLAST_RADIUS"]
                    if payload["impact_radius_lower_score"] < payload["impact_radius_upper_score"]
                    else []
                ),
            }
        )
        payload["reason_codes"] = sorted(reason_codes or default_reason_codes)
        payload["hazard_contract_hash"] = (
            derive_governance_mutation_hazard_contract_hash(payload) or "hazard-contract-hash-invalid"
        )
        return payload

    def governance_mutation_basis_contract_payload(
        *,
        policy_snapshot_hash: str = "policy-1",
        access_binding_hash: str = "binding-hash-1",
        dependency_topology_hash: str = "topology-1",
        simulation_basis_hash: str = "sim-basis-1",
        hazard_contract_hash: str | None = None,
        bounded_safe_mutation: int = 0,
        approval_requirement: str | None = None,
        required_approvals: list[str] | None = None,
        simulation_confidence_score: int = 92,
        predictability_score: int = 88,
        commit_authority_posture: str | None = None,
    ) -> dict[str, Any]:
        resolved_approval_requirement = approval_requirement or (
            "NOT_REQUIRED" if bounded_safe_mutation == 1 else "SECURITY_REVIEW"
        )
        resolved_required_approvals = sorted(
            required_approvals
            if required_approvals is not None
            else ([] if resolved_approval_requirement == "NOT_REQUIRED" else ["SECURITY_TEAM"])
        )
        resolved_commit_authority_posture = commit_authority_posture or expected_governance_commit_authority_posture(
            simulation_confidence_score,
            predictability_score,
            bounded_safe_mutation,
        )
        resolved_hazard_contract_hash = hazard_contract_hash or governance_mutation_hazard_contract_payload(
            policy_snapshot_hash=policy_snapshot_hash,
            access_binding_hash=access_binding_hash,
            dependency_topology_hash=dependency_topology_hash,
            simulation_basis_hash=simulation_basis_hash,
            bounded_safe_mutation=bounded_safe_mutation,
            approval_requirement=resolved_approval_requirement,
            required_approvals=resolved_required_approvals,
            simulation_confidence_score=simulation_confidence_score,
            predictability_score=predictability_score,
            commit_authority_posture=resolved_commit_authority_posture,
        )["hazard_contract_hash"]
        payload = {
            "contract_version": GOVERNANCE_MUTATION_BASIS_CONTRACT_VERSION,
            "basis_contract_hash": "",
            "policy_snapshot_hash": policy_snapshot_hash,
            "access_binding_hash": access_binding_hash,
            "dependency_topology_hash": dependency_topology_hash,
            "simulation_basis_hash": simulation_basis_hash,
            "hazard_contract_hash": resolved_hazard_contract_hash,
            "commit_authority_posture": resolved_commit_authority_posture,
            "approval_requirement": resolved_approval_requirement,
            "bounded_safe_mutation": bounded_safe_mutation,
            "required_approvals": resolved_required_approvals,
            "simulation_confidence_score": simulation_confidence_score,
            "predictability_score": predictability_score,
        }
        payload["basis_contract_hash"] = (
            derive_governance_mutation_basis_contract_hash(payload) or "basis-contract-hash-invalid"
        )
        return payload

