    def trust_summary_decision_explainability_contract_payload(
        *,
        payload: dict[str, Any],
    ) -> dict[str, Any]:
        trust_semantic_qualifiers: list[str] = []
        reason_codes = payload.get("reason_codes", [])
        trust_input_basis_payload = payload.get("trust_input_basis_contract", {})
        if (
            payload.get("authority_uncertainty_score", 0) > 0
            or trust_input_basis_payload.get("authority_progression_state") in {"REVIEW_LIMITED", "BLOCKED"}
            or reason_codes_indicate_authority(reason_codes)
        ):
            trust_semantic_qualifiers.append("AUTHORITY_STATE")
        if (
            payload.get("automation_level") in {"LIMITED", "BLOCKED"}
            or bool(payload.get("decision_constraint_codes"))
            or payload.get("threshold_stability_state") == "EDGE_REVIEW"
        ):
            trust_semantic_qualifiers.append("LIMITATION_STATE")
        if (
            payload.get("active_filing_critical_override_count", 0) > 0
            or reason_codes_indicate_override(reason_codes)
        ):
            trust_semantic_qualifiers.append("OVERRIDE_STATE")
        return {
            "contract_version": "DECISION_EXPLAINABILITY_V1",
            "artifact_family": "TRUST_SUMMARY",
            "grammar_profile_code": "LOW_NOISE_DECISION_GRAMMAR_V1",
            "reason_order_policy": "DOMINANT_REASON_FIRST_CANONICAL_PRIORITY",
            "dominant_reason_selection_policy": "FIRST_ORDERED_REASON_IS_DOMINANT",
            "summary_source_policy": "READ_SURFACES_MUST_USE_PERSISTED_FIELDS",
            "compression_policy": "PREFIX_COMPRESS_ORDERED_REASON_CODES_WITH_SUPPRESSED_COUNT",
            "compression_reason_cap": 3,
            "ordered_reason_codes": copy.deepcopy(reason_codes),
            "dominant_reason_code": payload.get("dominant_reason_code"),
            "compressed_reason_codes": compressed_reason_prefix(reason_codes),
            "suppressed_reason_count": max(len(reason_codes) - 3, 0),
            "semantic_qualifiers": canonical_semantic_qualifiers(trust_semantic_qualifiers),
            "action_projection_state": "NONE",
            "plain_text_field_name": "plain_summary",
            "plain_text_character_limit": 200,
        }

    def finalize_trust_summary_payload(payload: dict[str, Any]) -> dict[str, Any]:
        payload = copy.deepcopy(payload)
        basis_contract = payload.get("trust_input_basis_contract")
        if isinstance(basis_contract, dict) and "trust_fresh_until" not in payload:
            payload["trust_fresh_until"] = basis_contract.get("trust_fresh_until")
        payload["decision_explainability_contract"] = (
            trust_summary_decision_explainability_contract_payload(payload=payload)
        )
        payload["trust_sensitivity_analysis_contract"] = (
            derive_trust_sensitivity_contract(payload) or {}
        )
        return payload

