def print_issues(issues: Iterable[Issue]) -> None:
    for issue in issues:
        print(f"[{issue.kind}] {issue.location}: {issue.message}")


def main() -> int:
    parser = argparse.ArgumentParser(description="Validate Taxat contract schemas and custom invariants.")
    parser.add_argument(
        "--self-test",
        action="store_true",
        help="Run built-in regression tests for custom invariant checks.",
    )
    args = parser.parse_args()

    registry = build_registry()
    issues = run_schema_validation(registry)
    issues.extend(run_schema_shape_validation())
    issues.extend(run_sample_validation(registry))
    issues.extend(run_repo_coherence_checks())
    issues.extend(run_guard_validation())
    if args.self_test:
        issues.extend(run_custom_regression_tests())

    if issues:
        print_issues(issues)
        print(f"FAIL: {len(issues)} validation issue(s) found.")
        return 1

    print("PASS: schemas, bundled samples, and custom invariants validated.")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
